"use client";

import { useState, useRef, useEffect, useCallback } from "react";
import Link from "next/link";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardHeader,
  CardFooter,
} from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { PasswordInput } from "@/components/ui/password-input";
import { Checkbox } from "@/components/ui/checkbox";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormMessage,
} from "@/components/ui/form";
import { SocialLogin } from "@/components/auth/social-login";
import { Loader2, ArrowLeft, Lock, Smartphone, Mail, CheckCircle2 } from "lucide-react";
import { TOAST_IDS, showErrorToast } from "@/hooks/utils/use-toast";
import { useAuth } from "@/hooks/auth/useAuth";
import useZodForm from "@/hooks/utils/useZodForm";
import { loginSchema, otpSchema } from "@/lib/schema";
import { AuthResponse, OTPFormData } from "@/types/auth.types";
import { ROUTES } from "@/lib/config/routes";
import { cn } from "@/lib/utils";
import { z } from "zod";
import PhoneInput from "@/components/ui/phone-input";

type LoginMethod = "selection" | "password" | "otp";
type OtpMethod = "email" | "phone";

type SuccessPhase = "none" | "alert" | "redirecting";

export default function LoginPage() {
  const [view, setView] = useState<LoginMethod>("selection");
  const [showOTPInput, setShowOTPInput] = useState(false);
  const [otpMethod, setOtpMethod] = useState<OtpMethod>("email");
  const [isSocialLoginLoading, setIsSocialLoginLoading] = useState(false);
  const [successPhase, setSuccessPhase] = useState<SuccessPhase>("none");

  // Shared email state to persist across views
  const [sharedIdentifier, setSharedIdentifier] = useState("");

  const otpInputRef = useRef<HTMLInputElement>(null);
  const { loginAsync, requestOTP, verifyOTP, isLoggingIn, isVerifyingOTP } = useAuth();
  
  const isFormDisabled = isSocialLoginLoading || successPhase !== "none";

  const triggerSuccessFlow = useCallback(() => {
    setSuccessPhase("alert");
    setTimeout(() => setSuccessPhase("redirecting"), 1500);
  }, []);

  useEffect(() => {
    if (showOTPInput && otpInputRef.current) {
      otpInputRef.current.focus();
    }
  }, [showOTPInput]);

  // Login Mutation
  const loginMutation = useCallback(
    async (data: z.infer<typeof loginSchema>): Promise<AuthResponse> => {
      const result = await loginAsync({
        email: data.email,
        password: data.password,
        rememberMe: data.rememberMe,
      });
      triggerSuccessFlow();
      return result;
    },
    [loginAsync, triggerSuccessFlow]
  );

  // OTP Mutation
  const otpMutation = async (data: z.infer<typeof otpSchema>): Promise<AuthResponse> => {
    const result = await verifyOTP(data as OTPFormData);
    triggerSuccessFlow();
    return result;
  };

  const passwordForm = useZodForm(loginSchema, loginMutation, {
    email: sharedIdentifier,
    password: "",
    rememberMe: false,
  });

  const otpForm = useZodForm(otpSchema, otpMutation, {
    identifier: sharedIdentifier,
    otp: "",
    rememberMe: false,
  });

  const handleRequestOTP = async (identifier: string) => {
    try {
      await requestOTP({ identifier });
      setShowOTPInput(true);
    } catch (error) {
      // Handled by hook
    }
  };

  const handleBack = () => {
    setView("selection");
    setShowOTPInput(false);
  }

  // Render Selection View
  const renderSelectionView = () => (
    <div className="space-y-4">
      <SocialLogin
        showDivider={false}
        onLoadingStateChange={setIsSocialLoginLoading}
        onSuccess={triggerSuccessFlow}
        onError={(error) => {
          showErrorToast(error.message, { id: TOAST_IDS.AUTH.SOCIAL_LOGIN });
        }}
      />

       <div className="relative py-1">
        <div className="absolute inset-0 flex items-center">
          <span className="w-full border-t border-gray-200 dark:border-slate-700" />
        </div>
        <div className="relative flex justify-center text-xs uppercase">
          <span className="bg-background px-4 text-muted-foreground text-gray-400 dark:text-gray-500 text-[10px]">OR</span>
        </div>
      </div>

      <div className="space-y-3">
        {/* OTP Option */}
        <button
          className={cn(
            "w-full flex items-center p-3 rounded-xl border transition-all duration-200 text-left hover:border-blue-500 hover:bg-blue-50/50 dark:hover:bg-blue-900/20 group",
            "border-slate-200 dark:border-slate-700"
          )}
          onClick={() => {
            setView("otp");
            setOtpMethod("email");
          }}
          disabled={isFormDisabled}
        >
          <div className="h-10 w-10 rounded-full bg-blue-100 dark:bg-blue-900/30 flex items-center justify-center shrink-0 group-hover:bg-blue-200 dark:group-hover:bg-blue-900/50 transition-colors">
            <Smartphone className="h-5 w-5 text-blue-600 dark:text-blue-400" />
          </div>
          <div className="ml-3 flex-1">
             <div className="flex items-center gap-2">
              <span className="font-semibold text-sm text-gray-900 dark:text-gray-100">Sign in with OTP</span>
              <span className="px-1.5 py-0.5 rounded-full bg-blue-600 text-[9px] font-bold text-white uppercase tracking-wider">
                Recommended
              </span>
            </div>
            <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">Passwordless login</p>
          </div>
        </button>

        {/* Password Option */}
        <button
          className={cn(
            "w-full flex items-center p-3 rounded-xl border transition-all duration-200 text-left hover:border-purple-500 hover:bg-purple-50/50 dark:hover:bg-purple-900/20 group",
            "border-slate-200 dark:border-slate-700"
          )}
          onClick={() => {
             setView("password");
          }}
          disabled={isFormDisabled}
        >
          <div className="h-10 w-10 rounded-full bg-purple-100 dark:bg-purple-900/30 flex items-center justify-center shrink-0 group-hover:bg-purple-200 dark:group-hover:bg-purple-900/50 transition-colors">
            <Lock className="h-5 w-5 text-purple-600 dark:text-purple-400" />
          </div>
          <div className="ml-3">
            <div className="font-semibold text-sm text-gray-900 dark:text-gray-100">Sign in with Password</div>
            <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">Use your email and password</p>
          </div>
        </button>
      </div>
    </div>
  );

  const renderPasswordView = () => (
      <Form {...passwordForm}>
        <form
        onSubmit={(e) => {
            passwordForm.onFormSubmit(e).catch((error) => {
            passwordForm.setError("root", {
                message: error.message || "Invalid credentials. Please try again.",
            });
            });
        }}
        className="space-y-4"
        >
        {passwordForm.formState.errors.root && (
            <div className="p-3 text-sm text-red-500 bg-red-50 border border-red-200 rounded-md">
            {passwordForm.formState.errors.root.message}
            </div>
        )}
        <FormField
            control={passwordForm.control}
            name="email"
            render={({ field }) => (
            <FormItem>
                <FormControl>
                <Input
                    type="email"
                    placeholder="Email address"
                    {...field}
                    value={field.value || sharedIdentifier} // synced
                    onChange={(e) => {
                      field.onChange(e);
                      setSharedIdentifier(e.target.value);
                    }}
                    disabled={isFormDisabled}
                    autoComplete="email"
                />
                </FormControl>
                <FormMessage />
            </FormItem>
            )}
        />

        <FormField
            control={passwordForm.control}
            name="password"
            render={({ field }) => (
            <FormItem>
                <FormControl>
                <PasswordInput
                    placeholder="Password"
                    {...field}
                    disabled={isFormDisabled}
                    autoComplete="current-password"
                />
                </FormControl>
                <FormMessage />
            </FormItem>
            )}
        />

        <div className="flex flex-col gap-3">
            <div className="flex items-center justify-between">
                <FormField
                    control={passwordForm.control}
                    name="rememberMe"
                    render={({ field }) => (
                    <FormItem className="flex flex-row items-center space-x-2 space-y-0">
                        <FormControl>
                        <Checkbox
                            checked={field.value}
                            onCheckedChange={field.onChange}
                            disabled={isFormDisabled}
                        />
                        </FormControl>
                        <div className="space-y-1 leading-none">
                        <label
                            htmlFor="rememberMe"
                            className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70"
                        >
                            Remember me
                        </label>
                        </div>
                    </FormItem>
                    )}
                />

                <Link
                    href={ROUTES.FORGOT_PASSWORD}
                    className="text-sm font-medium text-blue-600 hover:text-blue-800 transition-colors"
                >
                Forgot?
                </Link>
            </div>
        </div>

        <Button
            type="submit"
            className="w-full"
            disabled={isFormDisabled || isLoggingIn}
        >
            {isLoggingIn ? (
            <>
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                Signing in...
            </>
            ) : (
            "Sign in"
            )}
        </Button>
        </form>
    </Form>
  );

  const renderOtpView = () => (
       <Form {...otpForm}>
          <form onSubmit={otpForm.onFormSubmit} className="space-y-4">
             {!showOTPInput && (
              <div className="flex p-1 bg-gray-100 dark:bg-slate-800 rounded-lg mb-4">
                <button
                  type="button"
                  onClick={() => setOtpMethod("email")}
                  className={cn(
                    "flex-1 flex items-center justify-center py-2 text-sm font-medium rounded-md transition-all",
                    otpMethod === "email"
                      ? "bg-white dark:bg-slate-700 text-blue-600 dark:text-blue-400 shadow-sm"
                      : "text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200"
                  )}
                >
                  <Mail className="w-4 h-4 mr-2" />
                  Email
                </button>
                <button
                  type="button"
                  onClick={() => setOtpMethod("phone")}
                  className={cn(
                    "flex-1 flex items-center justify-center py-2 text-sm font-medium rounded-md transition-all",
                    otpMethod === "phone"
                      ? "bg-white dark:bg-slate-700 text-blue-600 dark:text-blue-400 shadow-sm"
                      : "text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200"
                  )}
                >
                  <Smartphone className="w-4 h-4 mr-2" />
                  Phone
                </button>
              </div>
            )}

            <FormField
              control={otpForm.control}
              name="identifier"
              render={({ field }) => (
                <FormItem>
                  <FormControl>
                    {otpMethod === "phone" ? (
                      <PhoneInput
                        {...field}
                        placeholder="Phone Number"
                        defaultCountry="IN"
                        disabled={isFormDisabled || showOTPInput}
                        value={field.value || sharedIdentifier}
                        onChange={(value: string | undefined) => {
                          field.onChange(value);
                          setSharedIdentifier(value || "");
                        }}
                      />
                    ) : (
                      <Input
                        type="email"
                        placeholder="Email Address"
                        {...field}
                        value={field.value || sharedIdentifier}
                        onChange={(e) => {
                          field.onChange(e);
                          setSharedIdentifier(e.target.value);
                        }}
                        disabled={isFormDisabled || showOTPInput}
                      />
                    )}
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            {showOTPInput ? (
              <FormField
                control={otpForm.control}
                name="otp"
                render={({ field }) => (
                  <FormItem>
                    <FormControl>
                      <Input
                        type="text"
                        placeholder="Enter OTP"
                        {...field}
                        ref={otpInputRef}
                        disabled={isFormDisabled}
                        className="text-center tracking-widest text-lg"
                        maxLength={6}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
            ) : (
              <Button
                type="button"
                variant="outline"
                className="w-full"
                onClick={() => {
                  const id = otpForm.getValues("identifier");
                  if (id) {
                    handleRequestOTP(id);
                  } else {
                    showErrorToast("Please enter your email or phone first", {
                      id: TOAST_IDS.AUTH.OTP,
                    });
                  }
                }}
                disabled={isFormDisabled}
              >
                Request OTP
              </Button>
            )}

            <FormField
              control={otpForm.control}
              name="rememberMe"
              render={({ field }) => (
                <FormItem className="flex flex-row items-start space-x-2 space-y-0">
                  <FormControl>
                    <Checkbox
                      checked={field.value}
                      onCheckedChange={field.onChange}
                      disabled={isFormDisabled}
                    />
                  </FormControl>
                  <div className="space-y-1 leading-none">
                    <label
                      htmlFor="rememberMe"
                      className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70"
                    >
                      Remember me
                    </label>
                  </div>
                </FormItem>
              )}
            />

            {showOTPInput && (
              <Button
                type="submit"
                className="w-full"
                disabled={isFormDisabled || isVerifyingOTP}
              >
                {isVerifyingOTP ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    Verifying...
                  </>
                ) : (
                  "Verify & Sign In"
                )}
              </Button>
            )}
          </form>
        </Form>
  );
  
  const getHeaderTitle = () => {
    if (view === "otp") return "Sign in with OTP";
    if (view === "password") return "Sign in with Password";
    return "Welcome Back";
  };
  
  const getHeaderSubtitle = () => {
      if (view === "otp") return "Enter your details to receive a code";
      if (view === "password") return "Enter your email and password";
      return "Choose your preferred sign in method";
  };

  // Redirecting overlay — replaces the whole card content
  if (successPhase === "redirecting") {
    return (
      <Card className="w-full max-w-[380px] mx-auto shadow-lg">
        <CardContent className="flex flex-col items-center justify-center py-16 gap-5">
          <div className="relative flex items-center justify-center">
            <div className="h-16 w-16 rounded-full bg-green-100 dark:bg-green-900/30 flex items-center justify-center">
              <CheckCircle2 className="h-8 w-8 text-green-600 dark:text-green-400" />
            </div>
            <Loader2 className="absolute h-20 w-20 animate-spin text-green-500/40" />
          </div>
          <div className="text-center space-y-1">
            <p className="font-semibold text-gray-900 dark:text-gray-100">Successfully signed in!</p>
            <p className="text-sm text-gray-500 dark:text-gray-400">Redirecting to dashboard…</p>
          </div>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card className="w-full max-w-[380px] mx-auto shadow-lg">
      <CardHeader className={cn("space-y-1 px-4 sm:px-6 relative", view !== "selection" ? "pt-10" : "pt-2")}>
          {view !== "selection" && (
           <Button
               variant="ghost"
               size="sm"
               className="absolute left-4 top-3 text-gray-500 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-100 p-0 hover:bg-transparent"
               onClick={handleBack}
           >
               <ArrowLeft className="h-4 w-4 mr-2" />
               Back
           </Button>
        )}
        <h2 className={cn("text-xl font-bold text-center", view !== "selection" ? "pt-6" : "")}>
          {getHeaderTitle()}
        </h2>
        <p className="text-xs text-gray-500 dark:text-gray-400 text-center">
          {getHeaderSubtitle()}
        </p>
      </CardHeader>
      <CardContent className="px-4 sm:px-6">
        {/* Success alert — shown briefly before the redirecting overlay */}
        {successPhase === "alert" && (
          <div className="mb-4 flex items-center gap-3 p-3 rounded-lg bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800 animate-in fade-in slide-in-from-top-2 duration-300">
            <CheckCircle2 className="h-5 w-5 text-green-600 dark:text-green-400 shrink-0" />
            <div>
              <p className="text-sm font-semibold text-green-800 dark:text-green-300">Sign in successful!</p>
              <p className="text-xs text-green-600 dark:text-green-400">Redirecting to your dashboard…</p>
            </div>
          </div>
        )}
        {view === "selection" && renderSelectionView()}
        {view === "password" && renderPasswordView()}
        {view === "otp" && renderOtpView()}
      </CardContent>
      <CardFooter className="flex flex-col space-y-2 px-4 sm:px-6 pb-4 sm:pb-6">
          <div className="text-xs text-center">
            Don&apos;t have an account?{" "}
            <Link
              href={ROUTES.REGISTER}
              className="text-blue-600 hover:text-blue-800 transition-colors"
            >
              Sign up
            </Link>
          </div>
      </CardFooter>
    </Card>
  );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardFooter,
  CardHeader,
} from "@/components/ui/card";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { PasswordInput } from "@/components/ui/password-input";
import { Checkbox } from "@/components/ui/checkbox";
import { SocialLogin } from "@/components/auth/social-login";
import { PasswordStrength } from "@/components/ui/password-strength";
import { registerSchema } from "@/lib/schema";
import { Role, type RegisterData } from "@/types/auth.types";
import { useAuth, useAuthForm } from "@/hooks/auth/useAuth";
import useZodForm from "@/hooks/utils/useZodForm";
import { ERROR_MESSAGES } from "@/lib/config/config";
import { TOAST_IDS, showErrorToast, showSuccessToast } from "@/hooks/utils/use-toast";
import { ROUTES } from "@/lib/config/routes";
import { EmailOtpRegisterForm } from "@/components/auth/email-otp-register-form";
import { PhoneOtpRegisterForm } from "@/components/auth/phone-otp-register-form";
import PhoneInput from "@/components/ui/phone-input";
import { 
  Loader2, 
  CheckCircle2, 
  Mail, 
  Lock, 
  ArrowLeft, 
  Smartphone 
} from "lucide-react";
import { cn } from "@/lib/utils";

type RegistrationMethod = "selection" | "otp" | "password";
type OtpMethod = "email" | "phone";

export default function RegisterPage() {
  const router = useRouter();
  const { register: registerUser, isPending } = useAuth();
  
  // State for view navigation
  const [view, setView] = useState<RegistrationMethod>("selection");
  const [otpMethod, setOtpMethod] = useState<OtpMethod>("email");
  
  const [formError, setFormError] = useState<string | null>(null);
  const [isSocialLoginLoading, setIsSocialLoginLoading] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [countdown, setCountdown] = useState(5);

  const isFormDisabled = isSocialLoginLoading || isSuccess;

  // Unified auth form hook
  const { executeAuthOperation } = useAuthForm({
    toastId: TOAST_IDS.AUTH.REGISTER,
    loadingMessage: "Creating account...",
    successMessage: "Account created successfully!",
    errorMessage: ERROR_MESSAGES.REGISTER_FAILED,
    showToast: true,
    onError: (error: Error) => {
      if (
        error.message.toLowerCase().includes("already exists") ||
        error.message.toLowerCase().includes("please login")
      ) {
        showErrorToast(
          "An account with this email address already exists. Please login.",
          { id: TOAST_IDS.AUTH.REGISTER }
        );
        setFormError("An account with this email address already exists. Please login.");
        setTimeout(() => router.push(ROUTES.LOGIN), 3000);
        return;
      }
      setFormError(error.message);
    },
  });


  // Handle success redirect countdown
  useEffect(() => {
    if (isSuccess) {
      const timer = setInterval(() => {
        setCountdown((prev) => {
          if (prev <= 1) {
            clearInterval(timer);
            router.push(ROUTES.LOGIN);
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
      return () => clearInterval(timer);
    }
    return undefined; // Explicit return for TypeScript
  }, [isSuccess, router]);

  // Password Registration Form
  const passwordForm = useZodForm(
    registerSchema,
    async (values: any) => {
      setFormError(null);
      const formData = { ...values, role: Role.PATIENT };
      
      const result = await executeAuthOperation(async () => {
        return await registerUser(formData as RegisterData);
      });

      if (result) {
        if (result.requiresVerification && result.user?.email) {
          showSuccessToast("Verification code sent to your email.", {
              id: TOAST_IDS.AUTH.REGISTER,
          });
          setTimeout(() => {
             router.push(`${ROUTES.VERIFY_OTP}?email=${encodeURIComponent(result.user.email)}`);
          }, 1000);
          return;
        }

        if ("user" in result && result.user) {
          setIsSuccess(true);
          passwordForm.reset();
        }
      }
    },
    {
      email: "",
      password: "",
      confirmPassword: "",
      firstName: "",
      lastName: "",
      phone: "",
      gender: "male",
      role: Role.PATIENT as any,
      age: 18,
      terms: false,
    }
  );

  const handleBack = () => {
    setFormError(null);
    setView("selection");
  };

  // Render Functions
  const renderSuccess = () => (
    <div className="flex flex-col items-center justify-center py-12 gap-5 animate-in fade-in zoom-in duration-300">
      <div className="relative flex items-center justify-center">
        <div className="h-16 w-16 rounded-full bg-green-100 dark:bg-green-900/30 flex items-center justify-center">
          <CheckCircle2 className="h-8 w-8 text-green-600 dark:text-green-400" />
        </div>
        <Loader2 className="absolute h-20 w-20 animate-spin text-green-500/40" />
      </div>
      <div className="text-center space-y-1">
        <p className="font-semibold text-gray-900 dark:text-gray-100">Account created successfully!</p>
        <p className="text-sm text-gray-500 dark:text-gray-400">
          Redirecting to login in{" "}
          <span className="font-bold text-blue-600 dark:text-blue-400">{countdown}s</span>…
        </p>
      </div>
      <Button onClick={() => router.push(ROUTES.LOGIN)} size="sm" variant="outline">
        Go to Login Now
      </Button>
    </div>
  );

  // Icons
  const GoogleIcon = () => (
    <svg className="h-4 w-4 mr-2" viewBox="0 0 24 24">
      <path
        d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"
        fill="#4285F4"
      />
      <path
        d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
        fill="#34A853"
      />
      <path
        d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
        fill="#FBBC05"
      />
      <path
        d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
        fill="#EA4335"
      />
    </svg>
  );

  const renderSelectionView = () => (
    <div className="space-y-4">
      <div className="space-y-3">
        {/* OTP Option */}
        <button
          className={cn(
            "w-full flex items-center p-3 rounded-xl border transition-all duration-200 text-left hover:border-blue-500 hover:bg-blue-50/50 dark:hover:bg-blue-900/20 group",
            view === "otp" ? "border-blue-500 bg-blue-50 dark:bg-blue-900/30" : "border-slate-200 dark:border-slate-700"
          )}
          onClick={() => {
            setView("otp");
            setOtpMethod("email"); // Default to email OTP
          }}
          disabled={isFormDisabled}
        >
          <div className="h-10 w-10 rounded-full bg-blue-100 dark:bg-blue-900/30 flex items-center justify-center shrink-0 group-hover:bg-blue-200 dark:group-hover:bg-blue-900/50 transition-colors">
            <Mail className="h-5 w-5 text-blue-600 dark:text-blue-400" />
          </div>
          <div className="ml-3 flex-1">
            <div className="flex items-center gap-2">
              <span className="font-semibold text-sm text-gray-900 dark:text-gray-100">Continue with OTP</span>
              <span className="px-1.5 py-0.5 rounded-full bg-blue-600 text-[9px] font-bold text-white uppercase tracking-wider">
                Recommended
              </span>
            </div>
            <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">Email or Phone verification</p>
          </div>
        </button>

        {/* Password Option */}
        <button
          className={cn(
            "w-full flex items-center p-3 rounded-xl border transition-all duration-200 text-left hover:border-purple-500 hover:bg-purple-50/50 dark:hover:bg-purple-900/20 group",
            view === "password" ? "border-purple-500 bg-purple-50 dark:bg-purple-900/30" : "border-slate-200 dark:border-slate-700"
          )}
          onClick={() => setView("password")}
          disabled={isFormDisabled}
        >
          <div className="h-10 w-10 rounded-full bg-purple-100 dark:bg-purple-900/30 flex items-center justify-center shrink-0 group-hover:bg-purple-200 dark:group-hover:bg-purple-900/50 transition-colors">
            <Lock className="h-5 w-5 text-purple-600 dark:text-purple-400" />
          </div>
          <div className="ml-3">
            <div className="font-semibold text-sm text-gray-900 dark:text-gray-100">Create with Password</div>
            <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">Traditional signup</p>
          </div>
        </button>
      </div>

      <div className="relative py-1">
        <div className="absolute inset-0 flex items-center">
          <span className="w-full border-t border-gray-200 dark:border-slate-700" />
        </div>
        <div className="relative flex justify-center text-xs uppercase">
          <span className="bg-background px-4 text-muted-foreground text-gray-400 dark:text-gray-500 text-[10px]">OR</span>
        </div>
      </div>

      <div className="space-y-3">
        {/* Custom Google Button */}
        <button
          type="button"
          className="w-full flex items-center justify-center px-4 py-2 border border-slate-200 dark:border-slate-700 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          onClick={() => {
            // Trigger generic Google login if available, or visual fallback
            document.querySelector<HTMLElement>('[aria-label="Sign in with Google"]')?.click();
          }}
          disabled={isFormDisabled}
        >
          <GoogleIcon />
          <span className="font-medium text-sm text-gray-700 dark:text-gray-200">Sign up with Google</span>
        </button>
      </div>

      {/* Hidden SocialLogin component to handle logic */}
      <div className="hidden">
           <SocialLogin
            onLoadingStateChange={setIsSocialLoginLoading}
            onError={(error) => {
                 showErrorToast(error.message, { id: TOAST_IDS.AUTH.SOCIAL_LOGIN });
            }}
           />
      </div>

      <div className="text-center px-4">
          <p className="text-[10px] text-gray-500 dark:text-gray-400">
             By signing up, you agree to our{" "}
             <Link href="/terms" className="text-blue-600 hover:underline">
                 Terms of Service
             </Link>{" "}
             and{" "}
             <Link href="/privacy" className="text-blue-600 hover:underline">
                 Privacy Policy
             </Link>
          </p>
      </div>
    </div>
  );

  const renderOtpView = () => (
    <div className="space-y-6">
      <div className="flex justify-center mb-6">
         <div className="h-16 w-16 bg-blue-50 dark:bg-blue-900/30 rounded-full flex items-center justify-center">
            {otpMethod === "email" ? (
                <Mail className="h-8 w-8 text-blue-600 dark:text-blue-400" />
            ) : (
                <Smartphone className="h-8 w-8 text-blue-600 dark:text-blue-400" />
            )}
         </div>
      </div>

      <div className="flex p-1 bg-gray-100 dark:bg-slate-800 rounded-lg">
        <button
          type="button"
          onClick={() => setOtpMethod("email")}
          className={cn(
            "flex-1 flex items-center justify-center py-2 text-sm font-medium rounded-md transition-all",
            otpMethod === "email" 
              ? "bg-white dark:bg-slate-700 text-blue-600 dark:text-blue-400 shadow-sm" 
              : "text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200"
          )}
        >
          <Mail className="w-4 h-4 mr-2" />
          Email
        </button>
        <button
          type="button"
          onClick={() => setOtpMethod("phone")}
          className={cn(
            "flex-1 flex items-center justify-center py-2 text-sm font-medium rounded-md transition-all",
            otpMethod === "phone" 
              ? "bg-white dark:bg-slate-700 text-blue-600 dark:text-blue-400 shadow-sm" 
              : "text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200"
          )}
        >
          <Smartphone className="w-4 h-4 mr-2" />
          Phone
        </button>
      </div>

      <div className="mt-6">
        {otpMethod === "email" && <EmailOtpRegisterForm />}
        {otpMethod === "phone" && <PhoneOtpRegisterForm />}
      </div>
    </div>
  );

  const renderPasswordView = () => (
    <div className="space-y-4">
      {formError && (
        <div className="mb-4 p-3 bg-red-50 border border-red-200 rounded-md">
          <p className="text-sm text-red-600">{formError}</p>
        </div>
      )}

      <Form {...passwordForm}>
        <form
          onSubmit={passwordForm.handleSubmit(async () => {
            try {
              await passwordForm.onFormSubmit();
            } catch {
              // Error handled in hook
            }
          })}
          className="space-y-4"
          noValidate
        >
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <FormField
              control={passwordForm.control}
              name="firstName"
              render={({ field }) => (
                <FormItem>
                  <FormControl>
                    <Input
                      placeholder="First name"
                      {...field}
                      disabled={isFormDisabled}
                    />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />
            <FormField
              control={passwordForm.control}
              name="lastName"
              render={({ field }) => (
                <FormItem>
                  <FormControl>
                    <Input
                      placeholder="Last name"
                      {...field}
                      disabled={isFormDisabled}
                    />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />
          </div>

          <FormField
            control={passwordForm.control}
            name="email"
            render={({ field }) => (
              <FormItem>
                <FormControl>
                  <Input
                    type="email"
                    placeholder="Email address"
                    {...field}
                    disabled={isFormDisabled}
                  />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={passwordForm.control}
            name="phone"
            render={({ field }) => (
              <FormItem>
                <FormControl>
                  <PhoneInput
                    {...field}
                    placeholder="Phone number"
                    defaultCountry="IN"
                    disabled={isFormDisabled}
                    onChange={(value: string | undefined) => field.onChange(value)} 
                  />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={passwordForm.control}
            name="password"
            render={({ field }) => (
              <FormItem>
                <FormControl>
                  <PasswordInput
                    placeholder="Create password"
                    {...field}
                    disabled={isFormDisabled}
                  />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <PasswordStrength password={passwordForm.watch("password")} />

          <FormField
            control={passwordForm.control}
            name="confirmPassword"
            render={({ field }) => (
              <FormItem>
                <FormControl>
                  <PasswordInput
                    placeholder="Confirm password"
                    {...field}
                    disabled={isFormDisabled}
                  />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={passwordForm.control}
            name="terms"
            render={({ field }) => (
              <FormItem className="flex flex-row items-start space-x-3 space-y-0">
                <FormControl>
                  <Checkbox
                    checked={field.value}
                    onCheckedChange={field.onChange}
                    disabled={isFormDisabled}
                  />
                </FormControl>
                <div className="space-y-1 leading-none">
                  <label
                    htmlFor="terms"
                    className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70"
                  >
                    I agree to the{" "}
                    <Link href="/terms" className="text-blue-600 hover:text-blue-800">
                      Terms of Service
                    </Link>{" "}
                    and{" "}
                    <Link href="/privacy" className="text-blue-600 hover:text-blue-800">
                      Privacy Policy
                    </Link>
                  </label>
                </div>
              </FormItem>
            )}
          />

          <Button
            type="submit"
            className="w-full"
            disabled={isFormDisabled || isPending}
          >
            {isPending ? (
              <>
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                Creating account...
              </>
            ) : (
              "Create account"
            )}
          </Button>
        </form>
      </Form>
    </div>
  );

  const getHeaderTitle = () => {
    if (isSuccess) return "Account Created!";
    if (view === "otp") return "Sign up with OTP";
    if (view === "password") return "Create Account";
    return "Create Account";
  };

  const getHeaderSubtitle = () => {
      if (isSuccess) return "Your account has been successfully created.";
      if (view === "otp") return "Choose your verification method";
      if (view === "password") return "Enter your details below";
      return "Choose how you'd like to sign up";
  };

  return (
    <Card className="w-full max-w-[380px] mx-auto shadow-lg">
      <CardHeader className={cn("space-y-1 px-4 sm:px-6 relative", view !== "selection" && !isSuccess ? "pt-10" : "pt-2")}>
        {view !== "selection" && !isSuccess && (
            <Button
                variant="ghost"
                size="sm"
                className="absolute left-4 top-3 text-gray-500 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-100 p-0 hover:bg-transparent"
                onClick={handleBack}
            >
                <ArrowLeft className="h-4 w-4 mr-2" />
                Back
            </Button>
        )}
        <h2 className={cn("text-xl font-bold text-center", view !== "selection" && !isSuccess ? "pt-6" : "")}>
          {getHeaderTitle()}
        </h2>
        <p className="text-xs text-gray-500 dark:text-gray-400 text-center">
            {getHeaderSubtitle()}
        </p>
      </CardHeader>
      
      <CardContent className="px-4 sm:px-6">
        {isSuccess ? (
            renderSuccess()
        ) : (
            <>
                {view === "selection" && renderSelectionView()}
                {view === "otp" && renderOtpView()}
                {view === "password" && renderPasswordView()}
            </>
        )}
      </CardContent>

      {!isSuccess && (
        <CardFooter className="flex flex-col space-y-2 px-4 sm:px-6 pb-4 sm:pb-6">
          <div className="text-xs text-center">
            Already have an account?{" "}
            <Link
              href={ROUTES.LOGIN}
              className="text-blue-600 hover:text-blue-800 transition-colors"
            >
              Sign in
            </Link>
          </div>
        </CardFooter>
      )}
    </Card>
  );
}

"use client";

import { useMemo } from "react";
import Link from "next/link";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { useCurrentClinic, useClinicStats, useActiveLocations } from "@/hooks/query/useClinics";
import { useMedicineDeskQueue } from "@/hooks/query/usePharmacy";
import { useRealTimeAppointments, useRealTimeQueueStatus } from "@/hooks/realtime/useRealTimeQueries";
import { cn } from "@/lib/utils";
import { getQueuePositionLabel, normalizeQueueEntry } from "@/lib/queue/queue-adapter";
import {
  Settings,
  Clock,
  TrendingUp,
  AlertCircle,
  Plus,
  CalendarDays,
  Loader2,
  ArrowUpRight,
  ArrowDownRight,
  Activity,
  UserPlus,
  IndianRupee,
  RefreshCcw,
} from "lucide-react";

export default function ClinicAdminDashboard() {
  const { data: currentClinic, isPending: isLoadingClinic } = useCurrentClinic();
  const clinicId = currentClinic?.id;

  const { data: locations = [] } = useActiveLocations(clinicId || "");
  const locationId = locations[0]?.id || "";

  // Real data fetching
  const { data: clinicStats, isPending: isLoadingStats, refetch: refetchStats } = useClinicStats(clinicId || "");
  const { data: appointmentsData } = useRealTimeAppointments({
    limit: 100,
  });
  const { isPending: isLoadingQueue } = useRealTimeQueueStatus(undefined, locationId);
  const { data: medicineDeskQueue = [] } = useMedicineDeskQueue(clinicId || "", !!clinicId);

  const appointments = (appointmentsData as any)?.data || [];
  const queueItems = useMemo(
    () =>
      appointments
        .filter((item: any) => ["CONFIRMED", "IN_PROGRESS"].includes(String(item.status || "").toUpperCase()))
        .sort((a: any, b: any) => {
          const aToken = typeof a.queuePosition === "number" ? a.queuePosition : 9999;
          const bToken = typeof b.queuePosition === "number" ? b.queuePosition : 9999;
          return aToken - bToken;
        }),
    [appointments]
  );

  const stats = useMemo(() => {
    if (!clinicStats) return null;
    return {
      totalAppointments: clinicStats.totalAppointments || 0,
      todayAppointments: clinicStats.todayAppointments || 0,
      totalStaff: clinicStats.totalUsers || 0,
      activePatients: clinicStats.totalPatients || 0,
      revenue: clinicStats.revenue || 0,
      waitTime: clinicStats.avgWaitTime || 0,
      completionRate: clinicStats.completionRate || 0,
    };
  }, [clinicStats]);

  const recentEvents = useMemo(() => {
    return appointments.slice(0, 3).map((apt: any) => ({
      id: apt.id,
      type: "appointment",
      message: `Appointment scheduled for ${apt.patient?.name || apt.patient?.firstName || apt.patientName || "a patient"}`,
      time: new Date(apt.createdAt || Date.now()).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      date: new Date(apt.createdAt).toLocaleDateString(),
    }));
  }, [appointments]);

  const medicineDeskItems = useMemo(
    () =>
      (Array.isArray(medicineDeskQueue) ? medicineDeskQueue : [])
        .filter((item: any) => item?.id)
        .map((item: any) => {
          const entry = normalizeQueueEntry(item);
          return {
            id: entry.entryId,
            patientName: entry.patientName || "Unknown Patient",
            paymentStatus: String(entry.paymentStatus || "PENDING").toUpperCase(),
            queuePosition: entry.position > 0 ? entry.position : null,
            pendingAmount: Number(item.pendingAmount || 0),
            readyForHandover: Boolean(entry.readyForHandover),
          };
        })
        .slice(0, 8),
    [medicineDeskQueue]
  );

  const liveAlerts = useMemo(() => {
    const alerts: Array<{ title: string; description: string; tone: "amber" | "blue" }> = [];

    if ((stats?.waitTime || 0) > 30) {
      alerts.push({
        title: "Wait Time Threshold Exceeded",
        description: `Average clinic wait time is ${stats?.waitTime || 0} minutes`,
        tone: "amber",
      });
    }

    const unpaidMedicineCount = medicineDeskItems.filter(
      (item) => !item.readyForHandover && item.paymentStatus !== "PAID"
    ).length;
    if (unpaidMedicineCount > 0) {
      alerts.push({
        title: "Medicine Desk Payments Pending",
        description: `${unpaidMedicineCount} prescription handover${unpaidMedicineCount === 1 ? "" : "s"} awaiting payment`,
        tone: "blue",
      });
    }

    return alerts;
  }, [medicineDeskItems, stats?.waitTime]);

  if (isLoadingClinic || isLoadingStats) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[80vh] gap-4">
        <Loader2 className="w-12 h-12 animate-spin text-primary" />
        <p className="text-muted-foreground font-medium animate-pulse text-lg">Waking up the clinic dashboard...</p>
      </div>
    );
  }

  return (
    <div className="p-4 sm:p-8 space-y-8 bg-transparent min-h-screen">
      {/* Premium Header */}
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div className="space-y-2">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-primary/10 rounded-2xl">
              <Activity className="w-6 h-6 text-primary" />
            </div>
            <div>
              <h1 className="text-4xl font-black tracking-tight text-neutral-900 dark:text-neutral-50 drop-shadow-sm">
                Control Hub
              </h1>
              <p className="text-muted-foreground font-medium flex items-center gap-2">
                <span className="text-primary font-bold">{currentClinic?.name}</span>
                <span className="w-1 h-1 bg-neutral-300 rounded-full" />
                Live operational status
              </p>
            </div>
          </div>
        </div>

        <div className="flex flex-wrap items-center gap-3 bg-white dark:bg-neutral-900 p-1.5 rounded-2xl shadow-sm ring-1 ring-neutral-200 dark:ring-neutral-800">
          <Button 
            variant="ghost" 
            size="sm" 
            onClick={() => refetchStats()}
            className="h-10 px-4 font-bold flex items-center gap-2"
          >
            <RefreshCcw className="w-4 h-4" />
            Sync Data
          </Button>
          <Button asChild className="h-10 px-6 font-bold shadow-lg shadow-primary/20 active:scale-95 transition-all flex items-center gap-2 rounded-xl">
            <Link href="/clinic-admin/schedule">
              <Plus className="w-4 h-4" />
              Manage Schedule
            </Link>
          </Button>
        </div>
      </div>

      {/* Impact Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6">
        {[
          { 
            label: "Appointments Today", 
            value: stats?.todayAppointments || 0, 
            sub: `${stats?.totalAppointments || 0} this month`, 
            icon: CalendarDays, 
            color: "text-blue-600", 
            bg: "bg-blue-500/10",
            trend: `${stats?.totalAppointments || 0} month`,
            isUp: true
          },
          { 
            label: "Clinic Revenue", 
            value: `₹${(stats?.revenue || 0).toLocaleString()}`, 
            sub: "Gross billing", 
            icon: IndianRupee, 
            color: "text-purple-600", 
            bg: "bg-purple-500/10",
            trend: "Live billing",
            isUp: true
          },
          { 
            label: "Active Patients", 
            value: stats?.activePatients || 0, 
            sub: "Verified records", 
            icon: UserPlus, 
            color: "text-emerald-600", 
            bg: "bg-emerald-500/10",
            trend: "Verified",
            isUp: true
          },
          { 
            label: "Queue Efficiency", 
            value: `${stats?.waitTime || 0}m`, 
            sub: "Average wait time", 
            icon: Clock, 
            color: "text-orange-600", 
            bg: "bg-orange-500/10",
            trend: `${queueItems.length} live`,
            isUp: (stats?.waitTime || 0) <= 30
          },
          {
            label: "Medicine Desk",
            value: medicineDeskItems.length,
            sub: "Active handovers",
            icon: Activity,
            color: "text-amber-600",
            bg: "bg-amber-500/10",
            trend: `${medicineDeskItems.filter((item) => item.paymentStatus !== "PAID").length} unpaid`,
            isUp: medicineDeskItems.filter((item) => item.paymentStatus === "PAID").length > 0
          }
        ].map((item, i) => (
          <Card key={i} className="group border-none shadow-sm hover:shadow-xl transition-all duration-300 hover:-translate-y-1 bg-white dark:bg-neutral-900 ring-1 ring-neutral-200 dark:ring-neutral-800 overflow-hidden">
            <div className={cn("h-1 w-full opacity-30 group-hover:opacity-100 transition-opacity", item.color.replace('text', 'bg'))} />
            <CardContent className="p-6">
              <div className="flex items-center justify-between mb-4">
                <div className={cn("p-2.5 rounded-xl shrink-0", item.bg)}>
                  <item.icon className={cn("w-5 h-5", item.color)} />
                </div>
                <div className={cn(
                  "flex items-center gap-1 text-[10px] font-black uppercase px-2 py-1 rounded-lg",
                  item.isUp ? "bg-emerald-500/10 text-emerald-600" : "bg-red-500/10 text-red-600"
                )}>
                  {item.isUp ? <ArrowUpRight className="w-3 h-3" /> : <ArrowDownRight className="w-3 h-3" />}
                  {item.trend}
                </div>
              </div>
              <div className="space-y-1">
                <p className="text-2xl font-black tracking-tight">{item.value}</p>
                <div className="flex items-center justify-between">
                  <p className="text-xs font-bold text-muted-foreground uppercase tracking-wider">{item.label}</p>
                  <span className="text-[10px] font-medium text-neutral-400">{item.sub}</span>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 text-foreground">
        {/* Live Queue Tracker */}
        <Card className="lg:col-span-8 border-none shadow-lg bg-white dark:bg-neutral-900 ring-1 ring-neutral-200 dark:ring-neutral-800 overflow-hidden">
          <CardHeader className="p-6 border-b bg-neutral-50/50 dark:bg-neutral-900/50 flex flex-row items-center justify-between">
            <div className="space-y-1">
              <CardTitle className="text-xl font-black flex items-center gap-2">
                <Clock className="w-5 h-5 text-primary" />
                Live Clinic Queue
              </CardTitle>
              <CardDescription className="text-xs font-medium">Real-time patient flow across all departments</CardDescription>
            </div>
            <Badge variant="outline" className="bg-emerald-500/10 text-emerald-600 border-none animate-pulse">
              Live Monitoring
            </Badge>
          </CardHeader>
          <CardContent className="p-0">
            {isLoadingQueue ? (
              <div className="flex justify-center p-12">
                <Loader2 className="w-8 h-8 animate-spin text-primary" />
              </div>
            ) : queueItems.length > 0 ? (
              <div className="divide-y divide-neutral-100 dark:divide-neutral-800">
                {queueItems.map((item: any, idx: number) => (
                  <div key={idx} className="flex flex-col sm:flex-row sm:items-center justify-between p-4 gap-4 hover:bg-neutral-50 dark:hover:bg-neutral-800/50 transition-colors group">
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 rounded-xl bg-linear-to-br from-primary/10 to-blue-500/10 flex items-center justify-center font-black text-primary text-sm shadow-sm group-hover:scale-110 transition-transform">
                        {item.tokenNumber || item.queuePosition || idx + 1}
                      </div>
                        <div>
                          <h4 className="font-bold text-sm">{item.patientName || "Walk-in Patient"}</h4>
                          <div className="flex items-center gap-2 mt-0.5">
                            <span className="text-[10px] font-bold uppercase text-muted-foreground">
                              {item.doctorName || "Unassigned Doctor"}
                              {String(item.doctorRole || "").toUpperCase() === "ASSISTANT_DOCTOR"
                                ? " (ASSISTANT)"
                                : ""}
                            </span>
                            <span className="w-1 h-1 bg-neutral-300 rounded-full" />
                            <span className="text-[10px] font-bold uppercase text-primary/80">
                              {item.serviceType || item.type || item.treatmentType || "Consultation"}
