                    <p className="mt-2 text-sm text-gray-600">
                      {summarizeWorkingHours(location.workingHours)}
                    </p>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>

          {filteredLocations.length === 0 && (
            <Card>
              <CardContent className="py-12 text-center">
                <MapPin className="w-12 h-12 text-gray-400 mx-auto mb-4" />
                <p className="text-gray-600">
                  {searchTerm
                    ? "No locations found matching your search"
                    : "No locations added yet"}
                </p>
              </CardContent>
            </Card>
          )}

          {/* Edit Dialog */}
          <Dialog open={isEditDialogOpen} onOpenChange={setIsEditDialogOpen}>
            <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
              <DialogHeader>
                <DialogTitle>Edit Location</DialogTitle>
                <DialogDescription>
                  Update location information
                </DialogDescription>
              </DialogHeader>
              {selectedLocation && (
                <div className="space-y-4">
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <Label htmlFor="edit-name">Location Name *</Label>
                      <Input
                        id="edit-name"
                        value={selectedLocation.name}
                        onChange={(e) =>
                          setSelectedLocation({
                            ...selectedLocation,
                            name: e.target.value,
                          })
                        }
                      />
                    </div>
                    <div>
                      <Label htmlFor="edit-phone">Phone *</Label>
                      <Input
                        id="edit-phone"
                        value={selectedLocation.phone}
                        onChange={(e) =>
                          setSelectedLocation({
                            ...selectedLocation,
                            phone: e.target.value,
                          })
                        }
                      />
                    </div>
                  </div>
                  <div>
                    <Label htmlFor="edit-address">Address *</Label>
                    <Textarea
                      id="edit-address"
                      value={selectedLocation.address}
                      onChange={(e) =>
                        setSelectedLocation({
                          ...selectedLocation,
                          address: e.target.value,
                        })
                      }
                      rows={2}
                    />
                  </div>
                  <div className="grid grid-cols-3 gap-4">
                    <div>
                      <Label htmlFor="edit-city">City *</Label>
                      <Input
                        id="edit-city"
                        value={selectedLocation.city}
                        onChange={(e) =>
                          setSelectedLocation({
                            ...selectedLocation,
                            city: e.target.value,
                          })
                        }
                      />
                    </div>
                    <div>
                      <Label htmlFor="edit-state">State *</Label>
                      <Input
                        id="edit-state"
                        value={selectedLocation.state}
                        onChange={(e) =>
                          setSelectedLocation({
                            ...selectedLocation,
                            state: e.target.value,
                          })
                        }
                      />
                    </div>
                    <div>
                      <Label htmlFor="edit-zipCode">ZIP Code *</Label>
                      <Input
                        id="edit-zipCode"
                        value={selectedLocation.zipCode}
                        onChange={(e) =>
                          setSelectedLocation({
                            ...selectedLocation,
                            zipCode: e.target.value,
                          })
                        }
                      />
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <Label htmlFor="edit-email">Email *</Label>
                      <Input
                        id="edit-email"
                        type="email"
                        value={selectedLocation.email}
                        onChange={(e) =>
                          setSelectedLocation({
                            ...selectedLocation,
                            email: e.target.value,
                          })
                        }
                      />
                    </div>
                    <div>
                      <Label htmlFor="edit-timezone">Timezone</Label>
                      <Select
                        value={selectedLocation.timezone}
                        onValueChange={(value) =>
                          setSelectedLocation({
                            ...selectedLocation,
                            timezone: value,
                          })
                        }
                      >
                        <SelectTrigger>
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="Asia/Kolkata">
                            Asia/Kolkata (IST)
                          </SelectItem>
                          <SelectItem value="Asia/Dubai">
                            Asia/Dubai (GST)
                          </SelectItem>
                          <SelectItem value="UTC">UTC</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                  </div>
                  <div className="flex items-center justify-between">
                    <Label>Active Status</Label>
                    <Switch
                      checked={selectedLocation.isActive}
                      onCheckedChange={(checked) =>
                        setSelectedLocation({
                          ...selectedLocation,
                          isActive: checked,
                        })
                      }
                    />
                  </div>
                  <div className="space-y-3">
                    <Label>Working Hours</Label>
                    <div className="grid gap-3">
                      {DAYS.map((day) => {
                        const slot = normalizeWorkingHours(selectedLocation.workingHours)[day];
                        return (
                          <div key={day} className="grid grid-cols-1 md:grid-cols-[120px_80px_1fr_1fr] gap-3 items-center">
                            <div className="font-medium capitalize">{day}</div>
                            <div className="flex items-center gap-2">
                              <Switch
                                checked={!!slot}
                                onCheckedChange={(checked) => toggleWorkingDay("edit", day, checked)}
                              />
                              <span className="text-xs text-gray-500">
                                {slot ? "Open" : "Closed"}
                              </span>
                            </div>
                            <Input
                              type="time"
                              value={slot?.start || ""}
                              disabled={!slot}
                              onChange={(e) => updateWorkingHours("edit", day, "start", e.target.value)}
                            />
                            <Input
                              type="time"
                              value={slot?.end || ""}
                              disabled={!slot}
                              onChange={(e) => updateWorkingHours("edit", day, "end", e.target.value)}
