        <div><Label>Email</Label><Input value={clinicForm.email} onChange={e=>setCF("email",e.target.value)} /></div><div><Label>Website</Label><Input value={clinicForm.website} onChange={e=>setCF("website",e.target.value)} /></div>
        <div><Label>City</Label><Input value={clinicForm.city} onChange={e=>setCF("city",e.target.value)} /></div><div><Label>State</Label><Input value={clinicForm.state} onChange={e=>setCF("state",e.target.value)} /></div>
        <div><Label>Country</Label><Input value={clinicForm.country} onChange={e=>setCF("country",e.target.value)} /></div><div><Label>Zip Code</Label><Input value={clinicForm.zipCode} onChange={e=>setCF("zipCode",e.target.value)} /></div>
        <div className="md:col-span-2"><Label>Address</Label><Textarea value={clinicForm.address} onChange={e=>setCF("address",e.target.value)} /></div>
      </CardContent></Card>

      <Card><CardHeader><CardTitle>Dynamic OPD Sessions</CardTitle><CardDescription>Add multiple sessions per day.</CardDescription></CardHeader><CardContent className="space-y-3">
        {DAYS.map(d => <div key={d} className="border rounded-md p-3 space-y-2"><div className="flex items-center justify-between"><p className="font-medium text-sm">{DAY_LABEL[d]}</p><Button type="button" variant="outline" size="sm" onClick={()=>addSession(d)}><Plus className="h-3 w-3 mr-1" />Add Session</Button></div>{sessions[d].length===0?<p className="text-xs text-muted-foreground">Closed</p>:sessions[d].map((s,i)=><div key={`${d}-${i}`} className="grid grid-cols-1 sm:grid-cols-[1fr_1fr_auto] gap-2 items-end"><div><Label className="text-xs">Start</Label><Input type="time" value={s.start} onChange={e=>updSession(d,i,"start",e.target.value)} /></div><div><Label className="text-xs">End</Label><Input type="time" value={s.end} onChange={e=>updSession(d,i,"end",e.target.value)} /></div><Button type="button" variant="outline" size="icon" onClick={()=>delSession(d,i)}><Trash2 className="h-4 w-4" /></Button></div>)}</div>)}
      </CardContent></Card>

      <Card><CardHeader><CardTitle>Emergency / OPD Controls</CardTitle></CardHeader><CardContent className="space-y-3">
        <div className="flex items-center justify-between border rounded-md p-3"><Label>Pause Clinic OPD</Label><Switch checked={settings.clinicPaused} onCheckedChange={v=>setSF("clinicPaused",v)} /></div>
        <div><Label>Pause Reason</Label><Input value={settings.pauseReason} onChange={e=>setSF("pauseReason",e.target.value)} /></div>
        <div className="flex items-center justify-between border rounded-md p-3"><Label>General Consultation Enabled</Label><Switch checked={settings.generalConsultationEnabled} onCheckedChange={v=>setSF("generalConsultationEnabled",v)} /></div>
        <div className="flex items-center justify-between border rounded-md p-3"><Label>Video Consultation Enabled</Label><Switch checked={settings.videoConsultationEnabled} onCheckedChange={v=>setSF("videoConsultationEnabled",v)} /></div>
        <div className="flex items-center justify-between border rounded-md p-3"><Label>Emergency Only Mode</Label><Switch checked={settings.emergencyOnly} onCheckedChange={v=>setSF("emergencyOnly",v)} /></div>
      </CardContent></Card>

      <Card><CardHeader><CardTitle>Doctor-Wise Controls</CardTitle></CardHeader><CardContent className="space-y-3">
        {doctors.length===0 ? <p className="text-sm text-muted-foreground">No doctors found.</p> : doctors.map((d:any)=>{ const c=doctorCtrl[d.id]; if(!c) return null; return <div key={d.id} className="border rounded-md p-3 space-y-2"><p className="font-medium">{d.name}</p><div className="grid grid-cols-1 sm:grid-cols-2 gap-2"><div className="flex items-center justify-between border rounded-md p-2"><Label className="text-sm">Pause Doctor</Label><Switch checked={c.isPaused} onCheckedChange={v=>updDoc(d.id,"isPaused",v)} /></div><div className="flex items-center justify-between border rounded-md p-2"><Label className="text-sm">General Enabled</Label><Switch checked={c.generalConsultationEnabled} onCheckedChange={v=>updDoc(d.id,"generalConsultationEnabled",v)} /></div><div className="flex items-center justify-between border rounded-md p-2"><Label className="text-sm">Video Enabled</Label><Switch checked={c.videoConsultationEnabled} onCheckedChange={v=>updDoc(d.id,"videoConsultationEnabled",v)} /></div><div className="flex items-center justify-between border rounded-md p-2"><Label className="text-sm">Emergency Only</Label><Switch checked={c.emergencyOnly} onCheckedChange={v=>updDoc(d.id,"emergencyOnly",v)} /></div></div><div><Label className="text-xs">Reason</Label><Input value={c.pauseReason} onChange={e=>updDoc(d.id,"pauseReason",e.target.value)} /></div></div>; })}
      </CardContent></Card>

      <Card><CardHeader><CardTitle>Assistant Doctor Coverage</CardTitle><CardDescription>Choose which primary doctors each assistant doctor can cover at this clinic. Reassignment will use this configuration.</CardDescription></CardHeader><CardContent className="space-y-3">
        {assistantDoctors.length===0 ? <p className="text-sm text-muted-foreground">No assistant doctors found.</p> : assistantDoctors.map((assistant: any) => { const coverage = assistantCoverage[assistant.id] || { primaryDoctorIds: [], isActive: false }; return <div key={assistant.id} className="border rounded-md p-3 space-y-3"><div className="flex items-center justify-between gap-3"><div><p className="font-medium">{assistant.name}</p><p className="text-xs text-muted-foreground">Assistant coverage for main doctor bookings</p></div><div className="flex items-center gap-2"><Label className="text-sm">Active</Label><Switch checked={coverage.isActive} onCheckedChange={(value)=>setAssistantCoverageActive(assistant.id, value)} /></div></div><div className="flex flex-wrap gap-2">{primaryDoctors.length===0 ? <p className="text-sm text-muted-foreground">No primary doctors found.</p> : primaryDoctors.map((doctor: any) => { const selected = coverage.primaryDoctorIds.includes(doctor.id); return <Button key={doctor.id} type="button" variant={selected ? "default" : "outline"} size="sm" onClick={()=>toggleAssistantPrimaryDoctor(assistant.id, doctor.id)}>{doctor.name}</Button>; })}</div></div>; })}
      </CardContent></Card>
    </div>
  );
}

"use client";

import { useState, useMemo, useEffect } from "react";
import { Role } from "@/types/auth.types";
import { useLayoutStore } from "@/stores/layout.store";
import { AssignRoleModal } from "@/components/clinic/AssignRoleModal";
import { AddStaffModal } from "@/components/clinic/AddStaffModal";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

import { useAuth } from "@/hooks/auth/useAuth";
import { useCurrentClinic } from "@/hooks/query/useClinics";
import { useUsersByClinic } from "@/hooks/query/useUsers";
import { ConnectionStatusIndicator as WebSocketStatusIndicator } from "@/components/common/StatusIndicator";
import { useWebSocketQuerySync } from "@/hooks/realtime/useRealTimeQueries";
import { cn } from "@/lib/utils";
import {
  Users,
  Plus,
  Search,
  UserCheck,
  Mail,
  Phone,
  Stethoscope,
  UserCog,
  Loader2,
  Filter,
  ShieldCheck,
} from "lucide-react";

export default function ClinicAdminStaff() {
  useAuth();
  const { data: currentClinic } = useCurrentClinic();
  const clinicId = currentClinic?.id;
  const clinicName = currentClinic?.name;

  const setPageTitle = useLayoutStore((s) => s.setPageTitle);
  useEffect(() => {
    setPageTitle("Staff Directory");
  }, [setPageTitle]);

  const [searchTerm, setSearchTerm] = useState("");
  const [roleFilter, setRoleFilter] = useState("all");
  const [statusFilter, setStatusFilter] = useState("all");

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 8;

  const [assignModalStaff, setAssignModalStaff] = useState<{
    id: string;
    name: string;
    email: string;
    role: string;
    status?: string;
    permissions?: string[];
  } | null>(null);

  const [isAddStaffModalOpen, setIsAddStaffModalOpen] = useState(false);

  // Fetch real staff data
  const { data: staffData, isPending: isLoadingStaff, refetch } = useUsersByClinic(
    clinicId || ""
  );

  // Sync with WebSocket
  useWebSocketQuerySync();

  // Transform staff data
  const staff = useMemo(() => {
    if (!staffData) return [];
    const data = staffData as any;
    const users = Array.isArray(data) ? data : data?.users || data?.data || [];

    return users.map((user: any) => ({
      id: user.id,
      name: user.name || `${user.firstName || ""} ${user.lastName || ""}`.trim() || "Unnamed",
      email: user.email,
      phone: user.phone || "No contact",
      role: user.role || user.roles?.[0]?.name || "STAFF",
      status: user.isActive !== false ? "Active" : "Inactive",
      specialization: user.specialization || "General",
      department: user.department || "Medical",
      joinDate: user.createdAt || user.joinedAt,
      experience: user.experience || "N/A",
      location: user.location?.name || "Main Clinic",
      permissions: user.permissions || user.roles?.[0]?.permissions || null,
    }));
  }, [staffData]);

  const filteredStaff = useMemo(() => {
    return staff.filter((member: any) => {
      const matchesSearch =
        !searchTerm ||
        member.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        member.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
        member.specialization.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesRole = roleFilter === "all" || member.role === roleFilter;
      const matchesStatus =
        statusFilter === "all" || member.status.toLowerCase() === statusFilter;

      return matchesSearch && matchesRole && matchesStatus;
    });
  }, [staff, searchTerm, roleFilter, statusFilter]);

  // Reset to page 1 if filters change
  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm, roleFilter, statusFilter]);

  // Pagination Logic
  const totalPages = Math.ceil(filteredStaff.length / itemsPerPage);
  const paginatedStaff = useMemo(() => {
    const startIndex = (currentPage - 1) * itemsPerPage;
    return filteredStaff.slice(startIndex, startIndex + itemsPerPage);
  }, [filteredStaff, currentPage, itemsPerPage]);

  const getRoleBadge = (role: Role | string) => {
    const r = role as Role;
    switch (r) {
      case Role.DOCTOR:
        return <Badge className="bg-blue-500/10 text-blue-700 dark:text-blue-400 border-blue-200/50 hover:bg-blue-500/20">Doctor</Badge>;
      case Role.CLINIC_ADMIN:
        return <Badge className="bg-purple-500/10 text-purple-700 dark:text-purple-400 border-purple-200/50 hover:bg-purple-500/20">Admin</Badge>;
      case Role.RECEPTIONIST:
        return <Badge className="bg-emerald-500/10 text-emerald-700 dark:text-emerald-400 border-emerald-200/50 hover:bg-emerald-500/20">Reception</Badge>;
      case Role.PHARMACIST:
        return <Badge className="bg-orange-500/10 text-orange-700 dark:text-orange-400 border-orange-200/50 hover:bg-orange-500/20">Pharmacy</Badge>;
      case Role.NURSE:
        return <Badge className="bg-teal-500/10 text-teal-700 dark:text-teal-400 border-teal-200/50 hover:bg-teal-500/20">Nurse</Badge>;
      case Role.THERAPIST:
        return <Badge className="bg-indigo-500/10 text-indigo-700 dark:text-indigo-400 border-indigo-200/50 hover:bg-indigo-500/20">Therapist</Badge>;
      case Role.LAB_TECHNICIAN:
        return <Badge className="bg-rose-500/10 text-rose-700 dark:text-rose-400 border-rose-200/50 hover:bg-rose-500/20">Lab Tech</Badge>;
      case Role.COUNSELOR:
        return <Badge className="bg-pink-500/10 text-pink-700 dark:text-pink-400 border-pink-200/50 hover:bg-pink-500/20">Counselor</Badge>;
      case Role.FINANCE_BILLING:
        return <Badge className="bg-amber-500/10 text-amber-700 dark:text-amber-400 border-amber-200/50 hover:bg-amber-500/20">Finance</Badge>;
      case Role.HR_MANAGER:
        return <Badge className="bg-slate-500/10 text-slate-700 dark:text-slate-400 border-slate-200/50 hover:bg-slate-500/20">HR</Badge>;
      default:
        return <Badge variant="secondary" className="capitalize">{role.toLowerCase().replace('_', ' ')}</Badge>;
    }
  };

  if (isLoadingStaff) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] gap-4">
        <Loader2 className="w-10 h-10 animate-spin text-primary" />
        <p className="text-muted-foreground animate-pulse">Loading staff database...</p>
      </div>
    );
  }

  return (
    <div className="p-4 sm:p-8 space-y-8 bg-transparent min-h-screen text-foreground">
      {/* Header Section */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div className="space-y-1">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-primary/10 rounded-lg">
              <Users className="w-6 h-6 text-primary" />
            </div>
            <h1 className="text-2xl font-bold tracking-tight text-neutral-900 dark:text-neutral-50">Clinic Staff Roster</h1>
          </div>
          <p className="text-muted-foreground font-medium">Manage healthcare professionals and administrative staff for <span className="text-primary font-bold">{clinicName || "your clinic"}</span></p>
        </div>

        <div className="flex flex-col sm:flex-row flex-wrap items-start sm:items-center gap-3 w-full md:w-auto">
          <div className="hidden sm:block">
            <WebSocketStatusIndicator />
          </div>
          <Button 
            onClick={() => setIsAddStaffModalOpen(true)}
            className="bg-primary w-full sm:w-auto hover:bg-primary/90 shadow-lg shadow-primary/20 transition-all active:scale-95 flex items-center justify-center gap-2 px-6"
          >
            <Plus className="w-4 h-4" />
            Add New Staff
          </Button>
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        {[
          { label: "Total Staff", value: staff.length, icon: Users, color: "text-blue-600 dark:text-blue-400", bg: "bg-blue-50 dark:bg-blue-500/10" },
          { label: "Doctors", value: staff.filter((s: any) => s.role === Role.DOCTOR).length, icon: Stethoscope, color: "text-purple-600 dark:text-purple-400", bg: "bg-purple-50 dark:bg-purple-500/10" },
          { label: "Active Now", value: staff.filter((s: any) => s.status === "Active").length, icon: UserCheck, color: "text-emerald-600 dark:text-emerald-400", bg: "bg-emerald-50 dark:bg-emerald-500/10" },
          { label: "Support Staff", value: staff.filter((s: any) => [Role.RECEPTIONIST, Role.PHARMACIST, Role.NURSE].includes(s.role as Role)).length, icon: UserCog, color: "text-orange-600 dark:text-orange-400", bg: "bg-orange-50 dark:bg-orange-500/10" },
        ].map((stat, i) => (
          <Card key={i} className="border-none shadow-sm bg-white dark:bg-neutral-900 hover:shadow-md transition-shadow ring-1 ring-neutral-200 dark:ring-neutral-800">
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-xs font-bold text-muted-foreground uppercase tracking-widest">{stat.label}</p>
                  <p className="text-3xl font-black mt-1">{stat.value}</p>
                </div>
                <div className={cn("p-3 rounded-2xl", stat.bg)}>
                  <stat.icon className={cn("w-6 h-6", stat.color)} />
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Filters & Search */}
      <div className="rounded-xl border-none shadow-sm bg-white dark:bg-neutral-900 ring-1 ring-neutral-200 dark:ring-neutral-800">
        <div className="p-4 flex flex-col lg:flex-row lg:items-center justify-between gap-4">
          <div className="flex items-center gap-4 flex-1">
            <div className="relative flex-1 max-w-md">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
              <Input
                placeholder="Search staff name or specialization..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10 bg-white dark:bg-neutral-900 ring-1 ring-neutral-200 dark:ring-neutral-800 focus-visible:ring-primary/30 transition-all border-none"
              />
            </div>
          </div>

          <div className="flex flex-wrap items-center gap-3 w-full lg:w-auto">
            <div className="flex flex-wrap sm:flex-nowrap items-center w-full sm:w-auto gap-2 bg-neutral-100 dark:bg-neutral-900 border border-neutral-200 dark:border-neutral-800 p-1 rounded-lg">
              <Select value={roleFilter} onValueChange={setRoleFilter}>
                <SelectTrigger className="w-full sm:w-[140px] border-none bg-transparent h-8 shadow-none focus:ring-0">
                  <Filter className="w-3.5 h-3.5 mr-2 text-muted-foreground" />
                  <SelectValue placeholder="All Roles" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Roles</SelectItem>
                  <SelectItem value={Role.DOCTOR}>Doctors</SelectItem>
                  <SelectItem value={Role.CLINIC_ADMIN}>Admins</SelectItem>
                  <SelectItem value={Role.RECEPTIONIST}>Reception</SelectItem>
                  <SelectItem value={Role.PHARMACIST}>Pharmacy</SelectItem>
                  <SelectItem value={Role.NURSE}>Nurse</SelectItem>
                  <SelectItem value={Role.THERAPIST}>Therapist</SelectItem>
                  <SelectItem value={Role.LAB_TECHNICIAN}>Lab Tech</SelectItem>
                  <SelectItem value={Role.COUNSELOR}>Counselor</SelectItem>
                  <SelectItem value={Role.FINANCE_BILLING}>Finance</SelectItem>
                  <SelectItem value={Role.HR_MANAGER}>HR Manager</SelectItem>
                </SelectContent>
              </Select>
              <div className="hidden sm:block w-px h-4 bg-neutral-300 dark:bg-neutral-700" />
              <Select value={statusFilter} onValueChange={setStatusFilter}>
                <SelectTrigger className="w-full sm:w-[120px] border-none bg-transparent h-8 shadow-none focus:ring-0">
                  <SelectValue placeholder="Status" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">Any Status</SelectItem>
                  <SelectItem value="active">Active</SelectItem>
                  <SelectItem value="inactive">Inactive</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>
        </div>
      </div>

      <div className="mt-8 space-y-4">
            <div className="overflow-x-auto bg-white dark:bg-neutral-900 rounded-xl ring-1 ring-neutral-200 dark:ring-neutral-800 shadow-sm">
              <table className="w-full text-left">
                <thead className="bg-neutral-50 dark:bg-neutral-900/50 text-[10px] font-bold text-muted-foreground uppercase tracking-widest border-b dark:border-neutral-800">
                  <tr>
                    <th className="px-6 py-4">Staff Member</th>
                    <th className="px-6 py-4">Role & Dept</th>
                    <th className="px-6 py-4">Specialization</th>
                    <th className="px-6 py-4">Status</th>
                    <th className="px-6 py-4">Contact</th>
                    <th className="px-6 py-4 text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-neutral-100 dark:divide-neutral-800">
                  {paginatedStaff.map((member: any) => (
                    <tr key={member.id} className="hover:bg-neutral-50/50 dark:hover:bg-neutral-900/30 transition-colors group">
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-3">
                          <div className="w-10 h-10 rounded-xl bg-primary/5 flex items-center justify-center text-primary font-bold">
                            {member.name.charAt(0)}
                          </div>
                          <div>
                            <p className="font-bold text-sm text-neutral-900 dark:text-neutral-100">{member.name}</p>
                            <p className="text-xs text-muted-foreground">ID: #{member.id.substring(0, 8)}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="space-y-1">
                          {getRoleBadge(member.role)}
                          <p className="text-[10px] font-medium text-muted-foreground">{member.department}</p>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span className="text-sm font-medium">{member.specialization}</span>
                      </td>
                      <td className="px-6 py-4">
                        <Badge variant={member.status === "Active" ? "outline" : "secondary"} className={cn(
                          "rounded-full border-none",
                          member.status === "Active" ? "bg-emerald-500/10 text-emerald-700 dark:text-emerald-400" : "bg-neutral-500/10 text-neutral-600 dark:text-neutral-400"
                        )}>
                          {member.status}
                        </Badge>
                      </td>
                      <td className="px-6 py-4 text-sm text-muted-foreground">
                        <div className="space-y-1">
                          <div className="flex items-center gap-1.5">
                            <Mail className="w-3.5 h-3.5" />
                            <span>{member.email}</span>
                          </div>
                          <div className="flex items-center gap-1.5">
                            <Phone className="w-3.5 h-3.5" />
                            <span>{member.phone}</span>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <Button 
                          variant="outline" 
                          size="sm"
                          onClick={() => setAssignModalStaff(member)}
                          className="font-medium bg-neutral-50 dark:bg-neutral-800 dark:hover:bg-neutral-700"
                        >
                          <ShieldCheck className="w-4 h-4 mr-2 text-primary" />
                          Manage Access
                        </Button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

          {filteredStaff.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-24 text-center">
              <div className="w-20 h-20 bg-neutral-100 dark:bg-neutral-800 rounded-full flex items-center justify-center mb-4">
                <Users className="w-10 h-10 text-neutral-400" />
              </div>
              <h3 className="text-xl font-bold">No staff matching your search</h3>
              <p className="text-muted-foreground max-w-xs mt-2">Adjust your filters or search terms to find the staff member you are looking for.</p>
              <Button variant="link" onClick={() => { setSearchTerm(""); setRoleFilter("all"); setStatusFilter("all"); }} className="mt-4">
                Clear all filters
              </Button>
            </div>
          ) : totalPages > 1 && (
            <div className="flex items-center justify-between px-6 py-4 border-t border-neutral-100 dark:border-neutral-800">
              <div className="text-sm text-muted-foreground flex-1">
                Showing <span className="font-medium text-foreground">{(currentPage - 1) * itemsPerPage + 1}</span> to <span className="font-medium text-foreground">{Math.min(currentPage * itemsPerPage, filteredStaff.length)}</span> of <span className="font-medium text-foreground">{filteredStaff.length}</span> results
              </div>
              <div className="flex items-center gap-2">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                  disabled={currentPage === 1}
                  className="h-8"
                >
                  Previous
                </Button>
                <div className="flex items-center gap-1 mx-2 text-sm font-medium">
                  Page {currentPage} of {totalPages}
                </div>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
                  disabled={currentPage === totalPages}
                  className="h-8"
                >
                  Next
                </Button>
              </div>
            </div>
          )}
      </div>

      {assignModalStaff && (
        <AssignRoleModal
          open={!!assignModalStaff}
          onOpenChange={(open) => !open && setAssignModalStaff(null)}
          staffMember={assignModalStaff}
          currentUserRole={Role.CLINIC_ADMIN}
          clinicId={clinicId || undefined}
          onSuccess={() => refetch?.()}
        />
      )}

      <AddStaffModal
        open={isAddStaffModalOpen}
        onOpenChange={setIsAddStaffModalOpen}
        onSuccess={() => refetch?.()}
      />
    </div>
  );
}

"use client";

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Loader2 } from "@/components/ui/loader";
import {
  Search,
  Calendar,
  Filter,
  Clock,
  CheckCircle,
  MessageCircle,
} from "lucide-react";
import { useAuth } from "@/hooks/use-auth";
import { useClinicContext } from "@/contexts/clinic-context";
import {
  useCounselorAppointments,
  useUpdateCounselorAppointment,
  useDeleteCounselorAppointment,
  useCreateCounselorAppointment,
} from "@/hooks/query/useCounselor";
import { useWebSocketQuerySync } from "@/hooks/query/utils/use-websocket-query-sync";

export default function CounselorAppointments() {
  const { user } = useAuth();
  const { clinicId } = useClinicContext();

  const [searchQuery, setSearchQuery] = useState("");
  const [filterStatus, setFilterStatus] = useState("all");

  const counselorId = user?.id;

  const { data: appointmentsData, isPending } = useCounselorAppointments(counselorId);
  const updateMutation = useUpdateCounselorAppointment();
  const deleteMutation = useDeleteCounselorAppointment();
  const createMutation = useCreateCounselorAppointment();

  // Sync with WebSocket for real-time updates
  useWebSocketQuerySync([['counselorAppointments', counselorId]]);

  const appointments = appointmentsData?.appointments || [];

  const filteredAppointments = appointments.filter((appointment: any) => {
    const matchesSearch =
      appointment.clientName?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      appointment.notes?.toLowerCase().includes(searchQuery.toLowerCase());

    const matchesStatus =
      filterStatus === "all" || appointment.status === filterStatus;

    return matchesSearch && matchesStatus;
  });

  const handleStatusChange = (appointmentId: string, newStatus: string) => {
    updateMutation.mutate({
      appointmentId,
      updates: { status: newStatus },
    });
  };

  const handleDelete = (appointmentId: string) => {
    if (confirm("Are you sure you want to delete this appointment?")) {
      deleteMutation.mutate(appointmentId);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case "COMPLETED":
        return "bg-green-100 text-green-800";
      case "SCHEDULED":
        return "bg-gray-100 text-gray-800";
      case "IN_PROGRESS":
        return "bg-blue-100 text-blue-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  if (isPending) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="h-8 w-8 animate-spin" />
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      <div>
        <h1 className="text-3xl font-bold">Appointments</h1>
        <p className="text-gray-600">Manage counseling sessions and appointments</p>
      </div>

      <Card>
        <CardContent className="pt-6">
          <div className="flex flex-col sm:flex-row gap-4">
            <div className="flex-1 relative">
              <Search className="absolute left-3 top-3 w-4 h-4 text-gray-400" />
              <Input
                placeholder="Search by client name or notes..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-10"
              />
            </div>
            <div className="flex gap-2">
              <Button
                variant={filterStatus === "all" ? "default" : "outline"}
                onClick={() => setFilterStatus("all")}
              >
                All
              </Button>
              <Button
                variant={filterStatus === "SCHEDULED" ? "default" : "outline"}
                onClick={() => setFilterStatus("SCHEDULED")}
              >
                Scheduled
              </Button>
              <Button
                variant={filterStatus === "COMPLETED" ? "default" : "outline"}
                onClick={() => setFilterStatus("COMPLETED")}
              >
                Completed
              </Button>
            </div>
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Calendar className="w-5 h-5" />
            Appointments List
          </CardTitle>
        </CardHeader>
        <CardContent>
          {filteredAppointments.length === 0 ? (
            <div className="text-center py-12">
              <Calendar className="w-16 h-16 mx-auto text-gray-300 mb-4" />
              <p className="text-gray-500">No appointments found</p>
              <p className="text-sm text-gray-400 mt-1">
                Try adjusting your search or filters
              </p>
            </div>
          ) : (
            <div className="space-y-4">
              {filteredAppointments.map((appointment: any) => (
                <div
                  key={appointment.id}
                  className="p-4 border rounded-lg hover:bg-gray-50"
                >
                  <div className="flex items-start justify-between gap-4">
                    <div className="flex items-center gap-4 flex-1">
                      <div className="w-10 h-10 bg-purple-100 rounded-full flex items-center justify-center">
                        <MessageCircle className="w-5 h-5 text-purple-600" />
                      </div>
                      <div>
                        <div className="flex items-center gap-2 mb-1">
                          <h4 className="font-semibold">{appointment.clientName}</h4>
                          <Badge variant="outline" className="text-xs">
                            {appointment.clientId}
                          </Badge>
                        </div>
                        <p className="text-sm text-gray-600">
                          {appointment.type} - {appointment.duration}
                        </p>
                        <div className="flex items-center gap-3 mt-1 text-xs text-gray-500">
                          <span className="flex items-center gap-1">
                            <Calendar className="w-3 h-3" />
                            {new Date(appointment.date).toLocaleDateString("en-IN")}
                          </span>
                          <span className="flex items-center gap-1">
                            <Clock className="w-3 h-3" />
                            {appointment.time}
                          </span>
                        </div>
                        {appointment.notes && (
                          <p className="text-xs text-gray-500 mt-1 italic">
                            {appointment.notes}
                          </p>
                        )}
                      </div>
                    </div>
                    <div className="text-right">
                      <Badge className={getStatusColor(appointment.status)}>
                        {appointment.status.toLowerCase()}
                      </Badge>
                      <div className="mt-2 flex gap-2">
                        {appointment.status === "SCHEDULED" && (
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => handleStatusChange(appointment.id, "IN_PROGRESS")}
                            disabled={updateMutation.isPending}
                          >
                            Start
                          </Button>
                        )}
                        {appointment.status === "IN_PROGRESS" && (
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => handleStatusChange(appointment.id, "COMPLETED")}
                            disabled={updateMutation.isPending}
                          >
                            Complete
                          </Button>
                        )}
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() => handleDelete(appointment.id)}
                          disabled={deleteMutation.isPending}
                        >
                          Delete
                        </Button>
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useMemo } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Loader2 } from "@/components/ui/loader";
import {
  Users,
  Calendar,
  CheckCircle,
  MessageCircle,
  Clock,
  Brain,
} from "lucide-react";
import { useAuth } from "@/hooks/use-auth";
import { useClinicContext } from "@/contexts/clinic-context";
import { useCounselorAppointments } from "@/hooks/query/useCounselor";
import { useWebSocketQuerySync } from "@/hooks/query/utils/use-websocket-query-sync";

export default function CounselorDashboard() {
  const { user } = useAuth();
  const { clinicId } = useClinicContext();

  const counselorId = user?.id;
  const today = new Date().toISOString().split('T')[0];

  const { data: todayAppointmentsData, isPending: isAppointmentsPending } = useCounselorAppointments(
    counselorId,
    { startDate: today, endDate: today }
  );

  const { data: allAppointmentsData, isPending: isAllAppointmentsPending } = useCounselorAppointments(
    counselorId,
    { startDate: today }
  );

  // Sync with WebSocket for real-time updates
  useWebSocketQuerySync([['counselorAppointments', counselorId]]);

  const todayAppointments = todayAppointmentsData?.appointments || [];
  const allAppointments = allAppointmentsData?.appointments || [];

  const stats = useMemo(() => {
    const completedToday = todayAppointments.filter((a: any) => a.status === "COMPLETED").length;
    return {
      todaySessions: todayAppointments.length,
      completedToday,
      totalClients: new Set(allAppointments.map((a: any) => a.clientId)).size,
      avgSessionDuration: allAppointments.length > 0
        ? Math.round(allAppointments.reduce((sum: number, a: any) => {
            const duration = parseInt(a.duration) || 60;
            return sum + duration;
          }, 0) / allAppointments.length)
        : 55,
    };
  }, [todayAppointments, allAppointments]);

  const getStatusColor = (status: string) => {
    switch (status) {
      case "COMPLETED":
        return "bg-green-100 text-green-800";
      case "SCHEDULED":
        return "bg-gray-100 text-gray-800";
      case "IN_PROGRESS":
        return "bg-blue-100 text-blue-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  if (isAppointmentsPending || isAllAppointmentsPending) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="h-8 w-8 animate-spin" />
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      <div>
        <h1 className="text-3xl font-bold">Counselor Dashboard</h1>
        <p className="text-gray-600">
          Welcome back! Here's your counseling overview.
        </p>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              Today&apos;s Sessions
            </CardTitle>
            <Calendar className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {stats.todaySessions}
            </div>
            <p className="text-xs text-muted-foreground">Scheduled</p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              Completed Today
            </CardTitle>
            <CheckCircle className="h-4 w-4 text-green-600" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-green-600">
              {stats.completedToday}
            </div>
            <p className="text-xs text-muted-foreground">
              Sessions finished
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              Total Clients
            </CardTitle>
            <Users className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.totalClients}</div>
            <p className="text-xs text-muted-foreground">Under care</p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              Avg. Duration
            </CardTitle>
            <Clock className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {stats.avgSessionDuration} min
            </div>
            <p className="text-xs text-muted-foreground">Per session</p>
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <MessageCircle className="w-5 h-5" />
            Today&apos;s Sessions
          </CardTitle>
        </CardHeader>
        <CardContent>
          {todayAppointments.length === 0 ? (
            <div className="text-center py-12">
              <Calendar className="w-16 h-16 mx-auto text-gray-300 mb-4" />
              <p className="text-gray-500">No sessions scheduled today</p>
            </div>
          ) : (
            <div className="space-y-4">
              {todayAppointments.map((session: any) => (
                <div
                  key={session.id}
                  className="flex items-center justify-between p-4 border rounded-lg hover:bg-gray-50"
                >
                  <div className="flex items-center gap-4">
                    <div className="w-10 h-10 bg-purple-100 rounded-full flex items-center justify-center">
                      <Brain className="w-5 h-5 text-purple-600" />
                    </div>
                    <div>
                      <h4 className="font-semibold">{session.clientName}</h4>
                      <p className="text-sm text-gray-600">
                        {session.type} - {session.duration}
                      </p>
                    </div>
                  </div>
                  <div className="text-right">
                    <div className="font-medium">{session.time}</div>
                    <Badge className={getStatusColor(session.status)}>
                      {session.status.toLowerCase()}
                    </Badge>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle>Counseling Specialties</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            <div className="flex items-center gap-3 p-4 bg-blue-50 rounded-lg">
              <MessageCircle className="w-6 h-6 text-blue-600" />
              <div>
                <div className="font-medium">Individual Counseling</div>
                <div className="text-sm text-gray-600">One-on-one</div>
              </div>
            </div>
            <div className="flex items-center gap-3 p-4 bg-green-50 rounded-lg">
              <Users className="w-6 h-6 text-green-600" />
              <div>
                <div className="font-medium">Family Therapy</div>
                <div className="text-sm text-gray-600">Group sessions</div>
              </div>
            </div>
            <div className="flex items-center gap-3 p-4 bg-purple-50 rounded-lg">
              <Brain className="w-6 h-6 text-purple-600" />
              <div>
                <div className="font-medium">Cognitive Behavioral</div>
                <div className="text-sm text-gray-600">CBT approach</div>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Loader2 } from "@/components/ui/loader";
import {
  Search,
  Users,
  Filter,
  Calendar,
  MessageCircle,
} from "lucide-react";
import { useAuth } from "@/hooks/use-auth";
import { useClinicContext } from "@/contexts/clinic-context";
import {
  useCounselorClients,
  useUpdateCounselorClientSession,
} from "@/hooks/query/useCounselor";
import { useWebSocketQuerySync } from "@/hooks/query/utils/use-websocket-query-sync";

export default function CounselorPatients() {
  const { user } = useAuth();
  const { clinicId } = useClinicContext();

  const [searchQuery, setSearchQuery] = useState("");

  const counselorId = user?.id;

  const { data: clientsData, isPending } = useCounselorClients(counselorId);
  const updateSessionMutation = useUpdateCounselorClientSession();

  // Sync with WebSocket for real-time updates
  useWebSocketQuerySync([['counselorClients', counselorId]]);

  const clients = clientsData?.clients || [];

  const filteredClients = clients.filter((client: any) => {
    return (
      client.name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      client.condition?.toLowerCase().includes(searchQuery.toLowerCase())
    );
  });

  const getStatusColor = (status: string) => {
    switch (status) {
      case "active":
        return "bg-green-100 text-green-800";
      case "inactive":
        return "bg-gray-100 text-gray-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  if (isPending) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="h-8 w-8 animate-spin" />
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      <div>
        <h1 className="text-3xl font-bold">Clients</h1>
        <p className="text-gray-600">Manage client records and counseling progress</p>
      </div>

      <Card>
        <CardContent className="pt-6">
          <div className="flex flex-col sm:flex-row gap-4">
            <div className="flex-1 relative">
              <Search className="absolute left-3 top-3 w-4 h-4 text-gray-400" />
              <Input
                placeholder="Search by client name or condition..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-10"
              />
            </div>
            <Button variant="outline" className="flex items-center gap-2">
              <Filter className="w-4 h-4" />
              Filter
            </Button>
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Users className="w-5 h-5" />
            Clients List
          </CardTitle>
        </CardHeader>
        <CardContent>
          {filteredClients.length === 0 ? (
            <div className="text-center py-12">
              <Users className="w-16 h-16 mx-auto text-gray-300 mb-4" />
              <p className="text-gray-500">No clients found</p>
              <p className="text-sm text-gray-400 mt-1">
                Try adjusting your search or filters
              </p>
            </div>
          ) : (
            <div className="space-y-4">
              {filteredClients.map((client: any) => (
                <div
                  key={client.id}
                  className="p-4 border rounded-lg hover:bg-gray-50"
                >
                  <div className="flex items-start justify-between gap-4">
                    <div className="flex items-center gap-4 flex-1">
                      <div className="w-10 h-10 bg-purple-100 rounded-full flex items-center justify-center">
                        <Users className="w-5 h-5 text-purple-600" />
                      </div>
                      <div>
                        <div className="flex items-center gap-2 mb-1">
                          <h4 className="font-semibold">{client.name}</h4>
                          <Badge className={getStatusColor(client.status)}>
                            {client.status}
                          </Badge>
                        </div>
                        <p className="text-sm text-gray-600">{client.condition}</p>
                        <div className="flex items-center gap-3 mt-1 text-xs text-gray-500">
                          <span>Sessions: {client.sessionsCompleted}</span>
                          <span className="flex items-center gap-1">
                            <Calendar className="w-3 h-3" />
                            Last:{" "}
                            {new Date(client.lastSession).toLocaleDateString("en-IN")}
                          </span>
                        </div>
                      </div>
                    </div>
                    <div className="flex gap-2">
                      <Button variant="outline" size="sm">
                        <MessageCircle className="w-3 h-3 mr-1" />
                        Notes
                      </Button>
                      <Button variant="outline" size="sm">
                        View Profile
                      </Button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useState, useMemo } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { VideoAppointmentRoom } from "@/components/video/VideoAppointmentRoom";
import type { VideoAppointment } from "@/hooks/query/useVideoAppointments";
import { useAuth } from "@/hooks/auth/useAuth";
import { useClinicContext } from "@/hooks/query/useClinics";
import { useAppointments, useStartAppointment, useCompleteAppointment } from "@/hooks/query/useAppointments";
import { ConnectionStatusIndicator as WebSocketStatusIndicator } from "@/components/common/StatusIndicator";
import { useWebSocketQuerySync } from "@/hooks/realtime/useRealTimeQueries";
import { showSuccessToast, showErrorToast, showInfoToast, TOAST_IDS } from "@/hooks/utils/use-toast";
import {
  Calendar,
  Play,
  CheckCircle,
  Clock,
  FileText,
  Video,
  Phone,
  MessageSquare,
  Search,
  Eye,
  Loader2
} from "lucide-react";
import type { AppointmentStatus } from "@/types/appointment.types";

// Appointment status constants - must match backend enum values
const APPOINTMENT_STATUS = {
  ALL: 'ALL',
  IN_PROGRESS: 'IN_PROGRESS',
  SCHEDULED: 'SCHEDULED',
  CONFIRMED: 'CONFIRMED',
  COMPLETED: 'COMPLETED',
  CANCELLED: 'CANCELLED',
  NO_SHOW: 'NO_SHOW',
} as const;

// Interface for the transformed appointment object
interface TransformedAppointment {
  id: string;
  appointmentId: string;
  patientId: string;
  doctorId: string;
  patientName: string;
  patientAge: number | null;
  patientGender: string;
  time: string;
  status: AppointmentStatus;
  type: string;
  duration: string;
  appointmentDate: string;
  patientPhone: string;
  patientEmail: string;
  chiefComplaint: string;
  medicalHistory: string[] | string;
  allergies: string[] | string;
  currentMedications: string[] | string;
  vitalSigns: {
    bp?: string;
    pulse?: string;
    temperature?: string;
    weight?: string;
  } | null;
  checkedInAt: string | null;
  queuePosition: number | null;
}

export default function DoctorAppointments() {
  const { session } = useAuth();
  const user = session?.user;
  const { clinicId } = useClinicContext();
  const [searchTerm, setSearchTerm] = useState("");
  const [statusFilter, setStatusFilter] = useState<AppointmentStatus | string>(APPOINTMENT_STATUS.ALL);
  const [selectedAppointment, setSelectedAppointment] = useState<TransformedAppointment | null>(null);
  const [consultationNotes, setConsultationNotes] = useState("");
  const [prescription, setPrescription] = useState("");
  const [diagnosis, setDiagnosis] = useState("");
  const [videoRoomAppointment, setVideoRoomAppointment] = useState<VideoAppointment | null>(null);
  const [isVideoRoomOpen, setIsVideoRoomOpen] = useState(false);

  // Fetch real appointment data
  const appointmentsQuery = useAppointments({
    clinicId: clinicId || "",
    doctorId: user?.id || "",
    ...(statusFilter !== APPOINTMENT_STATUS.ALL && { status: statusFilter as AppointmentStatus }),
    limit: 100,
  });

  const appointmentsData = appointmentsQuery.data;
  const isLoadingAppointments = appointmentsQuery.isPending;

  // Sync with WebSocket for real-time updates
  useWebSocketQuerySync();

  // Transform appointments data
  const appointments = useMemo(() => {
    if (!appointmentsData) return [];
    const apps = Array.isArray(appointmentsData) ? appointmentsData : appointmentsData.appointments || [];

    return apps.map((app: any): TransformedAppointment => ({
      id: app.id,
      appointmentId: app.id,
      patientId: app.patientId || app.patient?.id || app.patient?.userId || "",
      doctorId: app.doctorId || app.doctor?.id || app.doctor?.userId || "",
      patientName: app.patient?.name || `${app.patient?.firstName || ""} ${app.patient?.lastName || ""}`.trim() || "Unknown Patient",
      patientAge: app.patient?.age || (app.patient?.dateOfBirth ? Math.floor((new Date().getTime() - new Date(app.patient.dateOfBirth).getTime()) / (1000 * 60 * 60 * 24 * 365)) : null),
      patientGender: app.patient?.gender || "Unknown",
      time: app.startTime ? new Date(app.startTime).toLocaleTimeString("en-US", { hour: "2-digit", minute: "2-digit" }) : "TBD",
      status: (app.status || "SCHEDULED") as AppointmentStatus,
      type: app.type || app.appointmentType || "Consultation",
      duration: typeof app.duration === 'number' ? `${app.duration} min` : (app.duration as string || "30 min"),
      appointmentDate: app.startTime ? new Date(app.startTime).toISOString().split("T")[0] ?? "" : new Date().toISOString().split("T")[0] ?? "",
      patientPhone: app.patient?.phone || "",
      patientEmail: app.patient?.email || "",
      chiefComplaint: app.chiefComplaint || app.reason || "Not specified",
      medicalHistory: app.patient?.medicalHistory || [],
      allergies: app.patient?.allergies || [],
      currentMedications: app.patient?.currentMedications || [],
      vitalSigns: app.vitalSigns || null,
      checkedInAt: app.checkedInAt ? new Date(app.checkedInAt).toLocaleTimeString("en-US", { hour: "2-digit", minute: "2-digit" }) : null,
      queuePosition: app.queuePosition || null,
    }));
  }, [appointmentsData]);

  const filteredAppointments = useMemo(() => {
    return appointments.filter((app) => {
      const matchesSearch =
        !searchTerm ||
        app.patientName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        app.type?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        app.chiefComplaint?.toLowerCase().includes(searchTerm.toLowerCase());

      const matchesStatus = statusFilter === APPOINTMENT_STATUS.ALL || app.status === statusFilter;

      return matchesSearch && matchesStatus;
    });
  }, [appointments, searchTerm, statusFilter]);

  const getStatusColor = (status: string) => {
    switch (status) {
      case APPOINTMENT_STATUS.IN_PROGRESS: return 'bg-blue-100 text-blue-800';
      case APPOINTMENT_STATUS.CONFIRMED: return 'bg-green-100 text-green-800';
      case APPOINTMENT_STATUS.SCHEDULED: return 'bg-gray-100 text-gray-800';
      case APPOINTMENT_STATUS.COMPLETED: return 'bg-purple-100 text-purple-800';
      case APPOINTMENT_STATUS.CANCELLED: case APPOINTMENT_STATUS.NO_SHOW: return 'bg-red-100 text-red-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getStatusLabel = (status: string) => {
    const labels: Record<string, string> = {
      [APPOINTMENT_STATUS.IN_PROGRESS]: 'In Progress',
      [APPOINTMENT_STATUS.SCHEDULED]: 'Scheduled',
      [APPOINTMENT_STATUS.CONFIRMED]: 'Confirmed',
      [APPOINTMENT_STATUS.COMPLETED]: 'Completed',
      [APPOINTMENT_STATUS.CANCELLED]: 'Cancelled',
      [APPOINTMENT_STATUS.NO_SHOW]: 'No Show',
    };
    return labels[status] || status;
  };

  // Mutations for appointment actions
  const startAppointmentMutation = useStartAppointment();
  const completeAppointmentMutation = useCompleteAppointment();

  const startConsultation = async (appointmentId: string) => {
    try {
      await startAppointmentMutation.mutateAsync(appointmentId);
      showSuccessToast("Consultation started successfully", {
        id: TOAST_IDS.GLOBAL.SUCCESS,
      });
      appointmentsQuery.refetch();
    } catch (error: any) {
      showErrorToast(error?.message || "Failed to start consultation", {
        id: TOAST_IDS.GLOBAL.ERROR,
      });
    }
  };

  const completeConsultation = async (appointmentId: string, data?: {
    diagnosis?: string;
    prescription?: string;
    notes?: string;
  }) => {
    try {
      await completeAppointmentMutation.mutateAsync({
        id: appointmentId,
        data: data || {},
      });
      showSuccessToast("Consultation completed successfully", {
        id: TOAST_IDS.GLOBAL.SUCCESS,
      });
      setDiagnosis("");
      setPrescription("");
      setConsultationNotes("");
      setSelectedAppointment(null);
      appointmentsQuery.refetch();
    } catch (error: any) {
      showErrorToast(error?.message || "Failed to complete consultation", {
        id: TOAST_IDS.GLOBAL.ERROR,
      });
    }
  };

  return (
    <>
      {isLoadingAppointments ? (
        <div className="flex items-center justify-center min-h-[400px]">
          <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
        </div>
      ) : (
        <div className="p-6 space-y-6">
          <div className="flex items-center justify-between">
            <h1 className="text-3xl font-bold">My Appointments</h1>
            <WebSocketStatusIndicator />
          </div>
          <div className="text-sm text-gray-600">
            Today • {new Date().toLocaleDateString()}
          </div>

          {/* Stats Overview */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Confirmed</CardTitle>
                <CheckCircle className="h-4 w-4 text-green-600" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold text-green-600">
                  {appointments.filter(a => a.status === APPOINTMENT_STATUS.CONFIRMED).length}
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">In Progress</CardTitle>
                <Play className="h-4 w-4 text-blue-600" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold text-blue-600">
                  {appointments.filter(a => a.status === APPOINTMENT_STATUS.IN_PROGRESS).length}
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Scheduled</CardTitle>
                <Clock className="h-4 w-4 text-gray-600" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold text-gray-600">
                  {appointments.filter(a => a.status === APPOINTMENT_STATUS.SCHEDULED || a.status === APPOINTMENT_STATUS.CONFIRMED).length}
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Total Today</CardTitle>
                <Calendar className="h-4 w-4 text-purple-600" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold text-purple-600">
                  {appointments.length}
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Search and Filters */}
          <Card>
            <CardHeader>
              <CardTitle>Filter Appointments</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="flex flex-col md:flex-row gap-4">
                <div className="relative flex-1">
                  <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-500" />
                  <Input
                    placeholder="Search by patient name or appointment type..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-10"
                  />
                </div>
                <Select value={statusFilter} onValueChange={setStatusFilter}>
                  <SelectTrigger className="w-full md:w-64">
                    <SelectValue placeholder="Filter by status" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="ALL">All Status</SelectItem>
                    <SelectItem value="CONFIRMED">Confirmed</SelectItem>
                    <SelectItem value="IN_PROGRESS">In Progress</SelectItem>
                    <SelectItem value="SCHEDULED">Scheduled</SelectItem>
                    <SelectItem value="COMPLETED">Completed</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </CardContent>
          </Card>

          {/* Appointments List */}
          <div className="grid gap-4">
            {filteredAppointments.map((appointment) => (
              <Card key={appointment.id} className="hover:shadow-md transition-shadow">
                <CardContent className="p-6">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-linear-to-br from-blue-100 to-purple-100 rounded-full flex items-center justify-center">
                        <span className="text-blue-800 font-semibold text-lg">
                          {appointment.patientName?.charAt(0) || "?"}
                        </span>
                      </div>
                      <div>
                        <h3 className="text-lg font-semibold">{appointment.patientName}</h3>
                        <div className="flex items-center gap-4 text-sm text-gray-600">
                          <span>{appointment.patientAge} years • {appointment.patientGender}</span>
                          <span>{appointment.type}</span>
                          <span>{appointment.duration}</span>
                        </div>
                        <div className="flex items-center gap-2 mt-1">
                          <Clock className="w-4 h-4 text-gray-500" />
                          <span className="text-sm font-medium">{appointment.time}</span>
                          {appointment.checkedInAt && (
                            <span className="text-xs text-green-600">
                              (Checked in at {appointment.checkedInAt})
                            </span>
                          )}
                        </div>
                      </div>
                    </div>

                    <div className="flex items-center gap-3">
                      <div className="text-right">
                        <Badge className={getStatusColor(appointment.status)}>
                          {getStatusLabel(appointment.status)}
                        </Badge>
                        {appointment.queuePosition && (
                          <div className="text-xs text-gray-500 mt-1">
                            Queue Position: {appointment.queuePosition}
                          </div>
                        )}
                      </div>

                      <div className="flex gap-2">
                        <Button 
                          variant="outline" 
                          size="sm"
                          onClick={() => setSelectedAppointment(appointment)}
                        >
                          <Eye className="w-4 h-4" />
                        </Button>

                        {appointment.status === APPOINTMENT_STATUS.CONFIRMED && (
                          <Button 
                            size="sm" 
                            onClick={() => startConsultation(appointment.id)}
                            disabled={startAppointmentMutation.isPending}
                            className="flex items-center gap-1"
                          >
                            {startAppointmentMutation.isPending ? (
                              <>
                                <Loader2 className="w-3 h-3 animate-spin" />
                                Starting...
                              </>
                            ) : (
                              <>
                                <Play className="w-3 h-3" />
                                Start
                              </>
                            )}
                          </Button>
                        )}

                        {appointment.status === APPOINTMENT_STATUS.IN_PROGRESS && (
                          <>
                            <Button
                              variant="outline"
                              size="sm"
                              className="flex items-center gap-1"
                              onClick={() => {
                                const videoAppt: VideoAppointment = {
                                  id: appointment.id,
                                  appointmentId: appointment.id,
                                  roomName: `room-${appointment.id}`,
                                  doctorId: appointment.doctorId || user?.id || "",
                                  patientId: appointment.patientId || "",
                                  startTime: new Date().toISOString(),
                                  endTime: new Date().toISOString(),
                                  status: "in-progress",
                                  createdAt: new Date().toISOString(),
                                  updatedAt: new Date().toISOString(),
                                };
                                setVideoRoomAppointment(videoAppt);
                                setIsVideoRoomOpen(true);
                              }}
                            >
                              <Video className="w-3 h-3" />
                              Video
                            </Button>
                            <Button 
                              size="sm" 
                              onClick={() => completeConsultation(appointment.id, {
                              diagnosis: diagnosis,
                              prescription: prescription,
                              notes: consultationNotes,
                            })}
                              disabled={completeAppointmentMutation.isPending}
                              className="flex items-center gap-1"
                            >
                              {completeAppointmentMutation.isPending ? (
                                <>
                                  <Loader2 className="w-3 h-3 animate-spin" />
                                  Completing...
                                </>
                              ) : (
                                <>
                                  <CheckCircle className="w-3 h-3" />
                                  Complete
                                </>
                              )}
                            </Button>
                          </>
                        )}
                      </div>
                    </div>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>

          {filteredAppointments.length === 0 && (
            <Card>
              <CardContent className="text-center py-8">
                <Calendar className="w-12 h-12 text-gray-400 mx-auto mb-4" />
                <h3 className="text-lg font-semibold mb-2">No appointments found</h3>
                <p className="text-gray-600">Try adjusting your search criteria</p>
              </CardContent>
            </Card>
          )}

          {/* Patient Details Modal/Sidebar */}
          {selectedAppointment && (
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center justify-between">
                  <span>Patient Details: {selectedAppointment.patientName}</span>
                  <Button 
                    variant="outline" 
                    size="sm"
                    onClick={() => setSelectedAppointment(null)}
                  >
                    Close
                  </Button>
                </CardTitle>
              </CardHeader>
              <CardContent>
                <Tabs defaultValue="patient-info" className="space-y-4">
                  <TabsList className="grid w-full grid-cols-3">
                    <TabsTrigger value="patient-info">Patient Info</TabsTrigger>
                    <TabsTrigger value="consultation">Consultation</TabsTrigger>
                    <TabsTrigger value="prescription">Prescription</TabsTrigger>
                  </TabsList>

                  <TabsContent value="patient-info">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div className="space-y-4">
                        <div>
                          <h4 className="font-semibold mb-2">Contact Information</h4>
                          <div className="space-y-2 text-sm">
                            <div className="flex items-center gap-2">
                              <Phone className="w-4 h-4" />
                              <span>{selectedAppointment.patientPhone}</span>
                            </div>
                            <div className="flex items-center gap-2">
                              <MessageSquare className="w-4 h-4" />
                              <span>{selectedAppointment.patientEmail}</span>
                            </div>
                          </div>
                        </div>

                        <div>
                          <h4 className="font-semibold mb-2">Chief Complaint</h4>
                          <p className="text-sm text-gray-700">{selectedAppointment.chiefComplaint}</p>
                        </div>

                        <div>
                          <h4 className="font-semibold mb-2">Medical History</h4>
                          <p className="text-sm text-gray-700">
                            {Array.isArray(selectedAppointment.medicalHistory)
                              ? selectedAppointment.medicalHistory.join(", ") || "None"
                              : selectedAppointment.medicalHistory || "None"}
                          </p>
                        </div>
                      </div>

                      <div className="space-y-4">
                        {selectedAppointment.vitalSigns && (
                          <div>
                            <h4 className="font-semibold mb-2">Vital Signs</h4>
                            <div className="grid grid-cols-2 gap-2 text-sm">
                              <div>BP: {selectedAppointment.vitalSigns.bp ?? "-"}</div>
                              <div>Pulse: {selectedAppointment.vitalSigns.pulse ?? "-"}</div>
                              <div>Temp: {selectedAppointment.vitalSigns.temperature ?? "-"}</div>
                              <div>Weight: {selectedAppointment.vitalSigns.weight ?? "-"}</div>
                            </div>
                          </div>
                        )}

                        <div>
                          <h4 className="font-semibold mb-2">Allergies</h4>
                          <p className="text-sm text-gray-700">
                            {Array.isArray(selectedAppointment.allergies)
                              ? selectedAppointment.allergies.join(", ") || "None"
                              : selectedAppointment.allergies || "None"}
                          </p>
                        </div>

                        <div>
                          <h4 className="font-semibold mb-2">Current Medications</h4>
                          <p className="text-sm text-gray-700">
                            {Array.isArray(selectedAppointment.currentMedications)
                              ? selectedAppointment.currentMedications.join(", ") || "None"
                              : selectedAppointment.currentMedications || "None"}
                          </p>
                        </div>
                      </div>
                    </div>
                  </TabsContent>

                  <TabsContent value="consultation">
                    <div className="space-y-4">
                      <div>
                        <label htmlFor="diagnosis" className="block text-sm font-medium mb-2">
                          Diagnosis
                        </label>
                        <Input
                          id="diagnosis"
                          value={diagnosis}
                          onChange={(e) => setDiagnosis(e.target.value)}
                          placeholder="Enter diagnosis..."
                        />
                      </div>

                      <div>
                        <label htmlFor="consultationNotes" className="block text-sm font-medium mb-2">
                          Consultation Notes
                        </label>
                        <Textarea
                          id="consultationNotes"
                          value={consultationNotes}
                          onChange={(e) => setConsultationNotes(e.target.value)}
                          placeholder="Enter detailed consultation notes..."
                          rows={6}
                        />
                      </div>

                      <Button 
                        className="w-full"
                        onClick={() => {
                          if (selectedAppointment) {
                            completeConsultation(selectedAppointment.id, {
                              diagnosis: diagnosis,
                              prescription: prescription,
                              notes: consultationNotes,
                            });
                          }
                        }}
                        disabled={completeAppointmentMutation.isPending}
                      >
                        {completeAppointmentMutation.isPending ? (
                          <>
                            <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                            Saving...
                          </>
                        ) : (
                          <>
                            <FileText className="w-4 h-4 mr-2" />
                            Save Consultation Notes
                          </>
                        )}
                      </Button>
                    </div>
                  </TabsContent>

                  <TabsContent value="prescription">
                    <div className="space-y-4">
                      <div>
                        <label htmlFor="prescription" className="block text-sm font-medium mb-2">
                          Prescription & Treatment Plan
                        </label>
                        <Textarea
                          id="prescription"
                          value={prescription}
                          onChange={(e) => setPrescription(e.target.value)}
                          placeholder="Enter medications, dosage, and treatment instructions..."
                          rows={8}
                        />
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                        <Button 
                          variant="outline" 
                          className="w-full"
                          onClick={() => {
                            // Save prescription as draft (could be a separate mutation)
                            showInfoToast("Prescription saved as draft", {
                              id: TOAST_IDS.GLOBAL.INFO,
                            });
                          }}
                        >
                          Save as Draft
                        </Button>
                        <Button 
                          className="w-full"
                          onClick={() => {
                            if (selectedAppointment) {
                              completeConsultation(selectedAppointment.id, {
                                diagnosis: diagnosis,
                                prescription: prescription,
                                notes: consultationNotes,
                              });
                            }
                          }}
                          disabled={completeAppointmentMutation.isPending}
                        >
                          {completeAppointmentMutation.isPending ? (
                            <>
                              <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                              Saving...
                            </>
                          ) : (
                            <>
                              <CheckCircle className="w-4 h-4 mr-2" />
                              Generate Prescription
                            </>
                          )}
                        </Button>
                      </div>
                    </div>
                  </TabsContent>
                </Tabs>
              </CardContent>
            </Card>
          )}

          {/* Video Consultation Dialog */}
          {videoRoomAppointment && (
            <Dialog open={isVideoRoomOpen} onOpenChange={setIsVideoRoomOpen}>
              <DialogContent className="max-w-7xl w-full h-[90vh] p-0">
                <DialogHeader className="sr-only">
                  <DialogTitle>Video Consultation - {videoRoomAppointment.appointmentId}</DialogTitle>
                </DialogHeader>
                <VideoAppointmentRoom
                  appointment={videoRoomAppointment}
                  onEndCall={() => {
                    setIsVideoRoomOpen(false);
                    setVideoRoomAppointment(null);
                    appointmentsQuery.refetch();
                  }}
                  onLeaveRoom={() => {
                    setIsVideoRoomOpen(false);
                    setVideoRoomAppointment(null);
                  }}
                />
              </DialogContent>
            </Dialog>
          )}
        </div>
      )}
    </>
  );
}

"use client";

import { useMemo } from "react";
import { useRouter } from "next/navigation";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { useAuth } from "@/hooks/auth/useAuth";
import { useAppointments, useStartAppointment, useCompleteAppointment } from "@/hooks/query/useAppointments";
import { AppointmentWithRelations, AppointmentStatus } from "@/types/appointment.types";
import { useClinicContext } from "@/hooks/query/useClinics";
// import { ConnectionStatusIndicator as WebSocketStatusIndicator } from "@/components/common/StatusIndicator";
import { useWebSocketQuerySync } from "@/hooks/realtime/useRealTimeQueries";
import {
  Activity,
  Calendar,
  Users,
  Clock,
  Stethoscope,
  Play,
  CheckCircle,
  AlertCircle,
  FileText,
  Video,
} from "lucide-react";

// Interface for the transformed appointment object
interface TransformedAppointment {
  id: string;
  patientName: string;
  time: string;
  status: string;
  statusEnum: AppointmentStatus;
  type: string;
  duration: string;
  notes: string;
  isVideo: boolean;
}

export default function DoctorDashboard() {
  const router = useRouter();
  const { session } = useAuth();
  const user = session?.user;

  // Enable real-time WebSocket sync
  useWebSocketQuerySync();

  // Clinic context
  const { clinicId } = useClinicContext();

  // Fetch real data using existing hooks and server actions
  const { data: appointments } = useAppointments({
    ...(clinicId ? { clinicId } : {}),
    ...(user?.id ? { doctorId: user.id } : {}),
    limit: 100,
  });
  const startAppointmentMutation = useStartAppointment();
  const completeAppointmentMutation = useCompleteAppointment();

  // Calculate real stats from fetched data
  const appointmentsArray = Array.isArray(appointments)
    ? appointments
    : appointments?.appointments || [];

  // Today's appointments from real data (sorted by time)
  const todaysAppointments = useMemo(() => {
    const today = new Date().toDateString();
    return appointmentsArray
      .filter((apt: AppointmentWithRelations) => new Date(apt.date).toDateString() === today)
      .sort(
        (a: AppointmentWithRelations, b: AppointmentWithRelations) =>
          (a.time || "").localeCompare(b.time || "", undefined, { numeric: true })
      )
      .map((apt: AppointmentWithRelations): TransformedAppointment => {
        const patientName =
          `${apt.patient?.firstName || ""} ${apt.patient?.lastName || ""}`.trim() ||
          "Unknown Patient";
        const statusLabels: Partial<Record<AppointmentStatus, string>> = {
          IN_PROGRESS: "In Progress",
          SCHEDULED: "Scheduled",
          CONFIRMED: "Confirmed",
          AWAITING_SLOT_CONFIRMATION: "Awaiting Confirmation",
          COMPLETED: "Completed",
          CANCELLED: "Cancelled",
          NO_SHOW: "No Show",
        };
        return {
          id: apt.id,
          patientName,
          time: apt.time || "",
          status: statusLabels[apt.status] || apt.status,
          statusEnum: apt.status,
          type: apt.type || "Consultation",
          duration: `${apt.duration || 30} min`,
          notes: apt.notes || "",
          isVideo: apt.type === "VIDEO_CALL",
        };
      });
  }, [appointmentsArray]);

  const activeTreatmentQueue = useMemo(
    () =>
      todaysAppointments.filter(
        (apt: TransformedAppointment) => apt.statusEnum === "CONFIRMED" || apt.statusEnum === "IN_PROGRESS"
      ),
    [todaysAppointments]
  );

  const viewOnlyQueue = useMemo(
    () =>
      todaysAppointments.filter(
        (apt: TransformedAppointment) =>
          apt.statusEnum === "SCHEDULED" ||
          apt.statusEnum === "AWAITING_SLOT_CONFIRMATION"
      ),
    [todaysAppointments]
  );

  const stats = {
    todayAppointments:
      appointmentsArray.filter((apt: AppointmentWithRelations) => {
        const today = new Date().toDateString();
        return new Date(apt.date).toDateString() === today;
      }).length || 0,
    checkedInPatients:
      appointmentsArray.filter((apt) => apt.status === "CONFIRMED").length || 0,
    completedToday:
      appointmentsArray.filter((apt) => {
        const today = new Date().toDateString();
        return (
          new Date(apt.date).toDateString() === today &&
          apt.status === "COMPLETED"
        );
      }).length || 0,
    totalPatients: new Set(appointmentsArray.map((apt) => apt.patientId)).size,
    avgConsultationTime: 25,
    patientSatisfaction: 4.8,
    nextAppointment:
      todaysAppointments.find(
        (a: TransformedAppointment) =>
          a.statusEnum === "SCHEDULED" ||
          a.statusEnum === "CONFIRMED" ||
          a.statusEnum === "IN_PROGRESS"
      )?.time || "-",
  };

  const recentActivities = [
    {
      type: "consultation",
      message: "Completed consultation with Ramesh Patel",
      time: "30 minutes ago",
    },
    {
      type: "prescription",
      message: "Updated prescription for chronic pain management",
      time: "1 hour ago",
    },
    {
      type: "notes",
      message: "Added treatment notes for Aysha Khan",
      time: "2 hours ago",
    },
  ];

  const getStatusColor = (status: string) => {
    switch (status) {
      case "In Progress":
        return "bg-blue-100 text-blue-800";
      case "Confirmed":
        return "bg-green-100 text-green-800";
      case "Scheduled":
        return "bg-gray-100 text-gray-800";
      case "Completed":
        return "bg-purple-100 text-purple-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case "In Progress":
        return <Play className="w-4 h-4" />;
      case "Confirmed":
        return <CheckCircle className="w-4 h-4" />;
      case "Scheduled":
        return <Clock className="w-4 h-4" />;
      case "Completed":
        return <CheckCircle className="w-4 h-4" />;
      default:
        return <Clock className="w-4 h-4" />;
    }
  };


  return (
    
        <div className="p-6 space-y-6">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-3xl font-bold">
                Welcome, Dr. {user?.firstName || "Doctor"}
              </h1>
              <p className="text-gray-600">
                Today is{" "}
                {new Date().toLocaleDateString("en-IN", {
                  weekday: "long",
                  year: "numeric",
                  month: "long",
                  day: "numeric",
                })}
              </p>
            </div>
            <div className="text-right">
              <div className="text-sm text-gray-600">Next Appointment</div>
              <div className="text-2xl font-bold text-blue-600">
                {stats.nextAppointment}
              </div>
            </div>
          </div>

          {/* Key Metrics */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">
                  Today&apos;s Appointments
                </CardTitle>
                <Calendar className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">
                  {stats.todayAppointments}
                </div>
                <p className="text-xs text-muted-foreground">
                  {stats.checkedInPatients} confirmed and waiting
                </p>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">
                  Completed Today
                </CardTitle>
                <CheckCircle className="h-4 w-4 text-green-600" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold text-green-600">
                  {stats.completedToday}
                </div>
                <p className="text-xs text-muted-foreground">
                  Consultations finished
                </p>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">
                  Total Patients
                </CardTitle>
                <Users className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">{stats.totalPatients}</div>
                <p className="text-xs text-muted-foreground">Under your care</p>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">
                  Avg. Consultation
                </CardTitle>
                <Clock className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">
                  {stats.avgConsultationTime} min
                </div>
                <p className="text-xs text-muted-foreground">Per patient</p>
              </CardContent>
            </Card>
          </div>

          {/* Performance Indicators */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <Card>
              <CardHeader>
                <CardTitle className="text-lg">Patient Satisfaction</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="text-3xl font-bold text-green-600">
                  {stats.patientSatisfaction}/5.0
                </div>
                <p className="text-sm text-gray-600">
                  Average rating this month
                </p>
                <div className="mt-2 flex items-center">
                  {[...Array(5)].map((_, i) => (
                    <div
                      key={i}
                      className={`w-4 h-4 rounded-full mr-1 ${
                        i < Math.floor(stats.patientSatisfaction)
                          ? "bg-green-500"
                          : "bg-gray-200"
                      }`}
                    />
                  ))}
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle className="text-lg">Quick Actions</CardTitle>
              </CardHeader>
              <CardContent className="space-y-2">
                <Button
                  variant="outline"
                  className="w-full justify-start"
                  onClick={() => router.push("/doctor/video")}
                >
                  <Video className="w-4 h-4 mr-2" />
                  Start Video Consultation
                </Button>
                <Button
                  variant="outline"
                  className="w-full justify-start"
                  onClick={() => router.push("/doctor/appointments")}
                >
                  <FileText className="w-4 h-4 mr-2" />
                  Write Prescription
                </Button>
                <Button
                  variant="outline"
                  className="w-full justify-start"
                  onClick={() => router.push("/doctor/patients")}
                >
                  <Users className="w-4 h-4 mr-2" />
                  View Patient History
                </Button>
              </CardContent>
            </Card>
          </div>

          {/* Active Treatment Queue */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Clock className="w-5 h-5" />
                Active Treatment Queue
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                {activeTreatmentQueue.map((appointment: TransformedAppointment) => (
                  <div
                    key={appointment.id}
                    className="flex items-center justify-between p-4 border rounded-lg hover:bg-gray-50"
                  >
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 bg-blue-100 rounded-full flex items-center justify-center">
                        <Stethoscope className="w-5 h-5 text-blue-600" />
                      </div>
                      <div>
                        <h4 className="font-semibold">
                          {appointment.patientName}
                        </h4>
                        <p className="text-sm text-gray-600">
                          {appointment.type} - {appointment.duration}
                        </p>
                        <p className="text-xs text-gray-500 mt-1">
                          {appointment.notes}
                        </p>
                      </div>
                    </div>
                    <div className="flex items-center gap-4">
                      <div className="text-right">
                        <div className="font-medium">{appointment.time}</div>
                        <Badge
                          className={`${getStatusColor(
                            appointment.status
                          )} flex items-center gap-1`}
                        >
                          {getStatusIcon(appointment.status)}
                          {appointment.status}
                        </Badge>
                      </div>
                      {appointment.status === "Confirmed" && (
                        <Button
                          size="sm"
                          className="flex items-center gap-1"
                          disabled={startAppointmentMutation.isPending}
                          onClick={async () => {
                            await startAppointmentMutation.mutateAsync(appointment.id);
                            if (appointment.isVideo) {
                              router.push("/doctor/video");
                            }
                          }}
                        >
                          {startAppointmentMutation.isPending ? (
                            <Clock className="w-3 h-3 animate-spin" />
                          ) : (
                            <Play className="w-3 h-3" />
                          )}
                          Start
                        </Button>
                      )}
                      {appointment.status === "In Progress" && (
                        <Button
                          size="sm"
                          variant="outline"
                          className="flex items-center gap-1"
                          disabled={completeAppointmentMutation.isPending}
                          onClick={() =>
                            completeAppointmentMutation.mutateAsync({
                              id: appointment.id,
                              data: {},
                            })
                          }
                        >
                          {completeAppointmentMutation.isPending ? (
                            <Clock className="w-3 h-3 animate-spin" />
                          ) : (
                            <CheckCircle className="w-3 h-3" />
                          )}
                          Complete
                        </Button>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Calendar className="w-5 h-5" />
                Scheduled Queue (View Only)
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                {viewOnlyQueue.length === 0 ? (
                  <p className="text-sm text-muted-foreground">
                    No scheduled patients pending check-in.
                  </p>
                ) : (
                  viewOnlyQueue.map((appointment: TransformedAppointment) => (
                    <div
                      key={appointment.id}
                      className="flex items-center justify-between p-4 border rounded-lg bg-muted/20"
                    >
                      <div>
                        <h4 className="font-semibold">{appointment.patientName}</h4>
                        <p className="text-sm text-gray-600">
                          {appointment.type} - {appointment.duration}
                        </p>
                      </div>
                      <div className="text-right">
                        <div className="font-medium">{appointment.time}</div>
                        <Badge className={`${getStatusColor(appointment.status)} flex items-center gap-1`}>
                          {getStatusIcon(appointment.status)}
                          {appointment.status}
                        </Badge>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </CardContent>
          </Card>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Recent Activities */}
            <Card>
              <CardHeader>
                <CardTitle>Recent Activities</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-4">
                  {recentActivities.map((activity, index) => (
                    <div key={index} className="flex items-start gap-3">
                      <div className="shrink-0">
                        {activity.type === "consultation" && (
                          <Stethoscope className="w-4 h-4 text-blue-600" />
                        )}
                        {activity.type === "prescription" && (
                          <FileText className="w-4 h-4 text-green-600" />
                        )}
                        {activity.type === "notes" && (
                          <Activity className="w-4 h-4 text-purple-600" />
                        )}
                      </div>
                      <div className="flex-1">
                        <p className="text-sm font-medium">
                          {activity.message}
                        </p>
                        <p className="text-xs text-gray-600">{activity.time}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </CardContent>
            </Card>

            {/* Treatment Specialties */}
            <Card>
              <CardHeader>
                <CardTitle>Your Specialties</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="grid grid-cols-1 gap-3">
                  <div className="flex items-center justify-between p-3 bg-blue-50 rounded-lg">
                    <span className="font-medium">Panchakarma Therapy</span>
                    <Badge variant="outline">Primary</Badge>
                  </div>
                  <div className="flex items-center justify-between p-3 bg-green-50 rounded-lg">
                    <span className="font-medium">Nadi Pariksha</span>
                    <Badge variant="outline">Specialty</Badge>
                  </div>
                  <div className="flex items-center justify-between p-3 bg-purple-50 rounded-lg">
                    <span className="font-medium">Ayurvedic Medicine</span>
                    <Badge variant="outline">General</Badge>
                  </div>
                  <div className="flex items-center justify-between p-3 bg-orange-50 rounded-lg">
                    <span className="font-medium">Lifestyle Counseling</span>
                    <Badge variant="outline">Advisory</Badge>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Alerts */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <AlertCircle className="w-5 h-5 text-orange-600" />
                Important Notices
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-3">
                <div className="flex items-center gap-3 p-3 bg-blue-50 border border-blue-200 rounded-lg">
                  <AlertCircle className="w-5 h-5 text-blue-600" />
                  <div>
                    <p className="text-sm font-medium text-blue-800">
                      Schedule Update
                    </p>
                    <p className="text-xs text-blue-700">
                      Your afternoon schedule has been updated with 2 additional
                      slots
                    </p>
                  </div>
                </div>
                <div className="flex items-center gap-3 p-3 bg-green-50 border border-green-200 rounded-lg">
                  <CheckCircle className="w-5 h-5 text-green-600" />
                  <div>
                    <p className="text-sm font-medium text-green-800">
                      Patient Feedback
                    </p>
                    <p className="text-xs text-green-700">
                      You received 3 new positive reviews from recent patients
                    </p>
                  </div>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>
    
  );
}

"use client";

import { useState, useMemo } from "react";
import { Role } from "@/types/auth.types";
import { useComprehensiveHealthRecord } from "@/hooks/query/useMedicalRecords";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Drawer,
  DrawerContent,
  DrawerHeader,
  DrawerTitle,
} from "@/components/ui/drawer";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useAuth } from "@/hooks/auth/useAuth";
import { useClinicContext } from "@/hooks/query/useClinics";
import { usePatients } from "@/hooks/query/usePatients";
import { useWebSocketQuerySync } from "@/hooks/realtime/useRealTimeQueries";
import {
  Calendar,
  Users,
  Search,
  Eye,
  Phone,
  Mail,
  MapPin,
  Loader2,
  Clock,
  TrendingUp,
  Pill,
} from "lucide-react";

export default function DoctorPatients() {
  useAuth();
  const { clinicId } = useClinicContext();
  const [searchTerm, setSearchTerm] = useState("");
  const [genderFilter, setGenderFilter] = useState("all");
  const [ageFilter, setAgeFilter] = useState("all");
  const [drawerPatient, setDrawerPatient] = useState<any>(null);

  // Fetch real patient data
  const { data: patientsData, isPending: isPendingPatients } = usePatients(
    clinicId || "",
    {
      search: searchTerm,
      ...(genderFilter !== "all" && { gender: genderFilter }),
    }
  );

  // Sync with WebSocket for real-time updates
  useWebSocketQuerySync();

  // Extract patients array from response
  const patients = useMemo(() => {
    if (!patientsData) return [];
    return Array.isArray(patientsData)
      ? patientsData
      : (patientsData as any).patients || [];
  }, [patientsData]);

  const filteredPatients = patients.filter((patient: any) => {
    const name = patient.name || `${patient.firstName || ""} ${patient.lastName || ""}`.trim() || "";
    const matchesSearch =
      name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (patient.chiefComplaints || []).some((complaint: string) =>
        String(complaint).toLowerCase().includes(searchTerm.toLowerCase())
      );
    const matchesGender =
      genderFilter === "all" || patient.gender.toLowerCase() === genderFilter;
    const matchesAge =
      ageFilter === "all" ||
      (ageFilter === "young" && patient.age < 30) ||
      (ageFilter === "middle" && patient.age >= 30 && patient.age < 60) ||
      (ageFilter === "senior" && patient.age >= 60);

    return matchesSearch && matchesGender && matchesAge;
  });


  if (isPendingPatients) {
    return (
      
          <div className="p-6 flex items-center justify-center min-h-[400px]">
            <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
          </div>
      
    );
  }

  return (
    
        <div className="p-6 space-y-6">
          <div className="flex items-center justify-between">
            <h1 className="text-3xl font-bold">My Patients</h1>
            <div className="flex items-center gap-4">
              <div className="text-sm text-gray-600">
                Total: {patients.length} patients
              </div>
            </div>
          </div>

          {/* Stats Overview */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">
                  Total Patients
                </CardTitle>
                <Users className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">{patients.length}</div>
                <p className="text-xs text-muted-foreground">Under your care</p>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">This Week</CardTitle>
                <Calendar className="h-4 w-4 text-blue-600" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold text-blue-600">12</div>
                <p className="text-xs text-muted-foreground">
                  Appointments scheduled
                </p>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">
                  Follow-ups
                </CardTitle>
                <Clock className="h-4 w-4 text-orange-600" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold text-orange-600">5</div>
                <p className="text-xs text-muted-foreground">Due this week</p>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">
                  Recovery Rate
                </CardTitle>
                <TrendingUp className="h-4 w-4 text-green-600" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold text-green-600">92%</div>
                <p className="text-xs text-muted-foreground">
                  Patient improvement
                </p>
              </CardContent>
            </Card>
          </div>

          {/* Search and Filters */}
          <Card>
            <CardHeader>
              <CardTitle>Search & Filter Patients</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="flex flex-col md:flex-row gap-4">
                <div className="relative flex-1">
                  <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-500" />
                  <Input
                    placeholder="Search by name or condition..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-10"
                  />
                </div>
                <Select value={genderFilter} onValueChange={setGenderFilter}>
                  <SelectTrigger className="w-full md:w-48">
                    <SelectValue placeholder="Filter by gender" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All Genders</SelectItem>
                    <SelectItem value="male">Male</SelectItem>
                    <SelectItem value="female">Female</SelectItem>
                  </SelectContent>
                </Select>
                <Select value={ageFilter} onValueChange={setAgeFilter}>
                  <SelectTrigger className="w-full md:w-48">
                    <SelectValue placeholder="Filter by age" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All Ages</SelectItem>
                    <SelectItem value="young">Under 30</SelectItem>
                    <SelectItem value="middle">30-60</SelectItem>
                    <SelectItem value="senior">Over 60</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </CardContent>
          </Card>

          {/* Patients List */}
          <div className="grid gap-4">
            {filteredPatients.map((patient: any) => (
              <Card
                key={patient.id}
                className="hover:shadow-md transition-shadow"
              >
                <CardContent className="p-6">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-4">
                      <div className="w-16 h-16 bg-linear-to-br from-blue-100 to-green-100 rounded-full flex items-center justify-center">
                        <span className="text-blue-800 font-semibold text-xl">
                          {(patient.name || patient.firstName || "?")[0]}
                        </span>
                      </div>
                      <div>
                        <h3 className="text-lg font-semibold">
                          {patient.name ||
                            `${patient.firstName || ""} ${
                              patient.lastName || ""
                            }`.trim() ||
                            "Unknown Patient"}
                        </h3>
                        <div className="flex items-center gap-4 text-sm text-gray-600">
                          {patient.age && (
                            <span>
                              {patient.age} years{" "}
                              {patient.gender ? `• ${patient.gender}` : ""}
                            </span>
                          )}
                          {patient.phone && (
                            <span className="flex items-center gap-1">
                              <Phone className="w-3 h-3" />
                              {patient.phone}
                            </span>
                          )}
                          {patient.email && (
                            <span className="flex items-center gap-1">
                              <Mail className="w-3 h-3" />
                              {patient.email}
                            </span>
                          )}
                        </div>
                        {patient.address && (
                          <div className="mt-1 flex items-center gap-1 text-xs text-gray-500">
                            <MapPin className="w-3 h-3" />
                            {patient.address}
                          </div>
                        )}
                      </div>
                    </div>

                    <div className="text-right space-y-2">
                      <div className="text-sm">
                        {patient.lastVisit && (
                          <div>
                            <strong>Last Visit:</strong>{" "}
                            {new Date(patient.lastVisit).toLocaleDateString()}
                          </div>
                        )}
                        {patient.nextAppointment && (
                          <div>
                            <strong>Next:</strong>{" "}
                            {new Date(
                              patient.nextAppointment
                            ).toLocaleDateString()}
                          </div>
                        )}
                        {patient.totalVisits !== undefined && (
                          <div>
                            <strong>Total Visits:</strong> {patient.totalVisits}
                          </div>
                        )}
                      </div>
                      <div className="flex gap-2">
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() => setDrawerPatient(patient)}
                        >
                          <Eye className="w-4 h-4 mr-1" />
                          View EHR
                        </Button>

                        <Button size="sm" className="flex items-center gap-1">
                          <Calendar className="w-3 h-3" />
                          Schedule
                        </Button>
                      </div>
                    </div>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>

          {filteredPatients.length === 0 && (
            <Card>
              <CardContent className="text-center py-8">
                <Users className="w-12 h-12 text-gray-400 mx-auto mb-4" />
                <h3 className="text-lg font-semibold mb-2">
                  No patients found
                </h3>
                <p className="text-gray-600">
                  Try adjusting your search criteria
                </p>
              </CardContent>
            </Card>
          )}

          {/* EHR Drawer */}
          <Drawer
            open={!!drawerPatient}
            onOpenChange={(open) => !open && setDrawerPatient(null)}
          >
            <DrawerContent className="max-w-4xl mx-auto max-h-[90vh] overflow-y-auto">
              {drawerPatient && (
                <EhrDrawerContent
                  patient={drawerPatient}
                />
              )}
            </DrawerContent>
          </Drawer>
        </div>
    
  );
}

function EhrDrawerContent({
  patient,
}: {
  patient: any;
}) {
  const patientUserId = patient?.userId || patient?.user?.id;
  const { data: ehrData, isPending: isEhrLoading } =
    useComprehensiveHealthRecord(patientUserId || "") as { data: any; isPending: boolean };

  const patientName =
    `${patient?.firstName || ""} ${patient?.lastName || ""}`.trim() ||
    "Unknown Patient";

  return (
    <>
      <DrawerHeader>
        <DrawerTitle>{patientName} - Electronic Health Record</DrawerTitle>
      </DrawerHeader>
      <div className="px-6 pb-6">
        {isEhrLoading ? (
          <div className="flex items-center justify-center py-12">
            <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
          </div>
        ) : (
          <Tabs defaultValue="overview" className="space-y-4">
            <TabsList className="grid w-full grid-cols-4">
              <TabsTrigger value="overview">Overview</TabsTrigger>
