"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { QRScanner } from "@/components/qr/QRScanner";
import { scanLocationQRAndCheckIn } from "@/lib/actions/appointments.server";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import { CheckCircle2, Info, Loader2, QrCode, Clock, Stethoscope } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import {
  Drawer,
  DrawerClose,
  DrawerContent,
  DrawerDescription,
  DrawerFooter,
  DrawerHeader,
  DrawerTitle,
  DrawerTrigger,
} from "@/components/ui/drawer";
import { Input } from "@/components/ui/input";

interface EligibleAppointment {
  id: string;
  doctorName?: string;
  doctor?: { name?: string; firstName?: string; lastName?: string };
  startTime?: string;
  time?: string;
  type?: string;
}

export default function PatientCheckInPage() {
  const router = useRouter();
  const [isProcessing, setIsProcessing] = useState(false);
  const [successData, setSuccessData] = useState<any>(null);
  const [manualCode, setManualCode] = useState("");
  // Multi-appointment selection state
  const [eligibleAppointments, setEligibleAppointments] = useState<EligibleAppointment[]>([]);
  const [pendingQrCode, setPendingQrCode] = useState<string>("");
  const [selectingAppointment, setSelectingAppointment] = useState(false);

  const handleManualCheckIn = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!manualCode.trim()) return;
    handleScanSuccess(manualCode.trim());
  };

  const handleScanSuccess = async (decodedText: string) => {
    if (isProcessing) return;
    setIsProcessing(true);
    if ("vibrate" in navigator) navigator.vibrate(100);

    try {
      const result = await scanLocationQRAndCheckIn({ code: decodedText }) as any;

      if (result.success && result.appointment) {
        setSuccessData(result.appointment);
        toast.success("Check-in successful!");
      } else if (result.requiresSelection && result.appointments?.length > 0) {
        // Backend found multiple eligible appointments — let patient pick
        setEligibleAppointments(result.appointments);
        setPendingQrCode(decodedText);
        setSelectingAppointment(true);
        setIsProcessing(false);
        toast.info("Multiple appointments found. Please select one.");
      } else {
        toast.error(result.error || "Failed to check in. Please try again or ask reception.");
        setIsProcessing(false);
      }
    } catch (error) {
      console.error("Check-in error:", error);
      toast.error("An unexpected error occurred");
      setIsProcessing(false);
    }
  };

  const handleSelectAppointment = async (appointmentId: string) => {
    setSelectingAppointment(false);
    setIsProcessing(true);

    try {
      const result = await scanLocationQRAndCheckIn({
        code: pendingQrCode,
        appointmentId,
      } as any) as any;

      if (result.success && result.appointment) {
        setSuccessData(result.appointment);
        toast.success("Check-in successful!");
      } else {
        toast.error(result.error || "Failed to check in.");
        setIsProcessing(false);
      }
    } catch (error) {
      console.error("Check-in error:", error);
      toast.error("An unexpected error occurred");
      setIsProcessing(false);
    }
  };

  // ─── Success State ────────────────────────────────────────────────────────
  if (successData) {
    const doctorName = successData.doctorName ?? successData.doctor?.name ?? "Assigned Doctor";
    const locationName =
      successData.locationName ??
      successData.location?.locationName ??
      successData.location?.name ??
      "Booked Clinic Location";
    const timeDisplay = successData.checkedInAt
      ? new Date(successData.checkedInAt).toLocaleTimeString("en-IN", {
          hour: "2-digit",
          minute: "2-digit",
          hour12: true,
        })
      : successData.time ?? "—";

    return (
      <div className="flex items-center justify-center min-h-[60vh] p-6">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="w-full max-w-sm text-center space-y-8"
        >
          <div className="relative mx-auto w-24 h-24 bg-green-500/10 rounded-full flex items-center justify-center shadow-inner">
            <motion.div
              initial={{ scale: 0 }}
              animate={{ scale: 1 }}
              transition={{ type: "spring", stiffness: 200, damping: 15 }}
            >
              <CheckCircle2 className="h-10 w-10 text-green-600" />
            </motion.div>
          </div>

          <div className="space-y-2">
            <h1 className="text-3xl font-bold tracking-tight">Check-in Confirmed!</h1>
            <p className="text-muted-foreground text-sm font-medium">
              You&apos;re all set for your visit.
            </p>
          </div>

          <div className="grid gap-4 bg-muted/40 p-6 rounded-3xl border text-left">
            <div className="flex justify-between items-center text-sm">
              <span className="text-muted-foreground font-bold uppercase tracking-widest text-[10px]">
                Doctor
              </span>
              <span className="font-bold truncate max-w-[150px]">{doctorName}</span>
            </div>
            <div className="flex justify-between items-center text-sm">
              <span className="text-muted-foreground font-bold uppercase tracking-widest text-[10px]">
                Time
              </span>
              <span className="font-bold">{timeDisplay}</span>
            </div>
            <div className="flex justify-between items-center text-sm">
              <span className="text-muted-foreground font-bold uppercase tracking-widest text-[10px]">
                Location
              </span>
              <span className="font-bold truncate max-w-[160px] text-right">{locationName}</span>
            </div>
            <div className="flex justify-between items-center text-sm">
              <span className="text-muted-foreground font-bold uppercase tracking-widest text-[10px]">
                Queue #
              </span>
              <span className="font-black text-primary uppercase">
                {successData.queuePosition || "1"}
              </span>
            </div>
          </div>

          <Button
            className="w-full h-14 rounded-2xl text-base font-bold"
            onClick={() => router.push("/patient/dashboard")}
          >
            Go to Dashboard
          </Button>
        </motion.div>
      </div>
    );
  }

  // ─── Multi-Appointment Selection State ──────────────────────────────────
  if (selectingAppointment && eligibleAppointments.length > 0) {
    return (
      <div className="max-w-xl mx-auto space-y-6 py-4">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Select Appointment</h1>
          <p className="text-muted-foreground text-sm">
            You have multiple appointments today. Please select which one to check in for.
          </p>
        </div>

        <div className="space-y-3">
          {eligibleAppointments.map((apt) => {
            const doctorName =
              apt.doctorName ??
              apt.doctor?.name ??
              (`${apt.doctor?.firstName || ""} ${apt.doctor?.lastName || ""}`.trim() ||
              "Doctor");
            const timeStr = apt.startTime || apt.time
              ? new Date((apt.startTime || apt.time)!).toLocaleTimeString("en-IN", {
                  hour: "2-digit",
                  minute: "2-digit",
                  hour12: true,
                })
              : "—";

            return (
              <motion.button
                key={apt.id}
                initial={{ opacity: 0, y: 8 }}
                animate={{ opacity: 1, y: 0 }}
                className="w-full rounded-2xl border bg-card p-5 text-left hover:border-primary/50 hover:shadow-md transition-all focus:outline-none focus:ring-2 focus:ring-primary/30"
                onClick={() => handleSelectAppointment(apt.id)}
              >
                <div className="flex items-center justify-between">
                  <div className="space-y-1">
                    <div className="flex items-center gap-2">
                      <Stethoscope className="h-4 w-4 text-muted-foreground" />
                      <span className="font-semibold">{doctorName}</span>
                    </div>
                    <div className="flex items-center gap-2 text-sm text-muted-foreground">
                      <Clock className="h-3.5 w-3.5" />
                      <span>{timeStr}</span>
                      {apt.type && (
                        <>
                          <span className="text-muted-foreground/50">•</span>
                          <span>{apt.type}</span>
                        </>
                      )}
                    </div>
                  </div>
                  <div className="text-primary font-semibold text-sm">Select →</div>
                </div>
              </motion.button>
            );
          })}
        </div>

        <Button
          variant="ghost"
          className="w-full"
          onClick={() => {
            setSelectingAppointment(false);
            setEligibleAppointments([]);
            setPendingQrCode("");
          }}
        >
          Cancel
        </Button>
      </div>
    );
  }

  // ─── Scanner State ────────────────────────────────────────────────────────
  return (
    <div className="max-w-xl mx-auto space-y-6 py-4">
      {/* Page Title */}
      <div>
        <h1 className="text-2xl font-bold tracking-tight">QR Check-in</h1>
        <p className="text-muted-foreground text-sm">
          Scan the QR at your booked clinic location to confirm appointment and join the live queue.
        </p>
      </div>

      {/* Scanner Card */}
      <div className="rounded-2xl border bg-card shadow-sm overflow-hidden">
        <AnimatePresence mode="wait">
          {!isProcessing ? (
            <motion.div
              key="scanner-layout"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="p-4 flex flex-col items-center gap-4"
            >
              <div className="w-full max-w-sm">
                <QRScanner
                  onScanSuccess={handleScanSuccess}
                  onScanFailure={() => void 0}
                  autoStart={true}
                />
              </div>

              <div className="flex items-start gap-3 bg-blue-50/50 dark:bg-blue-900/10 p-4 rounded-xl border border-blue-100 dark:border-blue-900/30 w-full max-w-sm">
                <Info className="h-4 w-4 text-blue-600 dark:text-blue-500 shrink-0 mt-0.5" />
                <p className="text-[11px] text-blue-800 dark:text-blue-300/80 leading-relaxed font-medium">
                  QR check-in works only at the booked appointment location. Once scanned, you are added to the live queue.
                </p>
              </div>
            </motion.div>
          ) : (
            <motion.div
              key="processing-layout"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              className="flex flex-col items-center justify-center p-16 text-center space-y-6"
            >
              <div className="relative">
                <div className="absolute inset-0 blur-2xl bg-primary/20 scale-150 rounded-full animate-pulse" />
                <Loader2 className="h-10 w-10 text-primary animate-spin relative z-10" />
              </div>
              <div className="space-y-1">
                <h3 className="text-lg font-bold">Connecting</h3>
                <p className="text-muted-foreground text-xs">Syncing your arrival data securely</p>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      {/* Manual Check-in */}
      <div className="text-center">
        <Drawer>
          <DrawerTrigger asChild>
            <Button
              variant="ghost"
              className="text-xs text-muted-foreground hover:text-foreground font-semibold transition-colors h-auto py-3"
            >
              Can&apos;t scan? Check-in Manually
            </Button>
          </DrawerTrigger>
          <DrawerContent className="bg-background border rounded-t-4xl">
            <div className="mx-auto w-full max-w-sm">
              <DrawerHeader className="text-left mt-4">
                <div className="w-12 h-12 rounded-2xl bg-muted flex items-center justify-center mb-4 border">
                  <QrCode className="h-6 w-6" />
                </div>
                <DrawerTitle className="text-2xl font-bold">Manual Code</DrawerTitle>
                <DrawerDescription className="text-muted-foreground font-medium">
                  Enter the code encoded in the clinic QR poster to check in manually.
                </DrawerDescription>
              </DrawerHeader>
              <div className="p-4 pb-0">
                <form id="manual-checkin-form" onSubmit={handleManualCheckIn} className="space-y-6">
                  <Input
                    placeholder="Paste code from the clinic QR poster"
                    value={manualCode}
                    onChange={(e) => setManualCode(e.target.value.toUpperCase())}
                    className="h-14 rounded-xl bg-muted/50 px-3 text-center text-sm font-bold uppercase tracking-wide sm:text-lg sm:tracking-widest"
                    maxLength={160}
                    autoComplete="off"
                  />
                </form>
              </div>
              <DrawerFooter className="pt-8 pb-8">
                <Button
                  type="submit"
                  form="manual-checkin-form"
                  className="w-full h-14 rounded-xl text-base font-bold"
                  disabled={manualCode.length < 4 || isProcessing}
                >
                  {isProcessing ? (
                    <Loader2 className="h-5 w-5 animate-spin" />
                  ) : (
                    "Verify & Check-in"
                  )}
                </Button>
                <DrawerClose asChild>
                  <Button variant="outline" className="h-14 rounded-xl font-bold">
                    Cancel
                  </Button>
                </DrawerClose>
              </DrawerFooter>
            </div>
          </DrawerContent>
        </Drawer>
      </div>
    </div>
  );
}

"use client";

import { useMemo } from "react";
import { useRouter } from "next/navigation";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { useAuth } from "@/hooks/auth/useAuth";
import { useMyAppointments } from "@/hooks/query/useAppointments";
import { useClinicContext } from "@/hooks/query/useClinics";
import {
  usePatientMedicalRecords,
  usePatientVitalSigns,
} from "@/hooks/query/usePatients";
import {
  usePatientPrescriptions,
  useComprehensiveHealthRecord,
} from "@/hooks/query/useMedicalRecords";
import { useWebSocketQuerySync } from "@/hooks/realtime/useRealTimeQueries";
import { useTranslation } from "@/lib/i18n/context";
import { theme } from "@/lib/utils/theme-utils";
import {
  Activity,
  Calendar,
  FileText,
  Pill,
  Clock,
  CheckCircle,
  Plus,
  Video,
  MapPin,
  Heart,
  Leaf,
  Sun,
  Moon,
  Waves,
  Stethoscope,
} from "lucide-react";
import { Skeleton } from "@/components/ui/skeleton";
import { ClinicSelectDialog } from "@/components/appointments/ClinicSelectDialog";
import { BookAppointmentDialog } from "@/components/appointments/BookAppointmentDialog";
import { PatientQueueCard } from "@/components/dashboard/PatientQueueCard";

export default function PatientDashboard() {
  const { session } = useAuth();
  const router = useRouter();
  const user = session?.user;
  const { t } = useTranslation();

  // Enable real-time WebSocket sync
  useWebSocketQuerySync();

  const { clinicId } = useClinicContext();
  const patientId = user?.id || "";

  // Fetch real data using hooks with loading and error states
  const { data: appointmentsData, isPending: isPendingAppointments } = useMyAppointments();
  const { data: medicalRecordsData } = usePatientMedicalRecords(
    clinicId || "",
    patientId
  );
  const { data: vitalSignsData, isPending: isPendingVitals } = usePatientVitalSigns(patientId);
  const { data: prescriptionsData, isPending: isPendingPrescriptions } = usePatientPrescriptions(
    patientId,
    "active"
  );
  const { data: comprehensiveData, isPending: isPendingComprehensive } = useComprehensiveHealthRecord(patientId);

  // Transform real data
  const patientData = useMemo(() => {
    // Helper for safe date formatting
    const safeFormatDate = (dateString: any, options?: Intl.DateTimeFormatOptions) => {
      try {
        if (!dateString) return "";
        const date = new Date(dateString);
        if (isNaN(date.getTime())) return "";
        return date.toLocaleDateString("en-US", options);
      } catch (e) {
        return "";
      }
    };

    const safeFormatTime = (dateString: any, options?: Intl.DateTimeFormatOptions) => {
      try {
        if (!dateString) return "";
        const date = new Date(dateString);
        if (isNaN(date.getTime())) return "";
        return date.toLocaleTimeString("en-US", options);
      } catch (e) {
        return "";
      }
    };

    const appointments = Array.isArray(appointmentsData?.appointments) ? appointmentsData.appointments : [];
    
    // Safety check for appointments array
    const upcomingAppointments = Array.isArray(appointments) 
      ? appointments
          .filter((apt: any) => {
            try {
               return new Date(apt.startTime || apt.date) >= new Date();
            } catch { return false; }
          })
          .slice(0, 5)
          .map((apt: any) => ({
            id: apt.id,
            doctor:
              apt.doctor?.name ||
              `${apt.doctor?.firstName || ""} ${
                apt.doctor?.lastName || ""
              }`.trim() ||
              "Unknown Doctor",
            type: apt.type || apt.appointmentType || "Consultation",
            date: apt.startTime
              ? safeFormatDate(apt.startTime).split("T")[0] // Fallback if regular date
              : "",
            time: safeFormatTime(apt.startTime, {
                 hour: "2-digit",
                 minute: "2-digit",
            }),
            location: apt.location || apt.clinic?.name || "Clinic",
            status: apt.status || "Scheduled",
            isOnline: apt.isOnline || false,
          }))
      : [];

    const latestVitals = (vitalSignsData as any)?.[0] || {};
    const latestPrescriptions = Array.isArray(prescriptionsData) ? prescriptionsData : [];

    const calculateAge = (dob: any) => {
      if (!dob) return null;
      try {
        const date = new Date(dob);
        if (isNaN(date.getTime())) return null;
        return Math.floor(
          (new Date().getTime() - date.getTime()) /
          (1000 * 60 * 60 * 24 * 365)
        );
      } catch { return null; }
    };

    return {
      personalInfo: {
        name:
          user?.name ||
          `${user?.firstName || ""} ${user?.lastName || ""}`.trim() ||
          "Patient",
        age: calculateAge((user as any)?.dateOfBirth),
        gender: (user as any)?.gender || "Unknown",
        phone: (user as any)?.phone || (user as any)?.phoneNumber || "",
        email: user?.email || "",
      },
      healthOverview: {
        primaryDosha: (comprehensiveData as any)?.doshaBalance?.dominant || "Unknown",
        currentTreatment: (medicalRecordsData as any)?.[0]?.treatment || "None",
        treatmentProgress: 0, 
        nextAppointment: upcomingAppointments[0]?.date || null,
        lastVisit:
          appointments
            .filter(
              (apt: any) =>
                apt.status === "COMPLETED" || apt.status === "completed"
            )
            .sort(
              (a: any, b: any) =>
                new Date(b.startTime || b.date).getTime() -
                new Date(a.startTime || a.date).getTime()
            )[0]?.time || null,
      },
      upcomingAppointments,
      recentActivity: [] as Array<{ type: string; message: string; time: string }>,
      currentTreatments: [] as Array<{ name: string; type: string; doctor: string; progress: number; nextSession: string }>,
      medications: latestPrescriptions.slice(0, 5).map((presc: any) => ({
        name: presc.medicineName || presc.name || "Unknown",
        dosage: presc.dosage || "As prescribed",
        nextRefill: presc.nextRefillDate ? safeFormatDate(presc.nextRefillDate) : null,
      })),
      vitalStats: {
        bloodPressure: latestVitals.bloodPressure || "N/A",
        heartRate: latestVitals.heartRate || "N/A",
        weight: latestVitals.weight || "N/A",
        lastUpdated: latestVitals.recordedAt
          ? safeFormatDate(latestVitals.recordedAt)
          : "N/A",
      },
      doshaBalance: (comprehensiveData as any)?.doshaBalance || {
        vata: 0,
        pitta: 0,
        kapha: 0,
        dominant: "Unknown",
      },
    };
  }, [
    appointmentsData,
    medicalRecordsData,
    vitalSignsData,
    prescriptionsData,
    comprehensiveData,
    user,
  ]);

  const getStatusColor = (status: string) => {
    switch (status) {
      case "Confirmed":
        return theme.badges.green;
      case "Pending":
        return theme.badges.yellow;
      case "Cancelled":
        return theme.badges.red;
      default:
        return theme.badges.gray;
    }
  };

  const getDoshaIcon = (dosha: string) => {
    switch (dosha.toLowerCase()) {
      case "vata":
        return <Waves className="w-4 h-4" />;
      case "pitta":
        return <Sun className="w-4 h-4" />;
      case "kapha":
        return <Moon className="w-4 h-4" />;
      default:
        return <Leaf className="w-4 h-4" />;
    }
  };

  return (
    
        <div className="space-y-6">
          <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
            <div className="max-w-full overflow-hidden">
              <h1
                className={`text-2xl sm:text-3xl font-bold bg-linear-to-r from-blue-600 to-purple-600 dark:from-blue-400 dark:to-purple-400 bg-clip-text text-transparent truncate`}
              >
                {t("dashboard.welcomeBack")},{" "}
                {patientData.personalInfo.name.split(" ")[0]}
              </h1>
              <p className={theme.textColors.muted}>
                {t("dashboard.overview")}
              </p>
            </div>
            <div className="flex flex-wrap items-center gap-2">
              <Button
                variant="outline"
                className="flex items-center gap-2 hover:scale-105 transition-transform"
                onClick={() => router.push('/patient/check-in')}
              >
                <div className="w-4 h-4 flex items-center justify-center border-2 border-current rounded-sm">
                   <div className="w-2 h-2 bg-current rounded-[1px]" />
                </div>
                Scan Check-In
              </Button>
              <Button
                variant="outline"
                className="flex items-center gap-2 hover:scale-105 transition-transform"
                onClick={() => router.push("/video-appointments")}
              >
                <Video className="w-4 h-4" />
                {t("appointments.bookNew")}
              </Button>
              <ClinicSelectDialog 
                trigger={
                  <Button className="flex items-center gap-2 hover:scale-105 transition-transform bg-linear-to-r from-blue-600 to-purple-600 dark:from-blue-500 dark:to-purple-500">
                    <Plus className="w-4 h-4" />
                    {t("dashboard.bookAppointment")}
                  </Button>
                }
              />
            </div>
          </div>

          
          {/* Real-time Queue Status */}
          <div className="animate-in fade-in slide-in-from-top-4 duration-500">
             <PatientQueueCard />
          </div>

          {/* Health Overview Cards */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            {/* Diagnosis Card */}
            {isPendingComprehensive ? (
               <div className="border rounded-lg p-4 space-y-3">
                 <Skeleton className="h-4 w-1/2" />
                 <Skeleton className="h-8 w-3/4" />
                 <Skeleton className="h-3 w-1/2" />
               </div>
            ) : (
            <Card
              className={`hover:shadow-lg transition-shadow duration-300 border-l-4 ${theme.borders.green}`}
            >
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle
                  className={`text-sm font-medium ${theme.textColors.heading}`}
                >
                  {t("healthcare.diagnosis")}
                </CardTitle>
                <Leaf className={`h-4 w-4 ${theme.iconColors.green}`} />
              </CardHeader>
              <CardContent>
                <div className={`text-2xl font-bold ${theme.iconColors.green}`}>
                  {patientData.doshaBalance.dominant}
                </div>
                <p className={`text-xs ${theme.textColors.muted}`}>
                  {t("patients.personalInfo")}
                </p>
              </CardContent>
            </Card>
            )}

            {/* Treatment Card */}
            <Card
              className={`hover:shadow-lg transition-shadow duration-300 border-l-4 ${theme.borders.blue}`}
            >
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle
                  className={`text-sm font-medium ${theme.textColors.heading}`}
                >
                  {t("healthcare.treatment")}
                </CardTitle>
                <Activity className={`h-4 w-4 ${theme.iconColors.blue}`} />
              </CardHeader>
              <CardContent>
                <div className={`text-2xl font-bold ${theme.iconColors.blue}`}>
                  {patientData.healthOverview.treatmentProgress}%
                </div>
                <p className={`text-xs ${theme.textColors.muted}`}>
                  {patientData.healthOverview.currentTreatment?.slice(0, 30) || "None"}
                </p>
              </CardContent>
            </Card>

            {/* Next Appointment Card */}
            {isPendingAppointments ? (
               <div className="border rounded-lg p-4 space-y-3">
                 <Skeleton className="h-4 w-1/2" />
                 <Skeleton className="h-8 w-3/4" />
                 <Skeleton className="h-3 w-1/2" />
               </div>
            ) : (
            <Card
              className={`hover:shadow-lg transition-shadow duration-300 border-l-4 ${theme.borders.purple}`}
            >
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle
                  className={`text-sm font-medium ${theme.textColors.heading}`}
                >
                  {t("appointments.upcoming")}
                </CardTitle>
                <Calendar className={`h-4 w-4 ${theme.iconColors.purple}`} />
              </CardHeader>
              <CardContent>
                <div className={`text-lg font-bold ${theme.iconColors.purple}`}>
                  {patientData.healthOverview.nextAppointment ? new Date(
                    patientData.healthOverview.nextAppointment
                  ).toLocaleDateString("en-IN", {
                    month: "short",
                    day: "numeric",
                  }) : "No appointments"}
                </div>
                <p className={`text-xs ${theme.textColors.muted}`}>
                  {patientData.healthOverview.nextAppointment ? new Date(
                    patientData.healthOverview.nextAppointment
                  ).toLocaleTimeString("en-IN", {
                    hour: "numeric",
                    minute: "2-digit",
                    hour12: true,
                  }) : "Schedule one now"}
                </p>
              </CardContent>
            </Card>
            )}

            {/* Vitals Card */}
            {isPendingVitals ? (
               <div className="border rounded-lg p-4 space-y-3">
                 <Skeleton className="h-4 w-1/2" />
                 <Skeleton className="h-8 w-3/4" />
                 <Skeleton className="h-3 w-1/2" />
               </div>
            ) : (
            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle
                  className={`text-sm font-medium ${theme.textColors.heading}`}
                >
                  Vital Stats
                </CardTitle>
                <Heart className={`h-4 w-4 ${theme.iconColors.red}`} />
              </CardHeader>
              <CardContent>
                <div className={`text-lg font-bold ${theme.iconColors.red}`}>
                  {patientData.vitalStats.bloodPressure}
                </div>
                <p className={`text-xs ${theme.textColors.muted}`}>
                  HR: {patientData.vitalStats.heartRate}
                </p>
              </CardContent>
            </Card>
            )}
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Dosha Balance Chart */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Leaf className="w-5 h-5" />
                  Dosha Balance Analysis
                </CardTitle>
              </CardHeader>
              <CardContent>
               {isPendingComprehensive ? (
                 <div className="space-y-4">
                   <Skeleton className="h-8 w-full" />
                   <Skeleton className="h-8 w-full" />
                   <Skeleton className="h-8 w-full" />
                 </div>
               ) : (
                <div className="space-y-4">
                  <div>
                    <div className="flex items-center justify-between mb-2">
                      <div className="flex items-center gap-2">
                        {getDoshaIcon("vata")}
                        <span className="font-medium">Vata (Air & Space)</span>
                      </div>
                      <span className="text-sm font-medium">
                        {patientData.doshaBalance.vata}%
                      </span>
                    </div>
                    <div
                      className={`w-full ${theme.backgrounds.tertiary} rounded-full h-2`}
                    >
                      <div
                        className="bg-blue-500 dark:bg-blue-400 h-2 rounded-full transition-all duration-300"
                        style={{ width: `${patientData.doshaBalance.vata}%` }}
                      />
                    </div>
                  </div>

                  <div>
                    <div className="flex items-center justify-between mb-2">
                      <div className="flex items-center gap-2">
                        {getDoshaIcon("pitta")}
                        <span className="font-medium">
                          Pitta (Fire & Water)
                        </span>
                      </div>
                      <span className="text-sm font-medium">
                        {patientData.doshaBalance.pitta}%
                      </span>
                    </div>
                    <div
                      className={`w-full ${theme.backgrounds.tertiary} rounded-full h-2`}
                    >
                      <div
                        className="bg-orange-500 dark:bg-orange-400 h-2 rounded-full transition-all duration-300"
                        style={{ width: `${patientData.doshaBalance.pitta}%` }}
                      />
                    </div>
                  </div>

                  <div>
                    <div className="flex items-center justify-between mb-2">
                      <div className="flex items-center gap-2">
                        {getDoshaIcon("kapha")}
                        <span className="font-medium">
                          Kapha (Earth & Water)
                        </span>
                      </div>
                      <span className="text-sm font-medium">
                        {patientData.doshaBalance.kapha}%
                      </span>
                    </div>
                    <div
                      className={`w-full ${theme.backgrounds.tertiary} rounded-full h-2`}
                    >
                      <div
                        className="bg-green-500 dark:bg-green-400 h-2 rounded-full transition-all duration-300"
                        style={{ width: `${patientData.doshaBalance.kapha}%` }}
                      />
                    </div>
                  </div>

                  <div
                    className={`mt-4 p-3 ${theme.containers.featureGreen} rounded-lg`}
                  >
                    <p className={`text-sm ${theme.textColors.success}`}>
                      <strong>Dominant Type:</strong>{" "}
                      {patientData.doshaBalance.dominant} constitution indicates
                      a balanced combination of air/space and fire/water
                      elements.
                    </p>
                  </div>
                </div>
               )}
              </CardContent>
            </Card>

            {/* Upcoming Appointments */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Calendar className="w-5 h-5" />
                  Upcoming Appointments
                </CardTitle>
              </CardHeader>
              <CardContent>
               {isPendingAppointments ? (
                  <div className="space-y-4">
                     <Skeleton className="h-16 w-full" />
                     <Skeleton className="h-16 w-full" />
                  </div>
               ) : (
                <div className="space-y-4">
                  {patientData.upcomingAppointments.length === 0 ? (
                     <div className="text-center py-8 text-gray-500">
                        No upcoming appointments
                     </div>
                  ) : (
                  patientData.upcomingAppointments.map((appointment: any) => (
                    <div
                      key={appointment.id}
                      className={`flex items-center justify-between p-4 border rounded-lg ${theme.borders.primary} hover:bg-gray-50 dark:hover:bg-gray-800/50`}
                    >
                      <div className="flex items-center gap-3">
                        <div
                          className={`w-10 h-10 ${theme.containers.featureBlue} rounded-full flex items-center justify-center`}
                        >
                          {appointment.isOnline ? (
                            <Video
                              className={`w-5 h-5 ${theme.iconColors.blue}`}
                            />
                          ) : (
                            <Stethoscope
                              className={`w-5 h-5 ${theme.iconColors.blue}`}
                            />
                          )}
                        </div>
                        <div>
                          <h4
                            className={`font-semibold ${theme.textColors.heading}`}
                          >
                            {appointment.type}
                          </h4>
                          <p
                            className={`text-sm ${theme.textColors.secondary}`}
                          >
                            {appointment.doctor}
                          </p>
                          <div
                            className={`flex items-center gap-2 text-xs ${theme.textColors.tertiary}`}
                          >
                            {appointment.isOnline ? (
                              <div className="flex items-center gap-1">
                                <Video className="w-3 h-3" />
                                <span>Online Consultation</span>
                              </div>
                            ) : (
                              <div className="flex items-center gap-1">
                                <MapPin className="w-3 h-3" />
                                <span>{appointment.location}</span>
                              </div>
                            )}
                          </div>
                        </div>
                      </div>
                      <div className="text-right">
                        <div className="font-medium">
                          {new Date(appointment.date).toLocaleDateString(
                            "en-IN",
                            {
                              month: "short",
                              day: "numeric",
                            }
                          )}
                        </div>
                        <div
                          className={`text-sm ${theme.textColors.secondary}`}
                        >
                          {appointment.time}
                        </div>
                        <Badge className={getStatusColor(appointment.status)}>
                          {appointment.status}
                        </Badge>
                      </div>
                    </div>
                  ))
                  )}

                  <BookAppointmentDialog
                    trigger={
                      <Button variant="outline" className="w-full">
                        <Plus className="w-4 h-4 mr-2" />
                        Schedule New Appointment
                      </Button>
                    }
                  />
                </div>
               )}
              </CardContent>
            </Card>
          </div>

          {/* Current Treatments */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Activity className="w-5 h-5" />
                Current Treatment Programs
              </CardTitle>
            </CardHeader>
            <CardContent>
              {patientData.currentTreatments.length === 0 ? (
                 <div className="text-center py-4 text-gray-500">
                    No active treatment programs
                 </div>
              ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {patientData.currentTreatments.map((treatment: any, index: number) => (
                  <div key={index} className="p-4 border rounded-lg">
                    <div className="flex items-center justify-between mb-3">
                      <h4 className="font-semibold">{treatment.name}</h4>
                      <Badge variant="outline">{treatment.type}</Badge>
                    </div>

                    <p className={`text-sm ${theme.textColors.secondary} mb-3`}>
                      with {treatment.doctor}
                    </p>

                    <div className="space-y-2">
                      <div className="flex justify-between text-sm">
                        <span>Progress</span>
                        <span>{treatment.progress}%</span>
                      </div>
                      <div
                        className={`w-full ${theme.backgrounds.tertiary} rounded-full h-2`}
                      >
                        <div
                          className="bg-green-500 dark:bg-green-400 h-2 rounded-full transition-all duration-300"
                          style={{ width: `${treatment.progress}%` }}
                        />
                      </div>
                      <p className={`text-xs ${theme.textColors.tertiary}`}>
                        Next session:{" "}
                        {new Date(treatment.nextSession).toLocaleDateString()}
                      </p>
                    </div>
                  </div>
                ))}
              </div>
              )}
            </CardContent>
          </Card>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Current Medications */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Pill className="w-5 h-5" />
                  Current Ayurvedic Medications
                </CardTitle>
              </CardHeader>
              <CardContent>
               {isPendingPrescriptions ? (
                  <div className="space-y-4">
                     <Skeleton className="h-12 w-full" />
                     <Skeleton className="h-12 w-full" />
                  </div>
               ) : (
                <div className="space-y-4">
                  {patientData.medications.length === 0 ? (
