                  onChange={(v) => setPrivacy((p) => ({ ...p, shareDataWithDoctors: v }))}
                />
                <NotificationRow
                  icon={<Monitor className="w-4 h-4" />}
                  label="Allow Analytics"
                  description="Help us improve by sharing anonymous usage data"
                  value={privacy.allowAnalytics}
                  onChange={(v) => setPrivacy((p) => ({ ...p, allowAnalytics: v }))}
                />
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Lock className="w-5 h-5 text-amber-500" />
                  Security
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <NotificationRow
                  icon={<Fingerprint className="w-4 h-4" />}
                  label="Two-Factor Authentication"
                  description="Add an extra layer of security to your account"
                  value={privacy.twoFactorEnabled}
                  onChange={(v) => setPrivacy((p) => ({ ...p, twoFactorEnabled: v }))}
                />

                <div>
                  <Label className="mb-2 block">Session Timeout</Label>
                  <Select
                    value={privacy.sessionTimeout}
                    onValueChange={(v) => setPrivacy((p) => ({ ...p, sessionTimeout: v }))}
                  >
                    <SelectTrigger className="w-48">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="15">15 minutes</SelectItem>
                      <SelectItem value="30">30 minutes</SelectItem>
                      <SelectItem value="60">1 hour</SelectItem>
                      <SelectItem value="240">4 hours</SelectItem>
                      <SelectItem value="never">Never</SelectItem>
                    </SelectContent>
                  </Select>
                  <p className="text-xs text-muted-foreground mt-1">
                    Automatically log out after inactivity
                  </p>
                </div>

                <div className="pt-2 border-t">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="font-medium text-sm">Connected Devices</p>
                      <p className="text-xs text-muted-foreground">
                        Manage where you're logged in
                      </p>
                    </div>
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => toast.info("Session management coming soon")}
                    >
                      View Sessions
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Button onClick={handleSavePrivacy} disabled={isSaving} className="w-full">
              {isSaving ? "Saving..." : "Save Privacy Settings"}
            </Button>
          </TabsContent>

          {/* ── APPEARANCE ── */}
          <TabsContent value="appearance" className="space-y-4">
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Palette className="w-5 h-5 text-purple-500" />
                  Theme
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="grid grid-cols-3 gap-3">
                  {[
                    { value: "light", icon: <Sun className="w-5 h-5" />, label: "Light" },
                    { value: "dark", icon: <Moon className="w-5 h-5" />, label: "Dark" },
                    { value: "system", icon: <Monitor className="w-5 h-5" />, label: "System" },
                  ].map((t) => (
                    <button
                      key={t.value}
                      onClick={() => setAppearance((p) => ({ ...p, theme: t.value }))}
                      className={`flex flex-col items-center gap-2 p-4 rounded-xl border-2 transition-all ${
                        appearance.theme === t.value
                          ? "border-primary bg-primary/5"
                          : "border-border hover:border-muted-foreground"
                      }`}
                    >
                      <div
                        className={
                          appearance.theme === t.value ? "text-primary" : "text-muted-foreground"
                        }
                      >
                        {t.icon}
                      </div>
                      <span className="text-sm font-medium">{t.label}</span>
                      {appearance.theme === t.value && (
                        <CheckCircle className="w-4 h-4 text-primary" />
                      )}
                    </button>
                  ))}
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Globe className="w-5 h-5 text-blue-500" />
                  Regional Settings
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4 pt-2">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <Label className="mb-2 block">Language</Label>
                    <Select
                      value={appearance.language}
                      onValueChange={(v) => setAppearance((p) => ({ ...p, language: v }))}
                    >
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="en">English</SelectItem>
                        <SelectItem value="hi">Hindi</SelectItem>
                        <SelectItem value="mr">Marathi</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div>
                    <Label className="mb-2 block">Timezone</Label>
                    <Select
                      value={appearance.timezone}
                      onValueChange={(v) => setAppearance((p) => ({ ...p, timezone: v }))}
                    >
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="Asia/Kolkata">India (IST +5:30)</SelectItem>
                        <SelectItem value="UTC">UTC</SelectItem>
                        <SelectItem value="America/New_York">New York (EST)</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div>
                    <Label className="mb-2 block">Date Format</Label>
                    <Select
                      value={appearance.dateFormat}
                      onValueChange={(v) => setAppearance((p) => ({ ...p, dateFormat: v }))}
                    >
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="DD/MM/YYYY">DD/MM/YYYY</SelectItem>
                        <SelectItem value="MM/DD/YYYY">MM/DD/YYYY</SelectItem>
                        <SelectItem value="YYYY-MM-DD">YYYY-MM-DD</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div>
                    <Label className="mb-2 block">Font Size</Label>
                    <Select
                      value={appearance.fontSize}
                      onValueChange={(v) => setAppearance((p) => ({ ...p, fontSize: v }))}
                    >
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="small">Small</SelectItem>
                        <SelectItem value="medium">Medium (Default)</SelectItem>
                        <SelectItem value="large">Large</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Button onClick={handleSaveAppearance} disabled={isSaving} className="w-full">
              {isSaving ? "Saving..." : "Save Appearance Settings"}
            </Button>
          </TabsContent>

          {/* ── DANGER ZONE ── */}
          <TabsContent value="danger" className="space-y-4">
            {/* Export Data */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Download className="w-5 h-5 text-blue-500" />
                  Export Your Data
                </CardTitle>
                <CardDescription>
                  Download a copy of all your health data stored with us
                </CardDescription>
              </CardHeader>
              <CardContent className="flex justify-between items-center">
                <p className="text-sm text-muted-foreground">
                  Includes appointments, medical records, and profile data (JSON / PDF)
                </p>
                <Button variant="outline" onClick={handleExportData} className="gap-2 shrink-0">
                  <Download className="w-4 h-4" />
                  Request Export
                </Button>
              </CardContent>
            </Card>

            {/* Sign out all devices */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <LogOut className="w-5 h-5 text-orange-500" />
                  Sign Out Everywhere
                </CardTitle>
                <CardDescription>
                  Log out from all devices and active sessions
                </CardDescription>
              </CardHeader>
              <CardContent className="flex justify-between items-center">
                <p className="text-sm text-muted-foreground">
                  This will invalidate all access tokens except your current session.
                </p>
                <Button
                  variant="outline"
                  className="gap-2 border-orange-200 text-orange-600 hover:bg-orange-50 shrink-0"
                  onClick={handleLogout}
                >
                  <LogOut className="w-4 h-4" />
                  Sign Out All
                </Button>
              </CardContent>
            </Card>

            {/* Delete Account */}
            <Card className="border-destructive/30">
              <CardHeader>
                <CardTitle className="flex items-center gap-2 text-destructive">
                  <Trash2 className="w-5 h-5" />
                  Delete Account
                </CardTitle>
                <CardDescription>
                  Permanently delete your account and all associated data. This action cannot be undone.
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <Alert variant="destructive">
                  <AlertTriangle className="h-4 w-4" />
                  <AlertDescription>
                    This will permanently erase all your appointments, medical records, and personal data. There is no way to recover this information.
                  </AlertDescription>
                </Alert>

                {!showDeleteConfirm ? (
                  <Button
                    variant="destructive"
                    onClick={() => setShowDeleteConfirm(true)}
                    className="gap-2"
                  >
                    <Trash2 className="w-4 h-4" />
                    Delete My Account
                  </Button>
                ) : (
                  <div className="space-y-3 p-4 border border-destructive/30 rounded-lg bg-destructive/5">
                    <p className="text-sm font-medium">
                      Type <strong>DELETE</strong> to confirm:
                    </p>
                    <Input
                      value={deleteConfirmText}
                      onChange={(e) => setDeleteConfirmText(e.target.value)}
                      placeholder="Type DELETE here"
                      className="border-destructive/50"
                    />
                    <div className="flex gap-2">
                      <Button
                        variant="destructive"
                        disabled={deleteConfirmText !== "DELETE"}
                        onClick={() => toast.error("Account deletion requires backend support. Please contact support.")}
                        className="flex-1"
                      >
                        Permanently Delete
                      </Button>
                      <Button
                        variant="outline"
                        onClick={() => {
                          setShowDeleteConfirm(false);
                          setDeleteConfirmText("");
                        }}
                        className="flex-1"
                      >
                        Cancel
                      </Button>
                    </div>
                  </div>
                )}
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>
      </div>
    
  );
}

"use client";

import { useMemo } from "react";
import { Role } from "@/types/auth.types";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { useAuth } from "@/hooks/auth/useAuth";
import {
  usePrescriptions,
  useInventory,
  usePharmacyStats,
  useMedicineDeskQueue,
} from "@/hooks/query/usePharmacy";
import { useClinicContext } from "@/hooks/query/useClinics";
import { useWebSocketQuerySync } from "@/hooks/realtime/useRealTimeQueries";
import {
  Pill,
  Package,
  AlertTriangle,
  CheckCircle,
  Clock,
  TrendingUp,
  Plus,
  Search,
  Eye,
  Check,
} from "lucide-react";
import { getQueuePositionLabel, normalizeQueueEntry } from "@/lib/queue/queue-adapter";

export default function PharmacistDashboard() {
  useAuth();

  // Enable real-time WebSocket sync
  useWebSocketQuerySync();

  // Clinic context
  const { clinicId } = useClinicContext();

  // Fetch real data using pharmacy hooks
  const { data: prescriptions = [], isPending: prescriptionsPending } =
    usePrescriptions(clinicId || "", {
      limit: 100,
    });

  const { data: inventory = [], isPending: inventoryPending } = useInventory(
    clinicId || "",
    {
      limit: 100,
    },
  );

  const { data: pharmacyStats } = usePharmacyStats(clinicId || "");
  const { data: medicineDeskQueue = [] } = useMedicineDeskQueue(clinicId || "", !!clinicId);

  // Calculate real stats from fetched data
  const stats = {
    pendingPrescriptions:
      (prescriptions as any[]).filter(
        (p: any) => p.status === "PENDING" || p.status === "pending",
      )?.length || 0,
    awaitingPayment:
      (prescriptions as any[]).filter((p: any) => {
        const status = String(p.status || "").toUpperCase();
        const paymentStatus = String(p.paymentStatus || "PENDING").toUpperCase();
        return status === "PENDING" && paymentStatus !== "PAID";
      })?.length || 0,
    dispensedPrescriptions:
      (prescriptions as any[]).filter(
        (p: any) =>
          p.status === "FILLED" ||
          p.status === "filled" ||
          p.status === "DISPENSED" ||
          p.status === "dispensed",
      )?.length || 0,
    lowStockItems:
      (inventory as any[]).filter((i: any) => i.currentStock < i.minStock)
        ?.length || 0,
    totalHandovers: (pharmacyStats as any)?.totalHandovers || 0,
    monthlyDispensed: (pharmacyStats as any)?.monthlyDispensed || 0,
    inventoryValue:
      (pharmacyStats as any)?.inventoryValue ||
      (inventory as any[]).reduce(
        (sum: number, item: any) => sum + item.costPerUnit * item.currentStock,
        0,
      ),
    expiringItems:
      (inventory as any[]).filter((i: any) => {
        if (!i.expiryDate) return false;
        const expiry = new Date(i.expiryDate);
        const in30Days = new Date();
        in30Days.setDate(in30Days.getDate() + 30);
        return expiry <= in30Days;
      })?.length || 0,
    averagePreparationTime:
      (pharmacyStats as any)?.averagePreparationTime || 15,
  };

  // Use real prescriptions data
  const pendingPrescriptions = (Array.isArray(medicineDeskQueue) ? medicineDeskQueue : [])
    .filter((p: any) => p?.id)
    .slice(0, 10)
    .map((p: any) => {
      const entry = normalizeQueueEntry(p);
      return {
        id: entry.entryId,
        patientName: entry.patientName || "Unknown Patient",
        doctorName: entry.doctorName || "Unknown Doctor",
        prescribedAt: p.prescribedAt || p.createdAt || new Date().toISOString(),
        medicines:
          p.medicineNames ||
          p.medicines?.map((m: any) => m.name || m.medicineName) ||
          p.medicines ||
          [],
        status:
          Boolean(entry.readyForHandover) ||
          String(entry.paymentStatus || "PENDING").toUpperCase() === "PAID"
            ? "ready_to_dispense"
            : "awaiting_payment",
        priority: p.priority?.toLowerCase() || "normal",
        pendingAmount: Number(p.pendingAmount || 0),
        queuePosition: entry.position > 0 ? entry.position : null,
      };
    });

  // Use real inventory data
  const lowStockItems = (inventory as any[])
    .filter((i: any) => i.currentStock < i.minStock)
    .slice(0, 10)
    .map((i: any) => ({
      name: i.name || i.medicineName,
      currentStock: i.currentStock || i.quantity,
      minStock: i.minStock || i.minThreshold,
      unit: i.unit || "units",
    }));

  // Recent handovers from completed prescriptions
  const recentHandovers = useMemo(() => {
    return (prescriptions as any[])
      .filter(
        (p: any) =>
          p.status === "FILLED" ||
          p.status === "filled" ||
          p.status === "DISPENSED" ||
          p.status === "dispensed"
      )
      .slice(0, 5)
      .map((p: any) => ({
        id: p.id,
        patientName: p.patient?.name || p.patientName || "Unknown Patient",
        handedOverAt: p.dispensedAt
          ? new Date(p.dispensedAt).toLocaleTimeString("en-US", {
              hour: "2-digit",
              minute: "2-digit",
            })
          : "N/A",
        medicines: p.medicines?.length || 0,
        status: "completed",
      }));
  }, [prescriptions]);

  const getPriorityColor = (priority: string) => {
    switch (priority) {
