type ViewAppointment = {
  id: string;
  patientName: string;
  patientPhone: string;
  doctorId: string;
  primaryDoctorId?: string;
  assignedDoctorId?: string;
  doctorName: string;
  doctorRole?: string;
  timeLabel: string;
  status: string;
  queuePosition: number | null;
  queueType: string;
  notes: string;
  waitLabel: string;
  isWalkIn: boolean;
  isDelegated: boolean;
};

const STATUS_STYLES: Record<string, string> = {
  SCHEDULED: "bg-slate-100 text-slate-800 dark:bg-slate-900/40 dark:text-slate-200",
  CONFIRMED: "bg-emerald-100 text-emerald-800 dark:bg-emerald-900/30 dark:text-emerald-300",
  IN_PROGRESS: "bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300",
  COMPLETED: "bg-violet-100 text-violet-800 dark:bg-violet-900/30 dark:text-violet-300",
  NO_SHOW: "bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-300",
  CANCELLED: "bg-rose-100 text-rose-800 dark:bg-rose-900/30 dark:text-rose-300",
};

function normalizeAppointment(
  app: any,
  serviceCatalogMap: Map<string, { label: string; serviceBucket: string; queueCategory: string }>
): ViewAppointment {
  const startAt = app.startTime || app.appointmentDate || (app.date && app.time ? `${app.date}T${app.time}` : null);
  const parsed = startAt ? new Date(startAt) : null;

  return {
    id: app.id,
    patientName:
      app.patient?.name ||
      `${app.patient?.firstName || ""} ${app.patient?.lastName || ""}`.trim() ||
      "Unknown Patient",
    patientPhone: app.patient?.phone || "",
    doctorId: app.doctor?.id || app.doctorId || "",
    primaryDoctorId: app.primaryDoctorId || app.metadata?.primaryDoctorId || app.doctorId || "",
    assignedDoctorId: app.assignedDoctorId || app.metadata?.assignedDoctorId || app.doctorId || "",
    doctorName:
      app.doctor?.name ||
      `${app.doctor?.firstName || ""} ${app.doctor?.lastName || ""}`.trim() ||
      "Unassigned Doctor",
    doctorRole: String(app.doctor?.role || app.doctor?.user?.role || "").toUpperCase(),
    timeLabel:
      parsed && !Number.isNaN(parsed.getTime())
        ? parsed.toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit", hour12: true })
        : app.time || "TBD",
    status: String(app.status || "SCHEDULED").toUpperCase(),
    queuePosition: typeof app.queuePosition === "number" ? app.queuePosition : null,
    queueType: resolveQueueDisplayLabel(app, serviceCatalogMap),
    notes: app.notes || app.reason || "",
    waitLabel:
      typeof app.estimatedWaitTime === "number"
        ? `${app.estimatedWaitTime} min`
        : typeof app.waitTime === "number"
          ? `${app.waitTime} min`
          : typeof app.waitTime === "string"
            ? app.waitTime
            : "Pending",
    isWalkIn: Boolean(app.isWalkIn),
    isDelegated:
      Boolean(app.primaryDoctorId || app.metadata?.primaryDoctorId) &&
      String(app.primaryDoctorId || app.metadata?.primaryDoctorId || "") !==
        String(app.assignedDoctorId || app.metadata?.assignedDoctorId || app.doctorId || ""),
  };
}

export default function ReceptionistAppointmentsPage() {
  useAuth();
  const { clinicId } = useClinicContext();
  useWebSocketQuerySync();
  const { data: serviceCatalog = [] } = useAppointmentServices();

  const today = new Date().toISOString().split("T")[0] || "";
  const [searchTerm, setSearchTerm] = useState("");
  const [statusFilter, setStatusFilter] = useState("all");
  const [queueFilter, setQueueFilter] = useState("all");
  const [selectedDate, setSelectedDate] = useState(today);
  const [activeActionId, setActiveActionId] = useState<string | null>(null);
  const [activeDoctorId, setActiveDoctorId] = useState<string | null>(null);
  const [selectedReassignments, setSelectedReassignments] = useState<Record<string, string>>({});
  const [reassignmentCandidates, setReassignmentCandidates] = useState<
    Record<
      string,
      Array<{
        id: string;
        name: string;
        role: string;
        eligible: boolean;
        reason?: string;
        isCurrent: boolean;
        isPrimary: boolean;
      }>
    >
  >({});

  const {
    data: appointmentsData,
    isPending,
    refetch,
  } = useAppointments({
    ...(clinicId ? { clinicId } : {}),
    ...(selectedDate ? { date: selectedDate } : {}),
    limit: 200,
  });
  const { data: doctorsData } = useDoctors(clinicId || "", { limit: 200 });

  const assignableDoctors = useMemo(() => {
    const normalize = (users: any[]) =>
      users
        .map((user) => {
          const role = String(user.role || user.doctor?.user?.role || "").toUpperCase();
          return {
            id: user.doctor?.id || user.id,
            name:
              user.name ||
              user.doctor?.user?.name ||
              `${user.firstName || ""} ${user.lastName || ""}`.trim() ||
              "Unknown Doctor",
            role,
          };
        })
        .filter((doctor) => doctor.id && (doctor.role === "DOCTOR" || doctor.role === "ASSISTANT_DOCTOR"));

    if (Array.isArray(doctorsData)) return normalize(doctorsData);
    if (Array.isArray((doctorsData as any)?.data?.doctors)) return normalize((doctorsData as any).data.doctors);
    if (Array.isArray((doctorsData as any)?.data)) return normalize((doctorsData as any).data);
    return normalize((doctorsData as any)?.doctors || []);
  }, [doctorsData]);

  const appointments = useMemo(() => {
    const raw = Array.isArray(appointmentsData)
      ? appointmentsData
      : appointmentsData?.appointments || [];
    const serviceMap = new Map(
      serviceCatalog.map((service) => [
        String(service.treatmentType).toUpperCase(),
        {
          label: service.label,
          serviceBucket: service.serviceBucket,
          queueCategory: service.queueCategory,
        },
      ])
    );

    return raw.map((appointment) => normalizeAppointment(appointment, serviceMap));
  }, [appointmentsData, serviceCatalog]);

  const availableQueueTypes = useMemo(() => {
    return Array.from(
      new Set(appointments.map((appointment) => appointment.queueType).filter(Boolean))
    ).sort((left, right) => left.localeCompare(right));
  }, [appointments]);

  const filteredAppointments = useMemo(() => {
    return appointments.filter((appointment) => {
      const matchesSearch =
        !searchTerm ||
        appointment.patientName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        appointment.doctorName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        appointment.patientPhone.includes(searchTerm);
      const matchesStatus = statusFilter === "all" || appointment.status === statusFilter;
      const matchesQueue = queueFilter === "all" || appointment.queueType === queueFilter;
      return matchesSearch && matchesStatus && matchesQueue;
    });
  }, [appointments, queueFilter, searchTerm, statusFilter]);

  const stats = useMemo(() => {
    const total = appointments.length;
    const scheduled = appointments.filter((item) => item.status === "SCHEDULED").length;
    const confirmed = appointments.filter((item) => item.status === "CONFIRMED").length;
    const inProgress = appointments.filter((item) => item.status === "IN_PROGRESS").length;
    const completed = appointments.filter((item) => item.status === "COMPLETED").length;
    return { total, scheduled, confirmed, inProgress, completed };
  }, [appointments]);

  const doctorBacklog = useMemo(() => {
    const grouped = new Map<
      string,
      {
        doctorId: string;
        doctorName: string;
        scheduled: number;
        confirmed: number;
        inProgress: number;
        nextPatient: string | null;
      }
    >();

    for (const appointment of filteredAppointments) {
      const current = grouped.get(appointment.doctorName) || {
        doctorId: appointment.doctorId,
        doctorName: appointment.doctorName,
        scheduled: 0,
        confirmed: 0,
        inProgress: 0,
        nextPatient: null,
      };

      if (appointment.status === "SCHEDULED") current.scheduled += 1;
      if (appointment.status === "CONFIRMED") {
        current.confirmed += 1;
        if (!current.nextPatient || appointment.queuePosition === 1) {
          current.nextPatient = appointment.patientName;
        }
      }
      if (appointment.status === "IN_PROGRESS") current.inProgress += 1;
      grouped.set(appointment.doctorName, current);
    }

    return Array.from(grouped.values()).sort((a, b) => b.confirmed - a.confirmed || b.scheduled - a.scheduled);
  }, [filteredAppointments]);

  useEffect(() => {
    const pendingAppointmentIds = filteredAppointments
      .filter(
        (appointment) =>
          (appointment.status === "SCHEDULED" || appointment.status === "CONFIRMED") &&
          !reassignmentCandidates[appointment.id]
      )
      .map((appointment) => appointment.id);

    if (pendingAppointmentIds.length === 0) {
      return;
    }

    let cancelled = false;

    void (async () => {
      const responses = await Promise.all(
        pendingAppointmentIds.map(async (appointmentId) => {
          const result = await getAppointmentReassignmentCandidates(appointmentId);
          return {
            appointmentId,
            candidates: result.success ? result.candidates || [] : [],
          };
        })
      );

      if (cancelled) {
        return;
      }

      setReassignmentCandidates((current) => {
        const next = { ...current };
        for (const response of responses) {
          next[response.appointmentId] = response.candidates;
        }
        return next;
      });
    })();

    return () => {
      cancelled = true;
    };
  }, [filteredAppointments, reassignmentCandidates]);

  async function handleConfirmArrival(appointmentId: string) {
    setActiveActionId(appointmentId);
    const result = await checkInAppointment(appointmentId);
    if (result.success) {
      showSuccessToast("Patient confirmed and added to queue", { id: TOAST_IDS.APPOINTMENT.CHECK_IN });
      await refetch?.();
    } else {
      showErrorToast(result.error || "Failed to confirm patient arrival", { id: TOAST_IDS.APPOINTMENT.CHECK_IN });
    }
    setActiveActionId(null);
  }

  async function handleMarkNoShow(appointmentId: string) {
    setActiveActionId(appointmentId);
    const result = await updateAppointmentStatus(appointmentId, { status: "NO_SHOW" });
    if (result.success) {
      showSuccessToast("Appointment marked as no-show", { id: TOAST_IDS.APPOINTMENT.UPDATE });
      await refetch?.();
    } else {
      showErrorToast(result.error || "Failed to mark no-show", { id: TOAST_IDS.APPOINTMENT.UPDATE });
    }
    setActiveActionId(null);
  }

  async function handleNotifyNext(doctorId: string) {
    if (!doctorId) {
      showErrorToast("Doctor is required to call the next patient");
      return;
    }

    setActiveDoctorId(doctorId);
    const result = (await callNextPatient(doctorId, "clinic")) as
      | { success?: boolean; message?: string }
      | null;
    if (result?.success) {
      showSuccessToast("Next patient moved into consultation", { id: TOAST_IDS.QUEUE.CALL_NEXT });
      await refetch?.();
    } else {
      showErrorToast(result?.message || "No waiting patient available for this doctor", {
        id: TOAST_IDS.QUEUE.CALL_NEXT,
      });
    }
    setActiveDoctorId(null);
  }

  async function handleReassignDoctor(appointmentId: string) {
    const selectedDoctorId = selectedReassignments[appointmentId];
    if (!selectedDoctorId) {
      showErrorToast("Select a doctor or assistant doctor first");
      return;
    }

    setActiveActionId(appointmentId);
    const result = await reassignAppointmentDoctor(appointmentId, {
      doctorId: selectedDoctorId,
      reason: "Reception desk reassignment",
    });

    if (result.success) {
      showSuccessToast("Appointment reassigned successfully", {
        id: TOAST_IDS.APPOINTMENT.UPDATE,
      });
      const refreshedCandidates = await getAppointmentReassignmentCandidates(appointmentId);
      if (refreshedCandidates.success && refreshedCandidates.candidates) {
        setReassignmentCandidates((current) => ({
          ...current,
          [appointmentId]: refreshedCandidates.candidates || [],
        }));
      }
      setSelectedReassignments((current) => {
        const next = { ...current };
        delete next[appointmentId];
        return next;
      });
      await refetch?.();
    } else {
      showErrorToast(result.error || "Failed to reassign appointment", {
        id: TOAST_IDS.APPOINTMENT.UPDATE,
      });
    }

    setActiveActionId(null);
  }

  return (
    <div className="p-4 md:p-6 space-y-6">
      <div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
        <div>
          <h1 className="text-3xl font-bold">Reception Queue Workspace</h1>
          <p className="text-muted-foreground">
            Schedule appointments, confirm arrivals, and manage the doctor backlog with live data
          </p>
        </div>
        <div className="flex flex-col sm:flex-row gap-2">
          <Button asChild variant="outline">
            <Link href="/receptionist/check-in">
              <QrCode className="w-4 h-4 mr-2" />
              QR / Manual Check-In
            </Link>
          </Button>
          <BookAppointmentDialog
            {...(clinicId ? { clinicId } : {})}
            trigger={
              <Button>
                <Calendar className="w-4 h-4 mr-2" />
                New Appointment
              </Button>
            }
          />
        </div>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-5 gap-4">
        <Card><CardContent className="p-4"><div className="text-sm text-muted-foreground">Total</div><div className="text-2xl font-bold">{stats.total}</div></CardContent></Card>
        <Card><CardContent className="p-4"><div className="text-sm text-muted-foreground">Scheduled</div><div className="text-2xl font-bold">{stats.scheduled}</div></CardContent></Card>
        <Card><CardContent className="p-4"><div className="text-sm text-muted-foreground">Queued</div><div className="text-2xl font-bold text-emerald-700 dark:text-emerald-300">{stats.confirmed}</div></CardContent></Card>
        <Card><CardContent className="p-4"><div className="text-sm text-muted-foreground">In Progress</div><div className="text-2xl font-bold text-blue-700 dark:text-blue-300">{stats.inProgress}</div></CardContent></Card>
        <Card><CardContent className="p-4"><div className="text-sm text-muted-foreground">Completed</div><div className="text-2xl font-bold text-violet-700 dark:text-violet-300">{stats.completed}</div></CardContent></Card>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Search and Filter</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid gap-3 md:grid-cols-4">
            <div className="relative md:col-span-2">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
              <Input
                className="pl-9"
                placeholder="Search patient, doctor, or phone"
                value={searchTerm}
                onChange={(event) => setSearchTerm(event.target.value)}
              />
            </div>
            <Input type="date" value={selectedDate} onChange={(event) => setSelectedDate(event.target.value)} />
            <div className="grid grid-cols-2 gap-3">
              <Select value={statusFilter} onValueChange={setStatusFilter}>
                <SelectTrigger><SelectValue placeholder="Status" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All</SelectItem>
                  <SelectItem value="SCHEDULED">Scheduled</SelectItem>
                  <SelectItem value="CONFIRMED">Confirmed</SelectItem>
                  <SelectItem value="IN_PROGRESS">In Progress</SelectItem>
                  <SelectItem value="COMPLETED">Completed</SelectItem>
                  <SelectItem value="NO_SHOW">No Show</SelectItem>
                </SelectContent>
              </Select>
              <Select value={queueFilter} onValueChange={setQueueFilter}>
                <SelectTrigger><SelectValue placeholder="Queue" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Queues</SelectItem>
                  {availableQueueTypes.map((queueType) => (
                    <SelectItem key={queueType} value={queueType}>
                      {queueType}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Stethoscope className="w-5 h-5" />
            Doctor Queue Backlog
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-3">
          {doctorBacklog.length === 0 ? (
            <p className="text-sm text-muted-foreground">
              {isPending ? "Loading doctor backlog..." : "No appointments match the selected filters."}
            </p>
          ) : (
            doctorBacklog.map((doctor) => (
              <div key={doctor.doctorName} className="rounded-xl border bg-card p-4 flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
                <div>
                  <p className="font-semibold">{doctor.doctorName}</p>
                  <p className="text-sm text-muted-foreground">
                    {doctor.nextPatient ? `Next queued patient: ${doctor.nextPatient}` : "No confirmed patient waiting"}
                  </p>
                </div>
                <div className="flex flex-wrap gap-2">
                  <Badge variant="secondary">Scheduled {doctor.scheduled}</Badge>
                  <Badge className={STATUS_STYLES.CONFIRMED}>Queued {doctor.confirmed}</Badge>
                  <Badge className={STATUS_STYLES.IN_PROGRESS}>In Progress {doctor.inProgress}</Badge>
                </div>
                <Button
                  variant="outline"
                  disabled={!doctor.doctorId || activeDoctorId === doctor.doctorId}
                  onClick={() => void handleNotifyNext(doctor.doctorId)}
                >
                  {activeDoctorId === doctor.doctorId ? (
                    <Loader2 className="w-4 h-4 animate-spin mr-2" />
                  ) : (
                    <Bell className="w-4 h-4 mr-2" />
                  )}
                  Notify Next
                </Button>
              </div>
            ))
          )}
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <UserCheck className="w-5 h-5" />
            Appointment List
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          {isPending ? (
            <div className="flex items-center justify-center py-10 text-muted-foreground">
              <Loader2 className="w-5 h-5 animate-spin mr-2" />
              Loading appointments...
            </div>
          ) : filteredAppointments.length === 0 ? (
            <p className="text-sm text-muted-foreground">No appointments match the current search and filter values.</p>
          ) : (
            filteredAppointments.map((appointment) => {
              const canConfirmArrival = appointment.status === "SCHEDULED";
              const canMarkNoShow = appointment.status === "SCHEDULED" || appointment.status === "CONFIRMED";

              return (
                <div key={appointment.id} className="rounded-xl border bg-card p-4 space-y-3">
                  <div className="flex flex-col gap-3 lg:flex-row lg:items-start lg:justify-between">
                    <div className="space-y-1">
                      <div className="flex flex-wrap items-center gap-2">
                        <p className="font-semibold">{appointment.patientName}</p>
                        {appointment.isWalkIn ? <Badge variant="outline">Walk-in</Badge> : null}
                        <Badge className={STATUS_STYLES[appointment.status] || STATUS_STYLES.SCHEDULED}>
                          {appointment.status.replaceAll("_", " ")}
                        </Badge>
                      </div>
                      <p className="text-sm text-muted-foreground">{appointment.doctorName}</p>
                      <div className="flex flex-wrap gap-3 text-xs text-muted-foreground">
                        <span>{appointment.patientPhone || "No phone"}</span>
                        <span>{appointment.timeLabel}</span>
                        <span>{appointment.queueType}</span>
                        <span>{getQueuePositionLabel({ position: appointment.queuePosition ?? 0 })}</span>
                        <span>Wait {appointment.waitLabel}</span>
                        <span>
                          Serving doctor: {appointment.doctorName}
                          {appointment.doctorRole === "ASSISTANT_DOCTOR" ? " (Assistant Doctor)" : ""}
                        </span>
                        {appointment.isDelegated ? (
                          <span>Delegated from primary doctor</span>
                        ) : null}
                      </div>
                      {appointment.notes ? <p className="text-sm text-muted-foreground">{appointment.notes}</p> : null}
                    </div>

                    <div className="flex flex-col gap-2 lg:items-end">
                      {(appointment.status === "SCHEDULED" || appointment.status === "CONFIRMED") ? (
                        <div className="flex flex-col gap-2 sm:flex-row">
                          {(() => {
                            const candidates =
                              reassignmentCandidates[appointment.id] ||
                              assignableDoctors.map((doctor) => ({
                                ...doctor,
                                eligible: true,
                                isCurrent: doctor.id === appointment.doctorId,
                                isPrimary: doctor.id === appointment.doctorId,
                              }));

                            const selectedCandidate = candidates.find(
                              (candidate) =>
                                candidate.id ===
                                (selectedReassignments[appointment.id] || appointment.doctorId)
                            );

                            return (
                              <>
                          <Select
                            value={selectedReassignments[appointment.id] || appointment.doctorId}
                            onValueChange={(value) =>
                              setSelectedReassignments((current) => ({
                                ...current,
                                [appointment.id]: value,
                              }))
                            }
                          >
                            <SelectTrigger className="min-w-[220px]">
                              <SelectValue placeholder="Assign doctor" />
                            </SelectTrigger>
                            <SelectContent>
                              {candidates.map((doctor) => (
                                <SelectItem
                                  key={doctor.id}
                                  value={doctor.id}
                                  disabled={!doctor.eligible && !doctor.isCurrent}
                                >
                                  {doctor.name}
                                  {doctor.role === "ASSISTANT_DOCTOR" ? " (Assistant)" : ""}
                                  {!doctor.eligible && !doctor.isCurrent ? " - Unavailable" : ""}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                          {selectedCandidate && !selectedCandidate.eligible && !selectedCandidate.isCurrent ? (
                            <p className="text-xs text-amber-600 dark:text-amber-300">
                              {selectedCandidate.reason || "This servicing doctor is not eligible"}
                            </p>
                          ) : null}
                          <Button
                            variant="outline"
                            onClick={() => void handleReassignDoctor(appointment.id)}
                            disabled={
                              activeActionId === appointment.id ||
                              !selectedReassignments[appointment.id] ||
                              selectedReassignments[appointment.id] === appointment.doctorId
                            }
                          >
                            Reassign Doctor
                          </Button>
                              </>
                            );
                          })()}
                        </div>
                      ) : null}
                      <div className="flex flex-wrap gap-2">
                      {canConfirmArrival ? (
                        <Button
                          onClick={() => void handleConfirmArrival(appointment.id)}
                          disabled={activeActionId === appointment.id}
                        >
                          {activeActionId === appointment.id ? (
                            <Loader2 className="w-4 h-4 animate-spin mr-2" />
                          ) : (
                            <UserCheck className="w-4 h-4 mr-2" />
                          )}
                          Confirm Arrival
                        </Button>
                      ) : null}
                      {canMarkNoShow ? (
                        <Button
                          variant="outline"
                          onClick={() => void handleMarkNoShow(appointment.id)}
                          disabled={activeActionId === appointment.id}
                        >
                          Mark No Show
                        </Button>
                      ) : null}
                      </div>
                    </div>
                  </div>
                </div>
              );
            })
          )}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

// 1. React & Next.js
import { useState } from "react";
// 2. External libraries
import {
  Search,
  CheckCircle2,
  UserCheck,
  Loader2,
  Calendar,
  Clock,
  Stethoscope,
} from "lucide-react";
// 3. Internal components
import { Role } from "@/types/auth.types";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
// 4. Hooks & config

import { useAuth } from "@/hooks/auth/useAuth";
import { useClinicContext } from "@/hooks/query/useClinics";
import { useAppointments } from "@/hooks/query/useAppointments";
import { showSuccessToast, showErrorToast, TOAST_IDS } from "@/hooks/utils/use-toast";
// 5. Server actions & utils
import { checkInAppointment } from "@/lib/actions/appointments.server";
import { sanitizeErrorMessage } from "@/lib/utils/error-handler";
import { logger } from "@/lib/utils/logger";
// 6. Types
/** Minimal appointment list item shape for API response */
interface AppointmentListItem {
  id: string;
  status?: string;
  startTime?: string;
  time?: string;
  patient?: { name?: string; firstName?: string; lastName?: string; phone?: string };
  doctor?: { name?: string; firstName?: string; lastName?: string };
}

export default function ReceptionistCheckInPage() {
  useAuth();
  const { clinicId } = useClinicContext();
  const [searchTerm, setSearchTerm] = useState("");
  const [checkingInId, setCheckingInId] = useState<string | null>(null);
  const today = new Date().toISOString().split("T")[0] || "";

  const { data: appointmentsData, isPending: isLoading, refetch } = useAppointments({
    ...(clinicId ? { clinicId } : {}),
    date: today,
    limit: 100,
  });

  const appointments: AppointmentListItem[] = Array.isArray(appointmentsData)
    ? appointmentsData
    : appointmentsData?.appointments || [];

  const canConfirmArrival = (status?: string) =>
    ["SCHEDULED"].includes((status || "").toUpperCase());

  const filteredAppointments = appointments.filter((apt: AppointmentListItem) => {
    const patientName =
      apt.patient?.name ||
      `${apt.patient?.firstName || ""} ${apt.patient?.lastName || ""}`.trim() ||
      "";
    const doctorName =
      apt.doctor?.name ||
      `${apt.doctor?.firstName || ""} ${apt.doctor?.lastName || ""}`.trim() ||
      "";
    const matchesSearch =
      !searchTerm ||
      patientName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      doctorName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (apt.patient?.phone || "").includes(searchTerm);
    return matchesSearch;
  });

  const handleCheckIn = async (appointmentId: string) => {
    setCheckingInId(appointmentId);
    try {
      const result = await checkInAppointment(appointmentId);
      if (result.success) {
        showSuccessToast("Patient confirmed and added to queue", {
          id: TOAST_IDS.APPOINTMENT.CHECK_IN,
        });
        refetch?.();
      } else {
        showErrorToast(result.error || "Failed to check in", {
          id: TOAST_IDS.APPOINTMENT.CHECK_IN,
        });
      }
    } catch (error) {
      logger.error("Arrival confirmation failed", error instanceof Error ? error : undefined, {
        component: "ReceptionistCheckInPage",
        appointmentId,
      });
      showErrorToast(sanitizeErrorMessage(error), {
        id: TOAST_IDS.APPOINTMENT.CHECK_IN,
      });
    } finally {
      setCheckingInId(null);
    }
  };


  if (isLoading) {
    return (
      
          <div className="p-6 flex items-center justify-center min-h-[400px]">
            <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
          </div>
      
    );
  }

  return (
    
        <div className="p-6 space-y-6">
          <div className="flex items-center justify-between">
            <h1 className="text-2xl font-bold flex items-center gap-2">
              <UserCheck className="w-7 h-7" />
              Patient Arrival Confirmation
            </h1>
            <div className="text-sm text-muted-foreground flex items-center gap-2">
              <Calendar className="w-4 h-4" />
              {new Date().toLocaleDateString("en-IN", {
                weekday: "long",
                year: "numeric",
                month: "long",
                day: "numeric",
              })}
            </div>
          </div>

          <Card>
            <CardHeader>
              <CardTitle className="text-lg">Today&apos;s Appointments</CardTitle>
              <p className="text-sm text-muted-foreground">
                Confirm patients as they arrive at reception and place them in the doctor queue
              </p>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <Input
                  placeholder="Search by patient name, doctor, or phone..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-9"
                />
              </div>

              <div className="rounded-lg border overflow-hidden">
                <div className="overflow-x-auto max-h-[500px]">
                  <table className="w-full">
                    <thead className="bg-muted/50 sticky top-0">
                      <tr>
                        <th className="text-left p-3 text-sm font-medium">Patient</th>
                        <th className="text-left p-3 text-sm font-medium">Doctor</th>
                        <th className="text-left p-3 text-sm font-medium">Time</th>
                        <th className="text-left p-3 text-sm font-medium">Status</th>
                        <th className="text-right p-3 text-sm font-medium">Action</th>
                      </tr>
                    </thead>
                    <tbody>
                      {filteredAppointments.length === 0 ? (
                        <tr>
                          <td colSpan={5} className="p-8 text-center text-muted-foreground">
                            No appointments for today
                          </td>
                        </tr>
                      ) : (
                        filteredAppointments.map((apt: AppointmentListItem) => {
                          const patientName =
                            apt.patient?.name ||
                            `${apt.patient?.firstName || ""} ${apt.patient?.lastName || ""}`.trim() ||
                            "Unknown";
                          const doctorName =
                            apt.doctor?.name ||
                            `${apt.doctor?.firstName || ""} ${apt.doctor?.lastName || ""}`.trim() ||
                            "Unknown";
                          const time =
                            apt.startTime || apt.time
                              ? new Date((apt.startTime || apt.time)!).toLocaleTimeString("en-IN", {
                                  hour: "2-digit",
                                  minute: "2-digit",
                                  hour12: true,
                                })
                              : "—";
                          const status = apt.status || "Scheduled";
                          const normalizedStatus = String(status || "").toUpperCase();
                          const isConfirmedArrival = ["CONFIRMED", "IN_PROGRESS", "COMPLETED"].includes(
                            normalizedStatus
                          );
                          const canCheckInThis = canConfirmArrival(status);

                          return (
                            <tr
                              key={apt.id}
                              className="border-t hover:bg-muted/30 transition-colors"
                            >
                              <td className="p-3">
                                <div className="font-medium">{patientName}</div>
                                {apt.patient?.phone && (
                                  <div className="text-xs text-muted-foreground">
                                    {apt.patient.phone}
                                  </div>
                                )}
                              </td>
                              <td className="p-3">
                                <div className="flex items-center gap-2">
                                  <Stethoscope className="w-4 h-4 text-muted-foreground" />
                                  {doctorName}
                                </div>
                              </td>
                              <td className="p-3">
                                <div className="flex items-center gap-2">
                                  <Clock className="w-4 h-4 text-muted-foreground" />
                                  {time}
                                </div>
                              </td>
                              <td className="p-3">
                                <Badge
                                  variant={isConfirmedArrival ? "default" : "secondary"}
                                  className={
                                    isConfirmedArrival
                                      ? "bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400"
                                      : ""
                                  }
                                >
                                  {status}
                                </Badge>
                              </td>
                              <td className="p-3 text-right">
                                {canCheckInThis ? (
                                  <Button
                                    size="sm"
                                    onClick={() => handleCheckIn(apt.id)}
                                    disabled={checkingInId === apt.id}
                                  >
                                    {checkingInId === apt.id ? (
                                      <Loader2 className="w-4 h-4 animate-spin" />
                                    ) : (
                                      <>
                                        <CheckCircle2 className="w-4 h-4 mr-1" />
                                        Confirm Arrival
                                      </>
                                    )}
                                  </Button>
                                ) : isConfirmedArrival ? (
                                  <span className="text-sm text-green-600 flex items-center justify-end gap-1">
                                    <CheckCircle2 className="w-4 h-4" />
                                    Confirmed
                                  </span>
                                ) : (
                                  <span className="text-sm text-muted-foreground">—</span>
                                )}
                              </td>
                            </tr>
                          );
                        })
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>
    
  );
}

"use client";

import Link from "next/link";
import { useMemo } from "react";
import { Calendar, CheckCircle, Clock, ListTodo, QrCode, Users } from "lucide-react";

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { BookAppointmentDialog } from "@/components/appointments/BookAppointmentDialog";
import { useAuth } from "@/hooks/auth/useAuth";
import { useAppointments } from "@/hooks/query/useAppointments";
import { useClinicContext } from "@/hooks/query/useClinics";
import { useMedicineDeskQueue } from "@/hooks/query/usePharmacy";
import { useWebSocketQuerySync } from "@/hooks/realtime/useRealTimeQueries";
import { getQueuePositionLabel, normalizeQueueEntry } from "@/lib/queue/queue-adapter";

type ReceptionAppointment = {
  id: string;
  patientName: string;
  doctorName: string;
  doctorRole?: string;
  isDelegated: boolean;
  status: string;
  timeLabel: string;
  queuePosition: number | null;
  waitLabel: string;
  queueCategory?: string;
};

const STATUS_STYLES: Record<string, string> = {
  SCHEDULED: "bg-slate-100 text-slate-800 dark:bg-slate-900/40 dark:text-slate-200",
  CONFIRMED: "bg-emerald-100 text-emerald-800 dark:bg-emerald-900/30 dark:text-emerald-300",
  IN_PROGRESS: "bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300",
  COMPLETED: "bg-violet-100 text-violet-800 dark:bg-violet-900/30 dark:text-violet-300",
  NO_SHOW: "bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-300",
  CANCELLED: "bg-rose-100 text-rose-800 dark:bg-rose-900/30 dark:text-rose-300",
};

export default function ReceptionistDashboard() {
  useAuth();
  const { clinicId } = useClinicContext();
  useWebSocketQuerySync();

  const today = new Date().toISOString().split("T")[0] || "";
  const { data: appointmentsData, isPending } = useAppointments({
    ...(clinicId ? { clinicId } : {}),
    date: today,
    limit: 200,
  });
  const { data: medicineDeskQueue = [] } = useMedicineDeskQueue(clinicId || "", !!clinicId);

  const appointments = useMemo(() => {
    const raw = Array.isArray(appointmentsData)
      ? appointmentsData
      : appointmentsData?.appointments || [];
    return raw.map(appointment => {
      const canonical = normalizeQueueEntry(appointment);
      const startAt = appointment.startTime || appointment.appointmentDate || (appointment.date && appointment.time ? `${appointment.date}T${appointment.time}` : null);
      const parsed = startAt ? new Date(startAt) : null;

      return {
        id: canonical.entryId || canonical.appointmentId || appointment.id,
        patientName: canonical.patientName || "Unknown Patient",
        doctorName: canonical.doctorName || "Unassigned Doctor",
        doctorRole: String(appointment.doctor?.role || appointment.doctor?.user?.role || "").toUpperCase(),
        isDelegated:
          Boolean(canonical.primaryDoctorId || appointment.primaryDoctorId || appointment.metadata?.primaryDoctorId) &&
          String(canonical.primaryDoctorId || appointment.primaryDoctorId || appointment.metadata?.primaryDoctorId || "") !==
            String(canonical.assignedDoctorId || appointment.assignedDoctorId || appointment.metadata?.assignedDoctorId || appointment.doctorId || ""),
        status: canonical.status,
        timeLabel:
          parsed && !Number.isNaN(parsed.getTime())
            ? parsed.toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit", hour12: true })
            : appointment.time || "TBD",
        queuePosition: canonical.position > 0 ? canonical.position : null,
        waitLabel:
          typeof canonical.estimatedWaitTime === "number"
            ? `${canonical.estimatedWaitTime} min`
            : typeof appointment.waitTime === "number"
              ? `${appointment.waitTime} min`
              : typeof appointment.waitTime === "string"
                ? appointment.waitTime
                : "Pending",
        queueCategory: canonical.queueCategory,
      };
    });
  }, [appointmentsData]);

  const stats = useMemo(() => {
    const total = appointments.length;
    const scheduled = appointments.filter((item) => item.status === "SCHEDULED").length;
    const confirmed = appointments.filter((item) => item.status === "CONFIRMED").length;
    const inProgress = appointments.filter((item) => item.status === "IN_PROGRESS").length;
    const completed = appointments.filter((item) => item.status === "COMPLETED").length;

    return { total, scheduled, confirmed, inProgress, completed };
  }, [appointments]);

  const doctorBacklog = useMemo(() => {
    const grouped = new Map<
      string,
      {
        doctorName: string;
        scheduled: number;
        confirmed: number;
        inProgress: number;
        total: number;
        nextPatient: string | null;
      }
    >();

    for (const appointment of appointments) {
      const current = grouped.get(appointment.doctorName) || {
        doctorName: appointment.doctorName,
        scheduled: 0,
        confirmed: 0,
        inProgress: 0,
        total: 0,
        nextPatient: null,
      };

      current.total += 1;
      if (appointment.status === "SCHEDULED") current.scheduled += 1;
      if (appointment.status === "CONFIRMED") {
        current.confirmed += 1;
        if (!current.nextPatient || appointment.queuePosition === 1) {
          current.nextPatient = appointment.patientName;
        }
      }
      if (appointment.status === "IN_PROGRESS") current.inProgress += 1;
      grouped.set(appointment.doctorName, current);
    }

    return Array.from(grouped.values()).sort((a, b) => b.confirmed - a.confirmed || b.scheduled - a.scheduled);
  }, [appointments]);

  const activeQueue = useMemo(
    () =>
      appointments
        .filter((item) => item.status === "CONFIRMED" || item.status === "IN_PROGRESS")
        .sort((a, b) => (a.queuePosition ?? 999) - (b.queuePosition ?? 999)),
    [appointments]
  );

  const upcoming = useMemo(
    () =>
      appointments
        .filter((item) => item.status === "SCHEDULED")
        .slice(0, 8),
    [appointments]
  );

  const medicineDesk = useMemo(
    () =>
      (Array.isArray(medicineDeskQueue) ? medicineDeskQueue : [])
        .filter((entry: any) => entry?.id)
        .map((raw: any) => {
          const entry = normalizeQueueEntry(raw);
          return {
            id: entry.entryId,
            patientName: entry.patientName || "Unknown Patient",
            queuePosition: entry.position > 0 ? entry.position : null,
            paymentStatus: String(entry.paymentStatus || "PENDING").toUpperCase(),
            pendingAmount: Number(raw?.pendingAmount || 0),
            readyForHandover: Boolean(entry.readyForHandover),
          };
        })
        .slice(0, 6),
    [medicineDeskQueue]
  );

  return (
    <div className="p-4 md:p-6 space-y-6">
      <div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
        <div>
          <h1 className="text-3xl font-bold">Reception Dashboard</h1>
          <p className="text-muted-foreground">
            Live appointment backlog, queue intake, and today&apos;s clinic flow
          </p>
        </div>
        <div className="flex flex-col sm:flex-row gap-2">
          <Button asChild variant="outline">
            <Link href="/receptionist/check-in">
              <QrCode className="w-4 h-4 mr-2" />
              Confirm Arrival
            </Link>
          </Button>
          <BookAppointmentDialog
            {...(clinicId ? { clinicId } : {})}
            onBooked={() => {
              void 0;
            }}
            trigger={
              <Button>
                <Calendar className="w-4 h-4 mr-2" />
                New Appointment
              </Button>
            }
          />
        </div>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-5 gap-4">
        <Card>
          <CardContent className="p-4">
            <div className="text-sm text-muted-foreground">Today</div>
            <div className="text-2xl font-bold">{stats.total}</div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="text-sm text-muted-foreground">Scheduled</div>
            <div className="text-2xl font-bold text-slate-700 dark:text-slate-200">{stats.scheduled}</div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="text-sm text-muted-foreground">Queued</div>
            <div className="text-2xl font-bold text-emerald-700 dark:text-emerald-300">{stats.confirmed}</div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="text-sm text-muted-foreground">In Progress</div>
            <div className="text-2xl font-bold text-blue-700 dark:text-blue-300">{stats.inProgress}</div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="text-sm text-muted-foreground">Completed</div>
            <div className="text-2xl font-bold text-violet-700 dark:text-violet-300">{stats.completed}</div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="text-sm text-muted-foreground">Medicine Desk</div>
            <div className="text-2xl font-bold text-amber-700 dark:text-amber-300">
              {medicineDesk.length}
            </div>
          </CardContent>
        </Card>
      </div>

      <div className="grid gap-6 xl:grid-cols-[1.2fr_0.8fr]">
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Users className="w-5 h-5" />
              Doctor Backlog
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            {doctorBacklog.length === 0 ? (
              <p className="text-sm text-muted-foreground">
                {isPending ? "Loading clinic backlog..." : "No doctor backlog for today."}
              </p>
            ) : (
              doctorBacklog.map((doctor) => (
                <div
                  key={doctor.doctorName}
                  className="rounded-xl border bg-card p-4 flex flex-col gap-3 md:flex-row md:items-center md:justify-between"
                >
                  <div>
                    <p className="font-semibold">{doctor.doctorName}</p>
                    <p className="text-sm text-muted-foreground">
                      {doctor.nextPatient ? `Next queued patient: ${doctor.nextPatient}` : "No patient waiting yet"}
                    </p>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    <Badge variant="secondary">Scheduled {doctor.scheduled}</Badge>
                    <Badge className="bg-emerald-100 text-emerald-800 dark:bg-emerald-900/30 dark:text-emerald-300">
                      Queued {doctor.confirmed}
                    </Badge>
                    <Badge className="bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300">
                      In Progress {doctor.inProgress}
                    </Badge>
                    <Badge variant="outline">Total {doctor.total}</Badge>
                  </div>
                </div>
              ))
            )}
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Clock className="w-5 h-5" />
              Active Queue
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            {activeQueue.length === 0 ? (
              <p className="text-sm text-muted-foreground">No confirmed patients in the live queue.</p>
            ) : (
              activeQueue.slice(0, 8).map((appointment) => (
                <div key={appointment.id} className="rounded-xl border p-3 bg-card">
                  <div className="flex items-center justify-between gap-3">
                    <div>
                      <p className="font-semibold">{appointment.patientName}</p>
                      <p className="text-sm text-muted-foreground">
                        {appointment.doctorName}
                        {appointment.doctorRole === "ASSISTANT_DOCTOR" ? " (Assistant Doctor)" : ""}
                      </p>
                    </div>
                    <Badge className={STATUS_STYLES[appointment.status] || STATUS_STYLES.SCHEDULED}>
                      {appointment.status.replaceAll("_", " ")}
                    </Badge>
                  </div>
                  <div className="mt-2 flex flex-wrap gap-3 text-xs text-muted-foreground">
                    <span>Time {appointment.timeLabel}</span>
                    <span>{getQueuePositionLabel({ position: appointment.queuePosition ?? 0 })}</span>
                    <span>Wait {appointment.waitLabel}</span>
                    {appointment.isDelegated ? <span>Delegated from primary doctor</span> : null}
                  </div>
                </div>
              ))
            )}
          </CardContent>
        </Card>
      </div>

        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <ListTodo className="w-5 h-5" />
              Upcoming Scheduled Patients
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-3">
          {upcoming.length === 0 ? (
            <p className="text-sm text-muted-foreground">No more scheduled patients for today.</p>
          ) : (
            upcoming.map((appointment) => (
              <div
                key={appointment.id}
                className="rounded-xl border p-4 bg-card flex flex-col gap-3 md:flex-row md:items-center md:justify-between"
              >
                <div>
                  <p className="font-semibold">{appointment.patientName}</p>
                  <p className="text-sm text-muted-foreground">
                    {appointment.doctorName}
                    {appointment.doctorRole === "ASSISTANT_DOCTOR" ? " (Assistant Doctor)" : ""}
                  </p>
                </div>
                <div className="flex items-center gap-3 text-sm">
                  <span>{appointment.timeLabel}</span>
                  <Badge className={STATUS_STYLES[appointment.status] || STATUS_STYLES.SCHEDULED}>
                    {appointment.status.replaceAll("_", " ")}
                  </Badge>
                </div>
              </div>
            ))
          )}
        </CardContent>
      </Card>

      <div className="grid gap-4 md:grid-cols-3">
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-2">
              <CheckCircle className="w-4 h-4 text-emerald-600" />
              <h3 className="font-semibold">Reception Intake</h3>
            </div>
            <p className="text-sm text-muted-foreground mb-3">
              Manually confirm a patient as arrived so they join the doctor queue.
            </p>
            <Button asChild variant="outline" className="w-full">
              <Link href="/receptionist/check-in">Open Check-In Desk</Link>
            </Button>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-2">
              <Calendar className="w-4 h-4 text-blue-600" />
              <h3 className="font-semibold">Schedule Patients</h3>
            </div>
            <p className="text-sm text-muted-foreground mb-3">
              Create appointments for walk-ins or assisted front-desk booking.
            </p>
            <BookAppointmentDialog
              {...(clinicId ? { clinicId } : {})}
              trigger={<Button variant="outline" className="w-full">Create Appointment</Button>}
            />
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-2 mb-2">
              <Clock className="w-4 h-4 text-violet-600" />
              <h3 className="font-semibold">Queue View</h3>
            </div>
            <p className="text-sm text-muted-foreground mb-3">
              Review scheduled backlog, queued patients, and live consultation state.
            </p>
            <Button asChild variant="outline" className="w-full">
              <Link href="/receptionist/appointments">Open Queue Workspace</Link>
            </Button>
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Clock className="w-5 h-5" />
            Medicine Desk Queue
          </CardTitle>
        </CardHeader>
        <CardContent>
          {medicineDesk.length > 0 ? (
            <div className="space-y-3">
              {medicineDesk.map((entry) => (
                <div
                  key={entry.id}
                  className="flex flex-col gap-3 rounded-lg border p-4 sm:flex-row sm:items-center sm:justify-between"
                >
                  <div>
                    <div className="font-semibold">{entry.patientName}</div>
                    <div className="text-sm text-muted-foreground">
                      {entry.queuePosition ? getQueuePositionLabel({ position: entry.queuePosition }) : "Medicine handover pending"}
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <Badge
                      className={
                        entry.readyForHandover || entry.paymentStatus === "PAID"
                          ? "bg-emerald-100 text-emerald-800 dark:bg-emerald-900/30 dark:text-emerald-300"
                          : "bg-amber-100 text-amber-800 dark:bg-amber-900/30 dark:text-amber-300"
                      }
                    >
                      {entry.readyForHandover || entry.paymentStatus === "PAID"
                        ? "Ready For Handover"
                        : "Awaiting Payment"}
                    </Badge>
                    {entry.pendingAmount > 0 ? (
                      <span className="text-sm font-medium text-muted-foreground">
                        INR {entry.pendingAmount.toFixed(2)}
                      </span>
                    ) : null}
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <p className="text-sm text-muted-foreground">
              No active medicine desk handovers right now.
            </p>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useState, useMemo } from "react";
import { Role } from "@/types/auth.types";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";

import { useAuth } from "@/hooks/auth/useAuth";
import { useClinicContext } from "@/hooks/query/useClinics";
import { usePatients, useCreatePatient } from "@/hooks/query/usePatients";
import { useWebSocketQuerySync } from "@/hooks/realtime/useRealTimeQueries";
import {
  Calendar,
  Users,
  Search,
  Eye,
  Phone,
  Mail,
  MapPin,
  Loader2,
  Plus,
  Edit,
  UserPlus,
  AlertCircle,
  Heart,
  UserCheck,
} from "lucide-react";
import { showSuccessToast, showErrorToast, TOAST_IDS } from "@/hooks/utils/use-toast";

export default function ReceptionistPatients() {
  useAuth();
  const { clinicId } = useClinicContext();
  const [searchTerm, setSearchTerm] = useState("");
  const [statusFilter, setStatusFilter] = useState("all");
  const [showNewPatientDialog, setShowNewPatientDialog] = useState(false);
  const [selectedPatient, setSelectedPatient] = useState<any>(null);

  // New patient form state
  const [newPatient, setNewPatient] = useState({
    firstName: "",
    lastName: "",
    phone: "",
    email: "",
    dateOfBirth: "",
    gender: "" as any,
    address: "",
    emergencyContact: "",
    emergencyPhone: "",
    medicalHistory: "",
    allergies: "",
    currentMedications: "",
  });

  // Fetch real patient data
  const { data: patientsData } = usePatients(
    clinicId || "",
    {
      ...(statusFilter !== "all" && { isActive: statusFilter === "active" }),
    }
  );

  // Sync with WebSocket for real-time updates
  useWebSocketQuerySync();

  // Create patient mutation
  const createPatientMutation = useCreatePatient();

  // Extract patients array from response
  const patients = useMemo(() => {
    if (!patientsData) return [];
    return Array.isArray(patientsData)
      ? patientsData
      : (patientsData as any).patients || [];
  }, [patientsData]);

  // Calculate age from dateOfBirth if needed
  const patientsWithAge = useMemo(() => {
    return patients.map((patient: any) => {
      if (!patient.age && patient.dateOfBirth) {
        const birthDate = new Date(patient.dateOfBirth);
        const today = new Date();
        const age = today.getFullYear() - birthDate.getFullYear();
        const monthDiff = today.getMonth() - birthDate.getMonth();
        return {
          ...patient,
          age:
            monthDiff < 0 ||
            (monthDiff === 0 && today.getDate() < birthDate.getDate())
              ? age - 1
              : age,
          name:
            patient.name ||
            `${patient.firstName || ""} ${patient.lastName || ""}`.trim(),
        };
      }
      return {
        ...patient,
        name:
          patient.name ||
          `${patient.firstName || ""} ${patient.lastName || ""}`.trim(),
      };
    });
  }, [patients]);

  const filteredPatients = useMemo(() => {
    return patientsWithAge.filter((patient: any) => {
      const matchesSearch =
        !searchTerm ||
        patient.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        patient.phone?.includes(searchTerm) ||
        patient.email?.toLowerCase().includes(searchTerm.toLowerCase());
      const patientStatus = patient.isActive ? "active" : "inactive";
      const matchesStatus =
        statusFilter === "all" || patientStatus === statusFilter;

      return matchesSearch && matchesStatus;
    });
  }, [patientsWithAge, searchTerm, statusFilter]);

  const handleNewPatientSubmit = async () => {
    if (!clinicId) {
      showErrorToast("Clinic ID is required", {
        id: TOAST_IDS.GLOBAL.ERROR,
      });
      return;
    }

    try {
      await createPatientMutation.mutate({
        firstName: newPatient.firstName,
        lastName: newPatient.lastName,
        phone: newPatient.phone,
        email: newPatient.email,
        dateOfBirth: newPatient.dateOfBirth,
        gender: newPatient.gender as any,
        address: newPatient.address,
        emergencyContact: {
          name: newPatient.emergencyContact,
          relationship: "", // Default or add field
          phone: newPatient.emergencyPhone,
        },
        medicalHistory: newPatient.medicalHistory ? [newPatient.medicalHistory] : [],
        allergies: newPatient.allergies ? newPatient.allergies.split(",").map(s => s.trim()) : [],
        currentMedications: newPatient.currentMedications,
      } as any);

      showSuccessToast("Patient created successfully", {
        id: TOAST_IDS.GLOBAL.SUCCESS,
      });
      setShowNewPatientDialog(false);
      // Reset form
      setNewPatient({
        firstName: "",
        lastName: "",
        phone: "",
        email: "",
        dateOfBirth: "",
        gender: "" as any,
        address: "",
        emergencyContact: "",
        emergencyPhone: "",
        medicalHistory: "",
        allergies: "",
        currentMedications: "",
      });
    } catch (error) {
      showErrorToast("Failed to create patient", {
        id: TOAST_IDS.GLOBAL.ERROR,
      });
      console.error(error);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case "Active":
        return "bg-green-100 text-green-800";
      case "Inactive":
        return "bg-gray-100 text-gray-800";
      case "Pending":
        return "bg-yellow-100 text-yellow-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };



  return (

        <div className="p-6 space-y-6">
          <div className="flex items-center justify-between">
            <h1 className="text-3xl font-bold">Patient Management</h1>
            <Dialog
              open={showNewPatientDialog}
              onOpenChange={setShowNewPatientDialog}
            >
              <DialogTrigger asChild>
                <Button className="flex items-center gap-2">
                  <Plus className="w-4 h-4" />
                  Add New Patient
                </Button>
              </DialogTrigger>
              <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
                <DialogHeader>
                  <DialogTitle>Register New Patient</DialogTitle>
                </DialogHeader>
                <div className="space-y-4">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <Label htmlFor="firstName">First Name *</Label>
                      <Input
                        id="firstName"
                        value={newPatient.firstName}
                        onChange={(e) =>
                          setNewPatient({
                            ...newPatient,
                            firstName: e.target.value,
                          })
                        }
                        required
                      />
                    </div>
                    <div>
                      <Label htmlFor="lastName">Last Name *</Label>
                      <Input
                        id="lastName"
                        value={newPatient.lastName}
                        onChange={(e) =>
                          setNewPatient({
                            ...newPatient,
                            lastName: e.target.value,
                          })
                        }
                        required
                      />
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <Label htmlFor="phone">Phone Number *</Label>
                      <Input
                        id="phone"
                        value={newPatient.phone}
                        onChange={(e) =>
                          setNewPatient({
                            ...newPatient,
                            phone: e.target.value,
                          })
                        }
                        required
                      />
                    </div>
                    <div>
                      <Label htmlFor="email">Email Address</Label>
                      <Input
                        id="email"
                        type="email"
                        value={newPatient.email}
                        onChange={(e) =>
                          setNewPatient({
                            ...newPatient,
                            email: e.target.value,
                          })
                        }
                      />
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <Label htmlFor="dateOfBirth">Date of Birth</Label>
                      <Input
                        id="dateOfBirth"
                        type="date"
                        value={newPatient.dateOfBirth}
                        onChange={(e) =>
                          setNewPatient({
                            ...newPatient,
                            dateOfBirth: e.target.value,
                          })
                        }
                      />
                    </div>
                    <div>
                      <Label htmlFor="gender">Gender</Label>
                      <Select
                        value={newPatient.gender}
                        onValueChange={(value) =>
                          setNewPatient({ ...newPatient, gender: value })
                        }
                      >
                        <SelectTrigger>
                          <SelectValue placeholder="Select gender" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="Male">Male</SelectItem>
                          <SelectItem value="Female">Female</SelectItem>
                          <SelectItem value="Other">Other</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                  </div>

                  <div>
                    <Label htmlFor="address">Address</Label>
                    <Textarea
                      id="address"
                      value={newPatient.address}
                      onChange={(e) =>
                        setNewPatient({
                          ...newPatient,
                          address: e.target.value,
                        })
                      }
                      rows={2}
                    />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <Label htmlFor="emergencyContact">
                        Emergency Contact
                      </Label>
                      <Input
                        id="emergencyContact"
                        value={newPatient.emergencyContact}
                        onChange={(e) =>
                          setNewPatient({
                            ...newPatient,
                            emergencyContact: e.target.value,
                          })
                        }
                        placeholder="Name (Relationship)"
                      />
                    </div>
                    <div>
                      <Label htmlFor="emergencyPhone">Emergency Phone</Label>
                      <Input
                        id="emergencyPhone"
                        value={newPatient.emergencyPhone}
                        onChange={(e) =>
                          setNewPatient({
                            ...newPatient,
                            emergencyPhone: e.target.value,
                          })
                        }
                      />
                    </div>
                  </div>

                  <div>
                    <Label htmlFor="medicalHistory">Medical History</Label>
                    <Textarea
                      id="medicalHistory"
                      value={newPatient.medicalHistory}
                      onChange={(e) =>
                        setNewPatient({
                          ...newPatient,
                          medicalHistory: e.target.value,
                        })
                      }
                      placeholder="Any existing medical conditions..."
                      rows={2}
                    />
                  </div>

                  <div>
                    <Label htmlFor="allergies">Known Allergies</Label>
                    <Input
                      id="allergies"
                      value={newPatient.allergies}
                      onChange={(e) =>
                        setNewPatient({
                          ...newPatient,
                          allergies: e.target.value,
                        })
                      }
                      placeholder="Food, drug, or other allergies..."
                    />
                  </div>

                  <div>
                    <Label htmlFor="currentMedications">
                      Current Medications
                    </Label>
                    <Textarea
                      id="currentMedications"
                      value={newPatient.currentMedications}
                      onChange={(e) =>
                        setNewPatient({
                          ...newPatient,
                          currentMedications: e.target.value,
                        })
                      }
                      placeholder="List current medications with dosage..."
                      rows={2}
                    />
                  </div>

                  <div className="flex justify-end gap-2 pt-4">
                    <Button
                      variant="outline"
                      onClick={() => setShowNewPatientDialog(false)}
                    >
                      Cancel
                    </Button>
                    <Button
                      onClick={handleNewPatientSubmit}
                      disabled={createPatientMutation.isPending}
                    >
                      {createPatientMutation.isPending ? (
                        <>
                          <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                          Creating...
                        </>
                      ) : (
                        "Register Patient"
                      )}
                    </Button>
                  </div>
                </div>
              </DialogContent>
            </Dialog>
          </div>

          {/* Stats Overview */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">
                  Total Patients
                </CardTitle>
                <Users className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">{patients.length}</div>
