                        <p className="text-sm text-gray-600">
                          {appointmentType} - {duration}
                        </p>
                        <div className="flex items-center gap-3 mt-1 text-xs text-gray-500">
                          <span className="flex items-center gap-1">
                            <Calendar className="w-3 h-3" />
                            {formatDate(appointment.date)}
                          </span>
                          <span className="flex items-center gap-1">
                            <Clock className="w-3 h-3" />
                            {time}
                          </span>
                        </div>
                      </div>
                      {appointment.notes && (
                        <p className="text-xs text-gray-500 mt-1 italic">
                          Notes: {appointment.notes}
                        </p>
                      )}
                    </div>
                  </div>
                  <div className="text-right">
                    <Badge
                      className={`${getStatusColor(status)} flex items-center gap-1`}
                    >
                      {getStatusIcon(status)}
                      {status.replace("_", " ").toLowerCase()}
                    </Badge>
                    <div className="flex gap-2 mt-2">
                      {status === "SCHEDULED" && (
                        <Button
                          size="sm"
                          onClick={() =>
                            updateAppointmentMutation.mutate({
                              appointmentId: appointment.id,
                              updates: { status: "CONFIRMED" },
                            })
                          }
                          disabled={updateAppointmentMutation.isPending}
                        >
                          Start
                        </Button>
                      )}
                      {status === "IN_PROGRESS" && (
                        <Button
                          size="sm"
                          variant="default"
                          onClick={() =>
                            updateAppointmentMutation.mutate({
                              appointmentId: appointment.id,
                              updates: { status: "COMPLETED" },
                            })
                          }
                          disabled={updateAppointmentMutation.isPending}
                        >
                          Complete
                        </Button>
                      )}
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() =>
                          deleteAppointmentMutation.mutate(appointment.id)
                        }
                        disabled={deleteAppointmentMutation.isPending}
                      >
                        Delete
                      </Button>
                    </div>
                  </div>
                </div>
              )})}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useMemo } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  Calendar,
  Users,
  Clock,
  CheckCircle,
  Brain,
  Activity,
  Play,
  Loader2,
} from "lucide-react";
import { useAuth } from "@/hooks/auth/useAuth";
import { useClinicContext } from "@/hooks/query/useClinics";
import { useTherapistAppointments, useTherapistClients } from "@/hooks/query/useTherapist";
import { useWebSocketQuerySync } from "@/hooks/realtime/useRealTimeQueries";

export default function TherapistDashboard() {
  useAuth();
  const { user } = useAuth();
  const { clinicId } = useClinicContext();

  // Fetch real data using hooks
  const { data: appointmentsData, isPending: isPendingAppointments } = useTherapistAppointments(clinicId);
  const { data: clientsData, isPending: isPendingClients } = useTherapistClients(clinicId);

  // Enable real-time WebSocket sync
  useWebSocketQuerySync();

  // Extract therapist ID from user
  const therapistId = useMemo(() => {
    return user?.id || "";
  }, [user?.id]);

  // Calculate stats from real data
  const appointmentsArray = appointmentsData?.appointments || [];
  const clientsArray = clientsData?.clients || [];

  const stats = useMemo(() => {
    const today = new Date().toDateString();
    const todayAppointments = appointmentsArray.filter(
      (apt: any) => apt.date === today
    );

    return {
      todayAppointments: todayAppointments.length,
      completedToday: todayAppointments.filter((a: any) => a.status === "COMPLETED").length,
      totalPatients: clientsArray.length,
      avgSessionDuration: 45,
    };
  }, [appointmentsArray, clientsArray]);

  const recentPatients = useMemo(() => {
    return clientsArray.slice(0, 3).map((client: any) => ({
      name: client.name,
      lastVisit: client.lastVisit,
      condition: client.condition,
      sessionsCompleted: client.sessionsCompleted || 0,
    }));
  }, [clientsArray]);

  const todaySessions = useMemo(() => {
    const today = new Date().toDateString();
    return appointmentsArray
      .filter((apt: any) => apt.date === today)
      .map((apt: any) => ({
        id: apt.id,
        patientName: apt.patientName,
        time: apt.time,
        date: apt.date,
        type: apt.type,
        duration: apt.duration,
        status: apt.status,
        notes: apt.notes,
      }));
  }, [appointmentsArray]);

  const getStatusColor = (status: string) => {
    switch (status) {
      case "IN_PROGRESS":
        return "bg-blue-100 text-blue-800";
      case "CONFIRMED":
        return "bg-green-100 text-green-800";
      case "SCHEDULED":
        return "bg-gray-100 text-gray-800";
      case "COMPLETED":
        return "bg-purple-100 text-purple-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case "IN_PROGRESS":
        return <Play className="w-4 h-4" />;
      case "CONFIRMED":
        return <CheckCircle className="w-4 h-4" />;
      case "SCHEDULED":
        return <Clock className="w-4 h-4" />;
      case "COMPLETED":
        return <CheckCircle className="w-4 h-4" />;
      default:
        return <Clock className="w-4 h-4" />;
    }
  };

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-3xl font-bold">Therapist Dashboard</h1>
        <p className="text-gray-600">
          Welcome back! Here's your overview for today.
        </p>
      </div>

      {/* Key Metrics */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              Today&apos;s Sessions
            </CardTitle>
            <Calendar className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {stats.todayAppointments}
            </div>
            <p className="text-xs text-muted-foreground">
              {stats.completedToday} completed
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              Completed Today
            </CardTitle>
            <CheckCircle className="h-4 w-4 text-green-600" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-green-600">
              {stats.completedToday}
            </div>
            <p className="text-xs text-muted-foreground">
              Therapy sessions finished
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              Total Clients
            </CardTitle>
            <Users className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.totalPatients}</div>
            <p className="text-xs text-muted-foreground">Under care</p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">
              Avg. Session
            </CardTitle>
            <Clock className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {stats.avgSessionDuration} min
            </div>
            <p className="text-xs text-muted-foreground">Per session</p>
          </CardContent>
        </Card>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Today's Appointments */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Calendar className="w-5 h-5" />
              Today&apos;s Appointments
            </CardTitle>
          </CardHeader>
          <CardContent>
            {isPendingAppointments ? (
              <div className="flex items-center justify-center min-h-[200px]">
                <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
              </div>
            ) : todaySessions.length === 0 ? (
              <div className="text-center py-8">
                <p className="text-gray-500">No appointments scheduled for today</p>
              </div>
            ) : (
              <div className="space-y-4">
                {todaySessions.map((appointment) => (
                  <div
                    key={appointment.id}
