                        <p className="text-xs text-gray-500 mt-1">
                          {appointment.notes}
                        </p>
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="font-medium">{appointment.time}</div>
                      <Badge
                        className={`${getStatusColor(appointment.status)} flex items-center gap-1`}
                      >
                        {getStatusIcon(appointment.status)}
                        {appointment.status.replace("_", " ").toLowerCase()}
                      </Badge>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>

        {/* Recent Clients */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Users className="w-5 h-5" />
              Recent Clients
            </CardTitle>
          </CardHeader>
          <CardContent>
            {isPendingClients ? (
              <div className="flex items-center justify-center min-h-[200px]">
                <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
              </div>
            ) : clientsArray.length === 0 ? (
              <div className="text-center py-8">
                <p className="text-gray-500">No clients found</p>
              </div>
            ) : (
              <div className="space-y-4">
                {recentPatients.map((client, index) => (
                  <div
                    key={index}
                    className="flex items-center justify-between p-4 border rounded-lg hover:bg-gray-50"
                  >
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 bg-purple-100 rounded-full flex items-center justify-center">
                        <Users className="w-5 h-5 text-purple-600" />
                      </div>
                      <div>
                        <h4 className="font-semibold">{client.name}</h4>
                        <p className="text-sm text-gray-600">{client.condition}</p>
                        <div className="flex items-center gap-3 mt-1 text-xs text-gray-500">
                          <span>Sessions: {client.sessionsCompleted}</span>
                          <span className="flex items-center gap-1">
                            <Clock className="w-3 h-3" />
                            Last:{" "}
                            {new Date(client.lastVisit).toLocaleDateString("en-IN")}
                          </span>
                        </div>
                      </div>
                    </div>
                    <div className="text-right">
                      <Badge variant="outline">
                        {client.sessionsCompleted} sessions
                      </Badge>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      </div>

      {/* Therapy Specialties */}
      <Card>
        <CardHeader>
          <CardTitle>Your Specialties</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            <div className="flex items-center gap-3 p-4 bg-purple-50 rounded-lg">
              <Activity className="w-6 h-6 text-purple-600" />
              <div>
                <div className="font-medium">Cognitive Behavioral Therapy</div>
                <div className="text-sm text-gray-600">Primary focus</div>
              </div>
            </div>
            <div className="flex items-center gap-3 p-4 bg-blue-50 rounded-lg">
              <Brain className="w-6 h-6 text-blue-600" />
              <div>
                <div className="font-medium">Mindfulness & Meditation</div>
                <div className="text-sm text-gray-600">Specialty</div>
              </div>
            </div>
            <div className="flex items-center gap-3 p-4 bg-green-50 rounded-lg">
              <Activity className="w-6 h-6 text-green-600" />
              <div>
                <div className="font-medium">Stress Management</div>
                <div className="text-sm text-gray-600">Expertise</div>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import React, { useState, Suspense } from "react";
import { useTranslation } from "@/lib/i18n/context";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Phone,
  Mail,
  MapPin,
  Clock,
  MessageCircle,
  Calendar,
  User,
  Heart,
  CheckCircle,
  Send,
  Star,
  Loader2,
} from "lucide-react";
import { ClinicInfo } from "@/components/clinic/clinic-info";
import { GoogleMaps } from "@/components/maps/google-maps";
import { LanguageSwitcher } from "@/components/ui/language-switcher";
import { CompactThemeSwitcher } from "@/components/theme/ThemeSwitcher";
import { PageTransition } from "@/components/ui/animated-wrapper";
import { LazySection } from "@/components/ui/lazy-section";
import { SectionSkeleton } from "@/lib/dynamic-imports";
import { getIconColorScheme } from "@/lib/config/color-palette";
import {
  useSubmitContactForm,
  useSubmitConsultationBooking,
} from "@/hooks/query/useCommunication";
import { showSuccessToast, showErrorToast, TOAST_IDS } from "@/hooks/utils/use-toast";
import { sanitizeErrorMessage } from "@/lib/utils/error-handler";

export default function ContactPage() {
  const { t } = useTranslation();
  const submitContactFormMutation = useSubmitContactForm();
  const submitConsultationBookingMutation = useSubmitConsultationBooking();
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    phone: "",
    condition: "",
    message: "",
  });
  const [isBookingDialogOpen, setIsBookingDialogOpen] = useState(false);
  const [bookingData, setBookingData] = useState({
    name: "",
    phone: "",
    preferredDate: "",
    preferredTime: "",
    reason: "",
  });

  const handleInputChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
  ) => {
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleBookingInputChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
  ) => {
    setBookingData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  // Validate email format
  const validateEmail = (email: string) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  // Validate phone number (basic validation)
  const validatePhone = (phone: string) => {
    const phoneRegex = /^[\d\s\-\+\(\)]+$/;
    return phoneRegex.test(phone) && phone.replace(/\D/g, "").length >= 10;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Validation
    if (!formData.name.trim()) {
      showErrorToast(
        t("contact.form.validation.nameRequired") || "Name is required",
        { id: TOAST_IDS.CONTACT.SUBMIT }
      );
      return;
    }

    if (!validateEmail(formData.email)) {
      showErrorToast(
        t("contact.form.validation.emailInvalid") ||
          "Please enter a valid email address",
        { id: TOAST_IDS.CONTACT.SUBMIT }
      );
      return;
    }

    if (!validatePhone(formData.phone)) {
      showErrorToast(
        t("contact.form.validation.phoneInvalid") ||
          "Please enter a valid phone number",
        { id: TOAST_IDS.CONTACT.SUBMIT }
      );
      return;
    }

    // Submit using React Query mutation
    submitContactFormMutation.mutate(
      {
        name: formData.name,
        email: formData.email,
        phone: formData.phone,
        ...(formData.condition && { condition: formData.condition }),
        message: formData.message,
        type: "contact",
      },
      {
        onSuccess: () => {
          // Reset form
          setFormData({
            name: "",
            email: "",
            phone: "",
            condition: "",
            message: "",
          });

          // ✅ Use centralized toast manager
          showSuccessToast(
            t("contact.form.success.title") || "Message Sent Successfully!",
            {
              id: TOAST_IDS.CONTACT.SUBMIT,
              description:
                t("contact.form.success.description") ||
                "We'll get back to you soon.",
            }
          );
        },
        onError: (error: any) => {
          // ✅ Use centralized error handler
          showErrorToast(sanitizeErrorMessage(error) || "Failed to send message", {
            id: TOAST_IDS.CONTACT.SUBMIT,
            description:
              t("contact.form.error.title") || "Failed to send message",
          });
        },
      }
    );
  };

  const handleBookConsultation = () => {
    setIsBookingDialogOpen(true);
  };

  const handleBookingSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!bookingData.name.trim() || !bookingData.phone.trim()) {
