"use client";

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useAuth } from "@/hooks/auth/useAuth";
import { useQueuePermissions } from "@/hooks/utils/useRBAC";
import { QueueProtectedComponent, ProtectedComponent } from "@/components/rbac";
import { useQueue } from "@/hooks/query/useQueue";
import { useQueueStats } from "@/hooks/query/useAppointments";
// ✅ Removed: useUpdateQueueStatus, useCallNextPatient - using optimistic hooks instead
import { useClinicContext, useActiveLocations } from "@/hooks/query/useClinics";
import { Permission } from "@/types/rbac.types";
import { useRealTimeQueueStatus } from "@/hooks/realtime/useRealTimeQueries";
import { ConnectionStatusIndicator as WebSocketStatusIndicator } from "@/components/common/StatusIndicator";
import { useWebSocketQuerySync } from "@/hooks/realtime/useRealTimeQueries";
import { showSuccessToast, showErrorToast, TOAST_IDS } from "@/hooks/utils/use-toast";
import {
  useOptimisticUpdateQueueStatus,
  useOptimisticCallNextPatient,
} from "@/hooks/utils/useOptimisticQueue";

// Real-time queue data interface
import {
  Clock,
  User,
  CheckCircle,
  AlertCircle,
  Play,
  Pause,
  SkipForward,
  UserCheck,
  Stethoscope,
  Flame,
  Droplets,
  Leaf,
  Users,
  Timer,
  Activity,
} from "lucide-react";

// Queue status constants - must match backend enum values
const QUEUE_STATUS = {
  WAITING: 'WAITING',
  CONFIRMED: 'CONFIRMED',
  IN_PROGRESS: 'IN_PROGRESS',
  COMPLETED: 'COMPLETED',
} as const;

export default function QueuePage() {
  const { session } = useAuth();
  const [activeQueue, setActiveQueue] = useState("consultations");

  // Enable real-time WebSocket sync
  useWebSocketQuerySync();

  // RBAC permissions
  const queuePermissions = useQueuePermissions();

  // Clinic context
  const { clinicId } = useClinicContext();
  const { data: locations = [] } = useActiveLocations(clinicId || "");
  const locationId = locations[0]?.id || "";

  // Fetch queue data with proper permissions
  const {
    data: _queueData,
    isPending: isLoading,
    error,
    refetch: refetchQueue,
  } = useQueue(clinicId || "", {
    type: activeQueue,
    enabled: !!clinicId && queuePermissions.canViewQueue,
  });

  // Real-time queue status with WebSocket updates
  const realTimeQueueStatus = useRealTimeQueueStatus(activeQueue, locationId);

  // Use real-time data if available
  const queueData =
    realTimeQueueStatus.isRealTimeEnabled && realTimeQueueStatus.data
      ? realTimeQueueStatus.data
      : _queueData;

  // Fetch queue statistics for authorized users — locationId is required by backend
  const { data: queueStats } = useQueueStats(locationId);

  // Mutation hooks for queue actions with React 19 useOptimistic
  const updateQueueStatusOptimistic = useOptimisticUpdateQueueStatus(clinicId);
  // Pass doctorId for call-next (use session user ID for doctor role)
  const callNextPatientOptimistic = useOptimisticCallNextPatient(clinicId, session?.user?.id);

  // ✅ Use optimistic hooks (React 19) - no legacy hooks needed

  // Handle queue actions with optimistic updates
  const handleUpdateQueueStatus = (patientId: string, status: string) => {
    updateQueueStatusOptimistic.mutation.mutate(
      { patientId, status },
      {
        onSuccess: () => {
          refetchQueue();
        },
      }
    );
  };

  const handleCallNextPatient = (_queueType: string) => {
    callNextPatientOptimistic.mutation.mutate(
      undefined,
      {
        onSuccess: () => {
          refetchQueue();
          showSuccessToast("Next patient called successfully", {
            id: TOAST_IDS.GLOBAL.SUCCESS,
          });
        },
        onError: (error: Error) => {
          showErrorToast(error?.message || "Failed to call next patient", {
            id: TOAST_IDS.GLOBAL.ERROR,
          });
        },
      }
    );
  };

  // Show loading state
  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <div className="animate-spin rounded-full h-32 w-32 border-b-2 border-blue-600 mx-auto"></div>
          <p className="mt-4 text-gray-600">Loading queue...</p>
        </div>
      </div>
    );
  }

  // Show error state
  if (error) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <p className="text-red-600">Error loading queue: {error.message}</p>
          <Button onClick={() => refetchQueue()} className="mt-4">
            Retry
          </Button>
        </div>
      </div>
    );
  }

  // Real-time queue data from API - filter by queue type
  const getQueueByType = (type: string) => {
    if (!queueData) return [];
    const data = Array.isArray((queueData as any)?.data)
      ? (queueData as any).data
      : Array.isArray(queueData)
      ? queueData
      : [];
    return data.filter(
      (item: any) =>
        item.type?.toLowerCase() === type.toLowerCase() ||
        item.queueType?.toLowerCase() === type.toLowerCase()
    );
  };

  const consultationQueue = getQueueByType("consultations");
  const agnikarmaQueue = getQueueByType("agnikarma");
  const panchakarmaQueue = getQueueByType("panchakarma");
  const shirodharaQueue = getQueueByType("shirodhara");



  const getStatusColor = (status: string) => {
    switch (status) {
      case QUEUE_STATUS.WAITING:
        return "bg-yellow-100 text-yellow-800";
      case QUEUE_STATUS.IN_PROGRESS:
        return "bg-blue-100 text-blue-800";
      case QUEUE_STATUS.CONFIRMED:
        return "bg-green-100 text-green-800";
      case QUEUE_STATUS.COMPLETED:
        return "bg-gray-100 text-gray-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case QUEUE_STATUS.WAITING:
        return <Clock className="w-4 h-4" />;
      case QUEUE_STATUS.IN_PROGRESS:
        return <Play className="w-4 h-4" />;
      case QUEUE_STATUS.CONFIRMED:
        return <UserCheck className="w-4 h-4" />;
      case QUEUE_STATUS.COMPLETED:
        return <CheckCircle className="w-4 h-4" />;
      default:
        return <AlertCircle className="w-4 h-4" />;
    }
  };

  const QueueCard = ({
    item,
    showActions = true,
  }: {
    item: any; // Real queue item from API
    showActions?: boolean;
  }) => (
    <Card className="hover:shadow-md transition-shadow">
      <CardContent className="p-4">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3 flex-1">
            <div className="w-10 h-10 bg-blue-100 rounded-full flex items-center justify-center">
              <User className="w-5 h-5 text-blue-600" />
            </div>
            <div className="flex-1">
              <h3 className="font-semibold">{item.patientName}</h3>
              <p className="text-sm text-gray-600">{item.doctorName}</p>
              <div className="flex items-center gap-4 mt-1">
                <span className="text-xs text-gray-500">
                  Appointment: {item.appointmentTime}
                </span>
                <span className="text-xs text-gray-500">
                  Confirmed: {item.checkedInAt || item.confirmedAt || item.updatedAt}
                </span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-3">
            <div className="text-right">
              <Badge
                className={`${getStatusColor(
                  item.status
                )} flex items-center gap-1`}
              >
                {getStatusIcon(item.status)}
                {item.status.replace("-", " ")}
              </Badge>
              {item.estimatedWait && (
                <p className="text-xs text-gray-500 mt-1">
                  Est. wait: {item.estimatedWait}
                </p>
              )}
              {item.estimatedDuration && (
                <p className="text-xs text-gray-500 mt-1">
                  Duration: {item.estimatedDuration}
                </p>
              )}
            </div>

            {showActions && (
              <div className="flex flex-col gap-1">
                {/* Start button - for users who can update queue status */}
                {item.status === QUEUE_STATUS.WAITING && (
                  <QueueProtectedComponent action="update-status">
                    <Button
                      size="sm"
                      className="flex items-center gap-1"
                      onClick={() =>
                        handleUpdateQueueStatus(item.id, QUEUE_STATUS.IN_PROGRESS)
                      }
                      disabled={updateQueueStatusOptimistic.isPending}
                    >
                      <Play className="w-3 h-3" />
                      {updateQueueStatusOptimistic.isPending
                        ? "Starting..."
                        : "Start"}
                    </Button>
                  </QueueProtectedComponent>
                )}

                {/* In-progress actions */}
                {item.status === QUEUE_STATUS.IN_PROGRESS && (
                  <>
                    <QueueProtectedComponent action="update-status">
                      <Button
                        size="sm"
                        variant="outline"
                        className="flex items-center gap-1"
                        onClick={() =>
                          handleUpdateQueueStatus(item.id, QUEUE_STATUS.WAITING)
                        }
                        disabled={updateQueueStatusOptimistic.isPending}
                      >
                        <Pause className="w-3 h-3" />
                        Pause
                      </Button>
                    </QueueProtectedComponent>

                    <QueueProtectedComponent action="update-status">
                      <Button
                        size="sm"
                        className="flex items-center gap-1"
                        onClick={() =>
                          handleUpdateQueueStatus(item.id, QUEUE_STATUS.COMPLETED)
                        }
                        disabled={updateQueueStatusOptimistic.isPending}
                      >
                        <CheckCircle className="w-3 h-3" />
                        Complete
                      </Button>
                    </QueueProtectedComponent>
                  </>
                )}

                {/* Call next patient - for users who can call next patient */}
                {item.status === QUEUE_STATUS.CONFIRMED && (
                  <QueueProtectedComponent action="call-next">
                    <Button
                      size="sm"
                      variant="outline"
                      className="flex items-center gap-1"
                      onClick={() => handleCallNextPatient(activeQueue)}
                      disabled={callNextPatientOptimistic.isPending}
                    >
                      <SkipForward className="w-3 h-3" />
                      {callNextPatientOptimistic.isPending
                        ? "Calling..."
                        : "Call Next"}
                    </Button>
                  </QueueProtectedComponent>
                )}
              </div>
            )}
          </div>
        </div>
      </CardContent>
    </Card>
  );

  const TherapyQueueSection = ({
    title,
    items,
    icon,
  }: {
    title: string;
    items: any[]; // Real queue items from API
    icon: React.ReactNode;
  }) => (
    <div className="space-y-4">
      <div className="flex items-center gap-2">
        {icon}
        <h3 className="text-lg font-semibold">{title}</h3>
        <Badge variant="secondary">{items.length}</Badge>
      </div>
      {items.length > 0 ? (
        <div className="space-y-3">
          {items.map((item: any) => (
            <QueueCard key={item.id} item={item} />
          ))}
        </div>
      ) : (
        <Card>
          <CardContent className="p-6 text-center">
            <div className="text-gray-400 mb-2">{icon}</div>
            <p className="text-gray-500">
              No patients in {title.toLowerCase()} queue
            </p>
          </CardContent>
        </Card>
      )}
    </div>
  );

  return (
    <div className="p-6 space-y-6">
      {/* Real-time WebSocket Status Indicator */}
      <div className="flex items-center justify-between mb-4">
        <div>
          <h1 className="text-3xl font-bold">Queue Management</h1>
          <p className="text-gray-600">
            {queuePermissions.canManageQueue
              ? "Monitor and manage patient queues"
              : "View patient queue status"}
          </p>
        </div>
        <WebSocketStatusIndicator />
      </div>

      {/* Queue Statistics for authorized users */}
      <ProtectedComponent
        permission={Permission.MANAGE_QUEUE}
        showFallback={false}
      >
        {queueStats ? (
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
            <Card>
              <CardContent className="p-4">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm font-medium text-gray-600">
                      Total in Queue
                    </p>
                    <p className="text-2xl font-bold">
                      {(queueStats as any)?.totalInQueue || 0}
                    </p>
                  </div>
                  <Users className="h-8 w-8 text-blue-600" />
                </div>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="p-4">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm font-medium text-gray-600">
                      Average Wait
                    </p>
                    <p className="text-2xl font-bold text-yellow-600">
                      {(queueStats as any)?.averageWaitTime || 0}m
                    </p>
                  </div>
                  <Timer className="h-8 w-8 text-yellow-600" />
                </div>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="p-4">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm font-medium text-gray-600">
                      In Progress
                    </p>
                    <p className="text-2xl font-bold text-green-600">
                      {(queueStats as any)?.inProgress || 0}
                    </p>
                  </div>
                  <Activity className="h-8 w-8 text-green-600" />
                </div>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="p-4">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm font-medium text-gray-600">
                      Completed Today
                    </p>
                    <p className="text-2xl font-bold text-blue-600">
                      {(queueStats as any)?.completedToday || 0}
                    </p>
                  </div>
                  <CheckCircle className="h-8 w-8 text-blue-600" />
                </div>
              </CardContent>
            </Card>
          </div>
        ) : null}
      </ProtectedComponent>

      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold">Queue Management</h1>
          <p className="text-gray-600">
            {queuePermissions.canManageQueue
              ? "Monitor and manage patient queues"
              : "View patient queue status"}
          </p>
        </div>
        <div className="flex items-center gap-2">
          <Badge variant="outline" className="flex items-center gap-1">
            <Clock className="w-3 h-3" />
            Live Updates
          </Badge>
        </div>
      </div>

      {/* Queue Statistics */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600">Total Waiting</p>
                <p className="text-2xl font-bold">8</p>
              </div>
              <Clock className="w-8 h-8 text-yellow-600" />
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600">In Progress</p>
                <p className="text-2xl font-bold">3</p>
              </div>
              <Play className="w-8 h-8 text-blue-600" />
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600">Completed Today</p>
                <p className="text-2xl font-bold">24</p>
              </div>
              <CheckCircle className="w-8 h-8 text-green-600" />
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600">Avg Wait Time</p>
                <p className="text-2xl font-bold">18m</p>
              </div>
              <AlertCircle className="w-8 h-8 text-orange-600" />
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Queue Tabs */}
      <Tabs
        value={activeQueue}
        onValueChange={setActiveQueue}
        className="space-y-6"
      >
        <TabsList>
          <TabsTrigger value="consultations">Consultations</TabsTrigger>
          <TabsTrigger value="therapies">Therapies</TabsTrigger>
        </TabsList>

        <TabsContent value="consultations" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Stethoscope className="w-5 h-5" />
                Consultation Queue
                <Badge variant="secondary">{consultationQueue.length}</Badge>
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-3">
              {consultationQueue.map((item: any) => (
                <QueueCard key={item.id} item={item} />
              ))}
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="therapies" className="space-y-6">
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            <TherapyQueueSection
              title="Agnikarma"
              items={agnikarmaQueue}
              icon={<Flame className="w-5 h-5 text-orange-600" />}
            />
            <TherapyQueueSection
              title="Panchakarma"
              items={panchakarmaQueue}
              icon={<Droplets className="w-5 h-5 text-blue-600" />}
            />
            <TherapyQueueSection
              title="Shirodhara"
              items={shirodharaQueue}
              icon={<Leaf className="w-5 h-5 text-green-600" />}
            />
          </div>
        </TabsContent>
      </Tabs>
    </div>
  );
}

"use client";

import React, { useState } from "react";
import {
  Card,
  CardContent,
} from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useAuth } from "@/hooks/auth/useAuth";
import {
  useVideoAppointments,
  useJoinVideoAppointment,
  useEndVideoAppointment,
} from "@/hooks/query/useVideoAppointments";
import {
  useAppointments,
  useConfirmVideoSlot,
} from "@/hooks/query/useAppointments";
import { useClinicContext } from "@/hooks/query/useClinics";
import { ProposeVideoAppointmentDialog } from "@/components/appointments/ProposeVideoAppointmentDialog";
import {
  Video,
  Plus,
  Play,
  Square,
  Download,
  Clock,
  Calendar,
  User,
  Loader2,
  CheckCircle,
  CreditCard,
} from "lucide-react";
import { showSuccessToast, showErrorToast, TOAST_IDS } from "@/hooks/utils/use-toast";
import { format } from "date-fns";
import { ConnectionStatusIndicator as WebSocketStatusIndicator } from "@/components/common/StatusIndicator";
import { useWebSocketQuerySync } from "@/hooks/realtime/useRealTimeQueries";
import { useVideoAppointmentWebSocket } from "@/hooks/realtime/useVideoAppointmentSocketIO";
import { ProtectedComponent } from "@/components/rbac/ProtectedComponent";
import { Permission } from "@/types/rbac.types";
import { Role } from "@/types/auth.types";
import { PaymentButton } from "@/components/payments/PaymentButton";
import { useMyAppointments } from "@/hooks/query/useAppointments";
import { useQueryClient } from "@/hooks/core";

export default function VideoAppointmentsPage() {
  const { session } = useAuth();
  const { clinicId } = useClinicContext();
  const [searchTerm, setSearchTerm] = useState("");
  const [filterStatus, setFilterStatus] = useState("");
  const [isCreateDialogOpen, setIsCreateDialogOpen] = useState(false);
  const [isProposeDialogOpen, setIsProposeDialogOpen] = useState(false);

  const userId = session?.user?.id || "";
  const userRole = (session?.user?.role as Role) ?? "";
  const queryClient = useQueryClient();

  // Enable real-time WebSocket sync
  useWebSocketQuerySync();

  // Fetch video appointments using hook
  const {
    data: appointmentsData,

    isPending,
    refetch,
  } = useVideoAppointments({
    status: filterStatus || "",
    page: 1,
    limit: 50,
  });

  // Real-time video appointment WebSocket hooks
  const {
    subscribeToVideoAppointments,
    subscribeToParticipantEvents,
    subscribeToRecordingEvents,
  } = useVideoAppointmentWebSocket();

  // Subscribe to real-time video appointment updates
  React.useEffect(() => {
    const unsubscribeAppointments = subscribeToVideoAppointments(
      () => {
        // Invalidate queries on real-time updates
        refetch();
      }
    );

    const unsubscribeParticipants = subscribeToParticipantEvents(
      () => {
        // Invalidate queries on participant events
        refetch();
      }
    );

    const unsubscribeRecordings = subscribeToRecordingEvents(() => {
      // Invalidate queries on recording events
      refetch();
    });

    return () => {
      unsubscribeAppointments();
      unsubscribeParticipants();
      unsubscribeRecordings();
    };
  }, [
    subscribeToVideoAppointments,
    subscribeToParticipantEvents,
    subscribeToRecordingEvents,
    refetch,
  ]);

  const appointments = Array.isArray(appointmentsData?.appointments)
    ? appointmentsData.appointments
    : Array.isArray(appointmentsData?.data)
    ? appointmentsData.data
    : [];



  // Appointments with AWAITING_SLOT_CONFIRMATION (for doctor to confirm)
  const { data: appointmentsApi } = useAppointments({
    clinicId: clinicId || "",
    type: "VIDEO_CALL",
    status: "AWAITING_SLOT_CONFIRMATION",
    limit: 50,
  });
  const awaitingConfirmation = Array.isArray((appointmentsApi as any)?.appointments)
    ? (appointmentsApi as any).appointments
    : Array.isArray((appointmentsApi as any)?.data)
    ? (appointmentsApi as any).data
    : [];

  // Patient's proposed appointments (awaiting slot confirmation + payment)
  const { data: myAppointmentsData } = useMyAppointments();
  const myProposedVideo = React.useMemo(() => {
    const list = Array.isArray((myAppointmentsData as any)?.appointments)
      ? (myAppointmentsData as any).appointments
      : [];
    return list.filter(
      (apt: any) =>
        String(apt.status) === "AWAITING_SLOT_CONFIRMATION" &&
        String(apt.type) === "VIDEO_CALL"
    );
  }, [myAppointmentsData]);

  // Mutations
  const joinVideoAppointment = useJoinVideoAppointment();
  const endVideoAppointment = useEndVideoAppointment();
  const confirmSlotMutation = useConfirmVideoSlot();

  // Filter appointments
  const filteredAppointments = appointments.filter((apt: any) => {
    const matchesSearch =
      !searchTerm ||
      apt.appointmentId?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      apt.roomName?.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = !filterStatus || filterStatus === "all" || apt.status === filterStatus;
    return matchesSearch && matchesStatus;
  });

  // Separate by status
  const upcomingAppointments = filteredAppointments.filter(
    (apt: any) => apt.status === "scheduled" || apt.status === "in-progress"
  );
  const completedAppointments = filteredAppointments.filter(
    (apt: any) => apt.status === "completed"
  );
  const cancelledAppointments = filteredAppointments.filter(
    (apt: any) => apt.status === "cancelled"
  );

  const handleJoinAppointment = async (appointmentId: string) => {
    try {
      const result = await joinVideoAppointment.mutateAsync({
        appointmentId,
        userId,
        role: session?.user?.role === "DOCTOR" ? "doctor" : "patient",
      });

      if (result?.token) {
        // Open video consultation in new window or redirect
        window.open(
          `/video-consultation/${appointmentId}?token=${result.token.token}`,
          "_blank"
        );
        showSuccessToast("Joining video consultation...", {
          id: TOAST_IDS.VIDEO.JOIN,
        });
      }
    } catch (error: any) {
      showErrorToast(error.message || "Failed to join appointment", {
        id: TOAST_IDS.VIDEO.ERROR,
      });
    }
  };

  const handleEndAppointment = async (appointmentId: string) => {
    try {
      await endVideoAppointment.mutateAsync(appointmentId);
      showSuccessToast("Video appointment ended successfully", {
        id: TOAST_IDS.VIDEO.END,
      });
      refetch();
    } catch (error: any) {
      showErrorToast(error.message || "Failed to end appointment", {
        id: TOAST_IDS.VIDEO.ERROR,
      });
    }
  };

  const getStatusBadge = (status: string) => {
    const statusConfig: Record<
      string,
      {
        label: string;
        variant: "default" | "secondary" | "destructive" | "outline";
      }
    > = {
      scheduled: { label: "Scheduled", variant: "outline" },
      "in-progress": { label: "In Progress", variant: "default" },
      completed: { label: "Completed", variant: "secondary" },
      cancelled: { label: "Cancelled", variant: "destructive" },
    };

    const config = statusConfig[status] || {
      label: status,
      variant: "outline",
    };

    return <Badge variant={config.variant}>{config.label}</Badge>;
  };

  const AppointmentCard = ({ appointment }: { appointment: any }) => (
    <Card className="mb-4">
      <CardContent className="pt-6">
        <div className="flex items-start justify-between">
          <div className="flex-1">
            <div className="flex items-center gap-2 mb-2">
              <Video className="h-5 w-5 text-primary" />
              <h3 className="font-semibold text-lg">
                {appointment.roomName || `Room ${appointment.appointmentId}`}
              </h3>
              {getStatusBadge(appointment.status)}
            </div>

            <div className="grid grid-cols-2 gap-4 mt-4 text-sm text-muted-foreground">
              <div className="flex items-center gap-2">
                <Calendar className="h-4 w-4" />
                <span>
                  {appointment.startTime
                    ? format(new Date(appointment.startTime), "MMM dd, yyyy")
                    : "N/A"}
                </span>
              </div>
              <div className="flex items-center gap-2">
                <Clock className="h-4 w-4" />
                <span>
                  {appointment.startTime
                    ? format(new Date(appointment.startTime), "hh:mm a")
                    : "N/A"}
                </span>
              </div>
              <div className="flex items-center gap-2">
                <User className="h-4 w-4" />
                <span>
                  Appointment ID: {appointment.appointmentId?.slice(0, 8)}...
                </span>
              </div>
              {appointment.recordingUrl && (
                <div className="flex items-center gap-2">
                  <Download className="h-4 w-4" />
                  <span>Recording Available</span>
                </div>
              )}
            </div>
          </div>

          <div className="flex gap-2">
            {appointment.status === "scheduled" && (
              <Button
                onClick={() => handleJoinAppointment(appointment.appointmentId)}
                size="sm"
                className="gap-2"
                disabled={joinVideoAppointment.isPending}
              >
                {joinVideoAppointment.isPending ? (
                  <>
                    <Loader2 className="h-4 w-4 animate-spin" />
