"use client";

import { useEffect } from 'react';
import { useHealthRealtime } from '@/hooks/realtime/useHealthRealtime';
import { useHealthStore } from '@/stores';


/**
 * Health Status Provider
 * Initializes Socket.IO connection for health monitoring and renders global health status button
 * Auto-subscribes when socket connects (handled in useHealthRealtime)
 * Should be added to AppProvider
 */
export function HealthStatusProvider() {
  // ✅ Only enable health realtime when not on auth pages
  const isAuthPage = typeof window !== 'undefined' && window.location.pathname.startsWith('/auth');
  const { socket, subscribe } = useHealthRealtime({ enabled: !isAuthPage });
  const isConnected = useHealthStore((state) => state.isConnected);

  useEffect(() => {
    // ✅ Don't subscribe on auth pages to prevent blocking
    if (isAuthPage) {
      return;
    }

    // Subscribe to health updates when socket is connected
    // Note: useHealthRealtime already auto-subscribes on connect,
    // but we call subscribe here as a fallback if connection happens after mount
    if (socket?.connected || isConnected) {
      subscribe();
      if (process.env.NODE_ENV === 'development') {
        console.log('✅ HealthStatusProvider: Subscribed to health updates');
      }
    }
  }, [socket, isConnected, subscribe, isAuthPage]);

  return null;
}

"use client";

import { useEffect } from 'react';
import { useReportWebVitals } from 'next/web-vitals';

// ============================================================================
// WEB VITALS TRACKING WITH NEXT.JS 15
// ============================================================================

interface WebVitalsMetric {
  id: string;
  name: string;
  value: number;
  label: 'web-vital' | 'custom';
  startTime?: number;
  delta?: number;
}

// Enhanced Web Vitals tracking for Next.js 15
export function WebVitalsTracker() {
  useReportWebVitals((metric: WebVitalsMetric) => {
    // Track Core Web Vitals
    switch (metric.name) {
      case 'FCP': // First Contentful Paint
        trackWebVital('First Contentful Paint', metric.value);
        break;
      case 'LCP': // Largest Contentful Paint
        trackWebVital('Largest Contentful Paint', metric.value);
        break;
      case 'CLS': // Cumulative Layout Shift
        trackWebVital('Cumulative Layout Shift', metric.value);
        break;
      case 'FID': // First Input Delay
        trackWebVital('First Input Delay', metric.value);
        break;
      case 'TTFB': // Time to First Byte
        trackWebVital('Time to First Byte', metric.value);
        break;
      case 'INP': // Interaction to Next Paint (new in 2024)
        trackWebVital('Interaction to Next Paint', metric.value);
        break;
      default:
        // Custom metrics
        trackCustomMetric(metric.name, metric.value);
    }
  });

  return null;
}

// ============================================================================
// PERFORMANCE MONITORING UTILITIES
// ============================================================================

function trackWebVital(name: string, value: number) {
  // Send to analytics
  if (typeof window !== 'undefined' && window.gtag) {
    window.gtag('event', 'web_vitals', {
      event_category: 'Web Vitals',
      event_label: name,
      value: Math.round(value),
      non_interaction: true,
    });
  }

  // Send to custom analytics endpoint
  if (process.env.NODE_ENV === 'production') {
    fetch('/api/analytics/web-vitals', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        name,
        value,
        timestamp: Date.now(),
        url: window.location.href,
        userAgent: navigator.userAgent,
      }),
    }).catch(console.error);
  }
}

function trackCustomMetric(name: string, value: number) {
  if (typeof window !== 'undefined' && window.gtag) {
    window.gtag('event', 'custom_metric', {
      event_category: 'Performance',
      event_label: name,
      value: Math.round(value),
      non_interaction: true,
    });
  }
}

// ============================================================================
// RESOURCE LOADING PERFORMANCE
// ============================================================================

export function ResourcePerformanceTracker() {
  useEffect(() => {
    // Track resource loading performance
    const observer = new PerformanceObserver((list) => {
      list.getEntries().forEach((entry) => {
        if (entry.entryType === 'resource') {
          const resourceEntry = entry as PerformanceResourceTiming;

          // Track slow resources
          if (resourceEntry.duration > 1000) {
            trackCustomMetric(`slow_resource_${resourceEntry.initiatorType}`, resourceEntry.duration);
          }

          // Track failed resources
          if (resourceEntry.transferSize === 0 && resourceEntry.decodedBodySize === 0) {
            trackCustomMetric(`failed_resource_${resourceEntry.initiatorType}`, 1);
          }
        }
      });
    });

    observer.observe({ entryTypes: ['resource'] });

    return () => observer.disconnect();
  }, []);

  return null;
}

// ============================================================================
// NAVIGATION PERFORMANCE
// ============================================================================

export function NavigationPerformanceTracker() {
  useEffect(() => {
    // Track navigation timing
    const observer = new PerformanceObserver((list) => {
      list.getEntries().forEach((entry) => {
        if (entry.entryType === 'navigation') {
          const navEntry = entry as PerformanceNavigationTiming;

          // Track key navigation metrics
          trackCustomMetric('dns_lookup_time', navEntry.domainLookupEnd - navEntry.domainLookupStart);
          trackCustomMetric('tcp_connect_time', navEntry.connectEnd - navEntry.connectStart);
          trackCustomMetric('server_response_time', navEntry.responseEnd - navEntry.requestStart);
          trackCustomMetric('dom_processing_time', navEntry.domComplete - (navEntry as any).domLoading);
          trackCustomMetric('page_load_time', navEntry.loadEventEnd - navEntry.loadEventStart);
        }
      });
    });

    observer.observe({ entryTypes: ['navigation'] });

    return () => observer.disconnect();
  }, []);

  return null;
}

// ============================================================================
// MEMORY PERFORMANCE TRACKING
// ============================================================================

export function MemoryPerformanceTracker() {
  useEffect(() => {
    // Track memory usage (if supported)
    if ('memory' in performance) {
      const memoryInfo = (performance as any).memory;

      const trackMemory = () => {
        trackCustomMetric('js_heap_used', memoryInfo.usedJSHeapSize);
        trackCustomMetric('js_heap_total', memoryInfo.totalJSHeapSize);
        trackCustomMetric('js_heap_limit', memoryInfo.jsHeapSizeLimit);
      };

      // Track memory on page load
      trackMemory();

      // Track memory periodically
      const interval = setInterval(trackMemory, 30000); // Every 30 seconds

      return () => clearInterval(interval);
    }
    return () => {}; // Return empty cleanup function if memory is not supported
  }, []);

  return null;
}

// ============================================================================
// COMPREHENSIVE PERFORMANCE PROVIDER
// ============================================================================

interface PerformanceProviderProps {
  children: React.ReactNode;
  enableWebVitals?: boolean;
  enableResourceTracking?: boolean;
  enableNavigationTracking?: boolean;
  enableMemoryTracking?: boolean;
}

export function PerformanceProvider({
  children,
  enableWebVitals = true,
  enableResourceTracking = true,
  enableNavigationTracking = true,
  enableMemoryTracking = false, // Disabled by default as it's experimental
}: PerformanceProviderProps) {
  return (
    <>
      {enableWebVitals && <WebVitalsTracker />}
      {enableResourceTracking && <ResourcePerformanceTracker />}
      {enableNavigationTracking && <NavigationPerformanceTracker />}
      {enableMemoryTracking && <MemoryPerformanceTracker />}
      {children}
    </>
  );
}

// ============================================================================
// PERFORMANCE BUDGET MONITORING
// ============================================================================

interface PerformanceBudget {
  fcp: number; // First Contentful Paint (ms)
  lcp: number; // Largest Contentful Paint (ms)
  cls: number; // Cumulative Layout Shift
  fid: number; // First Input Delay (ms)
  ttfb: number; // Time to First Byte (ms)
}

const DEFAULT_BUDGET: PerformanceBudget = {
  fcp: 1800,  // 1.8s
  lcp: 2500,  // 2.5s
  cls: 0.1,   // 0.1
  fid: 100,   // 100ms
  ttfb: 800,  // 800ms
};

export function PerformanceBudgetMonitor(budget: Partial<PerformanceBudget> = {}) {
  const fullBudget = { ...DEFAULT_BUDGET, ...budget };

  useReportWebVitals((metric: WebVitalsMetric) => {
    let budgetValue: number;
    let exceeded = false;

    switch (metric.name) {
      case 'FCP':
        budgetValue = fullBudget.fcp;
        exceeded = metric.value > budgetValue;
        break;
      case 'LCP':
        budgetValue = fullBudget.lcp;
        exceeded = metric.value > budgetValue;
        break;
      case 'CLS':
        budgetValue = fullBudget.cls;
        exceeded = metric.value > budgetValue;
        break;
      case 'FID':
        budgetValue = fullBudget.fid;
        exceeded = metric.value > budgetValue;
        break;
      case 'TTFB':
        budgetValue = fullBudget.ttfb;
        exceeded = metric.value > budgetValue;
        break;
      default:
        return;
    }

    if (exceeded) {
      // Alert about budget exceeded
      console.warn(`Performance budget exceeded for ${metric.name}: ${metric.value}ms > ${budgetValue}ms`);

      // Track budget violations
      trackCustomMetric(`budget_exceeded_${metric.name.toLowerCase()}`, metric.value - budgetValue);
    }
  });

  return null;
}

// ============================================================================
// PERFORMANCE DEBUGGING (Development Only)
// ============================================================================

export function PerformanceDebugger() {
  useEffect(() => {
    if (process.env.NODE_ENV !== 'development') return;

    // Log performance entries to console
    const observer = new PerformanceObserver((list) => {
      list.getEntries().forEach((entry) => {
        console.log(`[Performance] ${entry.name}: ${entry.duration}ms`);
      });
    });

    observer.observe({ entryTypes: ['measure', 'navigation', 'resource'] });

    return () => observer.disconnect();
  }, []);

  return null;
}

/**
 * Push Notification Provider
 *
 * Manages push notification initialization and token registration
 */

"use client";

import React, { useEffect, useState } from "react";
import { useFCM } from "@/hooks/realtime/useFCM";
import { APP_CONFIG } from "@/lib/config/config";

interface PushNotificationProviderProps {
  children: React.ReactNode;
}

export function PushNotificationProvider({
  children,
}: PushNotificationProviderProps) {
  const {
    isSupported,
    permission,
    isRegistered,
    isLoading,
    requestPermission,
  } = useFCM();

  const [serviceWorkerRegistered, setServiceWorkerRegistered] = useState(false);

  // Register service worker
  useEffect(() => {
    if (typeof window === "undefined" || !("serviceWorker" in navigator)) {
      return;
    }

    const registerServiceWorker = async () => {
      try {
        // Register service worker
        const registration = await navigator.serviceWorker.register(
          "/firebase-messaging-sw.js",
          {
            scope: "/",
          }
        );

        console.log("Service Worker registered:", registration);

        // Inject Firebase config into service worker
        const sendConfigToSW = () => {
          if (registration.active) {
            registration.active.postMessage({
              type: "FIREBASE_CONFIG",
              firebaseConfig: {
                apiKey: APP_CONFIG.FIREBASE.API_KEY,
                authDomain: APP_CONFIG.FIREBASE.AUTH_DOMAIN,
                projectId: APP_CONFIG.FIREBASE.PROJECT_ID,
                storageBucket: APP_CONFIG.FIREBASE.STORAGE_BUCKET,
                messagingSenderId: APP_CONFIG.FIREBASE.MESSAGING_SENDER_ID,
                appId: APP_CONFIG.FIREBASE.APP_ID,
              },
            });
          } else if (registration.installing) {
            registration.installing.addEventListener("statechange", () => {
              if (registration.installing?.state === "activated") {
                registration.active?.postMessage({
                  type: "FIREBASE_CONFIG",
                  firebaseConfig: {
                    apiKey: APP_CONFIG.FIREBASE.API_KEY,
                    authDomain: APP_CONFIG.FIREBASE.AUTH_DOMAIN,
                    projectId: APP_CONFIG.FIREBASE.PROJECT_ID,
                    storageBucket: APP_CONFIG.FIREBASE.STORAGE_BUCKET,
                    messagingSenderId: APP_CONFIG.FIREBASE.MESSAGING_SENDER_ID,
                    appId: APP_CONFIG.FIREBASE.APP_ID,
                  },
                });
              }
            });
          }
        };

        sendConfigToSW();

        setServiceWorkerRegistered(true);

        // Listen for service worker updates
        registration.addEventListener("updatefound", () => {
          const newWorker = registration.installing;
          if (newWorker) {
            newWorker.addEventListener("statechange", () => {
              if (
                newWorker.state === "installed" &&
                navigator.serviceWorker.controller
              ) {
                console.log(
                  "New service worker available. Please refresh the page."
                );
              }
            });
          }
        });
      } catch (error) {
        console.error("Service Worker registration failed:", error);
      }
    };

    registerServiceWorker();
  }, []);

  // Request permission when supported and not already granted
  useEffect(() => {
    if (
      isSupported &&
      permission === "default" &&
      !isLoading &&
      serviceWorkerRegistered &&
      APP_CONFIG.FEATURES.NOTIFICATIONS
    ) {
      // Auto-request permission after a short delay
      const timer = setTimeout(() => {
        requestPermission();
      }, 2000);

      return () => clearTimeout(timer);
    }
    return undefined;
  }, [
    isSupported,
    permission,
    isLoading,
    serviceWorkerRegistered,
    requestPermission,
  ]);

  // Log registration status
  useEffect(() => {
    if (isRegistered) {
      console.log("Push notifications registered successfully");
    }
  }, [isRegistered]);

  return <>{children}</>;
}

"use client";

import React, { createContext, useContext, useEffect, ReactNode } from "react";
import { useWebSocketIntegration } from "@/hooks/realtime/useWebSocketIntegration";
import { useAppStore } from "@/stores";
import { WebSocketErrorBoundary } from "@/components/common/ErrorBoundary";
import { websocketManager } from "@/lib/config/websocket";

interface WebSocketContextType {
  isConnected: boolean;
  connectionStatus: string;
  error: string | null;
  isRealTimeEnabled: boolean;
  reconnect: () => void;
  emit: (event: string, data: Record<string, unknown>) => void;
  subscribe: (event: string, callback: (data: unknown) => void) => () => void;
}

const WebSocketContext = createContext<WebSocketContextType | undefined>(
  undefined
);

export function useWebSocketContext() {
  const context = useContext(WebSocketContext);
  if (!context) {
    throw new Error(
      "useWebSocketContext must be used within a WebSocketProvider"
    );
  }
  return context;
}

interface WebSocketProviderProps {
  children: ReactNode;
  autoConnect?: boolean;
  enableRetry?: boolean;
  enableErrorBoundary?: boolean;
}

export function WebSocketProvider({
  children,
  autoConnect = true,
  enableErrorBoundary = true,
}: WebSocketProviderProps) {
  const { user, currentClinic } = useAppStore();

  // Real-time WebSocket enabled - using Docker backend
  const shouldConnect = autoConnect;

  // Initialize WebSocket integration (disabled in mock mode)
  const webSocketIntegration = useWebSocketIntegration({
    autoConnect: shouldConnect,
    subscribeToQueues: shouldConnect,
    subscribeToAppointments: shouldConnect,
    tenantId: currentClinic?.id || undefined,
    userId: user?.id || undefined,
  });

  // ✅ Retry logic is handled by useWebSocketIntegration hook

  // Initialize WebSocket manager
  useEffect(() => {
    if (shouldConnect && user) {
      const initializeWebSocket = async () => {
        try {
          // Use environment-aware WebSocket URL
          const { APP_CONFIG } = await import("@/lib/config/config");
          websocketManager.initialize({
            url: process.env.NEXT_PUBLIC_WEBSOCKET_URL || APP_CONFIG.WEBSOCKET.URL || '',
            autoConnect: false, // We handle connection through the integration hook
          });
        } catch (error) {
          console.error("Failed to initialize WebSocket manager:", error);
        }
      };

      initializeWebSocket();
    }

    // Cleanup on unmount
    return () => {
      websocketManager.destroy();
    };
  }, [shouldConnect, user]);

  // Context value
  const contextValue: WebSocketContextType = {
    ...webSocketIntegration,
    isRealTimeEnabled: webSocketIntegration.isReady,
  };

  const content = (
    <WebSocketContext.Provider value={contextValue}>
      {children}
    </WebSocketContext.Provider>
  );

  // Wrap with error boundary if enabled
  if (enableErrorBoundary) {
    return (
      <WebSocketErrorBoundary
        onError={(error, errorInfo) => {
          console.error("WebSocket Error Boundary:", error, errorInfo);
          // Report to monitoring service in production
          if (process.env.NODE_ENV === "production") {
            // Send to error reporting service
          }
        }}
      >
        {content}
      </WebSocketErrorBoundary>
    );
  }

  return content;
}

// Higher-order component for components that require WebSocket
export function withWebSocket<P extends object>(
  WrappedComponent: React.ComponentType<P>
) {
  const WithWebSocketComponent = (props: P) => {
    const webSocketContext = useWebSocketContext();

    return <WrappedComponent {...props} webSocket={webSocketContext} />;
  };

  WithWebSocketComponent.displayName = `withWebSocket(${
    WrappedComponent.displayName || WrappedComponent.name
  })`;

  return WithWebSocketComponent;
}

// Hook for components that need WebSocket connection status
export function useWebSocketStatus() {
  const { isConnected, connectionStatus, error, isRealTimeEnabled } =
    useWebSocketContext();

  return {
    isConnected,
    connectionStatus,
    error,
    isRealTimeEnabled,
    isOnline: isConnected && !error,
    isOffline: !isConnected || !!error,
  };
}

// Hook for emitting WebSocket events with error handling
export function useWebSocketEmit() {
  const { emit, isConnected } = useWebSocketContext();
  const { addNotification } = useAppStore();

  return React.useCallback(
    (
      event: string,
      data: Record<string, unknown>,
      options?: {
        showSuccess?: boolean;
        showError?: boolean;
        successMessage?: string;
        errorMessage?: string;
      }
    ) => {
      const {
        showSuccess = false,
        showError = true,
        successMessage = "Event sent successfully",
        errorMessage = "Failed to send event - not connected to server",
      } = options || {};

      try {
        if (!isConnected) {
          if (showError) {
            addNotification({
              type: "warning",
              title: "Connection Required",
              message: errorMessage,
              read: false,
            });
          }
          return false;
        }

        emit(event, data);

        if (showSuccess) {
          addNotification({
            type: "success",
            title: "Success",
            message: successMessage,
            read: false,
          });
        }

        return true;
      } catch (error) {
        if (showError) {
          addNotification({
            type: "error",
            title: "Error",
            message:
              error instanceof Error ? error.message : "Unknown error occurred",
            read: false,
          });
        }
        return false;
      }
    },
    [emit, isConnected, addNotification]
  );
}

// Hook for subscribing to WebSocket events with automatic cleanup
export function useWebSocketSubscription(
  event: string,
  callback: (data: unknown) => void,
  deps: React.DependencyList = []
) {
  const { subscribe, isConnected } = useWebSocketContext();

  useEffect(() => {
    if (!isConnected) return;

    const unsubscribe = subscribe(event, callback);

    return () => {
      unsubscribe();
    };
  }, [event, isConnected, subscribe, ...deps]);
}

// Utility component for showing WebSocket status
export function WebSocketStatusBar() {
  const { isConnected, connectionStatus, error } = useWebSocketStatus();
  const { reconnect } = useWebSocketContext();

  if (!isConnected || error) {
    return (
      <div className="bg-primary/10 border-b border-primary/20 p-2 text-sm text-center">
        <div className="flex items-center justify-center gap-2">
          <div className="w-2 h-2 bg-primary rounded-full animate-pulse"></div>
          <span>
            {connectionStatus === "connecting"
              ? "Connecting to real-time updates..."
              : "Real-time updates unavailable"}
          </span>
          {error && (
            <button
              onClick={reconnect}
              className="ml-2 text-yellow-700 hover:text-yellow-900 underline"
            >
              Retry
            </button>
          )}
        </div>
      </div>
    );
  }

  return null;
}

