  const [selectedSlot, setSelectedSlot] = useState("");
  const [chiefComplaint, setChiefComplaint] = useState("");
  const [urgency, setUrgency] = useState("Normal");
  const [bookedAppointmentId, setBookedAppointmentId] = useState("");

  // ─── Queries ─────────────────────────────────────────────────────────────
  const { data: locations = [] } = useActiveLocations(activeClinicId);
  const { data: appointmentServices = [], isPending: servicesLoading } = useAppointmentServices();
  const { data: doctorsData, isPending: doctorsLoading } = useDoctors(activeClinicId, {
    locationId: selectedLocationId,
  });

  const dateString = useMemo(() => (selectedDate ? formatDateIST(selectedDate) : ""), [selectedDate]);

  const { data: availability, isPending: availabilityLoading, error: availabilityError } = useDoctorAvailability(
    activeClinicId,
    selectedDoctorId,
    dateString,
    selectedLocationId
  );

  const { mutateAsync: createAppointment, isPending: isBooking } = useCreateAppointment();
  const { data: subscriptionsData = [] } = useSubscriptions(session?.user?.id || "");

  // ─── Derived ─────────────────────────────────────────────────────────────
  const modeAppointmentType: AppointmentType =
    consultationMode === "VIDEO" ? "VIDEO_CALL" : "IN_PERSON";

  const visibleServices = useMemo(() => {
    return (appointmentServices as AppointmentServiceDefinition[]).filter(
      (service) =>
        service.active &&
        service.appointmentModes.includes(modeAppointmentType)
    );
  }, [appointmentServices, modeAppointmentType]);

  const selectedService = useMemo(
    () => visibleServices.find((service) => service.treatmentType === selectedServiceId),
    [selectedServiceId, visibleServices]
  );

  const doctorsList: any[] = useMemo(() => {
    // The GET /doctors API returns User records with a nested `doctor` relation:
    // { id: userId, name, doctor: { id: doctorId, specialization, ... } }
    // We need to normalize this so `d.id` = the Doctor entity ID (not User ID)
    const normalize = (users: any[]) =>
      users.map((u) => ({
        ...u,
        // Expose the Doctor entity's id as the primary id for availability/booking
        id: u.doctor?.id || u.id,
        userId: u.id, // Keep user id separately
        name: u.name || u.doctor?.user?.name || `Dr. ${u.id?.slice(0, 6)}`,
        specialization: u.doctor?.specialization || u.specialization || '',
        image: u.profilePicture || u.doctor?.user?.profilePicture || u.image || '',
      }));

    if (Array.isArray(doctorsData)) return normalize(doctorsData);
    if (Array.isArray((doctorsData as any)?.data?.doctors)) return normalize((doctorsData as any).data.doctors);
    if (Array.isArray((doctorsData as any)?.data)) return normalize((doctorsData as any).data);
    const raw = (doctorsData as any)?.doctors || [];
    return normalize(raw);
  }, [doctorsData]);

  const selectedDoctor = useMemo(
    () => doctorsList.find((d: any) => d.id === selectedDoctorId),
    [doctorsList, selectedDoctorId]
  );

  const activeSubscription = useMemo(
    () =>
      (subscriptionsData as any[]).find(
        (s: any) =>
          (s.status === "ACTIVE" || s.status === "TRIALING") &&
          (!s.clinicId || s.clinicId === activeClinicId)
      ),
    [subscriptionsData, activeClinicId]
  );

  const slots = useMemo(() => {
    if (Array.isArray((availability as any)?.availableSlots)) return (availability as any).availableSlots;
    if (Array.isArray((availability as any)?.data?.availableSlots)) return (availability as any).data.availableSlots;
    if (Array.isArray((availability as any)?.data?.data?.availableSlots)) return (availability as any).data.data.availableSlots;
    return [];
  }, [availability]);

  const restrictions = useMemo(() => {
    const r =
      (availability as any)?.restrictions ||
      (availability as any)?.data?.restrictions ||
      (availability as any)?.data?.data?.restrictions ||
      {};
    return {
      clinicPaused: !!r.clinicPaused,
      doctorPaused: !!r.doctorPaused,
      emergencyOnly: !!r.emergencyOnly,
      generalConsultationEnabled: r.generalConsultationEnabled !== false,
      videoConsultationEnabled: r.videoConsultationEnabled !== false,
      reason: typeof r.reason === "string" ? r.reason : "",
    };
  }, [availability]);

  const consultationBlocked = useMemo(() => {
    if (restrictions.clinicPaused || restrictions.doctorPaused) return true;
    if (consultationMode === "IN_PERSON" && !restrictions.generalConsultationEnabled) return true;
    if (consultationMode === "VIDEO" && !restrictions.videoConsultationEnabled) return true;
    return false;
  }, [consultationMode, restrictions]);

  const effectiveSlots = useMemo(
    () => (consultationBlocked ? [] : (slots as string[])),
    [consultationBlocked, slots]
  );

  const slotGroups = useMemo(() => groupSlotsByPeriod(effectiveSlots as string[]), [effectiveSlots]);

  // ─── Reset on close ───────────────────────────────────────────────────────
  useEffect(() => {
    if (!open) {
      setStep(locationId ? 2 : 1);
      setSelectedLocationId(locationId || "");
      setConsultationMode("IN_PERSON");
      setSelectedServiceId("");
      setSelectedDoctorId("");
      setSelectedDate(getTodayIST());
      setSelectedSlot("");
      setChiefComplaint("");
      setUrgency("Normal");
      setBookedAppointmentId("");
    }
  }, [open, locationId]);

  // Auto-pick first location
  useEffect(() => {
    if (!selectedLocationId && locations.length > 0) {
      setSelectedLocationId((locations[0] as any)?.id || "");
    }
  }, [locations, selectedLocationId]);

  useEffect(() => {
    if (
      selectedServiceId &&
      !visibleServices.some(service => service.treatmentType === selectedServiceId)
    ) {
      setSelectedServiceId("");
    }
  }, [selectedServiceId, visibleServices]);

  // ─── Book appointment ─────────────────────────────────────────────────────
  const handleBook = useCallback(async () => {
    if (!selectedService || !selectedDoctorId || !selectedDate || !selectedSlot) return;

    const redirectToSubscriptionCheckout = (message?: string) => {
      toast.error(
        message || "You don't have an active subscription for this in-person appointment. Please subscribe to continue."
      );
      router.push("/billing?tab=plans&intent=subscribe");
    };

    try {
      const finalAppointmentType: AppointmentType =
        consultationMode === "VIDEO" ? "VIDEO_CALL" : "IN_PERSON";

      if (finalAppointmentType === "IN_PERSON" && userRole === "PATIENT" && !activeSubscription) {
        redirectToSubscriptionCheckout(
          "You don't have an active subscription for in-person appointments. Please subscribe to continue."
        );
        return;
      }

      if (finalAppointmentType === "IN_PERSON" && activeSubscription?.id) {
        const coverageResult = await checkSubscriptionCoverage(activeSubscription.id, "IN_PERSON");
        if (!coverageResult.success) {
          toast.error(coverageResult.error || "Unable to validate subscription coverage.");
          return;
        }
        const coverage = coverageResult.coverage;
        const covered =
          coverage?.covered === true ||
          coverage?.allowed === true;
        if (!covered) {
          const reason =
            coverage?.message ||
            coverage?.reason ||
            (coverage?.requiresPayment
              ? `Subscription coverage unavailable. Additional payment required: INR ${coverage?.paymentAmount || 0}`
              : "Subscription quota exhausted or inactive.");
          redirectToSubscriptionCheckout(reason);
          return;
        }
      }

      const appointmentDate = new Date(selectedDate);
      const [hours, minutes] = selectedSlot.split(":").map(Number);
      appointmentDate.setHours(hours ?? 0, minutes ?? 0, 0, 0);

      let apptId = "";
      if (finalAppointmentType === "IN_PERSON" && userRole === "PATIENT" && activeSubscription?.id) {
        const atomicResult = await createInPersonAppointmentWithSubscription({
          subscriptionId: activeSubscription.id,
          patientId: session?.user?.id ?? "",
          doctorId: selectedDoctorId,
          clinicId: activeClinicId,
          locationId: selectedLocationId,
          appointmentDate: appointmentDate.toISOString(),
          duration: selectedService.defaultDurationMinutes,
          treatmentType: selectedService.treatmentType,
          priority: urgency.toUpperCase(),
          notes: chiefComplaint || selectedService.label,
        });
        if (!atomicResult.success) {
          throw new Error(atomicResult.error || "Failed to create subscription-based appointment");
        }
        apptId =
          (atomicResult as any)?.appointment?.id ||
          (atomicResult as any)?.appointment?.data?.id ||
          "APPT-" + Date.now();
      } else {
        const appointment = await createAppointment({
          clinicId: activeClinicId,
          doctorId: selectedDoctorId,
          locationId: selectedLocationId,
          date: formatDateIST(appointmentDate),
          time: selectedSlot,
          type: finalAppointmentType,
          treatmentType: selectedService.treatmentType,
          duration: selectedService.defaultDurationMinutes,
          notes: chiefComplaint || selectedService.label,
          priority: urgency.toUpperCase() as any,
          patientId: session?.user?.id ?? "",
        });
        if (!appointment?.id) {
          throw new Error("Failed to create appointment");
        }
        apptId = appointment.id;
      }

      setBookedAppointmentId(apptId);
      onBooked?.();

      if (userRole === "PATIENT" && finalAppointmentType === "IN_PERSON") {
        toast.success("Appointment booked. Continue to clinic check-in.");
        router.push("/patient/check-in");
        return;
      }

      setStep(7); // step 7 = success/QR screen
    } catch (err: any) {
      const errorMessage =
        typeof err?.message === "string" ? err.message : "Failed to book appointment. Please try again.";
      const lowerErrorMessage = errorMessage.toLowerCase();
      const shouldRedirectToSubscription =
        userRole === "PATIENT" &&
        consultationMode === "IN_PERSON" &&
        (lowerErrorMessage.includes("active in-person subscription coverage is required") ||
          lowerErrorMessage.includes("active subscription required") ||
          lowerErrorMessage.includes("subscription quota exhausted") ||
          lowerErrorMessage.includes("subscription coverage unavailable") ||
          (lowerErrorMessage.includes("subscription") && lowerErrorMessage.includes("required")));

      if (shouldRedirectToSubscription) {
        redirectToSubscriptionCheckout(
          "You don't have an active subscription for this appointment. Please subscribe and continue to payment."
        );
        return;
      }

      toast.error(errorMessage);
    }
  }, [
    selectedService,
    selectedDoctorId,
    selectedDate,
    selectedSlot,
    chiefComplaint,
    urgency,
    activeClinicId,
    selectedLocationId,
    createAppointment,
    session,
    onBooked,
    consultationMode,
    userRole,
    activeSubscription,
    router,
  ]);

  // ─── Navigation ──────────────────────────────────────────────────────────
  const canNext = useMemo(() => {
    if (step === 1) return !!selectedLocationId && !!consultationMode;
    if (step === 2) return !!selectedServiceId;
    if (step === 3) return !!selectedDoctorId;
    if (step === 4) return !!selectedDate;
    if (step === 5) return !!selectedSlot;
    return true;
  }, [step, selectedLocationId, selectedServiceId, selectedDoctorId, selectedDate, selectedSlot]);

  const TOTAL_STEPS = 6;
  const goNext = () => setStep((s) => Math.min(s + 1, TOTAL_STEPS));
  const goBack = () => setStep((s) => Math.max(s - 1, 1));

  // ─── QR data ─────────────────────────────────────────────────────────────
  // const qrData = useMemo(() => {
    // return JSON.stringify({
      // appointmentId: bookedAppointmentId,
      // patient: session?.user?.name,
      // doctor: selectedDoctor?.name,
      // date: selectedDate ? format(selectedDate, "yyyy-MM-dd") : "",
      // slot: selectedSlot,
    // });
  // }, [bookedAppointmentId, session, selectedDoctor, selectedDate, selectedSlot]);

  // const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(qrData)}`;

  // ─── Render helpers ───────────────────────────────────────────────────────

  const renderStepBar = () => (
    <div className="flex items-center justify-between px-1">
      {STEPS.map((label, i) => {
        const s = i + 1;
        const done = step > s;
        const active = step === s;
        return (
          <div key={label} className="flex items-center gap-1">
            <div className="flex flex-col items-center gap-0.5">
              <div
                className={`w-7 h-7 rounded-full flex items-center justify-center text-xs font-bold transition-all ${
                  done
                    ? "bg-primary text-primary-foreground"
                    : active
                    ? "bg-primary text-primary-foreground ring-4 ring-primary/20"
                    : "bg-muted text-muted-foreground"
                }`}
              >
                {done ? <Check className="w-3.5 h-3.5" /> : s}
              </div>
              <span
                className={`text-[9px] font-semibold uppercase tracking-wider hidden sm:block ${
                  active ? "text-primary" : done ? "text-primary/60" : "text-muted-foreground"
                }`}
              >
                {label}
              </span>
            </div>
            {i < STEPS.length - 1 && (
              <div className={`h-0.5 w-4 sm:w-8 rounded-full mx-1 ${done ? "bg-primary" : "bg-muted"}`} />
            )}
          </div>
        );
      })}
    </div>
  );

  // ─── Step 1: Location + Mode ─────────────────────────────────────────────
  const renderStep1 = () => (
    <div className="flex flex-col gap-5">
      {/* Location */}
      <div className="flex flex-col gap-2">
        <p className="text-xs font-bold text-muted-foreground uppercase tracking-wider">Visit Location</p>
        {(locations as any[]).length === 0 ? (
          <div className="text-center py-6 border border-dashed rounded-xl text-muted-foreground text-sm">
            <Building className="w-7 h-7 mx-auto mb-2 opacity-30" />
            Loading locations...
          </div>
        ) : (
          <div className="space-y-2">
            {(locations as any[]).map((loc) => (
              <button
                key={loc.id}
                onClick={() => {
                  setSelectedLocationId(loc.id);
                  // Auto-proceed if consultation mode is also selected (it has a default)
                  if (consultationMode) setTimeout(goNext, 150);
                }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl border text-left transition-all ${
                  selectedLocationId === loc.id
                    ? "border-primary bg-primary/5 ring-2 ring-primary/20"
                    : "border-border bg-card hover:border-primary/30 hover:bg-muted/30"
                }`}
              >
                <div className={`w-9 h-9 rounded-xl flex items-center justify-center shrink-0 ${
                  selectedLocationId === loc.id ? "bg-primary text-primary-foreground" : "bg-muted text-muted-foreground"
                }`}>
                  <MapPin className="w-4 h-4" />
                </div>
                <div className="flex-1 min-w-0">
                  <p className={`font-semibold text-sm ${ selectedLocationId === loc.id ? "text-primary" : ""}`}>
                    {loc.name || loc.address || "Location"}
                  </p>
                  {loc.address && loc.name && (
                    <p className="text-xs text-muted-foreground truncate">{loc.address}</p>
                  )}
                </div>
                {selectedLocationId === loc.id && (
                  <Check className="w-4 h-4 text-primary shrink-0" />
                )}
              </button>
            ))}
          </div>
        )}
      </div>

      {/* Mode */}
      <div className="flex flex-col gap-2">
        <p className="text-xs font-bold text-muted-foreground uppercase tracking-wider">Consultation Mode</p>
        <div className="grid grid-cols-2 gap-3">
          {([
            { value: "IN_PERSON", label: "In-Person", desc: "Visit the clinic", icon: <Building className="w-5 h-5" /> },
            { value: "VIDEO", label: "Video Call", desc: "Remote consultation", icon: <Video className="w-5 h-5" /> },
          ] as const).map(({ value, label, desc, icon }) => (
            <button
              key={value}
              onClick={() => {
                setConsultationMode(value);
                // Auto-proceed if location is also selected
                if (selectedLocationId) setTimeout(goNext, 150);
              }}
              className={`flex flex-col items-center gap-2 px-4 py-4 rounded-xl border transition-all ${
                consultationMode === value
                  ? "border-primary bg-primary/5 ring-2 ring-primary/20"
                  : "border-border bg-card hover:border-primary/30 hover:bg-muted/30"
              }`}
            >
              <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${
                consultationMode === value ? "bg-primary text-primary-foreground" : "bg-muted text-muted-foreground"
              }`}>
                {icon}
              </div>
              <div className="text-center">
                <p className={`text-sm font-semibold ${ consultationMode === value ? "text-primary" : ""}`}>{label}</p>
                <p className="text-[11px] text-muted-foreground">{desc}</p>
              </div>
            </button>
          ))}
        </div>
      </div>
    </div>
  );

  // Step 2: Service (was Step 1)
  const renderStep2_Service = () => {
    const categories = ["All", ...Array.from(new Set(visibleServices.map((t) => t.category)))];
    const filtered =
      serviceFilter === "All"
        ? visibleServices
        : visibleServices.filter((t) => t.category === serviceFilter);

    return (
      <div className="flex flex-col gap-4">
        <p className="text-sm text-muted-foreground">What type of consultation do you need?</p>
        {servicesLoading ? (
          <div className="space-y-2">
            {Array.from({ length: 4 }).map((_, index) => (
              <div key={index} className="h-16 rounded-xl bg-muted animate-pulse" />
            ))}
          </div>
        ) : null}
        <div className="flex gap-2 overflow-x-auto pb-1 scroll-smooth">
          {categories.map((cat) => (
            <button
              key={cat}
              onClick={() => setServiceFilter(cat)}
              className={`shrink-0 px-3 py-1.5 rounded-full text-xs font-semibold border transition-all ${
                serviceFilter === cat
                  ? "bg-primary text-primary-foreground border-primary"
                  : "border-border bg-card hover:border-primary/40"
              }`}
            >
              {cat}
            </button>
          ))}
        </div>
        <div className="space-y-2">
          {!servicesLoading && filtered.length === 0 ? (
            <div className="text-center py-10 text-muted-foreground border border-dashed rounded-xl">
              <Activity className="w-8 h-8 mx-auto mb-2 opacity-30" />
              <p className="text-sm">No services available for this mode</p>
            </div>
          ) : null}
          {filtered.map((t) => (
            <button
              key={t.treatmentType}
              onClick={() => {
                setSelectedServiceId(t.treatmentType);
                setTimeout(goNext, 100);
              }}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl border text-left transition-all ${
                selectedServiceId === t.treatmentType
                  ? "border-primary bg-primary/5 ring-2 ring-primary/20"
                  : "border-border bg-card hover:border-primary/30 hover:bg-muted/30"
              }`}
            >
              {(() => {
                const visual = getConsultationVisual(t.treatmentType);
                return (
              <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 ${
                selectedServiceId === t.treatmentType ? "bg-primary text-primary-foreground" : "bg-muted text-muted-foreground"
              }`}>
                    {visual.icon}
              </div>
                );
              })()}
              <div className="flex-1 min-w-0 pr-4">
                <p className={`font-semibold text-sm ${selectedServiceId === t.treatmentType ? "text-primary" : ""}`}>{t.label}</p>
                <p className="text-xs text-muted-foreground truncate">{t.description}</p>
              </div>
            </button>
          ))}
        </div>
      </div>
    );
  };

  // Step 2: Doctor
  const renderStep2 = () => (
    <div className="flex flex-col gap-3">
      <p className="text-sm text-muted-foreground">Choose your preferred doctor</p>
      {doctorsLoading ? (
        <div className="space-y-2">
          {Array.from({ length: 4 }).map((_, i) => (
            <div key={i} className="h-16 rounded-xl bg-muted animate-pulse" />
          ))}
        </div>
      ) : doctorsList.length === 0 ? (
        <div className="text-center py-10 text-muted-foreground border border-dashed rounded-xl">
          <User className="w-8 h-8 mx-auto mb-2 opacity-30" />
          <p className="text-sm">No doctors available</p>
        </div>
      ) : (
        <div className="space-y-2">
          {doctorsList.map((doctor: any) => (
            <button
              key={doctor.id}
              onClick={() => {
                setSelectedDoctorId(doctor.id);
                setSelectedSlot("");
                setTimeout(goNext, 100);
              }}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl border text-left transition-all ${
                selectedDoctorId === doctor.id
                  ? "border-primary bg-primary/5 ring-2 ring-primary/20"
                  : "border-border bg-card hover:border-primary/30 hover:bg-muted/30"
              }`}
            >
              <div className={`w-11 h-11 rounded-full flex items-center justify-center shrink-0 text-sm font-bold ${
                selectedDoctorId === doctor.id ? "bg-primary text-primary-foreground" : "bg-muted text-muted-foreground"
              }`}>
                {doctor.image
                  ? <img src={doctor.image} alt="" className="w-full h-full rounded-full object-cover" />
                  : (doctor.name || "D").charAt(0)}
              </div>
              <div className="flex-1 min-w-0">
                <p className={`font-semibold text-sm ${selectedDoctorId === doctor.id ? "text-primary" : ""}`}>
                  {doctor.name}
                </p>
                <p className="text-xs text-muted-foreground">{doctor.specialization || "General Physician"}</p>
              </div>
              <div className="flex items-center gap-1.5 shrink-0">
                <span className="w-2 h-2 rounded-full bg-green-500" />
                <span className="text-xs text-green-600 font-medium">Available</span>
              </div>
            </button>
          ))}
        </div>
      )}
    </div>
  );

  // Step 3: Date
  const renderStep3 = () => (
    <div className="flex flex-col gap-3">
      <p className="text-sm text-muted-foreground">Pick your preferred appointment date</p>
      <div className="flex justify-center p-2 rounded-2xl bg-muted/20 border border-border shadow-sm">
        <Calendar
          mode="single"
          selected={selectedDate}
          onSelect={(d) => {
            setSelectedDate(d);
            setSelectedSlot("");
            if (d) setTimeout(goNext, 150);
          }}
          disabled={(date) => {
            // Enforce Indian Standard Time (IST) exactly for calculating disabled "past" days
            const todayIST = getTodayIST();
            const maxDate = getMaxBookingDate();
            // Disable dates before today OR after 3 days from today
            return date < todayIST || date > maxDate;
          }}
          className="mx-auto"
        />
      </div>
      {selectedDate && (
        <div className="flex items-center gap-2 px-4 py-3 rounded-xl bg-primary/5 border border-primary/20">
          <CalendarIcon className="w-4 h-4 text-primary shrink-0" />
          <span className="text-sm font-semibold">{format(selectedDate, "EEEE, d MMMM yyyy")}</span>
        </div>
      )}
    </div>
  );

  // Step 4: Slot
  const renderStep4 = () => {
    const periods = [
      { key: "morning" as const, label: "Morning", icon: <Sun className="w-4 h-4" />, range: "Before 12pm", slots: slotGroups.morning },
      { key: "afternoon" as const, label: "Afternoon", icon: <CloudSun className="w-4 h-4" />, range: "12pm – 5pm", slots: slotGroups.afternoon },
      { key: "evening" as const, label: "Evening", icon: <Moon className="w-4 h-4" />, range: "After 5pm", slots: slotGroups.evening },
    ];

    return (
      <div className="flex flex-col gap-4">
        <p className="text-sm text-muted-foreground">
          Available slots for <span className="font-semibold text-foreground">{selectedDoctor?.name}</span> on{" "}
          <span className="font-semibold text-foreground">{selectedDate ? format(selectedDate, "d MMM") : ""}</span>
        </p>

        {availabilityLoading ? (
          <div className="flex items-center gap-2 py-6 text-muted-foreground text-sm justify-center">
            <Loader2 className="w-5 h-5 animate-spin" /> Checking availability...
          </div>
        ) : effectiveSlots.length === 0 ? (
          <div className="flex flex-col items-center py-10 text-muted-foreground text-center border border-dashed rounded-xl">
            <Clock className="w-8 h-8 mb-2 opacity-20" />
            <p className="text-sm font-medium">
              {consultationBlocked ? "Consultation currently unavailable" : "No slots available"}
            </p>
            <p className="text-xs mt-1 opacity-60">
              {consultationBlocked
                ? (restrictions.reason || "Clinic/doctor settings currently block this consultation type")
                : "Try a different date or doctor"}
            </p>
            {availabilityError && <p className="text-xs mt-4 p-2 bg-red-500/10 rounded-md text-red-500 border border-red-500/20 max-w-[90%] text-center">Error: {(availabilityError as any).message || "Unknown error"}</p>}
          </div>
        ) : (
          <div className="space-y-4">
            {periods.map((period) =>
              period.slots.length === 0 ? null : (
                <div key={period.key}>
                  <div className="flex items-center gap-2 mb-2">
                    <span className="text-muted-foreground">{period.icon}</span>
                    <span className="text-xs font-bold text-muted-foreground uppercase tracking-wider">{period.label}</span>
                    <span className="text-[10px] text-muted-foreground">({period.range})</span>
                    <span className="ml-auto text-[10px] bg-muted px-1.5 py-0.5 rounded-full text-muted-foreground">
                      {period.slots.length} slots
                    </span>
                  </div>
                  <div className="grid grid-cols-3 sm:grid-cols-4 gap-2">
                    {period.slots.map((slot) => (
                      <button
                        key={slot}
                        onClick={() => {
                          setSelectedSlot(slot);
                          setTimeout(goNext, 150);
                        }}
                        className={`py-2.5 px-2 rounded-xl text-xs font-semibold border transition-all text-center ${
                          selectedSlot === slot
                            ? "bg-primary text-primary-foreground border-primary shadow-md ring-2 ring-primary/20"
                            : "bg-card border-border hover:border-primary/50 hover:bg-primary/5"
                        }`}
                      >
                        {slot}
                      </button>
                    ))}
                  </div>
                </div>
              )
            )}
          </div>
        )}
      </div>
    );
  };

  // Step 5: Confirm
  const renderStep5 = () => (
    <div className="flex flex-col gap-4">
      <p className="text-sm text-muted-foreground">Review your appointment before confirming</p>

      {/* Summary card */}
      <div className="rounded-2xl border bg-muted/30 divide-y">
        {[
          { label: "Service", value: selectedService?.label, sub: selectedService?.category },
          { label: "Doctor", value: selectedDoctor?.name, sub: selectedDoctor?.specialization || "General Physician" },
          { label: "Date", value: selectedDate ? format(selectedDate, "EEEE, d MMMM yyyy") : "" },
          { label: "Time", value: selectedSlot },
        ].map(({ label, value, sub }) => (
          <div key={label} className="flex items-center justify-between px-4 py-3 gap-4">
            <span className="text-xs font-semibold text-muted-foreground uppercase tracking-wider w-16 shrink-0">{label}</span>
            <div className="flex-1 text-right">
              <p className="text-sm font-semibold">{value}</p>
              {sub && <p className="text-xs text-muted-foreground">{sub}</p>}
            </div>
          </div>
        ))}
      </div>

      {/* Additional fields */}
      <div className="space-y-3">
        <div>
          <label className="text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-1.5 block">
            Chief Complaint
          </label>
          <Textarea
            value={chiefComplaint}
            onChange={(e) => setChiefComplaint(e.target.value)}
            placeholder="Briefly describe your symptoms or reason for visit..."
            className="text-sm resize-none h-20"
          />
        </div>
        <div>
          <label className="text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-1.5 block">
            Urgency
          </label>
          <Select value={urgency} onValueChange={setUrgency}>
            <SelectTrigger className="h-9">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="Low">🟢 Low — Routine checkup</SelectItem>
              <SelectItem value="Normal">🟡 Normal — Regular visit</SelectItem>
              <SelectItem value="High">🔴 High — Urgent care needed</SelectItem>
            </SelectContent>
          </Select>
        </div>
      </div>
    </div>
  );

  // Step 6: Success + QR Code
  const renderStep6 = () => (
    <div className="flex flex-col items-center gap-5 py-2">
      <div className="w-14 h-14 rounded-full bg-green-100 dark:bg-green-900/30 flex items-center justify-center">
        <Check className="w-7 h-7 text-green-600 dark:text-green-400" />
      </div>
      <div className="text-center">
        <h3 className="text-lg font-bold">Appointment Confirmed!</h3>
        <p className="text-sm text-muted-foreground mt-1">
          Your appointment has been booked successfully.
        </p>
      </div>

      {consultationMode === "VIDEO" ? (
        <div className="flex flex-col items-center gap-3 p-4 rounded-2xl border bg-card w-full max-w-sm">
          <div className="flex items-center gap-2 text-sm font-semibold text-muted-foreground">
            <Video className="w-4 h-4" /> Video Payment Required
          </div>
          <p className="text-xs text-muted-foreground text-center">
            Video appointments are billed per appointment. Complete payment to proceed.
          </p>
          <PaymentButton
            appointmentId={bookedAppointmentId}
            amount={selectedService?.videoConsultationFee || 500}
            description={selectedService?.label || "Video Consultation"}
            className="w-full"
          >
            Pay INR {(selectedService?.videoConsultationFee || 500).toLocaleString("en-IN")}
          </PaymentButton>
        </div>
      ) : (
        <div className="flex flex-col items-center gap-3 p-4 rounded-2xl border bg-card w-full max-w-sm text-center">
          <div className="flex justify-center w-12 h-12 rounded-full bg-blue-100 dark:bg-blue-900/30 items-center mb-1">
            <QrCode className="w-6 h-6 text-blue-600 dark:text-blue-400" />
          </div>
          <h4 className="font-semibold text-sm">Fast Self Check-in Available</h4>
          <p className="text-xs text-muted-foreground">
            When you arrive at the clinic, simply scan the Reception QR code using your phone to instantly check-in to this appointment.
          </p>
        </div>
      )}

      {/* Summary pill row */}
      <div className="flex flex-wrap gap-2 justify-center">
        {[
          selectedService?.label,
          selectedDoctor?.name,
          selectedDate ? format(selectedDate, "d MMM") : "",
          selectedSlot,
        ].map((v, i) => v ? (
          <span key={i} className="px-3 py-1 bg-primary/10 text-primary text-xs font-semibold rounded-full">
            {v}
          </span>
        ) : null)}
      </div>

      <Button
        className="w-full"
        onClick={() => {
          setOpen(false);
          // Ensure users land on appointment list after successful booking.
          if (pathname !== postBookingRoute) {
            router.push(postBookingRoute);
          }
        }}
      >
        {postBookingLabel}
      </Button>
    </div>
  );

  // ─── Main render ──────────────────────────────────────────────────────────

  const stepContent = [
    renderStep1,        // 1: Location + Mode
    renderStep2_Service, // 2: Service
    renderStep2,        // 3: Doctor
    renderStep3,        // 4: Date
    renderStep4,        // 5: Slot
    renderStep5,        // 6: Confirm
    renderStep6,        // 7: Success + QR
  ][step - 1];

  const stepTitle = [
    "Location & Mode",
    "Select Service",
    "Select Doctor",
    "Select Date",
    "Select Time Slot",
    "Confirm Appointment",
    "Booking Confirmed! 🎉",
  ][step - 1];

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        {trigger || (
          <Button className="flex items-center gap-2 bg-linear-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700 hover:scale-105 transition-all">
            <Plus className="w-4 h-4" />
            Book Appointment
          </Button>
        )}
      </DialogTrigger>

      <DialogContent className="
        w-full max-w-none sm:max-w-md
        h-dvh sm:h-[650px]
        flex flex-col p-0 gap-0 overflow-hidden
        rounded-none sm:rounded-2xl
        top-0 sm:top-1/2 left-0 sm:left-1/2
        translate-y-0 sm:-translate-y-1/2 sm:-translate-x-1/2
      ">
        {/* Header */}
        <div className="px-4 sm:px-5 pt-4 pb-3 border-b shrink-0">
          <DialogHeader className="text-left w-full min-w-0">
            <DialogTitle className="text-base sm:text-lg font-bold truncate">{stepTitle}</DialogTitle>
          </DialogHeader>

          {/* Step bar — hide on success screen */}
          {step < 7 && (
            <div className="mt-3 overflow-x-auto">
              {renderStepBar()}
            </div>
          )}
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto px-4 sm:px-5 py-4">
          {stepContent?.()}
        </div>

        {/* Footer — hide on success screen */}
        {step < 7 && (
          <div className="px-4 sm:px-5 py-3 border-t bg-background flex items-center gap-3 shrink-0">
            <Button
              variant="outline"
              onClick={step > 1 ? goBack : () => setOpen(false)}
              className="gap-1.5 shrink-0"
              size="sm"
            >
              <ChevronLeft className="w-4 h-4" /> {step > 1 ? "Back" : "Cancel"}
            </Button>

            <div className="flex-1" />

            {step < 6 ? (
              <Button
                onClick={goNext}
                disabled={!canNext}
                className="gap-1.5 min-w-[100px]"
                size="sm"
              >
                Continue <ArrowRight className="w-4 h-4" />
              </Button>
            ) : (
              <Button
                onClick={handleBook}
                disabled={isBooking}
                className="gap-1.5 min-w-[140px] bg-green-600 hover:bg-green-700"
                size="sm"
              >
                {isBooking ? (
                  <><Loader2 className="w-4 h-4 animate-spin" /> Booking...</>
                ) : (
                  <><Check className="w-4 h-4" /> Confirm & Book</>
                )}
              </Button>
            )}
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { 
  Dialog, 
  DialogContent, 
  DialogHeader, 
  DialogTitle, 
  DialogTrigger 
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { useClinics, useClinicLocations, useMyClinic, useClinic } from "@/hooks/query/useClinics";
import { MapPin, Building, ChevronRight, Loader2, Plus } from "lucide-react";
import { ScrollArea } from "@/components/ui/scroll-area";


interface ClinicSelectDialogProps {
  trigger?: React.ReactNode;
}

export function ClinicSelectDialog({ trigger }: ClinicSelectDialogProps) {
  const router = useRouter();
  const [open, setOpen] = useState(false);
  const [selectedClinicId, setSelectedClinicId] = useState<string | null>(null);

  const { data: clinicsResponse, isPending: clinicsLoading } = useClinics();
  const { data: myClinic, isPending: myClinicLoading } = useMyClinic();
  const { data: defaultClinic, isPending: defaultClinicLoading } = useClinic();
  
  // Prioritize user's associated clinic for isolation, fallback to all clinics only if no association
  const clinics = myClinic 
    ? [myClinic] 
    : (clinicsResponse && clinicsResponse.length > 0 ? clinicsResponse : (defaultClinic ? [defaultClinic] : []));
    
const isLoading = clinicsLoading || myClinicLoading || defaultClinicLoading;

  const { data: locations, isPending: locationsLoading } = useClinicLocations(selectedClinicId || "");

  useEffect(() => {
    if (!selectedClinicId && clinics && clinics.length === 1 && clinics[0]) {
      setSelectedClinicId(clinics[0].id);
    }
  }, [clinics, selectedClinicId]);

  const handleSelectLocation = (clinicId: string, locationId: string) => {
    setOpen(false);
    const selectedClinic = clinics.find(c => c.id === clinicId);
    const clinicName = selectedClinic?.name || "";
    router.push(`/patient/appointments?clinicId=${clinicId}&locationId=${locationId}&clinicName=${encodeURIComponent(clinicName)}`);
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        {trigger || (
          <Button className="flex items-center gap-2 hover:scale-105 transition-transform bg-linear-to-r from-blue-600 to-purple-600">
            <Plus className="w-4 h-4" />
            Book Appointment
          </Button>
        )}
      </DialogTrigger>
      <DialogContent className="max-w-2xl max-h-[85vh] flex flex-col p-0 gap-0 overflow-hidden">
        <DialogHeader className="p-6 pb-2">
          <DialogTitle className="text-2xl font-bold flex items-center gap-2">
            <Building className="w-6 h-6 text-blue-600" />
            Select Clinic Location
          </DialogTitle>
          <p className="text-muted-foreground text-sm">
            Choose a clinic location to book your appointment.
          </p>
        </DialogHeader>

        <div className="flex-1 overflow-hidden flex flex-col border-t mt-4">
          {/* Clinic Header / Context - Only show if we have a clinic selected or only one option */}
          {(selectedClinicId && clinics.find(c => c.id === selectedClinicId)) && (
            <div className="px-6 py-4 bg-muted/30 border-b flex items-center justify-between">
              <div>
                 <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-1">Clinic</p>
                 <h3 className="font-semibold text-base text-foreground flex items-center gap-2">
                    <Building className="w-4 h-4 text-blue-600" />
                    {clinics.find(c => c.id === selectedClinicId)?.name}
                 </h3>
                 <p className="text-xs text-muted-foreground mt-0.5">{clinics.find(c => c.id === selectedClinicId)?.address}</p>
              </div>
              {clinics.length > 1 && (
                <Button variant="ghost" size="sm" onClick={() => setSelectedClinicId(null)} className="text-xs h-8">
                  Change
                </Button>
              )}
            </div>
          )}

          {/* Clinic List - Only show if no clinic is selected (rare case if length > 1) */}
          {!selectedClinicId && (
             <div className="flex-1 overflow-y-auto p-4">
               <p className="text-sm font-medium mb-3 text-muted-foreground">Please select a clinic</p>
               <div className="grid gap-3">
                 {isLoading ? (
                    <div className="flex justify-center p-4"><Loader2 className="animate-spin text-blue-600" /></div>
                 ) : clinics.map(clinic => (
                   <button
                     key={clinic.id}
                     onClick={() => setSelectedClinicId(clinic.id)}
                     className="w-full text-left p-4 rounded-xl border hover:border-blue-500 hover:shadow-sm transition-all bg-card"
                   >
                     <h4 className="font-semibold">{clinic.name}</h4>
                     <p className="text-sm text-muted-foreground">{clinic.address}</p>
                   </button>
                 ))}
               </div>
             </div>
          )}

          {/* Location List - Full Width */}
          {selectedClinicId && (
            <div className="flex-1 flex flex-col min-h-0 bg-background">
              <div className="px-6 py-3 border-b bg-background z-10">
                <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">
                  Available Locations
                </p>
              </div>
              <ScrollArea className="flex-1 h-[400px]">
                <div className="p-4 pt-2 space-y-3">
                  {locationsLoading ? (
                    <div className="flex items-center justify-center py-12">
                      <Loader2 className="w-6 h-6 animate-spin text-blue-600" />
                    </div>
                  ) : !locations || locations.length === 0 ? (
                    <div className="text-center py-12 space-y-3">
                      <div className="w-12 h-12 rounded-full bg-muted flex items-center justify-center mx-auto">
                         <MapPin className="w-6 h-6 text-muted-foreground" />
                      </div>
                      <p className="text-sm text-muted-foreground">No active locations for this clinic.</p>
                    </div>
                  ) : (
                    locations.map((loc) => (
                      <button
                        key={loc.id}
                        onClick={() => handleSelectLocation(selectedClinicId, loc.id)}
                        className="group w-full text-left p-4 rounded-xl border border-neutral-200 dark:border-neutral-800 hover:border-blue-500 hover:ring-2 hover:ring-blue-500/20 transition-all bg-white dark:bg-neutral-900 shadow-sm"
                      >
                        <div className="flex items-center justify-between">
                          <div className="space-y-1">
                            <h4 className="font-bold text-base group-hover:text-blue-600 transition-colors">
                              {loc.name}
                            </h4>
                            <div className="flex items-start gap-2 text-sm text-muted-foreground">
                              <MapPin className="w-4 h-4 mt-0.5 shrink-0 text-muted-foreground/70" />
                              <span>{loc.address}, {loc.city}</span>
                            </div>
                            {loc.phone && (
                              <p className="text-xs text-muted-foreground pl-6">
                                Ph: {loc.phone}
                              </p>
                            )}
                          </div>
                          <ChevronRight className="w-5 h-5 text-muted-foreground group-hover:text-blue-500 group-hover:translate-x-1 transition-all" />
                        </div>
                        {loc.isActive && (
                          <div className="mt-3 pl-6 flex items-center gap-2">
                             <span className="inline-flex items-center gap-1.5 py-0.5 px-2 rounded-full text-xs font-medium bg-green-50 text-green-700 dark:bg-green-900/20 dark:text-green-400 border border-green-100 dark:border-green-900/30">
                                <span className="relative flex h-2 w-2">
                                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                                  <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                                </span>
                                Accepting Appointments
                             </span>
                          </div>
                        )}
                      </button>
                    ))
                  )}
                </div>
              </ScrollArea>
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { useState } from "react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Plus, Trash2, Loader2 } from "lucide-react";
import { useProposeVideoAppointment } from "@/hooks/query/useAppointments";
import { useDoctors } from "@/hooks/query/useDoctors";
import { usePatients } from "@/hooks/query/usePatients";
import { useClinicContext } from "@/hooks/query/useClinics";
import { Role } from "@/types/auth.types";

const TIME_OPTIONS = ["09:00", "09:30", "10:00", "10:30", "11:00", "11:30", "14:00", "14:30", "15:00", "15:30", "16:00", "16:30", "17:00"];

export interface ProposeVideoAppointmentDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  patientId: string;
  userRole: Role | string;
}

export function ProposeVideoAppointmentDialog({
  open,
  onOpenChange,
  patientId: initialPatientId,
  userRole,
}: ProposeVideoAppointmentDialogProps) {
  const { clinicId } = useClinicContext();
  const proposeMutation = useProposeVideoAppointment();
  const { data: doctorsData } = useDoctors(clinicId || "", { limit: 100 });
  // Only fetch patients when RECEPTIONIST – backend GET /clinics/:id/patients denies PATIENT
  const { data: patientsData } = usePatients(
    userRole === Role.RECEPTIONIST ? (clinicId || "") : "",
    { limit: 200 }
  );
  const doctors = Array.isArray((doctorsData as any)?.doctors) 
    ? (doctorsData as any).doctors 
    : (Array.isArray((doctorsData as any)?.data?.doctors)
        ? (doctorsData as any).data.doctors
        : (Array.isArray((doctorsData as any)?.data) ? (doctorsData as any).data : []));

  const patients = Array.isArray((patientsData as any)?.patients) 
    ? (patientsData as any).patients 
    : (Array.isArray((patientsData as any)?.data?.patients)
        ? (patientsData as any).data.patients
        : (Array.isArray((patientsData as any)?.data) ? (patientsData as any).data : []));

  const [selectedPatientId, setSelectedPatientId] = useState("");
  const patientId = userRole === Role.RECEPTIONIST ? selectedPatientId : initialPatientId;

  const [doctorId, setDoctorId] = useState("");
  const [duration, setDuration] = useState(30);
  const [proposedSlots, setProposedSlots] = useState<Array<{ date: string; time: string }>>([
    { date: "", time: "" },
    { date: "", time: "" },
    { date: "", time: "" },
  ]);
  const [notes, setNotes] = useState("");

  const addSlot = () => {
    if (proposedSlots.length < 4) {
      setProposedSlots([...proposedSlots, { date: "", time: "" }]);
    }
  };

  const removeSlot = (index: number) => {
    if (proposedSlots.length > 3) {
      setProposedSlots(proposedSlots.filter((_, i) => i !== index));
    }
  };

  const updateSlot = (index: number, field: "date" | "time", value: string) => {
    const updated = [...proposedSlots];
    if (field === "date") {
      updated[index] = { ...updated[index], date: value } as { date: string; time: string };
    } else {
      updated[index] = { ...updated[index], time: value } as { date: string; time: string };
    }
    setProposedSlots(updated);
  };

  const getMinDate = () => {
    const d = new Date();
    d.setDate(d.getDate() + 2); // Backend requires at least 2 days advance for video appointments
    return d.toISOString().split("T")[0];
  };

  const handleSubmit = async () => {
    if (!clinicId) return;

    const validSlots = proposedSlots.filter((s) => s.date && s.time);
    if (validSlots.length < 3) {
      return;
    }

    await proposeMutation.mutateAsync({
      patientId,
      doctorId,
      clinicId,
      duration,
      proposedSlots: validSlots,
      ...(notes ? { notes } : {}),
    });

    onOpenChange(false);
    setDoctorId("");
    setProposedSlots([{ date: "", time: "" }, { date: "", time: "" }, { date: "", time: "" }]);
    setNotes("");
  };

  const validSlots = proposedSlots.filter((s) => s.date && s.time).length;
  const canSubmit =
    doctorId &&
    validSlots >= 3 &&
    clinicId &&
    (userRole !== Role.RECEPTIONIST || selectedPatientId);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[520px]">
        <DialogHeader>
          <DialogTitle>Propose Video Appointment</DialogTitle>
          <DialogDescription>
            Propose 3–4 time slots. The doctor will select one to confirm your video appointment.
          </DialogDescription>
        </DialogHeader>
        <div className="grid gap-4 py-4">
          {userRole === Role.RECEPTIONIST && (
            <div className="grid gap-2">
              <Label>Patient</Label>
              <Select value={selectedPatientId} onValueChange={setSelectedPatientId}>
                <SelectTrigger>
                  <SelectValue placeholder="Select patient" />
                </SelectTrigger>
                <SelectContent>
                  {patients.map((p: { id: string; user?: { name?: string }; userId?: string }) => (
                    <SelectItem key={p.id} value={p.id}>
                      {p.user?.name ?? p.userId ?? p.id}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          )}
          <div className="grid gap-2">
            <Label>Doctor</Label>
            <Select value={doctorId} onValueChange={setDoctorId}>
              <SelectTrigger>
                <SelectValue placeholder="Select doctor" />
              </SelectTrigger>
              <SelectContent>
                {doctors.map((doc: { id: string; user?: { name?: string; firstName?: string }; userId?: string }) => (
                  <SelectItem key={doc.id} value={doc.id}>
                    {doc.user?.name ?? doc.user?.firstName ?? doc.userId ?? doc.id}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
          <div className="grid gap-2">
            <Label>Duration (minutes)</Label>
            <Select value={String(duration)} onValueChange={(v) => setDuration(Number(v))}>
              <SelectTrigger>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="15">15 min</SelectItem>
                <SelectItem value="30">30 min</SelectItem>
                <SelectItem value="45">45 min</SelectItem>
                <SelectItem value="60">60 min</SelectItem>
              </SelectContent>
            </Select>
          </div>
          <div className="grid gap-2">
            <Label>Proposed time slots (3–4)</Label>
            {proposedSlots.map((slot, i) => (
              <div key={i} className="flex gap-2 items-center">
                <Input
                  type="date"
                  value={slot.date}
                  min={getMinDate()}
                  onChange={(e) => updateSlot(i, "date", e.target.value)}
                  className="w-32"
                />
                <Select value={slot.time} onValueChange={(v) => updateSlot(i, "time", v)}>
                  <SelectTrigger className="w-28">
                    <SelectValue placeholder="Time" />
                  </SelectTrigger>
                  <SelectContent>
                    {TIME_OPTIONS.map((t) => (
                      <SelectItem key={t} value={t}>
                        {t}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                {proposedSlots.length > 3 && (
                  <Button type="button" variant="ghost" size="icon" onClick={() => removeSlot(i)}>
                    <Trash2 className="h-4 w-4" />
                  </Button>
                )}
              </div>
            ))}
            {proposedSlots.length < 4 && (
              <Button type="button" variant="outline" size="sm" onClick={addSlot} className="gap-1 w-fit">
                <Plus className="h-4 w-4" />
                Add slot
              </Button>
            )}
          </div>
          <div className="grid gap-2">
            <Label>Notes (optional)</Label>
            <Textarea value={notes} onChange={(e) => setNotes(e.target.value)} placeholder="Any notes for the doctor" rows={2} />
          </div>
        </div>
        <DialogFooter>
          <Button variant="outline" onClick={() => onOpenChange(false)}>
            Cancel
          </Button>
          <Button onClick={handleSubmit} disabled={!canSubmit || proposeMutation.isPending}>
            {proposeMutation.isPending ? (
              <>
                <Loader2 className="h-4 w-4 animate-spin mr-2" />
                Proposing...
              </>
            ) : (
              "Propose Appointment"
            )}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { useState } from "react";
import { useAuth } from "@/hooks/auth/useAuth";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { InputOTP, InputOTPGroup, InputOTPSlot } from "@/components/ui/input-otp";
import { Loader2, ArrowLeft, Mail, CheckCircle2 } from "lucide-react";
import { showErrorToast } from "@/hooks/utils/use-toast";
import { REGEXP_ONLY_DIGITS_AND_CHARS } from "input-otp";

export function EmailOtpRegisterForm() {
  const { requestOTP, verifyOTP, isRequestingOTP, isVerifyingOTP } = useAuth();
  const [step, setStep] = useState<1 | 2>(1);
  const [email, setEmail] = useState("");
  const [otp, setOtp] = useState("");
  const [firstName, setFirstName] = useState("");
  const [lastName, setLastName] = useState("");

  const handleRequestOtp = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email) {
        showErrorToast("Please enter your email address");
        return;
    }
    try {
        await requestOTP({ identifier: email, isRegistration: true });
        setStep(2);
    } catch (error) {
        // Error handling is managed by the mutation hook via toasts mostly
    }
  };

  const handleVerify = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!otp || otp.length < 6) {
        showErrorToast("Please enter a valid OTP");
        return;
    }
    if (!firstName || !lastName) {
        showErrorToast("Please enter your full name");
        return;
    }
    
    try {
        await verifyOTP({
            identifier: email,
            otp,
            isRegistration: true,
            firstName,
            lastName
        });
    } catch (error) {
        // Error handling
    }
  };

  if (step === 1) {
    return (
      <form onSubmit={handleRequestOtp} className="space-y-4 pt-4">
        <div className="space-y-2">
          <Label htmlFor="email">Email</Label>
          <Input
            id="email"
            placeholder="name@example.com"
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            disabled={isRequestingOTP}
            required
          />
        </div>
        <Button 
            className="w-full" 
            type="submit" 
            disabled={isRequestingOTP}
        >
            {isRequestingOTP ? (
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
            ) : (
                <Mail className="mr-2 h-4 w-4" />
            )}
            Send OTP
        </Button>
      </form>
    );
  }

  return (
    <form onSubmit={handleVerify} className="space-y-4 pt-4">
      <div className="space-y-4">
        <div className="space-y-2">
          <Label>Enter OTP</Label>
          <div className="flex justify-center">
            <InputOTP
                maxLength={6}
                value={otp}
                onChange={(value) => setOtp(value)}
                pattern={REGEXP_ONLY_DIGITS_AND_CHARS}
                disabled={isVerifyingOTP}
            >
                <InputOTPGroup>
                <InputOTPSlot index={0} />
                <InputOTPSlot index={1} />
                <InputOTPSlot index={2} />
                <InputOTPSlot index={3} />
                <InputOTPSlot index={4} />
                <InputOTPSlot index={5} />
                </InputOTPGroup>
            </InputOTP>
          </div>
          <p className="text-xs text-center text-muted-foreground mt-2">
            We sent a code to <span className="font-medium">{email}</span>
          </p>
        </div>

        <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
                <Label htmlFor="firstName">First Name</Label>
                <Input
                    id="firstName"
                    placeholder="John"
                    value={firstName}
                    onChange={(e) => setFirstName(e.target.value)}
                    disabled={isVerifyingOTP}
                    required
                />
            </div>
            <div className="space-y-2">
                <Label htmlFor="lastName">Last Name</Label>
                <Input
                    id="lastName"
                    placeholder="Doe"
                    value={lastName}
                    onChange={(e) => setLastName(e.target.value)}
                    disabled={isVerifyingOTP}
                    required
                />
            </div>
        </div>
      </div>

      <div className="flex gap-2">
        <Button 
            variant="outline" 
            onClick={() => setStep(1)}
            disabled={isVerifyingOTP}
            type="button"
            className="w-1/3"
        >
            <ArrowLeft className="mr-2 h-4 w-4" />
            Back
        </Button>
        <Button 
            className="w-2/3" 
            type="submit"
            disabled={isVerifyingOTP}
        >
            {isVerifyingOTP ? (
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
            ) : (
                <CheckCircle2 className="mr-2 h-4 w-4" />
            )}
            Verify & Register
        </Button>
      </div>
    </form>
  );
}

