"use client";

import React, { useState } from "react";
import { cn } from "@/lib/utils/index";
import {
  Activity,
  RefreshCw,
  Server,
  Database,
  Wifi,
  HardDrive,
  Video,
  Zap,
} from "lucide-react";
import { StatusIndicator, StatusType, StatusDot } from "./StatusIndicator";
import { useDetailedHealthStatus } from "@/hooks/query/useHealth";

// Helper to map status string to StatusType
const mapStatus = (status?: string, healthy?: boolean): StatusType => {
  if (status === 'up' || healthy === true) return "active";
  if (status === 'degraded') return "warning";
  if (status === 'down' || healthy === false) return "error";
  return "loading";
};

export function BackendStatusIndicator() {
  const { data: healthStatus, refetch, isFetching, lastUpdate, isConnected } = useDetailedHealthStatus();

  const getOverallStatus = (): StatusType => {
    if (!healthStatus) return "loading";

    // Simple logic: if any critical service is down, global is error
    // If any service is degraded, global is warning
    const services = [
      healthStatus.database,
      healthStatus.cache,
      healthStatus.queue,
      healthStatus.communication,
      healthStatus.video
    ];

    const isUnhealthy = (s: any) => {
      if (!s) return false;
      if (s.status === 'down') return true;
      if ('healthy' in s && s.healthy === false) return true;
      if ('isHealthy' in s && s.isHealthy === false) return true;
      return false;
    };

    const isDegraded = (s: any) => {
      if (!s) return false;
      if (s.status === 'degraded') return true;
      if ('degraded' in s && s.degraded === true) return true;
      return false;
    };

    if (services.some(isUnhealthy)) return "error";
    if (services.some(isDegraded)) return "warning";

    return "active";
  };

  const getOverallLabel = () => {
    if (!healthStatus) return "Connecting...";
    const status = getOverallStatus();
    if (status === "active") return "100% Operational";
    if (status === "warning") return "Services Degraded";
    return "Partial Outage";
  };

  // Helper to construct service objects for display
  const services = [
    {
      name: "API Server",
      icon: Server,
      status: mapStatus(healthStatus ? 'up' : undefined, !!healthStatus), // API is up if we have data
      responseTime: healthStatus?.system?.requestRate ? Math.round(1000 / (healthStatus.system.requestRate || 1)) : 1, // Estimate from rate
    },
    {
      name: "Database",
      icon: Database,
      status: mapStatus(healthStatus?.database?.status, healthStatus?.database?.isHealthy),
      responseTime: healthStatus?.database?.avgResponseTime,
    },
    {
      name: "Cache Service",
      icon: HardDrive,
      status: mapStatus(healthStatus?.cache?.status, healthStatus?.cache?.healthy),
      responseTime: healthStatus?.cache?.latency,
    },
    {
      name: "Queue System",
      icon: Zap,
      status: mapStatus(healthStatus?.queue?.status, healthStatus?.queue?.healthy),
      responseTime: healthStatus?.queue?.connection?.latency,
    },
    {
      name: "Communication",
      icon: Wifi,
      status: mapStatus(healthStatus?.communication?.status, healthStatus?.communication?.healthy),
      responseTime: healthStatus?.communication?.socket?.latency,
    },
    {
      name: "Video Service",
      icon: Video,
      status: mapStatus(healthStatus?.video?.status, healthStatus?.video?.isHealthy),
      responseTime: undefined,
    },
    {
      name: "Logger Service",
      icon: HardDrive,
      status: mapStatus(healthStatus?.logging?.status, healthStatus?.logging?.healthy),
      responseTime: healthStatus?.logging?.service?.latency,
    },
  ];

  const indicator = (
    <StatusIndicator
      status={getOverallStatus()}
      label={getOverallLabel()}
      icon={Activity}
      size="sm"
    />
  );

  const detailed = (
    <div className="space-y-2">
      <div className="flex items-center justify-between">
        <h4 className="font-medium text-sm">Backend Services Status</h4>
        <button
          onClick={() => refetch()}
          disabled={isFetching}
          className="p-1 text-gray-500 hover:text-gray-700 disabled:opacity-50"
          title="Refresh backend status"
          aria-label="Refresh backend status"
        >
          <RefreshCw
            className={cn(
              "h-4 w-4",
              isFetching && "animate-spin"
            )}
          />
        </button>
      </div>

      <div className="space-y-1">
        {services.map((service) => {
          const statusColor =
            {
              active: "text-green-600",
              warning: "text-yellow-700",
              error: "text-red-700",
              loading: "text-blue-600",
              inactive: "text-gray-500",
            }[service.status] || "text-gray-600";

          return (
            <div
              key={service.name}
              className="flex items-center justify-between text-xs"
            >
              <div className="flex items-center gap-2">
                <service.icon className={cn("h-3 w-3", statusColor)} />
                <span className={cn("font-medium", statusColor)}>
                  {service.name}
                </span>
              </div>
              <div className="flex items-center gap-2">
                {service.responseTime !== undefined &&
                  service.responseTime !== null && (
                    <span
                      className={cn(
                        "text-xs",
                        service.status === "active"
                          ? "text-green-600"
                          : service.status === "warning"
                          ? "text-yellow-600"
                          : service.status === "error"
                          ? "text-red-600"
                          : "text-gray-500"
                      )}
                    >
                      {Math.round(service.responseTime)}ms
                    </span>
                  )}
                <StatusDot status={service.status} size="sm" />
              </div>
            </div>
          );
        })}
      </div>

      <div className="flex justify-between items-center border-t pt-2">
         {lastUpdate && (
          <div className="text-xs text-gray-500">
            Last update: {lastUpdate.toLocaleTimeString()}
          </div>
        )}
        <div className="text-xs text-gray-500">
           {isConnected ? 'Realtime Connected' : 'Updates Paused'}
        </div>
      </div>
    </div>
  );

  return {
    indicator,
    detailed,
    refresh: refetch,
    isChecking: isFetching
  };
}

export function CompactBackendStatus({ className }: { className?: string }) {
  const backend = BackendStatusIndicator();

  return (
    <div className={cn("flex items-center gap-2", className)}>
      {backend.indicator}
    </div>
  );
}

export function DetailedBackendStatus({ className }: { className?: string }) {
  const backend = BackendStatusIndicator();

  return (
    <div className={cn("bg-white rounded-lg border p-4 shadow-sm", className)}>
      {backend.detailed}
    </div>
  );
}

export function BackendStatusWidget({ className }: { className?: string }) {
  const backend = BackendStatusIndicator();
  const [showDetails, setShowDetails] = useState(false);
  const [showModal, setShowModal] = useState(false);

  const GlobalHealthStatusModal = React.lazy(() =>
    import("@/components/admin/GlobalHealthStatusModal").then((m) => ({
      default: m.GlobalHealthStatusModal,
    }))
  );

  const handleClick = () => {
    setShowModal(true);
    setShowDetails(false);
  };

  return (
    <>
      <div className={cn("relative", className)}>
        <div
          className="cursor-pointer"
          onClick={handleClick}
          onKeyDown={(e) => {
            if (e.key === "Enter" || e.key === " ") {
              e.preventDefault();
              handleClick();
            }
          }}
          role="button"
          tabIndex={0}
          aria-label="View comprehensive system health status"
        >
          {backend.indicator}
        </div>

        {showDetails && (
          <div className="absolute top-full left-0 mt-2 z-50 bg-white rounded-lg border shadow-lg p-4 min-w-80">
            {backend.detailed}
          </div>
        )}
      </div>

      {showModal && (
        <React.Suspense fallback={null}>
          <GlobalHealthStatusModal
            open={showModal}
            onOpenChange={setShowModal}
          />
        </React.Suspense>
      )}
    </>
  );
}

"use client";

import React, { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Activity } from 'lucide-react';
import { cn } from '@/lib/utils';
import { useDetailedHealthStatus } from '@/hooks/query/useHealth';
import { Badge } from '@/components/ui/badge';

// Dynamically import to avoid SSR issues and circular dependencies
const GlobalHealthStatusModal = React.lazy(
  () => import('@/components/admin/GlobalHealthStatusModal').then(m => ({ default: m.GlobalHealthStatusModal }))
);

interface GlobalHealthStatusButtonProps {
  className?: string;
  variant?: 'floating' | 'inline';
  position?: 'bottom-right' | 'bottom-left' | 'top-right' | 'top-left';
}

export function GlobalHealthStatusButton({
  className,
  variant = 'floating',
  position = 'bottom-right',
}: GlobalHealthStatusButtonProps) {
  const [isOpen, setIsOpen] = useState(false);
  const { 
    data: healthData, 
    isConnected,
    connectionStatus,
  } = useDetailedHealthStatus();

  // Calculate overall health
  const services = [
    { name: 'Database', status: (healthData as any)?.database?.status || 'unknown' },
    { name: 'Cache', status: (healthData as any)?.cache?.status || 'unknown' },
    { name: 'Queue', status: (healthData as any)?.queue?.status || 'unknown' },
    { name: 'Communication', status: (healthData as any)?.communication?.status || 'unknown' },
    { name: 'Video', status: (healthData as any)?.video?.status || 'unknown' },
    { name: 'Logging', status: (healthData as any)?.logging?.status || 'unknown' },
  ];

  const healthyCount = services.filter(s => s.status === 'up').length;
  const totalCount = services.length;
  const overallHealth = healthyCount === totalCount ? 'healthy' : healthyCount === 0 ? 'critical' : 'degraded';

  const positionClasses = {
    'bottom-right': 'bottom-20 right-4', // Positioned above WhatsApp button (which is at bottom-4)
    'bottom-left': 'bottom-4 left-4',
    'top-right': 'top-4 right-4',
    'top-left': 'top-4 left-4',
  };

  const healthColors = {
    healthy: 'bg-green-500 hover:bg-green-600',
    degraded: 'bg-yellow-500 hover:bg-yellow-600',
    critical: 'bg-red-500 hover:bg-red-600',
  };

  if (variant === 'floating') {
    return (
      <>
        <Button
          onClick={() => setIsOpen(true)}
          className={cn(
            'fixed z-40 shadow-lg rounded-full h-14 w-14 p-0 relative',
            positionClasses[position],
            healthColors[overallHealth],
            className
          )}
          title={`View System Health Status${isConnected ? ' (Real-time)' : connectionStatus === 'connecting' ? ' (Connecting...)' : ' (Offline)'}`}
        >
          <Activity className="h-6 w-6 text-white" />
          {overallHealth !== 'healthy' && (
            <Badge
              variant="destructive"
              className="absolute -top-1 -right-1 h-5 w-5 p-0 flex items-center justify-center text-xs"
            >
              !
            </Badge>
          )}
          {/* Connection status indicator */}
          <div className={cn(
            'absolute bottom-0 right-0 h-3 w-3 rounded-full border-2 border-white',
            isConnected ? 'bg-green-500' : connectionStatus === 'connecting' ? 'bg-yellow-500' : 'bg-red-500',
            (isConnected || connectionStatus === 'connecting') && 'animate-pulse'
          )} />
        </Button>
        {isOpen && (
          <React.Suspense fallback={null}>
            <GlobalHealthStatusModal open={isOpen} onOpenChange={setIsOpen} />
          </React.Suspense>
        )}
      </>
    );
  }

  return (
    <>
      <Button
        onClick={() => setIsOpen(true)}
        variant="outline"
        className={cn('flex items-center gap-2', className)}
      >
        <Activity className="h-4 w-4" />
        <span>System Health</span>
        {overallHealth !== 'healthy' && (
          <Badge
            variant={overallHealth === 'critical' ? 'destructive' : 'secondary'}
            className="ml-1"
          >
            {healthyCount}/{totalCount}
          </Badge>
        )}
      </Button>
      {isOpen && (
        <React.Suspense fallback={null}>
          <GlobalHealthStatusModal open={isOpen} onOpenChange={setIsOpen} />
        </React.Suspense>
      )}
    </>
  );
}

"use client";

import { useDetailedHealthStatus } from "@/hooks/query/useHealth";
import { cn } from "@/lib/utils/index";
import { motion } from "framer-motion";
import Link from "next/link";

export function MinimalStatusIndicator({ className }: { className?: string }) {
  const { data: healthStatus, isPending } = useDetailedHealthStatus();

  // Helper logic to determine global status
  const getGlobalStatus = () => {
    if (!healthStatus) return 'loading';
    
    const services = [
        healthStatus.database,
        healthStatus.cache,
        healthStatus.queue,
        healthStatus.communication,
        healthStatus.video
    ];

    const isUnhealthy = (s: any) => {
        if (!s) return false;
        if (s.status === 'down') return true;
        if ('healthy' in s && s.healthy === false) return true;
        if ('isHealthy' in s && s.isHealthy === false) return true;
        return false;
    };
  
    const isDegraded = (s: any) => {
        if (!s) return false;
        if (s.status === 'degraded') return true;
        if ('degraded' in s && s.degraded === true) return true;
        return false;
    };

    if (services.some(isUnhealthy)) return 'down';
    if (services.some(isDegraded)) return 'degraded';
    return 'operational';
  };

  const status = getGlobalStatus();

  // Map globalStatus to UI colors/labels
  let statusColor = "bg-emerald-500";
  let textColor = "text-emerald-500";
  let label = "All Systems Operational";

  if (isPending || status === 'loading') {
     statusColor = "bg-blue-500";
     textColor = "text-blue-500";
     label = "Checking Systems...";
  } else if (status === 'down') {
     statusColor = "bg-red-500";
     textColor = "text-red-500";
     label = "System Outage";
  } else if (status === 'degraded') {
     statusColor = "bg-amber-500";
     textColor = "text-amber-500";
     label = "Systems Degraded";
  } else {
     // Operational
     statusColor = "bg-emerald-500";
     textColor = "text-emerald-700 dark:text-emerald-400";
     label = "All systems normal.";
  }

  return (
    <Link href="/status" className={cn("inline-flex items-center group", className)}>
      <motion.div 
        className={cn(
          "flex items-center gap-2 px-3 py-1.5 rounded-full border shadow-sm transition-all cursor-pointer",
          status === 'operational' 
            ? "bg-emerald-50 border-emerald-200 hover:bg-emerald-100 dark:bg-emerald-950/30 dark:border-emerald-800 dark:hover:bg-emerald-950/50" 
            : "bg-background/50 backdrop-blur-sm hover:bg-accent/50",
          status === 'down' && "border-red-500/20 bg-red-50 text-red-700",
          status === 'degraded' && "border-amber-500/20 bg-amber-50 text-amber-700"
        )}
        whileHover={{ scale: 1.02 }}
        whileTap={{ scale: 0.98 }}
      >
        <span className="relative flex h-2.5 w-2.5">
          <span className={cn("animate-ping absolute inline-flex h-full w-full rounded-full opacity-75", statusColor)}></span>
          <span className={cn("relative inline-flex rounded-full h-2.5 w-2.5", statusColor)}></span>
        </span>
        <span className={cn("text-xs font-medium tracking-wide", textColor)}>
          {label}
        </span>
      </motion.div>
    </Link>
  );
}

"use client";

import { useEffect, useMemo, createContext, useContext } from "react";
import { useAuth } from "@/hooks/auth/useAuth";
import {
  useRBAC,
  useRoleBasedNavigation,
  useAppointmentPermissions,
} from "@/hooks/utils/useRBAC";
import { Role } from "@/types/auth.types";
import { Permission } from "@/types/rbac.types";
import { Loader2, Shield, AlertTriangle } from "lucide-react";
import { useRouter, usePathname } from "next/navigation";
import { useQueryData } from "@/hooks/core/useQueryData";
import { getUserProfile } from "@/lib/actions/users.server";
import { transformApiResponse } from "@/lib/config/profile";
import { ROUTES, getProtectedRouteRoles } from "@/lib/config/routes";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Button } from "@/components/ui/button";
import type { UserProfile } from "@/types/auth.types";

// Layout imports
import Sidebar from "@/components/global/GlobalSidebar/Sidebar";
import { Header } from "@/components/global/Header";
import { cn } from "@/lib/utils";
import { sidebarLinksByRole, SidebarLink } from "@/lib/config/sidebarLinks";
import { useLayoutStore } from "@/stores/layout.store";
const DashboardShellContext = createContext<boolean>(false);

interface DashboardLayoutProps {
  children: React.ReactNode;
  /** Optional — used for RBAC error messages and permission warnings */
  title?: string;
  allowedRole?: Role | Role[];
  requiredPermission?: Permission;
  requiredPermissions?: Permission[];
  requireAllPermissions?: boolean;
  showPermissionWarnings?: boolean;
  customUnauthorizedMessage?: string;
}

export function DashboardLayout({
  children,
  title = "Dashboard",
  allowedRole,
  requiredPermission,
  requiredPermissions,
  requireAllPermissions = false,
  showPermissionWarnings = true,
  customUnauthorizedMessage,
}: DashboardLayoutProps) {
  const isInsideShell = useContext(DashboardShellContext);

  // ─── Global Layout Store Sync ──────────────────────────────────────────────
  const setDashboardMounted = useLayoutStore((state) => state.setDashboardMounted);
  const setPageTitle = useLayoutStore((state) => state.setPageTitle);
  const setDisplayUser = useLayoutStore((state) => state.setDisplayUser);

  const { session, isPending } = useAuth();
  const router = useRouter();
  const { user } = session || {};

  // RBAC hooks
  const rbac = useRBAC();
  const { getDefaultRoute } = useRoleBasedNavigation();
  const appointmentPermissions = useAppointmentPermissions();

  // Memoize allowed roles array
  const allowedRoles = useMemo(
    () =>
      allowedRole
        ? Array.isArray(allowedRole)
          ? allowedRole
          : [allowedRole]
        : [],
    [allowedRole]
  );
  const normalizedUserRole = useMemo(() => {
    return String(user?.role || "").toUpperCase().replace(/\s+/g, "_") as Role;
  }, [user?.role]);

  // Check permissions
  const hasPermissionAccess = useMemo(() => {
    if (!user) return false;

    if (requiredPermission) {
      return rbac.hasPermission(requiredPermission);
    }

    if (requiredPermissions && requiredPermissions.length > 0) {
      return requireAllPermissions
        ? rbac.hasAllPermissions(requiredPermissions)
        : rbac.hasAnyPermission(requiredPermissions);
    }

    return true;
  }, [user, rbac, requiredPermission, requiredPermissions, requireAllPermissions]);

  // Get current path for route-based protection
  const pathname = usePathname();

  // Check role access (Component Props)
  const hasRoleAccess = useMemo(() => {
    if (!user || allowedRoles.length === 0) return true;
    return allowedRoles.includes(normalizedUserRole);
  }, [user, allowedRoles, normalizedUserRole]);

  // Check role access (Route Config)
  const hasRouteRoleAccess = useMemo(() => {
    if (!user || !pathname) return false;
    const routeRoles = getProtectedRouteRoles(pathname);
    if (routeRoles && routeRoles.length > 0) {
      return routeRoles.includes(normalizedUserRole);
    }
    return true;
  }, [user, pathname, normalizedUserRole]);

  // Overall access check
  const hasAccess = hasRoleAccess && hasRouteRoleAccess && hasPermissionAccess;

  // ─── Fetch User Profile (React Query) ──────────────────────────────────────
  const { data: profile, isPending: loadingProfile } = useQueryData(
    ["dashboard-profile"],
    async () => {
      const response = await getUserProfile();
      if (typeof response === "object" && response !== null) {
        const data = (response as Record<string, unknown>).data || response;
        return transformApiResponse(data as Record<string, unknown>);
      }
      return transformApiResponse({} as Record<string, unknown>);
    },
    { enabled: !!session?.access_token }
  );

  // Memoize merged profile
  const mergedProfile = useMemo(() => {
    if (!user || !profile) return null;
    const dateOfBirthRaw = profile?.dateOfBirth ?? user?.dateOfBirth;
    const genderRaw = profile?.gender ?? user?.gender;
    const allowedGenders = ["male", "female", "other"];
    let gender: "male" | "female" | "other" | undefined = undefined;

    if (allowedGenders.includes((genderRaw || "").toLowerCase())) {
      gender = genderRaw as "male" | "female" | "other";
    }

    return {
      ...profile,
      ...user,
      dateOfBirth: dateOfBirthRaw === null ? undefined : dateOfBirthRaw,
      gender,
    } as UserProfile;
  }, [user, profile]);

  // ─── Sync Store Data (Zustand) ─────────────────────────────────────────────
  const userDisplayData = useMemo(() => {
    if (!user) return null;

    // Use profile data if available, fall back to basic user data
    const profileData = profile || {};
    const firstName = (profileData as any).firstName || user.firstName || "User";
    const lastName = (profileData as any).lastName || user.lastName || "";

    const displayName = lastName ? `${firstName} ${lastName}` : firstName;

    // Generate initials (more robustly)
    const initials = `${(firstName?.[0] || "U")}${(lastName?.[0] || "")}`.toUpperCase();

    const avatar = (profileData as any).profilePicture ||
      `https://ui-avatars.com/api/?name=${encodeURIComponent(displayName)}&background=random&format=png`;

    return {
      name: displayName,
      initials,
      role: normalizedUserRole || Role.PATIENT,
      avatar,
      email: user.email || "",
    };
  }, [user, profile, normalizedUserRole]);

  useEffect(() => {
    if (userDisplayData) {
      setDisplayUser(userDisplayData);
    }
  }, [userDisplayData, setDisplayUser]);

  // Sync page title
  useEffect(() => {
    if (title) {
      setPageTitle(title);
    }
  }, [title, setPageTitle]);

  // Authorization effect
  useEffect(() => {
    if (isPending || loadingProfile) return;

    if (!user) {
      router.replace(ROUTES.LOGIN);
      return;
    }

    if (!hasAccess) {
      router.replace(getDefaultRoute());
      return;
    }

    if (user?.profileComplete === false) {
      router.replace(ROUTES.PROFILE_COMPLETION);
    }
  }, [isPending, loadingProfile, user, mergedProfile, hasAccess, getDefaultRoute, router]);

  // Shell detection effect (for other store consumers)
  useEffect(() => {
    setDashboardMounted(true);
    return () => setDashboardMounted(false);
  }, [setDashboardMounted]);

  if (isPending || (!user && !session)) {
    return (
      <div className={cn(
        "flex items-center justify-center bg-background",
        isInsideShell ? "h-[400px] w-full" : "min-h-screen"
      )}>
        <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
      </div>
    );
  }

  if (!hasAccess) {
    return (
      <div className={cn(
        "flex items-center justify-center bg-background p-6",
        isInsideShell ? "h-[400px] w-full" : "min-h-screen"
      )}>
        <div className="max-w-md w-full text-center space-y-6">
          <Shield className="mx-auto h-12 w-12 text-red-500" />
          <h2 className="text-2xl font-bold">Access Denied</h2>
          <Alert variant="destructive">
            <AlertTriangle className="h-4 w-4" />
            <AlertDescription>
              {customUnauthorizedMessage || `Your role (${user?.role}) is not authorized for this area.`}
            </AlertDescription>
          </Alert>
          <div className="flex gap-4">
            <Button onClick={() => router.back()} variant="outline" className="flex-1">Back</Button>
            <Button onClick={() => router.push(getDefaultRoute())} className="flex-1">Dashboard</Button>
          </div>
        </div>
      </div>
    );
  }

  // Profile completeness check
  if (user?.profileComplete === false) {
    return (
      <div className={cn(
        "flex items-center justify-center bg-background",
        isInsideShell ? "h-[400px] w-full" : "min-h-screen"
      )}>
        <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
        <p className="ml-2">Redirecting to profile completion...</p>
      </div>
    );
  }

  // Shell Rendering info
  const userRole = String(userDisplayData?.role || Role.PATIENT).toUpperCase().replace(/\s+/g, "_");
  const sidebarLinks: SidebarLink[] = (sidebarLinksByRole[userRole] as SidebarLink[]) ?? [];

  // Render
  if (isInsideShell) {
    return (
      <div className="h-full w-full">
        {showPermissionWarnings && title.toLowerCase().includes("appointment") && !appointmentPermissions.canViewAppointments && (
          <Alert className="mb-4 bg-yellow-50 border-yellow-200">
            <AlertTriangle className="h-4 w-4 text-yellow-600" />
            <AlertDescription className="text-yellow-800">Limited appointment access.</AlertDescription>
          </Alert>
        )}
        {children}
      </div>
    );
  }

  return (
    <DashboardShellContext.Provider value={true}>
      <div className="relative min-h-screen bg-muted/40 dark:bg-muted/10">
        <Sidebar
          links={sidebarLinks}
          user={{
            name: userDisplayData?.name || "User",
            avatarUrl: userDisplayData?.avatar || "",
            role: String(userDisplayData?.role || ""),
          }}
        >
          <div className="flex flex-col h-full bg-background overflow-hidden text-neutral-900 dark:text-neutral-50">
            <Header className="bg-transparent border-b border-muted transition-none" />
            <main className="flex-1 overflow-auto">
              <div className="p-4 md:p-8">
                {showPermissionWarnings && title.toLowerCase().includes("appointment") && !appointmentPermissions.canViewAppointments && (
                  <Alert className="mb-4 bg-yellow-50 border-yellow-200">
                    <AlertTriangle className="h-4 w-4 text-yellow-600" />
                    <AlertDescription className="text-yellow-800">Limited appointment access.</AlertDescription>
                  </Alert>
                )}
                {children}
              </div>
            </main>
          </div>
        </Sidebar>
      </div>
    </DashboardShellContext.Provider>
  );
}

