                                      });
                                    } else {
                                      form.clearErrors("dateOfBirth");
                                      field.onChange(format(date, "yyyy-MM-dd"));
                                    }
                                  }
                                }}
                                disabled={(date) =>
                                  date > maxDate || date < minDate
                                }
                                captionLayout="dropdown"
                                fromYear={today.getFullYear() - 100}
                                toYear={today.getFullYear() - 12}
                                defaultMonth={maxDate}
                                initialFocus
                              />
                            </PopoverContent>
