  return (
    <ProtectedComponent
      {...(permission && { permission })}
      {...(permissions && { permissions })}
      {...(requireAll !== undefined && { requireAll })}
      {...(resource && { resource })}
      {...(action && { action })}
      showFallback={false}
    >
      <a href={href} className={className}>
