"use client";

import React from "react";
import { usePathname, useRouter } from "next/navigation";
import { useAuth } from "@/hooks/auth/useAuth";
import { useRBAC, useRoleBasedNavigation } from "@/hooks/utils/useRBAC";
import { Permission } from "@/types/rbac.types";
import { Role } from "@/types/auth.types";
import { ROUTES } from "@/lib/config/routes";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { Button } from "@/components/ui/button";
import { Lock, ArrowLeft } from "lucide-react";

interface ProtectedRouteProps {
  children: React.ReactNode;
  permission?: Permission;
  permissions?: Permission[];
  requireAll?: boolean;
  allowedRoles?: Role[];
  resource?: string;
  action?: string;
  redirectTo?: string;
  showUnauthorized?: boolean;
}

/**
 * Component that protects entire routes/pages based on user permissions
 */
export const ProtectedRoute: React.FC<ProtectedRouteProps> = ({
  children,
  permission,
  permissions,
  requireAll = false,
  allowedRoles,
  resource,
  action,
  redirectTo,
  showUnauthorized = true,
}) => {
  const { user, isAuthenticated, isPending } = useAuth();
  const rbac = useRBAC();
  const { getDefaultRoute } = useRoleBasedNavigation();
  const router = useRouter();
  const pathname = usePathname();

  // Check permission-based access
  const hasAccess = React.useMemo(() => {
    if (permission) return rbac.hasPermission(permission);
    if (permissions && permissions.length > 0) {
      return requireAll
        ? rbac.hasAllPermissions(permissions)
        : rbac.hasAnyPermission(permissions);
    }
    if (resource && action) return rbac.canAccess(resource, action);
    return true;
  }, [rbac, permission, permissions, requireAll, resource, action]);

  // Handle Redirection Side-Effects
  React.useEffect(() => {
    if (isPending) return;

    // 1. Unauthenticated Redirect
    if (!isAuthenticated || !user) {
      router.replace(ROUTES.LOGIN);
      return;
    }

    // 2. Role-based Redirect
    if (user.profileComplete === false) {
      const profileCompletionPath = `${ROUTES.PROFILE_COMPLETION}?redirect=${encodeURIComponent(pathname || "/")}`;
      router.replace(profileCompletionPath);
      return;
    }

    // 3. Role-based Redirect
    const userRole = user?.role as Role;
    if (allowedRoles && allowedRoles.length > 0) {
      if (!userRole || !allowedRoles.includes(userRole)) {
        if (redirectTo) {
          router.replace(redirectTo);
        } else if (!showUnauthorized) {
          router.replace(getDefaultRoute());
        }
      }
    }

    // 4. Permission-based Redirect
    if (!hasAccess) {
      if (redirectTo) {
        router.replace(redirectTo);
      } else if (!showUnauthorized) {
        router.replace(getDefaultRoute());
      }
    }
  }, [
    isPending, 
    isAuthenticated, 
    user, 
    pathname,
    allowedRoles, 
    hasAccess, 
    redirectTo, 
    showUnauthorized, 
    getDefaultRoute, 
    router
  ]);

  // Early return for loading
  if (isPending) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    );
  }

  // Early return if not authenticated (useEffect handles redirect)
  if (!isAuthenticated || !user) return null;

  const userRole = user?.role as Role;

  if (user.profileComplete === false) {
    return null;
  }

  // Render check: Unofficial role access
  if (allowedRoles && allowedRoles.length > 0) {
    if (!userRole || !allowedRoles.includes(userRole)) {
      if (showUnauthorized) return <UnauthorizedAccess />;
      return null;
    }
  }

  // Render check: No permission access
  if (!hasAccess) {
    if (showUnauthorized) return <UnauthorizedAccess />;
    return null;
  }

  return <>{children}</>;
};

