'use client';

import { useState, useEffect } from 'react';
import { getActiveSessions, revokeSession } from '@/lib/actions/session.server';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Badge } from '@/components/ui/badge';
import { Loader2, Monitor, Smartphone, AlertCircle, CheckCircle } from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';

interface Session {
  id: string;
  deviceInfo: string;
  ipAddress: string;
  lastActivity: string;
  createdAt: string;
  isCurrent: boolean;
}

export function ActiveSessionsList() {
  const [sessions, setSessions] = useState<Session[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [revokingId, setRevokingId] = useState<string | null>(null);

  useEffect(() => {
    loadSessions();
  }, []);

  async function loadSessions() {
    try {
      setLoading(true);
      setError('');
      const data = await getActiveSessions();
      setSessions(data);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load sessions');
    } finally {
      setLoading(false);
    }
  }

  async function handleRevoke(sessionId: string) {
    try {
      setRevokingId(sessionId);
      setError('');
      await revokeSession(sessionId);
      // Reload sessions after successful revocation
      await loadSessions();
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to revoke session');
    } finally {
      setRevokingId(null);
    }
  }

  function getDeviceIcon(deviceInfo: string) {
    const lower = deviceInfo.toLowerCase();
    if (lower.includes('mobile') || lower.includes('android') || lower.includes('iphone')) {
      return <Smartphone className="h-5 w-5" />;
    }
    return <Monitor className="h-5 w-5" />;
  }

  if (loading) {
    return (
      <Card>
        <CardContent className="py-12">
          <div className="flex flex-col items-center justify-center space-y-4">
            <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
            <p className="text-sm text-muted-foreground">Loading sessions...</p>
          </div>
        </CardContent>
      </Card>
    );
  }

  if (error) {
    return (
      <Alert variant="destructive">
        <AlertCircle className="h-4 w-4" />
        <AlertDescription>{error}</AlertDescription>
      </Alert>
    );
  }

  if (sessions.length === 0) {
    return (
      <Card>
        <CardContent className="py-12">
          <div className="text-center space-y-2">
            <CheckCircle className="h-12 w-12 mx-auto text-muted-foreground" />
            <p className="text-lg font-medium">No active sessions</p>
            <p className="text-sm text-muted-foreground">
              You're not logged in on any devices
            </p>
          </div>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-4">
      {sessions.map((session) => (
        <Card key={session.id}>
          <CardHeader>
            <div className="flex items-start justify-between">
              <div className="flex items-start space-x-4">
                <div className="mt-1">{getDeviceIcon(session.deviceInfo)}</div>
                <div className="space-y-1">
                  <div className="flex items-center gap-2">
                    <CardTitle className="text-base">{session.deviceInfo}</CardTitle>
                    {session.isCurrent && (
                      <Badge variant="secondary" className="text-xs">
                        Current Session
                      </Badge>
                    )}
                  </div>
                  <CardDescription>
                    IP: {session.ipAddress} • Last active{' '}
                    {formatDistanceToNow(new Date(session.lastActivity), { addSuffix: true })}
                  </CardDescription>
                </div>
              </div>
              {!session.isCurrent && (
                <Button
                  variant="destructive"
                  size="sm"
                  onClick={() => handleRevoke(session.id)}
                  disabled={revokingId === session.id}
                >
                  {revokingId === session.id ? (
                    <>
                      <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                      Revoking...
                    </>
                  ) : (
                    'Sign Out'
                  )}
                </Button>
              )}
            </div>
          </CardHeader>
        </Card>
      ))}
    </div>
  );
}

"use client";

import { useMemo } from "react";
import { Area, AreaChart, ResponsiveContainer, YAxis } from "recharts";
import { motion } from "framer-motion";
import { StatusType } from "@/components/common/StatusIndicator";
import { cn } from "@/lib/utils/index";

interface StatusCardProps {
  name: string;
  icon: any; // Relaxed type to allow style props
  status: StatusType;
  responseTime: number | null;
  className?: string;
}

// Generate deterministic random data based on name to keep charts consistent but varied
const generateSparklineData = (name: string, currentLatency: number | null) => {
  const seed = name.split("").reduce((acc, char) => acc + char.charCodeAt(0), 0);
  const data = [];
  const baseLatency = currentLatency || 50;
  
  for (let i = 0; i < 20; i++) {
    // smooth random walk
    const noise = Math.sin(i * 0.5 + seed) * 20 + (Math.random() - 0.5) * 10;
    data.push({
      value: Math.max(10, baseLatency + noise),
    });
  }
  
  // Add current value at the end
  if (currentLatency) {
    data.push({ value: currentLatency });
  }
  return data;
};

export function StatusCard({ name, icon: Icon, status, responseTime, className }: StatusCardProps) {
  const data = useMemo(() => generateSparklineData(name, responseTime), [name, responseTime]);

  // Color mapping
  const colors = {
    active: { stroke: "#10b981", fill: "#10b981", bg: "bg-emerald-500/10", border: "border-emerald-500/20", glow: "shadow-[0_0_20px_-5px_rgba(16,185,129,0.4)]" },
    warning: { stroke: "#f59e0b", fill: "#f59e0b", bg: "bg-amber-500/10", border: "border-amber-500/20", glow: "shadow-[0_0_20px_-5px_rgba(245,158,11,0.4)]" },
    error: { stroke: "#ef4444", fill: "#ef4444", bg: "bg-red-500/10", border: "border-red-500/20", glow: "shadow-[0_0_20px_-5px_rgba(239,68,68,0.4)]" },
    loading: { stroke: "#6366f1", fill: "#6366f1", bg: "bg-indigo-500/10", border: "border-indigo-500/20", glow: "shadow-[0_0_20px_-5px_rgba(99,102,241,0.4)]" },
    inactive: { stroke: "#6b7280", fill: "#6b7280", bg: "bg-gray-500/10", border: "border-gray-500/20", glow: "shadow-none" },
  };

  const theme = colors[status] || colors.inactive;



  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className={cn(
        "relative overflow-hidden rounded-xl border p-4 backdrop-blur-sm transition-all duration-300 hover:scale-[1.02]",
        theme.bg,
        theme.border,
        theme.glow,
        className
      )}
    >
      <div className="flex justify-between items-start mb-4">
        <div className="flex items-center gap-3">
          <div className={cn("p-2 rounded-lg bg-background/50 backdrop-blur-md", theme.border, "border")}>
            <Icon className="h-5 w-5" style={{ color: theme.stroke }} />
          </div>
          <div>
            <h3 className="font-semibold text-sm text-foreground/80">{name}</h3>
            <p className="text-xs font-medium uppercase tracking-wider" style={{ color: theme.stroke }}>
              {status === 'loading' ? 'Checking...' : status}
            </p>
          </div>
        </div>
        
        <div className="text-right">
           <div className="text-2xl font-bold font-mono tracking-tight">
             {responseTime ? `${Math.round(responseTime)}` : "--"}
             <span className="text-xs font-sans text-muted-foreground ml-1">ms</span>
           </div>
        </div>
      </div>

      <div className="h-[60px] w-full -mx-2">
        <ResponsiveContainer width="100%" height="100%">
          <AreaChart data={data}>
            <defs>
              <linearGradient id={`gradient-${name}`} x1="0" y1="0" x2="0" y2="1">
                <stop offset="0%" stopColor={theme.stroke} stopOpacity={0.4} />
                <stop offset="100%" stopColor={theme.stroke} stopOpacity={0.0} />
              </linearGradient>
            </defs>
            <YAxis domain={['dataMin - 10', 'dataMax + 10']} hide />
            <Area
              type="monotone"
              dataKey="value"
              stroke={theme.stroke}
              strokeWidth={2}
              fill={`url(#gradient-${name})`}
              isAnimationActive={false} // Disable for real-time feel or handle gracefully
            />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    </motion.div>
  );
}

"use client";

import * as React from "react";
import { cn } from "@/lib/utils";
import { motion, AnimatePresence, useInView, useAnimation } from "framer-motion";

// Fade In Animation
interface FadeInProps {
  children: React.ReactNode;
  delay?: number;
  duration?: number;
  direction?: "up" | "down" | "left" | "right";
  className?: string;
  once?: boolean;
}

const FadeIn: React.FC<FadeInProps> = ({
  children,
  delay = 0,
  duration = 0.6,
  direction = "up",
  className,
  once = true,
}) => {
  const ref = React.useRef(null);
  const isInView = useInView(ref, { once });
  const controls = useAnimation();

  const directionVariants = {
    up: { y: 50, opacity: 0 },
    down: { y: -50, opacity: 0 },
    left: { x: 50, opacity: 0 },
    right: { x: -50, opacity: 0 },
  };

  React.useEffect(() => {
    if (isInView) {
      controls.start({ x: 0, y: 0, opacity: 1 });
    }
  }, [isInView, controls]);

  return (
    <motion.div
      ref={ref}
      initial={directionVariants[direction]}
      animate={controls}
      transition={{ duration, delay }}
      className={className}
    >
      {children}
    </motion.div>
  );
};

// Stagger Container for multiple children
interface StaggerContainerProps {
  children: React.ReactNode;
  staggerDelay?: number;
  className?: string;
}

const StaggerContainer: React.FC<StaggerContainerProps> = ({
  children,
  staggerDelay = 0.1,
  className,
}) => {
  return (
    <motion.div
      className={className}
      initial="hidden"
      animate="show"
      variants={{
        hidden: {},
        show: {
          transition: {
            staggerChildren: staggerDelay,
          },
        },
      }}
    >
      {React.Children.map(children, (child, index) => (
        <motion.div
          key={index}
          variants={{
            hidden: { opacity: 0, y: 20 },
            show: { opacity: 1, y: 0 },
          }}
          transition={{ duration: 0.5 }}
        >
          {child}
        </motion.div>
      ))}
    </motion.div>
  );
};

// Scale on Hover
interface ScaleOnHoverProps {
  children: React.ReactNode;
  scale?: number;
  className?: string;
}

const ScaleOnHover: React.FC<ScaleOnHoverProps> = ({
  children,
  scale = 1.05,
  className,
}) => {
  return (
    <motion.div
      whileHover={{ scale }}
      whileTap={{ scale: 0.95 }}
      transition={{ type: "spring", stiffness: 400, damping: 17 }}
      className={cn("cursor-pointer", className)}
    >
      {children}
    </motion.div>
  );
};

// Slide In Notification
interface SlideInNotificationProps {
  children: React.ReactNode;
  isVisible: boolean;
  position?: "top" | "bottom" | "left" | "right";
  className?: string;
}

const SlideInNotification: React.FC<SlideInNotificationProps> = ({
  children,
  isVisible,
  position = "top",
  className,
}) => {
  const variants = {
    top: {
      hidden: { y: -100, opacity: 0 },
      visible: { y: 0, opacity: 1 },
    },
    bottom: {
      hidden: { y: 100, opacity: 0 },
      visible: { y: 0, opacity: 1 },
    },
    left: {
      hidden: { x: -100, opacity: 0 },
      visible: { x: 0, opacity: 1 },
    },
    right: {
      hidden: { x: 100, opacity: 0 },
      visible: { x: 0, opacity: 1 },
    },
  };

  return (
    <AnimatePresence>
      {isVisible && (
        <motion.div
          initial="hidden"
          animate="visible"
          exit="hidden"
          variants={variants[position]}
          transition={{ type: "spring", stiffness: 500, damping: 40 }}
          className={className}
        >
          {children}
        </motion.div>
      )}
    </AnimatePresence>
  );
};

// Pulse Animation
interface PulseProps {
  children: React.ReactNode;
  duration?: number;
  className?: string;
}

const Pulse: React.FC<PulseProps> = ({ children, duration = 2, className }) => {
  return (
    <motion.div
      animate={{ scale: [1, 1.05, 1] }}
      transition={{ duration, repeat: Infinity, ease: "easeInOut" }}
      className={className}
    >
      {children}
    </motion.div>
  );
};

// Loading Spinner with Animation
interface AnimatedSpinnerProps {
  size?: "sm" | "md" | "lg";
  className?: string;
}

const AnimatedSpinner: React.FC<AnimatedSpinnerProps> = ({ size = "md", className }) => {
  const sizeClasses = {
    sm: "w-4 h-4",
    md: "w-8 h-8",
    lg: "w-12 h-12",
  };

  return (
    <motion.div
      animate={{ rotate: 360 }}
