"use client";

import { useState, useEffect } from "react";
import { Badge } from "@/components/ui/badge";
import {
  Wifi,
  WifiOff,
  Signal,
  SignalLow,
  SignalMedium,
  SignalHigh,
} from "lucide-react";
import { useVideoAppointmentWebSocket } from "@/hooks/realtime/useVideoAppointmentSocketIO";
import {
  getCallQuality,
  updateQualityMetrics,
  type CallQualityMetrics,
} from "@/lib/actions/video.server";
import { useToast } from "@/hooks/utils/use-toast";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";

interface CallQualityIndicatorProps {
  appointmentId: string;
  className?: string;
  showDetails?: boolean;
}

export function CallQualityIndicator({
  appointmentId,
  className,
  showDetails = false,
}: CallQualityIndicatorProps) {
  const { toast } = useToast();
  const [quality, setQuality] = useState<CallQualityMetrics | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const { subscribeToCallQuality, isConnected } =
    useVideoAppointmentWebSocket();

  // Load initial quality metrics (only once, WebSocket handles updates)
  useEffect(() => {
    let mounted = true;
    const loadQuality = async () => {
      try {
        const result = await getCallQuality(appointmentId);
        if (mounted && result) {
          setQuality(result);
        }
      } catch (error) {
        // Error handled by React Query
      } finally {
        if (mounted) {
          setIsLoading(false);
        }
      }
    };

    loadQuality();
    return () => {
      mounted = false;
    };
  }, [appointmentId]);

  // Subscribe to real-time quality updates
  useEffect(() => {
    if (!isConnected) return;

    const unsubscribe = subscribeToCallQuality((data) => {
      if (data.appointmentId === appointmentId && data.metrics) {
        const metrics = data.metrics as unknown as CallQualityMetrics;
        if (metrics) {
          setQuality(metrics);
        }
      }
    });

    return unsubscribe;
  }, [isConnected, appointmentId, subscribeToCallQuality]);

  // Get quality status
  const getQualityStatus = () => {
    if (!quality) return { status: "unknown", color: "gray", icon: WifiOff };

    const networkQuality = quality.network.connectionQuality;
    const videoQuality = quality.video.quality;
    const audioQuality = quality.audio.quality;

    // Determine overall quality (worst of the three)
    const overallQuality =
      networkQuality === "poor" ||
      videoQuality === "poor" ||
      audioQuality === "poor"
        ? "poor"
        : networkQuality === "fair" ||
          videoQuality === "fair" ||
          audioQuality === "fair"
        ? "fair"
        : networkQuality === "good" ||
          videoQuality === "good" ||
          audioQuality === "good"
        ? "good"
        : "excellent";

    const statusConfig = {
      excellent: {
        status: "Excellent",
        color: "green",
        icon: SignalHigh,
        variant: "default" as const,
      },
      good: {
        status: "Good",
        color: "blue",
        icon: Signal,
        variant: "default" as const,
      },
      fair: {
        status: "Fair",
        color: "yellow",
        icon: SignalMedium,
        variant: "secondary" as const,
      },
      poor: {
        status: "Poor",
        color: "red",
        icon: SignalLow,
        variant: "destructive" as const,
      },
      unknown: {
        status: "Unknown",
        color: "gray",
        icon: WifiOff,
        variant: "outline" as const,
      },
    };

    return statusConfig[overallQuality] || statusConfig.unknown;
  };

  const qualityStatus = getQualityStatus();
  const QualityIcon = qualityStatus.icon;
  const qualityVariant =
    "variant" in qualityStatus ? qualityStatus.variant : "outline";

  const handleReportIssue = async () => {
    try {
      await updateQualityMetrics(
        appointmentId,
        quality || {
          network: {
            latency: 0,
            jitter: 0,
            packetLoss: 0,
            bandwidth: 0,
            connectionQuality: "poor",
          },
          audio: { bitrate: 0, codec: "", quality: "poor" },
          video: {
            bitrate: 0,
            resolution: "",
            framerate: 0,
            codec: "",
            quality: "poor",
          },
        }
      );
      toast({
        title: "Issue Reported",
        description: "Your quality issue has been reported",
      });
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to report issue",
        variant: "destructive",
      });
    }
  };

  if (isLoading) {
    return (
      <Badge variant="outline" className={className}>
        <Wifi className="h-3 w-3 mr-1 animate-pulse" />
        Checking...
      </Badge>
    );
  }

  if (!quality) {
    return (
      <Badge variant="outline" className={className}>
        <WifiOff className="h-3 w-3 mr-1" />
        No data
      </Badge>
    );
  }

  const qualityDetails = showDetails ? (
    <div className="space-y-2 text-xs">
      <div className="flex justify-between">
        <span>Network:</span>
        <span className="font-medium">{quality.network.connectionQuality}</span>
      </div>
      <div className="flex justify-between">
        <span>Latency:</span>
        <span className="font-medium">{quality.network.latency}ms</span>
      </div>
      <div className="flex justify-between">
        <span>Packet Loss:</span>
        <span className="font-medium">{quality.network.packetLoss}%</span>
      </div>
      <div className="flex justify-between">
        <span>Video:</span>
        <span className="font-medium">{quality.video.quality}</span>
      </div>
      <div className="flex justify-between">
        <span>Audio:</span>
        <span className="font-medium">{quality.audio.quality}</span>
      </div>
      {quality.network.connectionQuality === "poor" && (
        <button
          onClick={handleReportIssue}
          className="text-xs text-primary hover:underline mt-2"
        >
          Report Issue
        </button>
      )}
    </div>
  ) : null;

  return (
    <TooltipProvider>
      <Tooltip>
        <TooltipTrigger asChild>
          <Badge variant={qualityVariant} className={className}>
            <QualityIcon className="h-3 w-3 mr-1" />
            {qualityStatus.status}
          </Badge>
        </TooltipTrigger>
        {qualityDetails && (
          <TooltipContent side="bottom" className="w-48">
            {qualityDetails}
          </TooltipContent>
        )}
      </Tooltip>
    </TooltipProvider>
  );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
  Mic,
  Download,
  Search,
  User,
} from "lucide-react";
// import { useAuth } from "@/hooks/auth/useAuth";
import { useVideoAppointmentWebSocket } from "@/hooks/realtime/useVideoAppointmentSocketIO";
import {
  getTranscription,
  type TranscriptionSegment,
} from "@/lib/actions/video.server";
import { useToast } from "@/hooks/utils/use-toast";
import { format } from "date-fns";
import { Input } from "@/components/ui/input";

interface CallTranscriptionProps {
  appointmentId: string;
  className?: string;
}

export function CallTranscription({
  appointmentId,
  className,
}: CallTranscriptionProps) {
  const { toast } = useToast();
  const [transcription, setTranscription] = useState<TranscriptionSegment[]>([]);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const scrollAreaRef = useRef<HTMLDivElement>(null);

  const { subscribeToTranscription, isConnected } = useVideoAppointmentWebSocket();

  // Load existing transcription
  useEffect(() => {
    const loadTranscription = async () => {
      try {
        const result = await getTranscription(appointmentId);
        if (result) {
          if ('segments' in result) {
            setTranscription(result.segments);
          }
        }
      } catch (error) {
        // Error handled by React Query
      }
    };

    loadTranscription();
  }, [appointmentId]);

  // Subscribe to real-time transcription
  useEffect(() => {
    if (!isConnected) return;

    const unsubscribe = subscribeToTranscription((data) => {
      if (data.appointmentId === appointmentId) {
        if (data.action === "transcription_started") {
          setIsTranscribing(true);
          toast({
            title: "Transcription Started",
            description: "Call is now being transcribed",
          });
        } else if (data.action === "transcription_stopped") {
          setIsTranscribing(false);
          toast({
            title: "Transcription Stopped",
            description: "Transcription has been stopped",
          });
        } else if (data.action === "transcription_segment") {
          const segment = data.segment as unknown as TranscriptionSegment;
          setTranscription((prev) => {
            // Avoid duplicates
            if (prev.some((s) => s.id === segment.id)) return prev;
            return [...prev, segment].sort((a, b) => a.startTime - b.startTime);
          });

          // Auto-scroll to bottom
          setTimeout(() => {
            scrollAreaRef.current?.scrollTo({
              top: scrollAreaRef.current.scrollHeight,
              behavior: "smooth",
            });
          }, 100);
        }
      }
    });

    return unsubscribe;
  }, [isConnected, appointmentId, subscribeToTranscription, toast]);

  // Transcription is created automatically by backend when segments are received

  const handleDownload = () => {
    const content = transcription
      .map(
        (seg) =>
          `[${formatTime(seg.startTime)}] ${seg.speaker} (${seg.speakerRole}): ${seg.text}`
      )
      .join("\n\n");

    const blob = new Blob([content], { type: "text/plain" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `transcription-${appointmentId}-${format(new Date(), "yyyy-MM-dd")}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins.toString().padStart(2, "0")}:${secs.toString().padStart(2, "0")}`;
  };

  const filteredTranscription = searchTerm
    ? transcription.filter((seg) =>
        seg.text.toLowerCase().includes(searchTerm.toLowerCase())
      )
    : transcription;

  return (
    <Card className={className}>
      <CardHeader className="pb-3">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <CardTitle className="text-lg">Call Transcription</CardTitle>
            {isTranscribing && (
              <Badge variant="default" className="bg-red-500 animate-pulse">
                <Mic className="h-3 w-3 mr-1" />
                Recording
              </Badge>
            )}
          </div>
          <div className="flex gap-2">
            {transcription.length > 0 && (
              <Button size="sm" variant="outline" onClick={handleDownload}>
                <Download className="h-4 w-4 mr-2" />
                Download
              </Button>
            )}
          </div>
        </div>
      </CardHeader>
      <CardContent className="p-0 flex flex-col h-[400px]">
        {/* Search */}
        {transcription.length > 0 && (
          <div className="px-4 pt-4 pb-2">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <Input
                placeholder="Search transcription..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10"
              />
            </div>
          </div>
        )}

        {/* Transcription Content */}
        <ScrollArea className="flex-1 px-4" ref={scrollAreaRef}>
          {transcription.length === 0 ? (
            <div className="flex items-center justify-center h-full">
              <div className="text-center text-muted-foreground">
                <Mic className="h-12 w-12 mx-auto mb-4 opacity-50" />
                <p>No transcription yet</p>
                <p className="text-xs mt-2">
                  Transcription will appear here as the call progresses
                </p>
              </div>
            </div>
          ) : (
            <div className="space-y-4 py-4">
              {filteredTranscription.map((segment) => (
                <div key={segment.id} className="space-y-1">
                  <div className="flex items-center gap-2">
                    <Badge variant="outline" className="text-xs">
                      {formatTime(segment.startTime)} - {formatTime(segment.endTime)}
                    </Badge>
                    <Badge variant="secondary" className="text-xs">
                      <User className="h-3 w-3 mr-1" />
                      {segment.speaker} ({segment.speakerRole})
                    </Badge>
                    <Badge
                      variant="outline"
                      className="text-xs"
                      style={{
                        opacity: segment.confidence,
                      }}
                    >
                      {Math.round(segment.confidence * 100)}% confidence
                    </Badge>
                  </div>
                  <p className="text-sm">{segment.text}</p>
                </div>
              ))}
            </div>
          )}
        </ScrollArea>

      </CardContent>
    </Card>
  );
}

"use client";

import { useState } from "react";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Button } from "@/components/ui/button";
import {
  MoreVertical,
  Mic,
  MicOff,
  Video,
  VideoOff,
  UserX,
  Shield,
  ShieldOff,
  Monitor,
  MonitorOff,
  Loader2,
} from "lucide-react";
import { useRBAC } from "@/hooks/utils/useRBAC";
import { Permission } from "@/types/rbac.types";
import { manageParticipantEnhanced } from "@/lib/actions/video.server";
import { useToast } from "@/hooks/utils/use-toast";
import type { ParticipantInfo } from "@/lib/video/openvidu";

interface EnhancedParticipantControlsProps {
  appointmentId: string;
  participant: ParticipantInfo;
  currentUserId: string;
  onActionComplete?: () => void;
}

export function EnhancedParticipantControls({
  appointmentId,
  participant,
  currentUserId,
  onActionComplete,
}: EnhancedParticipantControlsProps) {
  const { hasPermission } = useRBAC();
  const { toast } = useToast();
  const [isLoading, setIsLoading] = useState(false);

  const canManage = hasPermission(Permission.END_VIDEO_APPOINTMENTS);
  const isSelf = participant.userId === currentUserId;

  if (!canManage || isSelf) {
    return null;
  }

  const handleAction = async (
    action: "mute" | "unmute" | "remove" | "promote" | "demote" | "disable_video" | "enable_video" | "grant_screen_share" | "revoke_screen_share"
  ) => {
    setIsLoading(true);
    try {
      const participantId = participant.userId || participant.connectionId;
      if (!participantId) {
        toast({
          title: "Error",
          description: "Participant ID is missing",
          variant: "destructive",
        });
        return;
      }
      const result = await manageParticipantEnhanced(appointmentId, {
        participantId,
        action,
      });

      if (result.success) {
        toast({
          title: "Action Completed",
          description: `Participant ${action} action completed`,
        });
        if (onActionComplete) {
          onActionComplete();
        }
      }
    } catch (error) {
      toast({
        title: "Error",
        description: `Failed to ${action} participant`,
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button
          size="sm"
          variant="ghost"
          disabled={isLoading}
          className="h-8 w-8 p-0"
        >
          {isLoading ? (
            <Loader2 className="h-4 w-4 animate-spin" />
          ) : (
            <MoreVertical className="h-4 w-4" />
          )}
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end">
        <DropdownMenuLabel>Participant Controls</DropdownMenuLabel>
        <DropdownMenuSeparator />

        <DropdownMenuItem onClick={() => handleAction("mute")}>
          <MicOff className="h-4 w-4 mr-2" />
          Mute Audio
        </DropdownMenuItem>
        <DropdownMenuItem onClick={() => handleAction("unmute")}>
          <Mic className="h-4 w-4 mr-2" />
          Unmute Audio
        </DropdownMenuItem>

        <DropdownMenuSeparator />

        <DropdownMenuItem onClick={() => handleAction("disable_video")}>
          <VideoOff className="h-4 w-4 mr-2" />
          Disable Video
        </DropdownMenuItem>
        <DropdownMenuItem onClick={() => handleAction("enable_video")}>
          <Video className="h-4 w-4 mr-2" />
          Enable Video
        </DropdownMenuItem>

        <DropdownMenuSeparator />

        <DropdownMenuItem onClick={() => handleAction("grant_screen_share")}>
          <Monitor className="h-4 w-4 mr-2" />
          Allow Screen Share
        </DropdownMenuItem>
        <DropdownMenuItem onClick={() => handleAction("revoke_screen_share")}>
          <MonitorOff className="h-4 w-4 mr-2" />
          Revoke Screen Share
        </DropdownMenuItem>

        <DropdownMenuSeparator />

        <DropdownMenuItem onClick={() => handleAction("promote")}>
          <Shield className="h-4 w-4 mr-2" />
          Promote to Moderator
        </DropdownMenuItem>
        <DropdownMenuItem onClick={() => handleAction("demote")}>
          <ShieldOff className="h-4 w-4 mr-2" />
          Remove Moderator
        </DropdownMenuItem>

        <DropdownMenuSeparator />

        <DropdownMenuItem
          onClick={() => handleAction("remove")}
          className="text-destructive"
        >
          <UserX className="h-4 w-4 mr-2" />
          Remove Participant
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

"use client";

import React, { useState } from "react";
import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import {
  Pause,
  Play,
  Settings,
  Loader2,
} from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { useVideoAppointmentWebSocket } from "@/hooks/realtime/useVideoAppointmentSocketIO";
import {
  pauseRecording,
  resumeRecording,
  setRecordingQuality,
} from "@/lib/actions/video.server";
import { useToast } from "@/hooks/utils/use-toast";

interface EnhancedRecordingControlsProps {
  appointmentId: string;
  isRecording: boolean;
  onRecordingChange?: (isRecording: boolean) => void;
}

export function EnhancedRecordingControls({
  appointmentId,
  isRecording,
}: EnhancedRecordingControlsProps) {
  const { toast } = useToast();
  const [isPaused, setIsPaused] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [quality, setQuality] = useState<"low" | "medium" | "high" | "ultra">("high");

  const { subscribeToRecordingEvents, isConnected } = useVideoAppointmentWebSocket();

  // Subscribe to recording pause/resume events
  React.useEffect(() => {
    if (!isConnected) return;

    const unsubscribe = subscribeToRecordingEvents((data) => {
      if (data.appointmentId === appointmentId) {
        if (data.action === "recording_paused") {
          setIsPaused(true);
        } else if (data.action === "recording_resumed") {
          setIsPaused(false);
        }
      }
    });

    return unsubscribe;
  }, [isConnected, appointmentId, subscribeToRecordingEvents]);

  const handlePause = async () => {
    setIsLoading(true);
    try {
      const result = await pauseRecording(appointmentId);
      if (result.success) {
        setIsPaused(true);
        toast({
          title: "Recording Paused",
          description: "Recording has been paused",
        });
      }
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to pause recording",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleResume = async () => {
    setIsLoading(true);
    try {
      const result = await resumeRecording(appointmentId);
      if (result.success) {
        setIsPaused(false);
        toast({
          title: "Recording Resumed",
          description: "Recording has been resumed",
        });
      }
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to resume recording",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleQualityChange = async (newQuality: "low" | "medium" | "high" | "ultra") => {
    setIsLoading(true);
    try {
      const result = await setRecordingQuality(appointmentId, newQuality);
      if (result.success) {
        setQuality(newQuality);
        toast({
          title: "Quality Updated",
          description: `Recording quality set to ${newQuality}`,
        });
      }
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to update recording quality",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  if (!isRecording) return null;

  return (
    <div className="flex items-center gap-2">
      {isPaused ? (
        <Button
          size="sm"
          variant="outline"
          onClick={handleResume}
          disabled={isLoading}
        >
          {isLoading ? (
            <Loader2 className="h-4 w-4 animate-spin" />
          ) : (
            <>
              <Play className="h-4 w-4 mr-2" />
              Resume
            </>
          )}
        </Button>
      ) : (
        <Button
          size="sm"
          variant="outline"
          onClick={handlePause}
          disabled={isLoading}
        >
          {isLoading ? (
            <Loader2 className="h-4 w-4 animate-spin" />
          ) : (
            <>
              <Pause className="h-4 w-4 mr-2" />
              Pause
            </>
          )}
        </Button>
      )}

      <Popover>
        <PopoverTrigger asChild>
          <Button size="sm" variant="outline" disabled={isLoading}>
            <Settings className="h-4 w-4 mr-2" />
            Quality: {quality}
          </Button>
        </PopoverTrigger>
        <PopoverContent className="w-48">
          <div className="space-y-2">
            <p className="text-sm font-medium mb-2">Recording Quality</p>
            <Select value={quality} onValueChange={(v) => handleQualityChange(v as typeof quality)}>
              <SelectTrigger>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="low">Low (480p)</SelectItem>
                <SelectItem value="medium">Medium (720p)</SelectItem>
                <SelectItem value="high">High (1080p)</SelectItem>
                <SelectItem value="ultra">Ultra (4K)</SelectItem>
              </SelectContent>
            </Select>
          </div>
        </PopoverContent>
      </Popover>

      {isPaused && (
        <Badge variant="secondary" className="gap-1">
          <Pause className="h-3 w-3" />
          Paused
        </Badge>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { FileText, Plus, Edit, Trash2, Save, X } from "lucide-react";
import { Input } from "@/components/ui/input";
import { useAuth } from "@/hooks/auth/useAuth";
import { useVideoAppointmentWebSocket } from "@/hooks/realtime/useVideoAppointmentSocketIO";
import {
  createMedicalNote,
  getMedicalNotes,
  deleteMedicalNote,
  type MedicalNote,
} from "@/lib/actions/video.server";
import { useToast } from "@/hooks/utils/use-toast";
import { format } from "date-fns";

interface MedicalNotesProps {
  appointmentId: string;
  className?: string;
}

export function MedicalNotes({ appointmentId, className }: MedicalNotesProps) {
  const { user } = useAuth();
  const { toast } = useToast();
  const [notes, setNotes] = useState<MedicalNote[]>([]);
  const [isCreating, setIsCreating] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [newNote, setNewNote] = useState({
    content: "",
    noteType: "GENERAL" as
      | "GENERAL"
      | "SYMPTOM"
      | "DIAGNOSIS"
      | "PRESCRIPTION"
      | "TREATMENT",
    title: "",
  });
  const { subscribeToMedicalNotes, isConnected } =
    useVideoAppointmentWebSocket();

  // Load notes
  useEffect(() => {
    const loadNotes = async () => {
      try {
        const result = await getMedicalNotes(appointmentId);
        if (result && result.notes) {
          setNotes(result.notes);
        }
      } catch (error) {
        // Error handled by React Query
      } finally {
        setIsLoading(false);
      }
    };

    loadNotes();
  }, [appointmentId]);

  // Subscribe to real-time note updates
  useEffect(() => {
    if (!isConnected) return;

    const unsubscribe = subscribeToMedicalNotes((data) => {
      if (data.appointmentId === appointmentId) {
        if (data.action === "note_created" || data.action === "note_updated") {
          const note = data.note as unknown as MedicalNote;
          setNotes((prev) => {
            const existing = prev.findIndex((n) => n.id === note.id);
            if (existing >= 0) {
              const updated = [...prev];
              updated[existing] = note;
              return updated;
            }
            return [...prev, note];
          });
        }
      }
    });

    return unsubscribe;
  }, [isConnected, appointmentId, subscribeToMedicalNotes]);

  const handleCreateNote = async () => {
    if (!newNote.content.trim()) return;

    try {
      const result = await createMedicalNote(appointmentId, {
        content: newNote.content,
        noteType: newNote.noteType,
        title: newNote.title,
      });
      if (result) {
        setNewNote({ content: "", noteType: "GENERAL", title: "" });
        setIsCreating(false);
        toast({
          title: "Note Created",
          description: "Medical note has been saved",
        });
      }
    } catch {
      toast({
        title: "Error",
        description: "Failed to create note",
        variant: "destructive",
      });
    }
  };

  const handleUpdateNote = async (noteId: string) => {
    try {
      const editingNote = notes.find((n) => n.id === noteId);
      if (!editingNote) return;

      // Backend doesn't support update, show error message
      setEditingId(null);
      toast({
        title: "Update Not Supported",
        description: "Please delete and create a new note to update.",
        variant: "destructive",
      });
    } catch {
      toast({
        title: "Error",
        description: "Failed to update note",
        variant: "destructive",
      });
    }
  };

  const handleDeleteNote = async (noteId: string) => {
    try {
      const result = await deleteMedicalNote(appointmentId, noteId);
      if (result && result.success) {
        setNotes((prev) => prev.filter((n) => n.id !== noteId));
        toast({
          title: "Note Deleted",
          description: "Medical note has been deleted",
        });
      }
    } catch {
      toast({
        title: "Error",
        description: "Failed to delete note",
        variant: "destructive",
      });
    }
  };

  const getTypeColor = (
    type: "general" | "symptom" | "diagnosis" | "prescription" | "treatment"
  ) => {
    const colors = {
      general: "default",
      symptom: "secondary",
      diagnosis: "destructive",
      prescription: "outline",
      treatment: "default",
    };
    return colors[type] || "default";
  };

  return (
    <Card className={className}>
      <CardHeader className="pb-3">
        <div className="flex items-center justify-between">
          <CardTitle className="text-lg">Medical Notes</CardTitle>
          {!isCreating && (
            <Button
              size="sm"
              onClick={() => setIsCreating(true)}
              variant="outline"
            >
              <Plus className="h-4 w-4 mr-2" />
              New Note
            </Button>
          )}
        </div>
      </CardHeader>
      <CardContent className="p-0 flex flex-col h-[400px]">
        <ScrollArea className="flex-1 px-4">
          {isLoading ? (
            <div className="flex items-center justify-center h-full">
              <p className="text-sm text-muted-foreground">Loading notes...</p>
            </div>
          ) : (
            <div className="space-y-4 py-4">
              {/* Create Note Form */}
              {isCreating && (
                <Card className="border-primary">
                  <CardContent className="pt-4 space-y-3">
                    <Input
                      placeholder="Note title (optional)..."
                      value={newNote.title}
                      onChange={(e) =>
                        setNewNote((prev) => ({
                          ...prev,
                          title: e.target.value,
                        }))
                      }
                    />

                    <Select
                      value={newNote.noteType}
                      onValueChange={(value) =>
                        setNewNote((prev) => ({
                          ...prev,
                          noteType: value as typeof newNote.noteType,
                        }))
                      }
                    >
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="GENERAL">General</SelectItem>
                        <SelectItem value="SYMPTOM">Symptom</SelectItem>
                        <SelectItem value="DIAGNOSIS">Diagnosis</SelectItem>
                        <SelectItem value="PRESCRIPTION">
                          Prescription
                        </SelectItem>
                        <SelectItem value="TREATMENT">Treatment</SelectItem>
                      </SelectContent>
                    </Select>

                    <Textarea
                      placeholder="Enter medical note..."
                      value={newNote.content}
                      onChange={(e) =>
                        setNewNote((prev) => ({
                          ...prev,
                          content: e.target.value,
                        }))
                      }
                      rows={4}
                    />

                    <div className="flex gap-2">
                      <Button size="sm" onClick={handleCreateNote}>
                        <Save className="h-4 w-4 mr-2" />
                        Save
                      </Button>
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => {
                          setIsCreating(false);
                          setNewNote({
                            content: "",
                            noteType: "GENERAL",
                            title: "",
                          });
                        }}
                      >
                        <X className="h-4 w-4 mr-2" />
                        Cancel
                      </Button>
                    </div>
                  </CardContent>
                </Card>
              )}

              {/* Notes List */}
              {notes.length === 0 ? (
                <div className="text-center py-8 text-muted-foreground">
                  <FileText className="h-12 w-12 mx-auto mb-4 opacity-50" />
                  <p>No notes yet</p>
                </div>
              ) : (
                notes.map((note) => (
                  <Card key={note.id} className="border-l-4 border-l-primary">
                    <CardContent className="pt-4">
                      <div className="flex items-start justify-between mb-2">
                        <div className="flex items-center gap-2">
                          <Badge
                            variant={
                              getTypeColor(
                                note.noteType.toLowerCase() as
                                  | "general"
                                  | "symptom"
                                  | "diagnosis"
                                  | "prescription"
                                  | "treatment"
                              ) as
                                | "default"
                                | "secondary"
                                | "destructive"
                                | "outline"
                            }
                          >
                            {note.noteType}
                          </Badge>
                          <span className="text-xs text-muted-foreground">
                            {note.user?.name || "Unknown"} •{" "}
                            {format(new Date(note.createdAt), "MMM dd, HH:mm")}
                          </span>
                        </div>
                        {note.userId === user?.id && (
                          <div className="flex gap-1">
                            <Button
                              size="sm"
                              variant="ghost"
                              onClick={() => setEditingId(note.id)}
                            >
                              <Edit className="h-3 w-3" />
                            </Button>
                            <Button
                              size="sm"
                              variant="ghost"
                              onClick={() => handleDeleteNote(note.id)}
                            >
                              <Trash2 className="h-3 w-3" />
                            </Button>
                          </div>
                        )}
                      </div>

                      {editingId === note.id ? (
                        <div className="space-y-2">
                          <Textarea
                            defaultValue={note.content}
                            rows={3}
                            ref={(el) => {
                              if (el) {
                                el.focus();
                                el.setSelectionRange(
                                  el.value.length,
                                  el.value.length
                                );
                              }
                            }}
                            onKeyDown={(e) => {
                              if (e.key === "Escape") {
                                setEditingId(null);
                              } else if (
                                e.key === "Enter" &&
                                (e.metaKey || e.ctrlKey)
                              ) {
                                handleUpdateNote(note.id);
                              }
                            }}
                          />
                          <div className="flex gap-2">
                            <Button
                              size="sm"
                              onClick={() => handleUpdateNote(note.id)}
                            >
                              Save
                            </Button>
                            <Button
                              size="sm"
                              variant="outline"
                              onClick={() => setEditingId(null)}
                            >
                              Cancel
                            </Button>
                          </div>
                        </div>
                      ) : (
                        <p className="text-sm whitespace-pre-wrap">
                          {note.content}
                        </p>
                      )}

                      {note.title && (
                        <p className="text-xs font-medium text-muted-foreground mb-1">
                          {note.title}
                        </p>
                      )}
                    </CardContent>
                  </Card>
                ))
              )}
            </div>
          )}
        </ScrollArea>
      </CardContent>
    </Card>
  );
}

"use client";

import { useRef, useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Pen,
  Type,
  Highlighter,
  Square,
  Trash2,
  Undo,
  Redo,
} from "lucide-react";
import { useAuth } from "@/hooks/auth/useAuth";
import { useVideoAppointmentWebSocket } from "@/hooks/realtime/useVideoAppointmentSocketIO";
import {
  createAnnotation,
  getAnnotations,
  deleteAnnotation,
  type Annotation,
} from "@/lib/actions/video.server";
import { useToast } from "@/hooks/utils/use-toast";

interface ScreenAnnotationProps {
  appointmentId: string;
  className?: string;
  onAnnotationChange?: (annotations: Annotation[]) => void;
}

type AnnotationTool = "drawing" | "text" | "arrow" | "highlight" | "shape";
type ShapeType = "rectangle" | "circle" | "line";

export function ScreenAnnotation({
  appointmentId,
  className,
  onAnnotationChange,
}: ScreenAnnotationProps) {
  const { user } = useAuth();
  const { toast } = useToast();
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [annotations, setAnnotations] = useState<Annotation[]>([]);
  const [isDrawing, setIsDrawing] = useState(false);
  const [currentTool, setCurrentTool] = useState<AnnotationTool>("drawing");
  const [currentShape, setCurrentShape] = useState<ShapeType>("rectangle");
  const [currentColor, setCurrentColor] = useState("#3b82f6");
  const [startPoint, setStartPoint] = useState<{ x: number; y: number } | null>(
    null
  );
  const [history, setHistory] = useState<Annotation[][]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  const { subscribeToAnnotations, isConnected } = useVideoAppointmentWebSocket();

  // Load annotations
  useEffect(() => {
    const loadAnnotations = async () => {
      try {
        const result = await getAnnotations(appointmentId);
        if (result && result.annotations) {
          setAnnotations(result.annotations);
          drawAnnotations(result.annotations);
        }
      } catch (error) {
        // Error handled by React Query
      }
    };

    loadAnnotations();
  }, [appointmentId]);

  // Subscribe to real-time annotation updates
  useEffect(() => {
    if (!isConnected) return;

    const unsubscribe = subscribeToAnnotations((data) => {
      if (data.appointmentId === appointmentId) {
        if (data.action === "annotation_created") {
          const annotation = data.annotation as unknown as Annotation;
          setAnnotations((prev) => [...prev, annotation]);
          drawAnnotation(annotation);
        } else if (data.action === "annotation_updated") {
          const annotation = data.annotation as unknown as Annotation;
          setAnnotations((prev) =>
            prev.map((a) => (a.id === annotation.id ? annotation : a))
          );
          redrawAll();
        } else if (data.action === "annotation_deleted") {
          const annotationId = data.annotationId as string;
          setAnnotations((prev) => prev.filter((a) => a.id !== annotationId));
          redrawAll();
        }
      }
    });

    return unsubscribe;
  }, [isConnected, appointmentId, subscribeToAnnotations]);

  // Notify parent of changes
  useEffect(() => {
    if (onAnnotationChange) {
      onAnnotationChange(annotations);
    }
  }, [annotations, onAnnotationChange]);

  const canvas = canvasRef.current;
  const ctx = canvas?.getContext("2d");

  const drawAnnotation = (annotation: Annotation) => {
    if (!ctx || !canvas) return;

    const color = (typeof annotation.data.color === 'string' ? annotation.data.color : annotation.color) || currentColor;
    ctx.strokeStyle = color;
    ctx.fillStyle = color;
    ctx.lineWidth = 2;

    switch (annotation.annotationType) {
      case "DRAWING":
        const drawingPoints = annotation.data.points as Array<{ x: number; y: number }> | undefined;
        if (drawingPoints && Array.isArray(drawingPoints) && drawingPoints.length > 1 && drawingPoints[0]) {
          ctx.beginPath();
          ctx.moveTo(drawingPoints[0].x, drawingPoints[0].y);
          drawingPoints.forEach((point) => {
            ctx.lineTo(point.x, point.y);
          });
          ctx.stroke();
        }
        break;
      case "TEXT":
        const textData = annotation.data.text as string | undefined;
        const textX = (annotation.data.x as number | undefined) ?? annotation.position?.x ?? 0;
        const textY = (annotation.data.y as number | undefined) ?? annotation.position?.y ?? 0;
        if (textData) {
          ctx.font = "16px Arial";
          ctx.fillText(textData, textX, textY);
        }
        break;
      case "SHAPE":
        const shapeData = annotation.data.shape as string | undefined;
        const shapeX = (annotation.data.x as number | undefined) ?? annotation.position?.x ?? 0;
        const shapeY = (annotation.data.y as number | undefined) ?? annotation.position?.y ?? 0;
        const shapeWidth = (annotation.data.width as number | undefined) ?? annotation.position?.width ?? 0;
        const shapeHeight = (annotation.data.height as number | undefined) ?? annotation.position?.height ?? 0;

        if (shapeData === "rectangle" && shapeWidth && shapeHeight) {
          ctx.strokeRect(shapeX, shapeY, shapeWidth, shapeHeight);
        } else if (shapeData === "circle" && shapeWidth) {
          ctx.beginPath();
          ctx.arc(
            shapeX + shapeWidth / 2,
            shapeY + shapeWidth / 2,
            shapeWidth / 2,
            0,
            2 * Math.PI
          );
          ctx.stroke();
        } else if (shapeData === "line") {
          const linePoints = annotation.data.points as Array<{ x: number; y: number }> | undefined;
          if (linePoints && Array.isArray(linePoints) && linePoints.length >= 2 && linePoints[0]) {
            ctx.beginPath();
            ctx.moveTo(linePoints[0].x, linePoints[0].y);
            ctx.lineTo(
              linePoints[1]?.x ?? shapeX,
              linePoints[1]?.y ?? shapeY
            );
            ctx.stroke();
          }
        }
        break;
      case "ARROW":
      case "HIGHLIGHT":
        // Similar handling for arrow and highlight
        break;
    }
  };

  const drawAnnotations = (anns: Annotation[]) => {
    if (!ctx || !canvas) return;
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    anns.forEach(drawAnnotation);
  };

  const redrawAll = () => {
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    annotations.forEach(drawAnnotation);
  };

  const saveToHistory = () => {
    setHistory((prev) => [...prev.slice(0, historyIndex + 1), annotations]);
    setHistoryIndex((prev) => prev + 1);
  };

  const handleMouseDown = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    setStartPoint({ x, y });
    setIsDrawing(true);

    if (currentTool === "text") {
      const text = prompt("Enter text:");
      if (text) {
        handleCreateAnnotation({
          type: "text",
          data: { x, y, text, color: currentColor },
        });
      }
    }
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!isDrawing || !startPoint || !canvas || !ctx) return;

    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    if (currentTool === "drawing") {
      // Draw preview
      redrawAll();
      ctx.beginPath();
      ctx.moveTo(startPoint.x, startPoint.y);
      ctx.lineTo(x, y);
      ctx.strokeStyle = currentColor;
      ctx.lineWidth = 2;
      ctx.stroke();
    }
  };

  const handleMouseUp = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!isDrawing || !startPoint || !canvas) return;

    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    if (currentTool === "drawing") {
      handleCreateAnnotation({
        type: "drawing",
        data: {
          x: startPoint.x,
          y: startPoint.y,
          points: [startPoint, { x, y }],
          color: currentColor,
        },
      });
    } else if (currentTool === "shape") {
      const width = Math.abs(x - startPoint.x);
      const height = Math.abs(y - startPoint.y);
      handleCreateAnnotation({
        type: "shape",
        data: {
          x: Math.min(startPoint.x, x),
          y: Math.min(startPoint.y, y),
          width,
          height,
          shape: currentShape,
          color: currentColor,
        },
      });
    }

    setIsDrawing(false);
    setStartPoint(null);
  };

  const handleCreateAnnotation = async (data: {
    type: AnnotationTool;
    data: Annotation["data"];
  }) => {
    try {
      const annotationData: {
        annotationType: 'DRAWING' | 'TEXT' | 'ARROW' | 'HIGHLIGHT' | 'SHAPE';
        data: Record<string, unknown>;
        position?: Annotation['position'];
        color?: string;
        thickness?: number;
      } = {
        annotationType: data.type.toUpperCase() as 'DRAWING' | 'TEXT' | 'ARROW' | 'HIGHLIGHT' | 'SHAPE',
        data: data.data as Record<string, unknown>,
        thickness: 2,
      };
      if (typeof data.data.color === 'string') {
        annotationData.color = data.data.color;
      }
      const result = await createAnnotation(appointmentId, annotationData);
      if (result) {
        saveToHistory();
        toast({
          title: "Annotation Created",
          description: "Annotation has been saved",
        });
      }
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to create annotation",
        variant: "destructive",
      });
    }
  };

  const handleDeleteAnnotation = async (annotationId: string) => {
    try {
      const result = await deleteAnnotation(appointmentId, annotationId);
      if (result && result.success) {
        saveToHistory();
        toast({
          title: "Annotation Deleted",
          description: "Annotation has been deleted",
        });
      }
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to delete annotation",
        variant: "destructive",
      });
    }
  };

  const handleUndo = () => {
    if (historyIndex > 0) {
      const newIndex = historyIndex - 1;
      setHistoryIndex(newIndex);
      const previousState = history[newIndex];
      if (previousState) {
        setAnnotations(previousState);
        redrawAll();
      }
    }
  };

  const handleRedo = () => {
    if (historyIndex < history.length - 1) {
      const newIndex = historyIndex + 1;
      setHistoryIndex(newIndex);
      const nextState = history[newIndex];
      if (nextState) {
        setAnnotations(nextState);
        redrawAll();
      }
    }
  };

  const colors = [
    "#3b82f6", // blue
    "#ef4444", // red
    "#10b981", // green
    "#f59e0b", // yellow
    "#8b5cf6", // purple
    "#000000", // black
  ];

  return (
    <Card className={className}>
      <CardHeader className="pb-3">
        <CardTitle className="text-lg">Screen Annotation</CardTitle>
      </CardHeader>
      <CardContent className="space-y-4">
        {/* Toolbar */}
        <div className="flex items-center gap-2 flex-wrap">
          <Button
            size="sm"
            variant={currentTool === "drawing" ? "default" : "outline"}
            onClick={() => setCurrentTool("drawing")}
          >
            <Pen className="h-4 w-4" />
          </Button>
          <Button
            size="sm"
            variant={currentTool === "text" ? "default" : "outline"}
            onClick={() => setCurrentTool("text")}
          >
            <Type className="h-4 w-4" />
          </Button>
          <Button
            size="sm"
            variant={currentTool === "shape" ? "default" : "outline"}
            onClick={() => setCurrentTool("shape")}
          >
            <Square className="h-4 w-4" />
          </Button>
          <Button
            size="sm"
            variant={currentTool === "highlight" ? "default" : "outline"}
            onClick={() => setCurrentTool("highlight")}
          >
            <Highlighter className="h-4 w-4" />
          </Button>

          {currentTool === "shape" && (
            <Select value={currentShape} onValueChange={(v) => setCurrentShape(v as ShapeType)}>
              <SelectTrigger className="w-32">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="rectangle">Rectangle</SelectItem>
                <SelectItem value="circle">Circle</SelectItem>
                <SelectItem value="line">Line</SelectItem>
              </SelectContent>
            </Select>
          )}

          <div className="flex gap-1">
            {colors.map((color) => (
              <button
                key={color}
                className={`w-6 h-6 rounded border-2 ${
                  currentColor === color ? "border-primary" : "border-transparent"
                }`}
                style={{ backgroundColor: color }}
                onClick={() => setCurrentColor(color)}
              />
            ))}
          </div>

          <div className="flex gap-1 ml-auto">
            <Button size="sm" variant="outline" onClick={handleUndo} disabled={historyIndex <= 0}>
              <Undo className="h-4 w-4" />
            </Button>
            <Button
              size="sm"
              variant="outline"
              onClick={handleRedo}
              disabled={historyIndex >= history.length - 1}
            >
              <Redo className="h-4 w-4" />
            </Button>
          </div>
        </div>

        {/* Canvas */}
        <div className="border rounded-lg relative bg-white">
          <canvas
            ref={canvasRef}
            width={800}
            height={400}
            className="w-full cursor-crosshair"
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={handleMouseUp}
            onMouseLeave={() => setIsDrawing(false)}
          />
        </div>

        {/* Annotations List */}
        {annotations.length > 0 && (
          <div className="space-y-2">
            <p className="text-sm font-medium">Annotations ({annotations.length})</p>
            <div className="space-y-1 max-h-32 overflow-y-auto">
              {annotations.map((annotation) => (
                <div
                  key={annotation.id}
                  className="flex items-center justify-between p-2 border rounded text-sm"
                >
                  <div className="flex items-center gap-2">
                    <Badge variant="outline">{annotation.annotationType}</Badge>
                    <span className="text-muted-foreground">
                      {new Date(annotation.createdAt).toLocaleTimeString()}
                    </span>
                  </div>
                  {annotation.userId === user?.id && (
                    <Button
                      size="sm"
                      variant="ghost"
                      onClick={() => handleDeleteAnnotation(annotation.id)}
                    >
                      <Trash2 className="h-3 w-3" />
                    </Button>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

"use client";

import { useEffect, useRef } from 'react';
import { User, MicOff } from 'lucide-react';

interface UserVideoComponentProps {
  streamManager: any; // OpenVidu StreamManager (Publisher or Subscriber)
  isLocal?: boolean;
}

export const UserVideoComponent = ({ streamManager, isLocal = false }: UserVideoComponentProps) => {
  const videoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    if (streamManager && videoRef.current) {
      streamManager.addVideoElement(videoRef.current);
    }
  }, [streamManager]);

  const getNicknameTag = () => {
    try {
      if (!streamManager.stream.connection.data) return 'Unknown';
      return JSON.parse(streamManager.stream.connection.data).displayName;
    } catch (error) {
      return 'Unknown';
    }
  };

  if (!streamManager) return null;

  return (
    <div className="relative w-full h-full bg-black rounded-lg overflow-hidden group">
      <video
        autoPlay={true}
        ref={videoRef}
        muted={isLocal} // Always mute local video to prevent echo
        className="w-full h-full object-cover"
      />
      
      {/* Name Tag */}
      <div className="absolute bottom-4 left-4 bg-black/60 px-3 py-1 rounded-full text-white text-sm font-medium flex items-center gap-2">
        <User className="w-3 h-3" />
        <span>{getNicknameTag()}</span>
        {isLocal && <span className="text-xs text-gray-300">(You)</span>}
      </div>

      {/* Audio Status Overlay (if muted) */}
      {!streamManager.stream.audioActive && (
        <div className="absolute top-4 right-4 bg-red-500/80 p-2 rounded-full">
          <MicOff className="w-4 h-4 text-white" />
        </div>
      )}
    </div>
  );
};

"use client";

// ✅ Video Appointment Room Component with WebSocket Integration
// This component provides a complete video appointment interface using OpenVidu with real-time WebSocket updates

import { useEffect, useState } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import {
  Phone,
  PhoneOff,
  Mic,
  MicOff,
  Video,
  VideoOff,
  Monitor,
  Hand,
  CircleDot,
  Settings,
  Users,
  MessageSquare,
  FileText,
  Calendar,
  Clock,
  User,
  UserCheck,
  XCircle,
  Wifi,
  WifiOff,
  Pen,
  Mic as MicIcon,
} from "lucide-react";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { VideoChat } from "./VideoChat";
import { WaitingRoom } from "./WaitingRoom";
import { MedicalNotes } from "./MedicalNotes";
import { CallQualityIndicator } from "./CallQualityIndicator";
import { ScreenAnnotation } from "./ScreenAnnotation";
import { CallTranscription } from "./CallTranscription";
import { EnhancedRecordingControls } from "./EnhancedRecordingControls";
import { EnhancedParticipantControls } from "./EnhancedParticipantControls";
import { UserVideoComponent } from "./UserVideoComponent";
import {
  useVideoCall,
  useVideoCallControls,
} from "@/hooks/query/useVideoAppointments";
import { useVideoAppointmentWebSocket } from "@/hooks/realtime/useVideoAppointmentSocketIO";
import { useAuth } from "@/hooks/auth/useAuth";
import { useToast } from "@/hooks/utils/use-toast";
import type { VideoAppointment } from "@/hooks/query/useVideoAppointments";
import type { OpenViduAPI } from "@/lib/video/openvidu";
import type { ParticipantInfo } from "@/lib/video/openvidu";

interface VideoAppointmentRoomProps {
  appointment: VideoAppointment;
  onEndCall?: () => void;
  onLeaveRoom?: () => void;
}

export function VideoAppointmentRoom({
  appointment,
  onEndCall,
  onLeaveRoom,
}: VideoAppointmentRoomProps) {
  const { user } = useAuth();
  const { toast } = useToast();
  const {
    startCall,
    endCall,
    isInCall,
    publisher,
    subscribers,
  } = useVideoCall();
  const { getCallControls } = useVideoCallControls();
  const {
    subscribeToParticipantEvents,
    subscribeToRecordingEvents,
    subscribeToChatMessages,
    subscribeToWaitingRoom,
    subscribeToMedicalNotes,
    subscribeToCallQuality,
    subscribeToAnnotations,
    subscribeToTranscription,
    sendParticipantJoined,
    sendParticipantLeft,
    sendRecordingStarted,
    sendRecordingStopped,
    isConnected,
  } = useVideoAppointmentWebSocket();

  // const videoContainerRef = useRef<HTMLDivElement>(null); // No longer needed
  const [call, setCall] = useState<OpenViduAPI | null>(null);
  const [isConnecting, setIsConnecting] = useState(false);
  const [isAudioMuted, setIsAudioMuted] = useState(false);
  const [isVideoMuted, setIsVideoMuted] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isScreenSharing, setIsScreenSharing] = useState(false);
  const [participants, setParticipants] = useState<ParticipantInfo[]>([]);
  const [callDuration, setCallDuration] = useState(0);

  // Role-based access
  const isDoctor = user?.role === 'DOCTOR';
  const isAdmin = user?.role === 'SUPER_ADMIN' || user?.role === 'CLINIC_ADMIN';

  // ✅ Subscribe to WebSocket events
  useEffect(() => {
    if (!isConnected) return;

    // Subscribe to participant events
    const unsubscribeParticipants = subscribeToParticipantEvents((data) => {
      if (data.appointmentId === appointment.appointmentId) {
        if (data.action === "participant_joined" && data.participant) {
          const participantData = data.participant;
          const participant: ParticipantInfo = {
            connectionId: participantData.userId || '',
            data: JSON.stringify(participantData),
            role: participantData.role || 'participant',
            userId: participantData.userId,
            displayName: participantData.displayName,
          };
          setParticipants((prev) => {
            if (prev.some(p => p.userId === participant.userId)) return prev;
            return [...prev, participant];
          });
          toast({
            title: "Participant Joined",
            description: `${participantData.displayName} joined the call`,
          });
        } else if (data.action === "participant_left" && data.participant) {
          const participantData = data.participant;
          setParticipants((prev) =>
            prev.filter((p) => (p.userId || p.connectionId) !== participantData.userId)
          );
          toast({
            title: "Participant Left",
            description: `${participantData.displayName} left the call`,
          });
        }
      }
    });

    // Subscribe to recording events
    const unsubscribeRecording = subscribeToRecordingEvents((data) => {
      if (data.appointmentId === appointment.appointmentId) {
        if (data.action === "recording_started") {
          setIsRecording(true);
          toast({
            title: "Recording Started",
            description: "Video recording has started",
          });
        } else if (data.action === "recording_stopped") {
          setIsRecording(false);
          toast({
            title: "Recording Stopped",
            description: "Video recording has stopped",
          });
        }
      }
    });

    // Subscribe to chat messages (real-time updates)
    const unsubscribeChat = subscribeToChatMessages((data) => {
      if (data.appointmentId === appointment.appointmentId) {
        // Chat component handles its own state updates via WebSocket
        // This subscription ensures we're listening to real-time messages
      }
    });

    // Subscribe to waiting room events
    const unsubscribeWaitingRoom = subscribeToWaitingRoom((data) => {
      if (data.appointmentId === appointment.appointmentId) {
        // Waiting room component handles its own state updates
        // This ensures real-time queue updates
      }
    });

    // Subscribe to medical notes events
    const unsubscribeNotes = subscribeToMedicalNotes((data) => {
      if (data.appointmentId === appointment.appointmentId) {
        // Medical notes component handles its own state updates
        // This ensures real-time note synchronization
      }
    });

    // Subscribe to call quality updates
    const unsubscribeQuality = subscribeToCallQuality((data) => {
      if (data.appointmentId === appointment.appointmentId) {
        // Call quality component handles its own state updates
        // This ensures real-time quality warnings
      }
    });

    // Subscribe to annotation events
    const unsubscribeAnnotations = subscribeToAnnotations((data) => {
      if (data.appointmentId === appointment.appointmentId) {
        // Screen annotation component handles its own state updates
        // This ensures real-time annotation synchronization
      }
    });

    // Subscribe to transcription events
    const unsubscribeTranscription = subscribeToTranscription((data) => {
      if (data.appointmentId === appointment.appointmentId) {
        // Call transcription component handles its own state updates
        // This ensures real-time transcription segments
      }
    });

    return () => {
      unsubscribeParticipants();
      unsubscribeRecording();
      unsubscribeChat();
      unsubscribeWaitingRoom();
      unsubscribeNotes();
      unsubscribeQuality();
      unsubscribeAnnotations();
      unsubscribeTranscription();
    };
  }, [
    appointment.appointmentId,
    isConnected,
    subscribeToParticipantEvents,
    subscribeToRecordingEvents,
    subscribeToChatMessages,
    subscribeToWaitingRoom,
    subscribeToMedicalNotes,
    subscribeToCallQuality,
    subscribeToAnnotations,
    subscribeToTranscription,
    toast,
  ]);

  // ✅ Start video call
  const handleStartCall = async () => {
    try {
      setIsConnecting(true);

      const userInfo = {
        userId: user?.id || "",
        displayName: user?.name || "Unknown User",
        email: user?.email || "",
        role: user?.role || "patient",
      };

      // Start call without container - React handles rendering
      const videoCall = await startCall(appointment, userInfo);
      setCall(videoCall);

      // Send WebSocket event for participant joined
      sendParticipantJoined(appointment.appointmentId, {
        userId: userInfo.userId || user?.id || '',
        displayName: userInfo.displayName || user?.name || 'User',
        role: userInfo.role || user?.role || 'patient',
      });

      toast({
        title: "Connected",
        description: "Successfully connected to video appointment",
      });
    } catch (error) {
      toast({
        title: "Connection Failed",
        description:
          error instanceof Error
            ? error.message
            : "Failed to connect to video call",
        variant: "destructive",
      });
    } finally {
      setIsConnecting(false);
    }
  };

  // ✅ End video call
  const handleEndCall = async () => {
    try {
      if (call) {
        await endCall(appointment.appointmentId);
        setCall(null);
      }

      // Send WebSocket event for participant left
      sendParticipantLeft(appointment.appointmentId, {
        userId: user?.id || "",
        displayName: user?.name || "Unknown User",
        role: user?.role || "patient",
      });

      if (onEndCall) {
        onEndCall();
      }

      toast({
        title: "Call Ended",
        description: "Video appointment has been ended",
      });
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to end video call",
        variant: "destructive",
      });
    }
  };

  // ✅ Leave room
  const handleLeaveRoom = () => {
    if (call) {
      call.dispose();
      setCall(null);
    }

    // Send WebSocket event for participant left
    sendParticipantLeft(appointment.appointmentId, {
      userId: user?.id || "",
      displayName: user?.name || "Unknown User",
      role: user?.role || "patient",
    });

    if (onLeaveRoom) {
      onLeaveRoom();
    }
  };

  // ✅ Get call controls
  const controls = call ? getCallControls(call) : null;

  // ✅ Toggle audio
  const toggleAudio = () => {
    if (controls) {
      controls.toggleAudio();
      setIsAudioMuted(!isAudioMuted);
    }
  };

  // ✅ Toggle video
  const toggleVideo = () => {
    if (controls) {
      controls.toggleVideo();
      setIsVideoMuted(!isVideoMuted);
    }
  };

  // ✅ Toggle recording
  const toggleRecording = () => {
    if (controls) {
      controls.toggleRecording();
      setIsRecording(!isRecording);

      // Send WebSocket event
      if (!isRecording) {
        sendRecordingStarted(appointment.appointmentId, {
          recordingId: appointment.appointmentId,
          status: 'starting',
        });
      } else {
        sendRecordingStopped(appointment.appointmentId, {
          recordingId: appointment.appointmentId,
          status: 'stopped',
        });
      }
    }
  };

  // ✅ Toggle screen sharing
  const toggleScreenSharing = () => {
    if (controls) {
      controls.shareScreen();
      setIsScreenSharing(!isScreenSharing);
    }
  };

  // ✅ Raise hand
  const raiseHand = () => {
    if (controls) {
      controls.raiseHand();
    }
  };

  // ✅ Update participants
  const updateParticipants = () => {
    if (call) {
      const currentParticipants = call.getParticipants();
      setParticipants(currentParticipants);
    } else if (controls) {
      const currentParticipants = controls.getParticipants();
      setParticipants(currentParticipants);
    }
  };

  // ✅ Call duration timer
  useEffect(() => {
    let interval: NodeJS.Timeout;

    if (isInCall()) {
      // Use setInterval for call duration (1 second updates are fine)
      interval = setInterval(() => {
        setCallDuration((prev) => prev + 1);
      }, 1000);
    }

    return () => {
      if (interval) {
        clearInterval(interval);
      }
    };
  }, [isInCall]);

  // ✅ Update participants periodically
  useEffect(() => {
    let interval: NodeJS.Timeout;

    if (isInCall()) {
      updateParticipants();
      interval = setInterval(updateParticipants, 5000);
    }

    return () => {
      if (interval) {
        clearInterval(interval);
      }
    };
  }, [isInCall]);

  // ✅ Format call duration
  const formatDuration = (seconds: number) => {
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    const secs = seconds % 60;

    if (hours > 0) {
      return `${hours}:${minutes.toString().padStart(2, "0")}:${secs
        .toString()
        .padStart(2, "0")}`;
    }
    return `${minutes}:${secs.toString().padStart(2, "0")}`;
  };

  // ✅ Get appointment status color
  const getStatusColor = (status: string) => {
    switch (status) {
      case "scheduled":
        return "bg-blue-100 text-blue-800";
      case "in-progress":
        return "bg-green-100 text-green-800";
      case "completed":
        return "bg-gray-100 text-gray-800";
      case "cancelled":
        return "bg-red-100 text-red-800";
      default:
