                    <div className="text-center text-white">
                      <Phone className="h-16 w-16 mx-auto mb-4 text-gray-400" />
                      <h2 className="text-2xl font-semibold mb-2">Ready to Join</h2>
                      <p className="text-gray-400 mb-6">
