} from '@/lib/utils/token-manager';

// Constants
const TOKEN_REFRESH_THRESHOLD = 5 * 60 * 1000; // 5 minutes
// SESSION_REFRESH_INTERVAL and MAX_RETRY_ATTEMPTS removed - not used

// Types
interface GoogleLoginResponse {
  user: User & {
    isNewUser?: boolean;
    googleId?: string;
  };
  token?: string;
  redirectUrl?: string;
}

// SessionData is replaced by imported Session type

// Helper functions
function getRedirectPath(user: { role?: Role | string } | null | undefined, redirectUrl?: string): string {
  if (redirectUrl && !redirectUrl.includes('/auth/')) {
    return redirectUrl;
  }
  if (user?.role) {
    return getDashboardByRole(user.role as Role);
  }
  return ROUTES.LOGIN;
}

function isTokenExpiringSoon(token: string): boolean {
  try {
    const payload = JSON.parse(atob(token.split('.')[1] || ''));
    const expiryTime = payload.exp * 1000;
    const currentTime = Date.now();
    const timeUntilExpiry = expiryTime - currentTime;

    return timeUntilExpiry < TOKEN_REFRESH_THRESHOLD;
  } catch (error) {
    if (process.env.NODE_ENV === 'development') {
      logger.error('Token parsing error', error, { component: 'useAuth' });
    }
    return true; // Assume token needs refresh if we can't parse it
  }
}

function isAuthError(error: unknown): boolean {
  if (error instanceof Error) {
    const status = (error as { status?: number }).status;
    return status === 401 || status === 403;
  }
  return false;
}

function resolveProfileComplete(user: Record<string, unknown> | null | undefined): boolean {
  if (!user) return false;
  if (typeof user.profileComplete === 'boolean') return user.profileComplete;
  if (typeof user.isProfileComplete === 'boolean') return user.isProfileComplete;
  if (typeof user.requiresProfileCompletion === 'boolean') {
    return !user.requiresProfileCompletion;
  }
  return false;
}

export function useAuth() {
  const router = useRouter();
  const queryClient = useQueryClient();

  // ✅ Sync with Zustand auth store
  const setSession = useAuthStore((state) => state.setSession);
  const clearAuth = useAuthStore((state) => state.clearAuth);
  const setLoading = useAuthStore((state) => state.setLoading);
  const setError = useAuthStore((state) => state.setError);

  // Get current session with auto-refresh using core hook
  const { data: session, isPending } = useQueryData<Session | null>(
    ['session'],
    async (): Promise<Session | null> => {
      try {
        const result = await getServerSession();

        if (!result) {
          return null;
        }

        // If session exists but token is expiring soon, refresh it
        if (result.user && result.access_token && isTokenExpiringSoon(result.access_token)) {
          try {
            const refreshedSession = await refreshToken();
            if (refreshedSession && refreshedSession.access_token && refreshedSession.user) {
              setAccessToken(refreshedSession.access_token);
              // Ensure clinicId is compatible by allowing undefined
              return {
                ...refreshedSession,
                user: {
                  ...refreshedSession.user,
                  clinicId: refreshedSession.user.clinicId || undefined
                }
              };
            }
            // If refresh failed, clear session and return null
            await clearSession();
            return null;
          } catch (error) {
            if (process.env.NODE_ENV === 'development') {
              logger.error('Session refresh error', error, { component: 'useAuth' });
            }
            await clearSession();
            return null;
          }
        }

        return result;
      } catch (error) {
        if (process.env.NODE_ENV === 'development') {
          logger.error('Session fetch error', error, { component: 'useAuth' });
        }
        // Clear session on error
        await clearSession();
        return null;
      }
    },
    {
  // ✅ Disable auto-refetch on auth pages to prevent blocking
      // Only refetch when window is focused or explicitly requested
      refetchInterval: false, // Disabled - will be enabled after successful login
      refetchOnWindowFocus: false, // Don't refetch on window focus
      refetchOnMount: false, // ✅ CRITICAL: Don't refetch on mount - prevents blocking navigation
      // ✅ Add caching to prevent duplicate calls - reduced staleTime for faster logout
      staleTime: 500, // Consider data fresh for only 500ms to prevent stale session after logout
      gcTime: 60000, // Cache for 60 seconds to prevent unnecessary refetches
      // ✅ Make query non-blocking - don't wait for it
      enabled: true, // Keep enabled but make it non-blocking
      // ✅ Prevent duplicate calls in development (React Strict Mode)
      refetchOnReconnect: false, // Don't refetch on reconnect
      // ✅ Use structuralSharing to prevent unnecessary re-renders
      structuralSharing: true,
      retry: (_failureCount: number, error: any) => {
        if (isAuthError(error)) {
          return false;
        }
        // ✅ No retries on auth pages to prevent blocking
        return false; // Don't retry at all on auth pages
      },
    }
  );

  // ✅ Sync session to Zustand store and localStorage
  useEffect(() => {
    if (typeof window === 'undefined') return;

    setLoading(isPending);

    if (session) {
      // Convert SessionData to Session format for Zustand
      const sessionForStore: Session = {
        user: session.user,
        access_token: session.access_token,
        session_id: session.session_id,
        isAuthenticated: session.isAuthenticated,
      };
      setSession(sessionForStore);

      // Sync to localStorage using token-manager
      setAccessToken(session.access_token);
      if (session.session_id) {
        setSessionId(session.session_id);
      }
      setError(null);
    } else if (session === null && !isPending) {
      // Only clear if explicitly null (logged out) and not loading
      clearAuth();
      clearTokens();
    }
  }, [session, isPending, setSession, clearAuth, setLoading, setError]);

  // Function to manually refresh the session
  const refreshSession = async (force?: boolean): Promise<Session | null> => {
    try {
      // If not forced, try to get the session from the server first (fastest)
      if (!force) {
        const serverSession = await getServerSession();

        if (serverSession) {
          queryClient.setQueryData(['session'], serverSession);
          return serverSession;
        }
      }

      // If forced or no server session, try to refresh the token (hits backend)
      const refreshedSession = await refreshToken();

      if (refreshedSession) {
        queryClient.setQueryData(['session'], refreshedSession);
        return refreshedSession;
      }

      // If refresh fails, clear session
      queryClient.setQueryData(['session'], null);
      return null;
    } catch (error) {
      if (process.env.NODE_ENV === 'development') {
        logger.error('Session refresh error', error, { component: 'useAuth' });
      }
      queryClient.setQueryData(['session'], null);
      return null;
    }
  };

  // Enhanced login mutation with proper error handling using core hook
  const loginMutation = useMutationOperation(
    async (data: { email: string; password: string; rememberMe?: boolean }) => {
      const result = await loginAction(data);

      // ✅ Check for explicit error return (avoids Next.js error masking)
      if ((result as any).error) {
        throw new Error((result as any).error);
      }

      if (!result.user) {
        throw new Error('Invalid user data received');
      }

      // Ensure required fields are present with defaults
      const user: User = {
        ...result.user,
        firstName: result.user.firstName || '',
        lastName: result.user.lastName || '',
      };

      return {
        ...result,
        user,
      };
    },
    {
      toastId: TOAST_IDS.AUTH.LOGIN,
      loadingMessage: 'Logging in...',
      successMessage: 'Logged in successfully',
      // showToast: true (default) - to ensure errors are shown
      onError: (error: Error) => {
        showErrorToast(error.message || 'Login failed', {
          id: TOAST_IDS.AUTH.LOGIN,
        });
      },
      onSuccess: (data) => {
        // Convert AuthResponse to Session
        const profileComplete = resolveProfileComplete(data.user as unknown as Record<string, unknown>);
        const { ...restUser } = data.user;
        const sessionData: Session = {
          user: {
            ...restUser,
            profileComplete,
          } as User,
          access_token: data.access_token,
          session_id: data.session_id,
          isAuthenticated: true,
        };

        // Update React Query cache
        queryClient.setQueryData(['session'], sessionData);

        // ✅ Use centralized redirect utility
        const currentPath = typeof window !== 'undefined' ? window.location.pathname : undefined;
        const redirect = resolveRedirect({
          user: {
            role: data.user.role as Role,
            profileComplete,
          },
          redirectUrl: data.redirectUrl,
          ...(currentPath ? { currentPath } : {}),
          isAuthenticated: true,
        });

        // Redirect to determined path
        router.push(redirect.path);
      },
    }
  );

  // Google login mutation - ✅ Use core hook
  const googleLoginMutation = useMutationOperation<GoogleLoginResponse, string>(
    async (token: string) => {
      const result = await googleLoginAction(token);

      if (!result) {
        throw new Error('Google login failed: No response from server');
      }

      if (!result.user || !result.user.id || !result.user.email || !result.user.role) {
        throw new Error('Google login failed: Invalid response from server');
      }

      return result;
    },
    {
      toastId: TOAST_IDS.AUTH.SOCIAL_LOGIN,
      loadingMessage: 'Logging in with Google...',
      successMessage: 'Logged in successfully',
      showToast: false, // Handle manually for custom message
      onSuccess: async (data) => {
        if (!data || !data.user) {
          showErrorToast('Google login failed: Invalid response data', {
            id: TOAST_IDS.AUTH.SOCIAL_LOGIN,
          });
          return;
        }

        // Create session data with proper defaults
        const sessionData: Session = {
          user: {
            id: data.user.id,
            email: data.user.email,
            role: data.user.role,
            name: data.user.name || '',
            firstName: data.user.firstName || data.user.name?.split(' ')[0] || '',
            lastName: data.user.lastName || data.user.name?.split(' ').slice(1).join(' ') || '',
            isVerified: true,
            googleId: data.user.googleId || '',
            profileComplete: resolveProfileComplete(data.user as unknown as Record<string, unknown>)
          },
          access_token: data.token || '',
          session_id: '',
          isAuthenticated: true
        };

        // Set the session data immediately
        queryClient.setQueryData(['session'], sessionData);

        // Refresh session from server after a brief delay
        try {
          await new Promise(resolve => setTimeout(resolve, 500));
          const serverSession = await getServerSession();

          if (serverSession) {
            queryClient.setQueryData(['session'], serverSession);
          }
        } catch (refreshError) {
          if (process.env.NODE_ENV === 'development') {
            logger.error('Error refreshing session', refreshError, { component: 'useAuth' });
          }
        }

        // Handle redirect based on profile completion
        const profileComplete = resolveProfileComplete(data.user as unknown as Record<string, unknown>);

        if (!profileComplete) {
          router.push(ROUTES.PROFILE_COMPLETION);
        } else {
          const redirectPath = getRedirectPath(data.user, data.redirectUrl);
          showSuccessToast(`Welcome${data.user.firstName ? ', ' + data.user.firstName : ''}!`, {
            id: TOAST_IDS.AUTH.SOCIAL_LOGIN,
          });
          router.push(redirectPath);
        }
      },
      onError: (error) => {
        showErrorToast(error, {
          id: TOAST_IDS.AUTH.SOCIAL_LOGIN,
        });
      },
    }
  );

  const googleLogin = googleLoginMutation.mutateAsync;
  const isGoogleLoggingIn = googleLoginMutation.isPending;

  // Register mutation - ✅ Use core hook
  const registerMutation = useMutationOperation<AuthResponse, RegisterData>(
    async (data: RegisterData) => {
       // @ts-ignore - fixing type mismatch with updated server action return type
       const result = await registerAction(data) as AuthResponse | { error: string };

       // ✅ Check for explicit error return
       if ((result as any).error) {
         throw new Error((result as any).error);
       }

       return result as AuthResponse;
    },
    {
      toastId: TOAST_IDS.AUTH.REGISTER,
      loadingMessage: 'Registering...',
      successMessage: 'Registration successful',
      showToast: false, // Let page component handle it
      // ✅ Removed onSuccess redirect - let page component handle it to prevent double redirects
      // ✅ Removed onError toast - let page component handle it to prevent duplicate toasts
    }
  );

  // Enhanced logout mutation with proper cleanup - ✅ Use core hook
  const logoutMutation = useMutationOperation<{ success: boolean }, void>(
    async () => {
      try {
        await logoutAction();
        return { success: true };
      } catch (error) {
        // If it's a 401 or session-related error, treat as success
        if (error instanceof Error &&
            (error.message.includes('401') ||
             error.message.includes('Session') ||
             error.message.includes('session'))) {
          return { success: true };
        }
        throw error;
      }
    },
    {
      toastId: TOAST_IDS.AUTH.LOGOUT,
      loadingMessage: 'Logging out...',
      successMessage: 'Logged out successfully',
      showToast: false, // Handle manually for custom messages
      onSuccess: () => {
        // ✅ CRITICAL FIX: Immediately invalidate session query to prevent dashboard render
        queryClient.invalidateQueries({ queryKey: ['session'] });
        queryClient.setQueryData(['session'], null);

        // Clear all query cache and Zustand stores (prevent cross-role state leakage)
        queryClient.clear();
        queryClient.setQueryData(['session'], null);
        resetAllStores();
        clearSession();

        // ✅ Use centralized redirect utility
        const currentPath = typeof window !== 'undefined' ? window.location.pathname : undefined;
        const redirectContext: Parameters<typeof resolveRedirect>[0] = {
          isAuthenticated: false,
        };
        if (currentPath) {
          redirectContext.currentPath = currentPath;
        }
        const redirect = resolveRedirect(redirectContext);

        // ✅ Use router.replace instead of push to prevent history issues
        router.replace(redirect.path);
        showSuccessToast('Logged out successfully', {
          id: TOAST_IDS.AUTH.LOGOUT,
        });
      },
      onError: (error: Error) => {
        if (process.env.NODE_ENV === 'development') {
          logger.error('Logout error', error, { component: 'useAuth' });
        }

        // ✅ CRITICAL FIX: Immediately invalidate session query to prevent dashboard render
        queryClient.invalidateQueries({ queryKey: ['session'] });
        queryClient.setQueryData(['session'], null);

        // Clear client state even if server logout fails (prevent cross-role state leakage)
        queryClient.clear();
        queryClient.setQueryData(['session'], null);
        resetAllStores();
        clearSession();

        // ✅ Use centralized redirect utility
        const currentPath = typeof window !== 'undefined' ? window.location.pathname : undefined;
        const redirectContext: Parameters<typeof resolveRedirect>[0] = {
          isAuthenticated: false,
        };
        if (currentPath) {
          redirectContext.currentPath = currentPath;
        }
        const redirect = resolveRedirect(redirectContext);

        // ✅ Use router.replace instead of push to prevent history issues
        router.replace(redirect.path);
        showErrorToast('Logged out locally, but server logout failed', {
          id: TOAST_IDS.AUTH.LOGOUT,
        });
      },
    }
  );

  // Register with clinic mutation - ✅ Use core hook
  const registerWithClinicMutation = useMutationOperation<AuthResponse, RegisterData & { clinicId: string; appName: string }>(
    (data) => registerWithClinicAction(data),
    {
      toastId: TOAST_IDS.AUTH.REGISTER,
      loadingMessage: 'Registering with clinic...',
      successMessage: 'Registration successful',
      showToast: false, // Component handles it
      invalidateQueries: [['session']],
      onSuccess: (data) => {
        if (data.user?.role) {
          router.push(getDashboardByRole(data.user.role as Role));
        } else if (data.redirectUrl) {
          router.push(data.redirectUrl);
        } else {
          router.push(`${ROUTES.LOGIN}?registered=true`);
        }
      },
    }
  );

  const registerWithClinic = registerWithClinicMutation.mutate;
  const isRegisteringWithClinic = registerWithClinicMutation.isPending;

  // OTP verification mutation - ✅ Use core hook
  const verifyOTPMutation = useMutationOperation<AuthResponse, OTPFormData>(
    (data) => verifyOTPAction(data) as Promise<AuthResponse>,
    {
      toastId: TOAST_IDS.AUTH.OTP,
      loadingMessage: 'Verifying OTP...',
      successMessage: 'OTP verified successfully! Welcome back!',
      showToast: false, // Handle manually for custom message
      onSuccess: (data) => {
        // Convert AuthResponse to Session
        const profileComplete = resolveProfileComplete(data.user as unknown as Record<string, unknown>);
        const { ...restUser } = data.user;
        const sessionData: Session = {
           user: {
             ...restUser,
             profileComplete,
           } as User,
           access_token: data.access_token || '',
           session_id: data.session_id || '',
           isAuthenticated: true,
        };

        queryClient.setQueryData(['session'], sessionData);

        // ✅ Use centralized redirect utility
        const currentPath = typeof window !== 'undefined' ? window.location.pathname : undefined;
        // ... (rest of function)
        const redirectContext: RedirectContext = {
          user: {
            role: data.user.role as Role,
            profileComplete,
          },
          isAuthenticated: true,
        };
        if (currentPath) {
          redirectContext.currentPath = currentPath;
        }
        if (data.redirectUrl) {
          redirectContext.redirectUrl = data.redirectUrl;
        }
        const redirect = resolveRedirect(redirectContext);

        router.push(redirect.path);
        showSuccessToast('OTP verified successfully! Welcome back!', {
          id: TOAST_IDS.AUTH.OTP,
        });
      },
      onError: (error) => {
        showErrorToast(error, {
          id: TOAST_IDS.AUTH.OTP,
        });
      },
    }
  );

  // Request OTP mutation - ✅ Use core hook
  const requestOTPMutation = useMutationOperation<{ success: boolean; message: string }, OtpRequestFormData>(
    async (data: OtpRequestFormData) => {
      return requestOTPAction(data) as Promise<{ success: boolean; message: string }>;
    },
    {
      toastId: TOAST_IDS.AUTH.OTP,
      loadingMessage: 'Sending OTP...',
      successMessage: 'OTP sent successfully! Please check your email.',
      invalidateQueries: [['session']],
      onSuccess: (data) => {
        showSuccessToast(data.message || 'OTP sent successfully! Please check your email.', {
          id: TOAST_IDS.AUTH.OTP,
        });
      },
    }
  );

  // Password reset mutations - ✅ Use core hooks
  const forgotPasswordMutation = useMutationOperation<MessageResponse, string>(
    (email) => forgotPasswordAction({ email }) as Promise<MessageResponse>,
    {
      toastId: TOAST_IDS.AUTH.FORGOT_PASSWORD,
      loadingMessage: 'Sending reset instructions...',
      successMessage: 'Password reset instructions sent to your email',
      onSuccess: (data) => {
        showSuccessToast(data.message || 'Password reset instructions sent to your email', {
          id: TOAST_IDS.AUTH.FORGOT_PASSWORD,
        });
      },
    }
  );

  const forgotPassword = forgotPasswordMutation.mutate;
  const isRequestingReset = forgotPasswordMutation.isPending;

  const resetPasswordMutation = useMutationOperation<MessageResponse, { token: string; newPassword: string }>(
    (data) => resetPasswordAction({ 
      token: data.token, 
      password: data.newPassword, 
      confirmPassword: data.newPassword 
    }) as Promise<MessageResponse>,
    {
      toastId: TOAST_IDS.AUTH.RESET_PASSWORD,
      loadingMessage: 'Resetting password...',
      successMessage: 'Password reset successful',
      onSuccess: (data) => {
        router.push(`${ROUTES.LOGIN}?reset=true`);
        showSuccessToast(data.message || 'Password reset successful', {
          id: TOAST_IDS.AUTH.RESET_PASSWORD,
        });
      },
    }
  );

  const resetPassword = resetPasswordMutation.mutate;
  const isResettingPassword = resetPasswordMutation.isPending;

  // Social login mutation - ✅ Use core hook
  const socialLoginMutation = useMutationOperation<AuthResponse, SocialLoginData>(
    (data) => socialLoginAction(data),
    {
      toastId: TOAST_IDS.AUTH.SOCIAL_LOGIN,
      loadingMessage: 'Logging in...',
      successMessage: 'Logged in successfully',
      invalidateQueries: [['session']],
      onSuccess: (data) => {
        const redirectPath = getRedirectPath(data.user, data.redirectUrl);
        router.push(redirectPath);
        showSuccessToast('Logged in successfully', {
          id: TOAST_IDS.AUTH.SOCIAL_LOGIN,
        });
      },
    }
  );

  const socialLogin = socialLoginMutation.mutate;
  const isSocialLoggingIn = socialLoginMutation.isPending;

  // Magic link mutations - ✅ Use core hooks
  const requestMagicLinkMutation = useMutationOperation<MessageResponse, string>(
    (email) => requestMagicLinkAction(email),
    {
      toastId: TOAST_IDS.AUTH.LOGIN,
      loadingMessage: 'Sending magic link...',
      successMessage: 'Magic link sent to your email',
      onSuccess: (data) => {
        showSuccessToast(data.message || 'Magic link sent to your email', {
          id: TOAST_IDS.AUTH.LOGIN,
        });
      },
    }
  );

  const requestMagicLink = requestMagicLinkMutation.mutate;
  const isRequestingMagicLink = requestMagicLinkMutation.isPending;

  const verifyMagicLinkMutation = useMutationOperation<AuthResponse, string>(
    (token) => verifyMagicLinkAction(token),
    {
      toastId: TOAST_IDS.AUTH.LOGIN,
      loadingMessage: 'Verifying magic link...',
      successMessage: 'Logged in successfully',
      invalidateQueries: [['session']],
      onSuccess: (data) => {
        const redirectPath = getRedirectPath(data.user, data.redirectUrl);
        router.push(redirectPath);
        showSuccessToast('Logged in successfully', {
          id: TOAST_IDS.AUTH.LOGIN,
        });
      },
    }
  );

  const verifyMagicLink = verifyMagicLinkMutation.mutate;
  const isVerifyingMagicLink = verifyMagicLinkMutation.isPending;

  // Change password mutation - ✅ Use core hook
  const changePasswordMutation = useMutationOperation<AuthResponse, { currentPassword?: string; newPassword: string }>(
    (data) => changePasswordAction(data),
    {
      toastId: TOAST_IDS.AUTH.RESET_PASSWORD,
      loadingMessage: 'Changing password...',
      successMessage: 'Password changed successfully',
      invalidateQueries: [['session']],
    }
  );

  const changePassword = changePasswordMutation.mutate;
  const isChangingPassword = changePasswordMutation.isPending;

  // Terminate all sessions mutation - ✅ Use core hook
  const terminateAllSessionsMutation = useMutationOperation<void, void>(
    () => terminateAllSessions(),
    {
      toastId: TOAST_IDS.SESSION.TERMINATE_ALL,
      loadingMessage: 'Terminating all sessions...',
      successMessage: 'All sessions terminated successfully',
      onSuccess: () => {
        queryClient.clear();
        queryClient.setQueryData(['session'], null);
        router.push(ROUTES.LOGIN);
        showSuccessToast('All sessions terminated successfully', {
          id: TOAST_IDS.SESSION.TERMINATE_ALL,
        });
      },
    }
  );

  // Check OTP Status mutation - ✅ Use core hook
  const checkOTPStatusMutation = useMutationOperation<{ hasActiveOTP: boolean }, string>(
    (email) => checkOTPStatusAction(email) as Promise<{ hasActiveOTP: boolean }>,
    {
      toastId: TOAST_IDS.VERIFICATION.OTP,
      loadingMessage: 'Checking OTP status...',
      successMessage: 'OTP status checked',
      showToast: false, // No toast for status checks
    }
  );

  const checkOTPStatus = checkOTPStatusMutation.mutate;
  const isCheckingOTPStatus = checkOTPStatusMutation.isPending;

  // Invalidate OTP mutation - ✅ Use core hook
  const invalidateOTPMutation = useMutationOperation<{ message: string }, string>(
    (email) => invalidateOTPAction(email) as Promise<{ message: string }>,
    {
      toastId: TOAST_IDS.AUTH.OTP,
      loadingMessage: 'Invalidating OTP...',
      successMessage: 'OTP invalidated',
      onSuccess: (data) => {
        showSuccessToast(data.message, {
          id: TOAST_IDS.AUTH.OTP,
        });
      },
    }
  );

  const invalidateOTP = invalidateOTPMutation.mutate;
  const isInvalidatingOTP = invalidateOTPMutation.isPending;

  // Verify Email mutation - ✅ Use core hook
  const verifyEmailMutation = useMutationOperation<{ success: boolean; message: string }, { email: string; otp: string }>(
    (data) => verifyEmailAction(data.email, data.otp),
    {
      toastId: 'verify-email', // Fallback string ID
      loadingMessage: 'Verifying email...',
      successMessage: 'Email verified successfully!',
      onSuccess: (data) => {
        if (!data.success) {
           throw new Error(data.message);
        }
        showSuccessToast(data.message || 'Email verified successfully!', {
          id: 'verify-email',
        });
        router.push(ROUTES.LOGIN);
      },
    }
  );

  const verifyEmail = verifyEmailMutation.mutate;
  const isVerifyingEmail = verifyEmailMutation.isPending;

  // Social Login mutations - ✅ Use core hooks
  const facebookLoginMutation = useMutationOperation<AuthResponse, string>(
    (token) => facebookLoginAction(token),
    {
      toastId: TOAST_IDS.AUTH.SOCIAL_LOGIN,
      loadingMessage: 'Logging in with Facebook...',
      successMessage: 'Logged in with Facebook successfully',
      invalidateQueries: [['session']],
      onSuccess: (data) => {
        const redirectPath = getRedirectPath(data.user, data.redirectUrl);
        router.push(redirectPath);
        showSuccessToast('Logged in with Facebook successfully', {
          id: TOAST_IDS.AUTH.SOCIAL_LOGIN,
        });
      },
    }
  );

  const facebookLogin = facebookLoginMutation.mutate;
  const isFacebookLoggingIn = facebookLoginMutation.isPending;

  const appleLoginMutation = useMutationOperation<{ success: boolean; user?: User; error?: string }, string>(
    async (token: string) => {
      const result = await appleLoginAction(token);
      if (!result.success) {
        throw new Error(result.error || 'Apple login failed');
      }
      return result;
    },
    {
      toastId: TOAST_IDS.AUTH.SOCIAL_LOGIN,
      loadingMessage: 'Logging in with Apple...',
      successMessage: 'Successfully logged in with Apple',
      invalidateQueries: [['session'], ['auth', 'session']],
      onSuccess: (data) => {
        // Handle successful Apple login
        if (data?.user) {
          // Redirect to dashboard
          router.push(getDashboardByRole(data.user.role as Role));
          showSuccessToast('Successfully logged in with Apple', {
            id: TOAST_IDS.AUTH.SOCIAL_LOGIN,
          });
        }
      },
    }
  );

  const appleLogin = appleLoginMutation.mutateAsync;
  const isAppleLoggingIn = appleLoginMutation.isPending;

  return {
    session,
    isPending,
    isAuthenticated: !!session?.user,
    user: session?.user,
    login: loginMutation.mutate,
    loginAsync: loginMutation.mutateAsync, // ✅ Use mutateAsync for awaitable login
    register: registerMutation.mutateAsync, // ✅ Use mutateAsync so await works properly
    logout: logoutMutation.mutate,
    verifyOTP: verifyOTPMutation.mutateAsync, // ✅ Use mutateAsync for awaitable OTP verification
    requestOTP: requestOTPMutation.mutateAsync, // ✅ Use mutateAsync for awaitable OTP request
    forgotPassword,
    resetPassword,
    changePassword,
    requestMagicLink,
    verifyMagicLink,
    registerWithClinic,
    terminateAllSessions: terminateAllSessionsMutation.mutate,
    checkOTPStatus,
    invalidateOTP,
    verifyEmail,
    googleLogin,
    facebookLogin,
    appleLogin,
    socialLogin,
    isCheckingOTPStatus,
    isInvalidatingOTP,
    isVerifyingEmail,
    isGoogleLoggingIn,
    isFacebookLoggingIn,
    isAppleLoggingIn,
    isLoggingIn: loginMutation.isPending,
    isRegistering: registerMutation.isPending,
    isLoggingOut: logoutMutation.isPending,
    isRequestingReset,
    isResettingPassword,
    isChangingPassword,
    isRequestingMagicLink,
    isVerifyingMagicLink,
    isTerminatingAllSessions: terminateAllSessionsMutation.isPending,
    isRegisteringWithClinic,
    isVerifyingOTP: verifyOTPMutation.isPending,
    isRequestingOTP: requestOTPMutation.isPending,
    isSocialLoggingIn,
    getRedirectPath,
    refreshSession,
  };
}

// ============================================================================
// ✅ UNIFIED AUTH FORM HOOK
// Follows SOLID, DRY, KISS principles
// Centralizes common auth form patterns: loading, error handling, toast, overlay
// ============================================================================

export interface AuthFormOptions {
  /** Toast ID for this operation */
  toastId: string;
  /** Loading message */
  loadingMessage: string;
  /** Success message */
  successMessage: string;
  /** Error message fallback */
  errorMessage?: string;
  /** Redirect URL on success */
  redirectUrl?: string;
  /** Delay before redirect (ms) */
  redirectDelay?: number;
  /** Callback on success */
  onSuccess?: (data?: AuthResponse) => void | Promise<void>;
  /** Callback on error */
  onError?: (error: Error) => void;
  /** Whether to show toast */
  showToast?: boolean;
}

/**
 * ✅ Unified Auth Form Hook
 * Provides consistent loading, error handling, and toast management
 * Uses Zustand for global loading state (no overlay)
 */
export function useAuthForm(options: AuthFormOptions) {
  const router = useRouter();
  const { startLoading, stopLoading } = useGlobalLoading();

  // ✅ Use refs to avoid dependency issues
  const startLoadingRef = useRef(startLoading);
  const stopLoadingRef = useRef(stopLoading);

  useEffect(() => {
    startLoadingRef.current = startLoading;
    stopLoadingRef.current = stopLoading;
  }, [startLoading, stopLoading]);

  /**
   * ✅ Execute auth operation with consistent error handling
   */
  const executeAuthOperation = useCallback(
    async <T,>(
      operation: () => Promise<T>,
      customOptions?: Partial<AuthFormOptions>
    ): Promise<T | null> => {
      const opts = { ...options, ...customOptions };
      const {
        toastId,
        loadingMessage,
        successMessage,
        errorMessage,
        redirectUrl,
        redirectDelay = 0,
        onSuccess,
        onError,
        showToast = true,
      } = opts;

      try {
        // ✅ Show loading indicators
        startLoadingRef.current(loadingMessage);
        if (showToast) {
          showLoadingToast(loadingMessage, toastId);
        }

        // ✅ Execute operation
        const result = await operation();

        // ✅ Handle success
        stopLoadingRef.current();
        if (showToast) {
          dismissToast(toastId);
          showSuccessToast(successMessage, { id: toastId });
        }

        // ✅ Call success callback
        if (onSuccess) {
          await onSuccess(result as AuthResponse);
        }

        // ✅ Redirect if specified
        if (redirectUrl) {
          if (redirectDelay > 0) {
            setTimeout(() => router.push(redirectUrl), redirectDelay);
          } else {
            router.push(redirectUrl);
          }
        }

        return result;
      } catch (error) {
        // ✅ Consistent error handling
        stopLoadingRef.current();
        if (showToast) {
          dismissToast(toastId);
        }

        const sanitizedError = sanitizeErrorMessage(error);
        const finalErrorMessage = errorMessage || sanitizedError || ERROR_MESSAGES.UNKNOWN_ERROR;

        if (showToast) {
          showErrorToast(error, { id: toastId });
        }

        if (onError) {
          onError(error instanceof Error ? error : new Error(finalErrorMessage));
        }

        return null;
      }
    },
    [options, router]
  );

  return {
    executeAuthOperation,
    startLoading: startLoadingRef.current,
    stopLoading: stopLoadingRef.current,
  };
}

/**
 * ✅ Unified Mutation Operation Hook
 * Follows SOLID, DRY, KISS principles
 * Centralizes common mutation patterns: loading, error handling, toast, cache invalidation
 * Single Responsibility: Handle mutation operations with consistent patterns
 * Open/Closed: Extensible for different mutation operations
 * Dependency Inversion: Uses abstractions (toast, query client) not implementations
 */

"use client";

import { useCallback, useRef } from "react";
import { useMutation, useQueryClient, UseMutationOptions } from "@tanstack/react-query";
import {
  showLoadingToast,
  showSuccessToast,
  showErrorToast,
  dismissToast,
} from "@/hooks/utils/use-toast";
import { sanitizeErrorMessage } from "@/lib/utils/error-handler";


export interface MutationOperationOptions<TData, TVariables, TError = Error> {
  /** Toast ID for this operation */
  toastId: string;
  /** Loading message */
  loadingMessage: string;
  /** Success message */
  successMessage: string;
  /** Error message fallback */
  errorMessage?: string;
  /** Query keys to invalidate on success */
  invalidateQueries?: (string | string[])[];
  /** Callback on success */
  onSuccess?: (data: TData, variables: TVariables) => void | Promise<void>;
  /** Callback on error */
  onError?: (error: TError, variables: TVariables) => void;
  /** Whether to show toast */
  showToast?: boolean;
  /** Whether to show loading toast */
  showLoading?: boolean;
  /** Additional mutation options */
  mutationOptions?: Omit<
    UseMutationOptions<TData, TError, TVariables>,
    "mutationFn" | "onSuccess" | "onError"
  >;
}

/**
 * ✅ Unified Mutation Operation Hook
 * Provides consistent loading, error handling, toast, and cache invalidation
 * 
 * @example
 * ```typescript
 * const { mutate, mutateAsync, isPending } = useMutationOperation({
 *   mutationFn: createPatient,
 *   toastId: TOAST_IDS.PATIENT.CREATE,
 *   loadingMessage: "Creating patient...",
 *   successMessage: "Patient created successfully!",
 *   invalidateQueries: [["patients", clinicId]],
 * });
 * ```
 */
export function useMutationOperation<TData, TVariables, TError = Error>(
  mutationFn: (variables: TVariables) => Promise<TData>,
  options: MutationOperationOptions<TData, TVariables, TError>
) {
  const queryClient = useQueryClient();
  const {
    toastId,
    loadingMessage,
    successMessage,
    errorMessage,
    invalidateQueries = [],
    onSuccess,
    onError,
    showToast = true,
    showLoading = true,
    mutationOptions,
  } = options;

  // ✅ Use refs to avoid dependency issues
  const queryClientRef = useRef(queryClient);
  queryClientRef.current = queryClient;

  /**
   * ✅ Execute mutation with consistent error handling
   * Follows DRY - single implementation for all mutation operations
   */
  const handleSuccess = useCallback(
    (data: TData, variables: TVariables) => {
      // ✅ Invalidate queries
      if (invalidateQueries.length > 0) {
        invalidateQueries.forEach((queryKey) => {
          queryClientRef.current.invalidateQueries({
            queryKey: Array.isArray(queryKey) ? queryKey : [queryKey],
          });
        });
      }

      // ✅ Handle success toast
      if (showToast) {
        dismissToast(toastId);
        showSuccessToast(successMessage, { id: toastId });
      }

      // ✅ Call success callback
      if (onSuccess) {
        onSuccess(data, variables);
      }
    },
    [toastId, successMessage, invalidateQueries, showToast, onSuccess]
  );

  const handleError = useCallback(
    (error: TError, variables: TVariables) => {
      // ✅ Consistent error handling
      if (showToast) {
        dismissToast(toastId);
      }

      sanitizeErrorMessage(error);
      // const finalErrorMessage =
      //   errorMessage || sanitizedError || ERROR_MESSAGES.UNKNOWN_ERROR;

      if (showToast) {
        showErrorToast(error, {
          id: toastId,
        });
      }

      // ✅ Call error callback
      if (onError) {
        onError(error, variables);
      }
    },
    [toastId, errorMessage, showToast, onError]
  );

  const mutation = useMutation<TData, TError, TVariables>({
    mutationFn,
    onSuccess: handleSuccess,
    onError: handleError,
    ...mutationOptions,
  });

  /**
   * ✅ Wrapper for mutate that shows loading toast
   */
  const mutate = useCallback(
    (variables: TVariables, customOptions?: any) => {
      if (showLoading) {
        showLoadingToast(loadingMessage, toastId);
      }
      return mutation.mutate(variables, customOptions);
    },
    [mutation, loadingMessage, toastId, showLoading]
  );

  /**
   * ✅ Wrapper for mutateAsync that shows loading toast
   */
  const mutateAsync = useCallback(
    async (variables: TVariables, customOptions?: any) => {
      if (showLoading) {
        showLoadingToast(loadingMessage, toastId);
      }
      try {
        const result = await mutation.mutateAsync(variables, customOptions);
        return result;
      } catch (error) {
        // Error is handled by onError
        throw error;
      }
    },
    [mutation, loadingMessage, toastId, showLoading]
  );

  return {
    ...mutation,
    mutate,
    mutateAsync,
    isPending: mutation.isPending,
  };
}

"use client";

/**
 * React 19 useOptimistic Hook Integration
 * Provides optimistic UI updates for mutations
 */

import { useOptimistic, useTransition, useMemo } from 'react';
import { useMutation, UseMutationOptions } from '@tanstack/react-query';
import { useQueryClient } from '@tanstack/react-query';

export interface OptimisticMutationOptions<TData, TVariables, TError = Error> {
  /**
   * Optimistic update function
   * Receives current state and new variables, returns optimistic state
   */
  optimisticUpdate: (current: TData[], variables: TVariables) => TData[];
  
  /**
   * Rollback function (optional)
   * Called if mutation fails to restore previous state
   */
  rollback?: (previous: TData[], error: TError) => TData[];
  
  /**
   * Query key to update optimistically
   */
  queryKey: (string | number | boolean | null | undefined)[];
  
  /**
   * Standard mutation options
   */
  mutationOptions?: Omit<UseMutationOptions<TData, TError, TVariables>, 'mutationFn'>;
}

/**
 * Hook for optimistic mutations with React 19 useOptimistic
 * 
 * @example
 * ```tsx
 * const { optimisticData, addOptimistic, mutation } = useOptimisticMutation({
 *   queryKey: ['appointments', clinicId],
 *   optimisticUpdate: (current, newAppointment) => [...current, newAppointment],
 *   mutationFn: createAppointment,
 * });
 * ```
 */
export function useOptimisticMutation<TData, TVariables, TError = Error>(
  options: OptimisticMutationOptions<TData, TVariables, TError> & {
    mutationFn: (variables: TVariables) => Promise<TData>;
  }
) {
  const queryClient = useQueryClient();
  const [isPending, startTransition] = useTransition();
  
  // ✅ OPTIMIZED: Memoize current data to prevent unnecessary re-renders
  // Get current data from query cache (updates when query data changes)
  const currentData = useMemo(
    () => queryClient.getQueryData<TData[]>(options.queryKey) || [],
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [queryClient, JSON.stringify(options.queryKey)]
  );
  
  // Optimistic state with useOptimistic
  // React 19's useOptimistic automatically syncs with base state changes
  const [optimisticData, addOptimistic] = useOptimistic(
    currentData,
    (state: TData[], variables: TVariables) => {
      return options.optimisticUpdate(state, variables);
    }
  );
  
  // Mutation with optimistic updates
  const mutation = useMutation({
    mutationFn: options.mutationFn,
    onMutate: async (variables: TVariables) => {
      // Cancel outgoing queries
      await queryClient.cancelQueries({ queryKey: options.queryKey });
      
      // Snapshot previous value
      const previous = queryClient.getQueryData<TData[]>(options.queryKey) || [];
      
      // Optimistically update
      startTransition(() => {
        addOptimistic(variables);
      });
      
      // Update query cache optimistically
      queryClient.setQueryData<TData[]>(options.queryKey, (old = []) => 
        options.optimisticUpdate(old, variables)
      );
      
      return { previous };
    },
    onError: (error: TError, _variables: TVariables, context) => {
      // Rollback on error
      if (context && typeof context === 'object' && 'previous' in context && context.previous) {
        queryClient.setQueryData(options.queryKey, context.previous);
      } else if (options.rollback) {
        const current = queryClient.getQueryData<TData[]>(options.queryKey) || [];
        queryClient.setQueryData(options.queryKey, options.rollback(current, error));
      }
    },
    onSuccess: (data: TData) => {
      // Update with real data on success
      queryClient.setQueryData<TData[]>(options.queryKey, (old = []) => {
        // Replace optimistic entry with real data
        const index = old.findIndex((item: any) => 
          (item as any).id === (data as any).id || 
          (item as any).tempId
        );
        if (index >= 0) {
          const updated = [...old];
          updated[index] = data;
          return updated;
        }
        return [...old, data];
      });
      
      // Invalidate to ensure fresh data
      queryClient.invalidateQueries({ queryKey: options.queryKey, exact: false });
    },
    ...options.mutationOptions,
  });
  
  return {
    optimisticData,
    addOptimistic,
    mutation,
    isPending: isPending || mutation.isPending,
  };
}

/**
 * Simplified hook for adding items optimistically
 */
export function useOptimisticAdd<TData extends { id: string }, TVariables>(
  queryKey: (string | number | boolean | null | undefined)[],
  mutationFn: (variables: TVariables) => Promise<TData>,
  createOptimisticItem: (variables: TVariables) => TData,
  options?: Omit<UseMutationOptions<TData, Error, TVariables, { previous: TData[] }>, 'mutationFn'>
) {
  return useOptimisticMutation<TData, TVariables, Error>({
    queryKey,
    mutationFn,
    optimisticUpdate: (current, variables) => {
      const optimisticItem = {
        ...createOptimisticItem(variables),
        id: `temp-${Date.now()}`,
        tempId: true,
      };
      return [...current, optimisticItem as TData];
    },
    ...(options && { 
      mutationOptions: options as Omit<UseMutationOptions<TData, Error, TVariables, unknown>, 'mutationFn'>
    }),
  });
}

/**
 * Simplified hook for updating items optimistically
 */
export function useOptimisticUpdate<TData extends { id: string }, TVariables extends { id: string }>(
  queryKey: (string | number | boolean | null | undefined)[],
  mutationFn: (variables: TVariables) => Promise<TData>,
  options?: Omit<UseMutationOptions<TData, Error, TVariables, { previous: TData[] }>, 'mutationFn'>
) {
  return useOptimisticMutation<TData, TVariables, Error>({
    queryKey,
    mutationFn,
    optimisticUpdate: (current, variables) => {
      return current.map((item) =>
        (item as TData & { id: string }).id === variables.id ? { ...item, ...variables } : item
      ) as TData[];
    },
    ...(options && { mutationOptions: options as Omit<UseMutationOptions<TData, Error, TVariables, unknown>, 'mutationFn'> }),
  });
}

/**
 * Simplified hook for deleting items optimistically
 */
export function useOptimisticDelete<TData extends { id: string }, TVariables extends { id: string }>(
  queryKey: (string | number | boolean | null | undefined)[],
  mutationFn: (variables: TVariables) => Promise<TData>,
  options?: Omit<UseMutationOptions<TData, Error, TVariables, { previous: TData[] }>, 'mutationFn'>
) {
  return useOptimisticMutation<TData, TVariables, Error>({
    queryKey,
    mutationFn,
    optimisticUpdate: (current, variables) => {
      return current.filter((item) => (item as TData & { id: string }).id !== variables.id) as TData[];
    },
    ...(options && { mutationOptions: options as Omit<UseMutationOptions<TData, Error, TVariables, unknown>, 'mutationFn'> }),
  });
}

import {
  UseQueryOptions,
  QueryKey,
  useQuery,
} from "@tanstack/react-query";
// ✅ Import query configuration for default options
import { queryClientConfig } from '../query/config';

/**
 * useQueryData Hook
 * Purpose: A wrapper around TanStack Query's useQuery hook to standardize query handling
 * Uses centralized query configuration for consistent behavior
 * 
 * @param queryKey - Unique identifier for the query (used for caching)
 * @param queryFn - Function that performs the actual data fetching
 * @param options - Optional useQuery options (merged with default config)
 * 
 * Returns: Commonly used query states and the refetch function
 */
export interface UseQueryDataReturn<TData, TError = Error> {
  data: TData | undefined;
  isPending: boolean;
  isFetched: boolean;
  isFetching: boolean;
  error: TError | null;
  refetch: (options?: { throwOnError?: boolean; cancelRefetch?: boolean }) => Promise<any>;
}

export const useQueryData = <
  TData = unknown,
  TError = Error
>(
  queryKey: QueryKey,
  queryFn: (() => Promise<TData>) | (() => TData),
  options?: Omit<UseQueryOptions<TData, TError, TData>, 'queryKey' | 'queryFn'>
): UseQueryDataReturn<TData, TError> => {
  // ✅ Merge with default query config for consistent behavior
  const defaultOptions = queryClientConfig.defaultOptions?.queries || {};

  const { 
    data,       // The query result data
    isPending,  // True if the query is in a pending state (loading first time)
    isFetched,  // True if the query has been fetched at least once
    isFetching, // True if the query is currently fetching (including background updates)
    error,      // Error object if query failed
    refetch     // Function to manually trigger a refetch
  } = useQuery<TData, TError>({
    queryKey,
    queryFn: queryFn as any,
    ...defaultOptions,
    ...options, // User options override defaults
  } as any);

  return { 
    data,       // The fetched data
    isPending,  // Loading state for first fetch (React Query v5)
    isFetched,  // Whether data has been fetched
    isFetching, // Current loading state
    error,      // Error object if query failed
    refetch     // Manual refetch trigger
  };
};

