/**
 * Hook to calculate percentage change
 */
export const useCalculatePercentageChange = () => {
  return (current: number, previous: number): number => {
    if (previous === 0) return current > 0 ? 100 : 0;
    return ((current - previous) / previous) * 100;
  };
};

