/**
 * Firebase Cloud Messaging (FCM) Hook
 * 
 * Manages FCM token registration and notification handling
 */

import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../auth/useAuth';
import {
  initializeFirebase,
  requestNotificationPermission,
  getFCMToken,
  onForegroundMessage,
  isFirebaseConfigured,
} from '@/lib/config/firebase';
import { showErrorToast, showInfoToast, TOAST_IDS } from '@/hooks/utils/use-toast';
import { useNotificationStore, type Notification } from '@/stores/notifications.store';
import { registerFCMToken } from '@/lib/actions/communication.server';

interface UseFCMReturn {
  token: string | null;
  isSupported: boolean;
  permission: NotificationPermission | null;
  isRegistered: boolean;
  isLoading: boolean;
  error: string | null;
  requestPermission: () => Promise<void>;
  registerToken: () => Promise<void>;
  unregisterToken: () => Promise<void>;
}

/**
 * Hook for managing FCM tokens and push notifications
 */
export function useFCM(): UseFCMReturn {
  const { session } = useAuth();
  const { addNotification } = useNotificationStore();
  const [token, setToken] = useState<string | null>(null);
  const [permission, setPermission] = useState<NotificationPermission | null>(null);
  const [isRegistered, setIsRegistered] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const isSupported = typeof window !== 'undefined' && 'Notification' in window && isFirebaseConfigured();

  // Check notification permission status
  useEffect(() => {
    if (typeof window !== 'undefined' && 'Notification' in window) {
      setPermission(Notification.permission);
    }
  }, []);

  // Initialize Firebase on mount
  useEffect(() => {
    if (!isSupported) {
      return;
    }

    try {
      initializeFirebase();
    } catch (err) {
      console.error('Failed to initialize Firebase:', err);
      setError('Failed to initialize Firebase');
    }
  }, [isSupported]);

  // Set up foreground message handler
  useEffect(() => {
    if (!isSupported || !token) {
      return;
    }

    const unsubscribe = onForegroundMessage((payload) => {
      // Backend handles push notification delivery (FCM, email, SMS, WhatsApp)
      // Frontend only shows in-app notification and toast for reading
      if (!session?.user?.id || !payload.notification) return;

      const notification: Notification = {
        id: payload.data?.id || payload.messageId || `fcm-${Date.now()}-${Math.random()}`,
        userId: session.user.id,
        type: (payload.data?.type || payload.data?.category || 'SYSTEM') as Notification['type'],
        title: payload.notification.title || 'New Notification',
        message: payload.notification.body || payload.data?.message || '',
        data: {
          ...payload.data,
          url: payload.data?.url || payload.data?.link,
        },
        isRead: false,
        createdAt: new Date().toISOString(),
      };

      // Show toast
      showInfoToast(notification.title, {
        id: TOAST_IDS.NOTIFICATION.NEW,
        description: notification.message,
        duration: 5000,
      });

      // Add to notification store for reading
      addNotification(notification);

      // Navigation handled by NotificationItem component on click
    });

    return () => {
      if (unsubscribe) {
        unsubscribe();
      }
    };
  }, [isSupported, token, session?.user?.id, addNotification]);

  /**
   * Request notification permission
   */
  const requestPermission = useCallback(async () => {
    if (!isSupported) {
      setError('Push notifications are not supported in this browser');
      return;
    }

    setIsLoading(true);
    setError(null);

    try {
      const permissionResult = await requestNotificationPermission();
      setPermission(permissionResult);

      if (permissionResult === 'granted') {
        // Get FCM token after permission is granted
        const fcmToken = await getFCMToken();
        if (fcmToken) {
          setToken(fcmToken);
        }
      } else if (permissionResult === 'denied') {
        setError('Notification permission was denied');
        showErrorToast('Notification permission denied. Please enable it in your browser settings.', {
          id: TOAST_IDS.NOTIFICATION.PERMISSION_DENIED,
        });
      }
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to request permission';
      setError(errorMessage);
      console.error('Error requesting notification permission:', err);
    } finally {
      setIsLoading(false);
    }
  }, [isSupported]);

  /**
   * Register FCM token with backend
   */
  const registerToken = useCallback(async () => {
    if (!token) {
      setError('No FCM token available');
      return;
    }

    if (!session?.user?.id) {
      setError('User not authenticated');
      return;
    }

    setIsLoading(true);
    setError(null);

    try {
      const deviceInfo = {
        deviceModel: navigator.userAgent.includes('Chrome') ? 'Chrome' : 
                     navigator.userAgent.includes('Firefox') ? 'Firefox' : 
                     navigator.userAgent.includes('Safari') ? 'Safari' : 'Unknown',
        osVersion: navigator.platform || 'Unknown',
        appVersion: process.env.NEXT_PUBLIC_APP_VERSION || '1.0.0',
      };

      const result = await registerFCMToken({
        token,
        platform: 'web',
        userId: session.user.id,
        ...deviceInfo,
      }) as { success: boolean; error?: string };

      if (!result.success) {
        throw new Error(result.error || 'Failed to register device token');
      }

      setIsRegistered(true);
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to register token';
      setError(errorMessage);
      showErrorToast('Failed to register push notification token', {
        id: TOAST_IDS.NOTIFICATION.FCM_ERROR,
      });
    } finally {
      setIsLoading(false);
    }
  }, [token, session]);

  /**
   * Unregister FCM token
   */
  const unregisterToken = useCallback(async () => {
    if (!token || !isRegistered) {
      return;
    }

    setIsLoading(true);
    setError(null);

    try {
      // You can implement token deletion on backend if needed
      setToken(null);
      setIsRegistered(false);
      console.log('Device token unregistered');
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to unregister token';
      setError(errorMessage);
      console.error('Error unregistering device token:', err);
    } finally {
      setIsLoading(false);
    }
  }, [token, isRegistered]);

  // Auto-register token when available and user is authenticated
  useEffect(() => {
    if (token && session?.user?.id && !isRegistered && !isLoading && permission === 'granted') {
      registerToken();
    }
  }, [token, session?.user?.id, isRegistered, isLoading, permission, registerToken]);

  return {
    token,
    isSupported,
    permission,
    isRegistered,
    isLoading,
    error,
    requestPermission,
    registerToken,
    unregisterToken,
  };
}

"use client";

import { useEffect, useCallback, useRef } from 'react';
import { io, Socket } from 'socket.io-client';
import { APP_CONFIG } from '@/lib/config/config';
import { useHealthStore } from '@/stores';
import { DetailedHealthStatus } from '../query/useHealth';

// Realtime health status types matching backend format
// Realtime health status types matching backend format (supporting both compressed and verbose)
export interface RealtimeHealthStatus {
  t?: string; // timestamp (ISO 8601) - compressed
  timestamp?: string; // verbose
  o?: 'healthy' | 'degraded' | 'unhealthy'; // overall status - compressed
  overall?: 'healthy' | 'degraded' | 'unhealthy'; // verbose
  s?: { // services - compressed
    [serviceName: string]: {
      status: 'healthy' | 'degraded' | 'unhealthy';
      timestamp: string;
      responseTime?: number;
      error?: string;
      details?: string | { message: string };
    };
  };
  services?: { // services - verbose
    [serviceName: string]: {
      status: 'healthy' | 'degraded' | 'unhealthy';
      timestamp: string;
      responseTime?: number;
      error?: string;
      details?: string | { message: string };
    };
  };
  sys?: { // system - compressed
    cpu: number;
    memory: number;
    activeConnections: number;
    requestRate: number;
    errorRate: number;
  };
  system?: { // system - verbose
    cpu: number;
    memory: number | { heapTotal: number; heapUsed: number; rss: number; [key: string]: any }; // Handle complex memory object if needed
    activeConnections: number;
    requestRate: number;
    errorRate: number;
  };
  u?: number; // uptime - compressed
  uptime?: number; // uptime - verbose
}

export interface HealthUpdate {
  t: string; // timestamp
  ty: 'service' | 'system'; // type
  id: string; // service ID
  st: 'healthy' | 'degraded' | 'unhealthy'; // status
  rt?: number; // response time
}

export interface HealthHeartbeat {
  t: string; // timestamp
  o: 'healthy' | 'degraded' | 'unhealthy'; // overall status
}

// Convert realtime format to DetailedHealthStatus format
function convertRealtimeToDetailed(realtime: RealtimeHealthStatus): DetailedHealthStatus {
  // Support both compressed ('s') and verbose ('services') keys
  const services = realtime.s || realtime.services || {};
  const result: DetailedHealthStatus = {};

  // Helper to safely get timestamp
  const getTimestamp = (ts: string | undefined) => ts || new Date().toISOString();

  // Database
  if (services.database) {
    result.database = {
      status: services.database.status === 'healthy' ? 'up' : 'down',
      isHealthy: services.database.status === 'healthy',
      lastHealthCheck: getTimestamp(services.database.timestamp),
    };
    if (services.database.responseTime !== undefined) {
      result.database.avgResponseTime = services.database.responseTime;
    }
    if (services.database.error) {
      result.database.errors = [services.database.error];
    }
  }

  // Cache
  if (services.cache) {
    const cacheConnection: {
      connected: boolean;
      latency?: number;
      provider: string;
      providerStatus: string;
    } = {
      connected: services.cache.status === 'healthy',
      provider: 'dragonfly',
      providerStatus: services.cache.status === 'healthy' ? 'connected' : 'disconnected',
    };

    if (services.cache.responseTime !== undefined) {
      cacheConnection.latency = services.cache.responseTime;
    }

    result.cache = {
      status: services.cache.status === 'healthy' ? 'up' : 'down',
      healthy: services.cache.status === 'healthy',
      connection: cacheConnection,
      provider: 'dragonfly',
    };

    if (services.cache.responseTime !== undefined) {
      result.cache.latency = services.cache.responseTime;
    }
  }

  // Queue
  if (services.queue) {
    const queueConnection: any = {
      connected: services.queue.status === 'healthy',
      provider: 'bullmq',
    };

    if (services.queue.responseTime !== undefined) {
      queueConnection.latency = services.queue.responseTime;
    }

    result.queue = {
      status: services.queue.status === 'healthy' ? 'up' : 'down',
      healthy: services.queue.status === 'healthy',
      connection: queueConnection,
    };
  }

  // Communication
  if (services.communication || services.socket) {
    const commStatus = services.communication?.status || services.socket?.status;
    const isHealthy = commStatus === 'healthy';

    result.communication = {
      status: isHealthy ? 'up' : 'down',
      healthy: isHealthy,
    };

    if (commStatus === 'degraded') {
      result.communication.degraded = true;
    }

    if (services.socket) {
      result.communication.socket = {
        connected: services.socket.status === 'healthy',
        connectedClients: 0,
      };
      if (services.socket.responseTime !== undefined) {
        result.communication.socket.latency = services.socket.responseTime;
      }
    }

    if (services.email) {
      result.communication.email = {
        connected: services.email.status === 'healthy',
      };
      if (services.email.responseTime !== undefined) {
        result.communication.email.latency = services.email.responseTime;
      }
    }

    if (services.whatsapp) {
      result.communication.whatsapp = {
        connected: services.whatsapp.status === 'healthy',
      };
    }

    if (services.push) {
      result.communication.push = {
        connected: services.push.status === 'healthy',
      };
    }
  }

  // Video
  if (services.video) {
    result.video = {
      status: services.video.status === 'healthy' ? 'up' : 'down',
      primaryProvider: 'openvidu',
    };
    if (services.video.status === 'healthy') {
      result.video.isHealthy = true;
    }
    if (services.video.error) {
      result.video.error = services.video.error;
    }
  }

  // Logging
  if (services.logger || services.logging) {
    const srv = services.logger || services.logging;
    if (srv) {
        const isHealthy = srv.status === 'healthy';

        const loggingService: any = {
          available: isHealthy,
          serviceName: "LoggingService",
        };

        if (srv.responseTime !== undefined) {
          loggingService.latency = srv.responseTime;
        }

        const loggingUpdate: any = {
          status: isHealthy ? "up" : "down",
          service: loggingService,
          healthy: isHealthy,
        };

        if (srv.error) {
          loggingUpdate.error = srv.error;
        }

        result.logging = loggingUpdate;
    }
  }

  // System Metrics & Uptime
  if (realtime.u !== undefined) result.uptime = realtime.u;
  if (realtime.uptime !== undefined) result.uptime = realtime.uptime;

  const sys = realtime.sys || realtime.system;
  if (sys) {
    // Basic mapping
    result.system = {
        cpu: typeof sys.cpu === 'number' ? sys.cpu : 0,
        memory: typeof sys.memory === 'number' ? sys.memory : 0,
        activeConnections: sys.activeConnections || 0,
        requestRate: sys.requestRate || 0,
        errorRate: sys.errorRate || 0
    };
  }

  return result;
}

export interface UseHealthRealtimeOptions {
  enabled?: boolean;
}

export interface UseHealthRealtimeReturn {
  socket: Socket | null;
  reconnect: () => void;
  subscribe: () => void;
  unsubscribe: () => void;
}

/**
 * Hook for real-time health monitoring via Socket.IO
 * Uses Zustand store for state management
 */
export function useHealthRealtime(
  options: UseHealthRealtimeOptions = {}
): UseHealthRealtimeReturn {
  const {
    enabled = true,
  } = options;

  // Get store actions
  const setHealthStatus = useHealthStore((state) => state.setHealthStatus);
  const setConnectionStatus = useHealthStore((state) => state.setConnectionStatus);
  const setIsConnected = useHealthStore((state) => state.setIsConnected);
  const setLastUpdate = useHealthStore((state) => state.setLastUpdate);
  const setError = useHealthStore((state) => state.setError);

  const socketRef = useRef<Socket | null>(null);

  // Initialize Socket.IO connection
  useEffect(() => {
    if (!enabled) return;

    // ✅ FIX: Use WebSocket URL, not API URL (API URL has /api/v1 prefix)
    // Socket.IO health namespace is at base WebSocket URL + /health
    const WEBSOCKET_URL = APP_CONFIG.WEBSOCKET.URL || '';

    // Normalize URL (remove /socket.io if present, convert ws:// to http://)
    let normalizedUrl = (WEBSOCKET_URL || '').trim();
    normalizedUrl = normalizedUrl.replace(/\/socket\.io\/?$/, '');
    normalizedUrl = normalizedUrl.replace(/^ws:\/\//, 'http://');
    normalizedUrl = normalizedUrl.replace(/^wss:\/\//, 'https://');

    // Socket.IO namespace syntax: base URL + namespace
    // This creates: {WEBSOCKET_URL}/health
    // Remove trailing slash from normalized URL before adding namespace
    const baseUrl = normalizedUrl.replace(/\/$/, '');
    const healthSocketUrl = `${baseUrl}/health`;

    console.log('🔌 Connecting to health namespace:', {
      baseUrl,
      healthSocketUrl,
      websocketUrl: WEBSOCKET_URL,
    });

    const healthSocket = io(healthSocketUrl, {
      transports: ['websocket', 'polling'],
      reconnection: true,
      reconnectionDelay: 1000,
      reconnectionDelayMax: 5000,
      reconnectionAttempts: 5,
      timeout: 20000,
      forceNew: false,
      // Health namespace typically doesn't require auth, but add if needed
      // auth: { token: await getAccessToken() },
    });

    socketRef.current = healthSocket;

    // Connection events
    healthSocket.on('connect', () => {
      console.log('✅ Health monitoring connected via Socket.IO to /health namespace', {
        id: healthSocket.id,
        url: healthSocketUrl,
        transport: healthSocket.io.engine.transport.name,
      });
      setIsConnected(true);
      setConnectionStatus('connected');
      setError(null);

      // Auto-subscribe to health updates on connection
      healthSocket.emit('health:subscribe', { room: 'health:all' }, (response: { success: boolean; status?: RealtimeHealthStatus }) => {
        if (response.success && response.status) {
          const converted = convertRealtimeToDetailed(response.status);
          setHealthStatus(converted);
          if (response.status.t) {
            setLastUpdate(new Date(response.status.t));
          }
          console.log('✅ Auto-subscribed to health updates on connection');
        }
      });
    });

    healthSocket.on('disconnect', (reason) => {
      console.log('❌ Health monitoring disconnected:', reason);
      setIsConnected(false);
      setConnectionStatus('disconnected');

      // ⚠️ FALLBACK: Start REST polling if Socket.IO disconnects
      // Note: BackendStatusIndicator also has polling fallback
      // This ensures health data is still available even if Socket.IO fails
      if (reason === 'io server disconnect' || reason === 'transport close') {
        console.warn('⚠️ Socket.IO disconnected, component will use REST polling fallback');
      }
    });

    healthSocket.on('connect_error', (err: Error & { type?: string; description?: string; context?: unknown }) => {
      console.error('❌ Health monitoring connection error:', {
        message: err.message,
        type: err.type,
        description: err.description,
        context: err.context,
        url: healthSocketUrl,
      });
      setConnectionStatus('error');
      setError(err);

      // ⚠️ FALLBACK: Connection error - component will use REST polling fallback
      console.warn('⚠️ Socket.IO connection error, component will use REST polling fallback');
    });

    // Health status events
    healthSocket.on('health:status', (data: RealtimeHealthStatus) => {
      try {
        const converted = convertRealtimeToDetailed(data);
        setHealthStatus(converted);
        if (data.t) {
          setLastUpdate(new Date(data.t));
        }
        setError(null);
      } catch (err) {
        console.error('Error converting health status:', err);
        setError(err instanceof Error ? err : new Error('Invalid health data'));
      }
    });

    healthSocket.on('health:service:update', (update: HealthUpdate) => {
      // Update service status in Zustand store
      const currentStatus = useHealthStore.getState().healthStatus;
      if (!currentStatus) return;

      const updated = { ...currentStatus };

      // Map service IDs to our format
      if (update.id === 'database' && updated.database) {
        updated.database = {
          ...updated.database,
          status: update.st === 'healthy' ? 'up' : 'down',
          isHealthy: update.st === 'healthy',
          ...(update.rt !== undefined && { avgResponseTime: update.rt }),
          lastHealthCheck: update.t,
        };
      } else if (update.id === 'cache' && updated.cache) {
        updated.cache = {
          ...updated.cache,
          status: update.st === 'healthy' ? 'up' : 'down',
          healthy: update.st === 'healthy',
          ...(update.rt !== undefined && { latency: update.rt }),
          connection: updated.cache.connection ? {
            ...updated.cache.connection,
            connected: update.st === 'healthy',
            ...(update.rt !== undefined && { latency: update.rt }),
          } : {
            connected: update.st === 'healthy',
            ...(update.rt !== undefined && { latency: update.rt }),
            provider: 'dragonfly',
          },
        };
      } else if (update.id === 'queue' && updated.queue) {
        updated.queue = {
          ...updated.queue,
          status: update.st === 'healthy' ? 'up' : 'down',
          healthy: update.st === 'healthy',
          connection: updated.queue.connection ? {
            ...updated.queue.connection,
            connected: update.st === 'healthy',
            ...(update.rt !== undefined && { latency: update.rt }),
          } : {
            connected: update.st === 'healthy',
            ...(update.rt !== undefined && { latency: update.rt }),
            provider: 'bullmq',
          },
        };
      } else if (update.id === 'communication' || update.id === 'socket') {
        if (updated.communication) {
          const commUpdate: typeof updated.communication = {
            ...updated.communication,
            status: update.st === 'healthy' ? 'up' : 'down',
            healthy: update.st === 'healthy',
          };

          if (update.st === 'degraded') {
            commUpdate.degraded = true;
          }

          if (updated.communication.socket) {
            commUpdate.socket = {
              ...updated.communication.socket,
              connected: update.st === 'healthy',
            };
            if (update.rt !== undefined) {
              commUpdate.socket.latency = update.rt;
            }
          }

          updated.communication = commUpdate;
        }
      } else if (update.id === 'video' && updated.video) {
        updated.video = {
          ...updated.video,
          status: update.st === 'healthy' ? 'up' : 'down',
          ...(update.st === 'healthy' && { isHealthy: true }),
        };
      } else if ((update.id === 'logger' || update.id === 'logging') && updated.logging) {
        const loggingUpdate: typeof updated.logging = {
          ...updated.logging,
          status: update.st === 'healthy' ? 'up' : 'down',
        };

        if (update.st === 'healthy') {
          loggingUpdate.healthy = true;
        }

        if (updated.logging.service) {
          loggingUpdate.service = {
            ...updated.logging.service,
            available: update.st === 'healthy',
          };
          if (update.rt !== undefined) {
            loggingUpdate.service.latency = update.rt;
          }
        }

        updated.logging = loggingUpdate;
      }

      setHealthStatus(updated);
      setLastUpdate(new Date(update.t));
    });

    healthSocket.on('health:heartbeat', (heartbeat: HealthHeartbeat) => {
      setLastUpdate(new Date(heartbeat.t));
    });

    setConnectionStatus('connecting');

    // Cleanup
    return () => {
      healthSocket.disconnect();
    };
  }, [enabled, setHealthStatus, setConnectionStatus, setIsConnected, setLastUpdate, setError]);

  const reconnect = useCallback(() => {
    if (socketRef.current) {
      socketRef.current.connect();
    }
  }, []);

  const subscribe = useCallback(() => {
    if (socketRef.current && socketRef.current.connected) {
      socketRef.current.emit('health:subscribe', { room: 'health:all' }, (response: { success: boolean; status?: RealtimeHealthStatus }) => {
        if (response.success && response.status) {
          const converted = convertRealtimeToDetailed(response.status);
          setHealthStatus(converted);
          if (response.status?.t) {
            setLastUpdate(new Date(response.status.t));
          }
        }
      });
    }
  }, [setHealthStatus, setLastUpdate]);

  const unsubscribe = useCallback(() => {
    if (socketRef.current && socketRef.current.connected) {
      socketRef.current.emit('health:unsubscribe', () => {});
    }
  }, []);

  return {
    socket: socketRef.current,
    reconnect,
    subscribe,
    unsubscribe,
  };
}

"use client";

import { useEffect, useRef } from 'react';
import { useQueryData, useOptimisticMutation, useQueryClient } from '@/hooks/core';
import { useWebSocketIntegration } from './useWebSocketIntegration';
import { useWebSocketContext, useWebSocketStatus } from '@/app/providers/WebSocketProvider';
import { useAppStore, useAppointmentsStore } from '@/stores';
// ✅ Consolidated: Import types from @/types (single source of truth)
import type { Appointment, AppointmentFilters } from '@/types/appointment.types';
import type { User } from '@/types/auth.types';
import type { Clinic } from '@/types/clinic.types';

// Enhanced query hooks with real-time WebSocket integration

export function useRealTimeAppointments(filters: AppointmentFilters = {}) {
  const queryClient = useQueryClient();
  const { currentClinic } = useAppStore();
  const { isConnected, subscribe } = useWebSocketIntegration();
  const subscriptionRef = useRef<(() => void) | null>(null);

  const query = useQueryData(
    ['appointments', filters, currentClinic?.id],
    async () => {
      if (!currentClinic) throw new Error('No clinic selected');

      // Use actual API endpoint from config
      const { API_ENDPOINTS } = await import('@/lib/config/config');
      const params = new URLSearchParams({
        clinicId: currentClinic.id,
        ...Object.fromEntries(
          Object.entries(filters).map(([key, value]) => [key, String(value)])
        )
      });

      // ✅ SECURITY: Use centralized API client instead of direct fetch
      const { clinicApiClient } = await import('@/lib/api/client');
      const response = await clinicApiClient.get<Appointment[]>(
        `${API_ENDPOINTS.APPOINTMENTS.GET_ALL}?${params}`
      );

      if (!response.success || !response.data) {
        throw new Error(response.message || 'Failed to fetch appointments');
      }

      // Handle both array and object with appointments property
      const appointments = Array.isArray(response.data) 
        ? response.data 
        : (response.data as { appointments?: Appointment[] }).appointments || [];

      return { success: true, data: appointments };
    },
    {
      enabled: !!currentClinic,
      staleTime: 60 * 1000, // 1 minute (optimized for 10M users - real-time updates reduce need for frequent refetch)
      gcTime: 10 * 60 * 1000, // 10 minutes (increased for 10M users)
      refetchOnWindowFocus: false,
    }
  );

  // Set up real-time subscriptions
  useEffect(() => {
    if (!isConnected || !currentClinic) return;

    // Clean up previous subscription
    if (subscriptionRef.current) {
      subscriptionRef.current();
      subscriptionRef.current = null;
    }

    // Subscribe to appointment updates for this clinic
    const unsubscribe = subscribe('appointment:real_time_update', (rawData: unknown) => {
      const data = rawData as {
        action: 'created' | 'updated' | 'deleted';
        appointment: Appointment;
        clinicId: string;
      };
      if (data.clinicId !== currentClinic.id) return;

      // Update the query cache based on the action
      switch (data.action) {
        case 'created':
          queryClient.setQueryData(['appointments', filters, currentClinic.id], (oldData: { success: boolean; data: Appointment[] } | undefined) => {
            if (oldData?.success && oldData?.data) {
              const newData = [...oldData.data, data.appointment];
              return { ...oldData, data: newData };
            }
            return oldData;
          });
          break;

        case 'updated':
          queryClient.setQueryData(['appointments', filters, currentClinic.id], (oldData: { success: boolean; data: Appointment[] } | undefined) => {
            if (oldData?.success && oldData?.data) {
              const updatedData = oldData.data.map((apt: Appointment) =>
                apt.id === data.appointment.id ? { ...apt, ...data.appointment } : apt
              );
              return { ...oldData, data: updatedData };
            }
            return oldData;
          });
          break;

        case 'deleted':
          queryClient.setQueryData(['appointments', filters, currentClinic.id], (oldData: { success: boolean; data: Appointment[] } | undefined) => {
            if (oldData?.success && oldData?.data) {
              const filteredData = oldData.data.filter((apt: Appointment) => apt.id !== data.appointment.id);
              return { ...oldData, data: filteredData };
            }
            return oldData;
          });
          break;
      }

      // Invalidate related queries to ensure consistency
      queryClient.invalidateQueries({ 
        queryKey: ['appointment-stats'], 
        exact: false 
      });
    });

    subscriptionRef.current = unsubscribe;

    return () => {
      if (subscriptionRef.current) {
        subscriptionRef.current();
        subscriptionRef.current = null;
      }
    };
  }, [isConnected, currentClinic, filters, subscribe, queryClient]);

  return {
    ...query,
    isRealTimeEnabled: isConnected,
  };
}

export function useRealTimeAppointmentStats() {
  const queryClient = useQueryClient();
  const { currentClinic } = useAppStore();
  const { isConnected, subscribe } = useWebSocketIntegration();

  const query = useQueryData(
    ['appointment-stats', currentClinic?.id],
    async () => {
      if (!currentClinic) throw new Error('No clinic selected');

      const { API_ENDPOINTS } = await import('@/lib/config/config');
      // ✅ SECURITY: Use centralized API client instead of direct fetch
      const { clinicApiClient } = await import('@/lib/api/client');
      const response = await clinicApiClient.get<Record<string, unknown>>(
        `${API_ENDPOINTS.APPOINTMENTS.ANALYTICS}?clinicId=${currentClinic.id}`
      );

      if (!response.success || !response.data) {
        throw new Error('Failed to fetch appointment stats');
      }

      return { success: true, data: response.data };
    },
    {
      enabled: !!currentClinic,
      staleTime: 5 * 60 * 1000, // 5 minutes (optimized for 10M users)
      gcTime: 15 * 60 * 1000, // 15 minutes
      refetchInterval: isConnected ? false : 10 * 60 * 1000, // 10 minutes if not real-time (increased for 10M users)
      refetchOnWindowFocus: false,
    }
  );

  useEffect(() => {
    if (!isConnected || !currentClinic) return;

    const unsubscribe = subscribe('appointment_stats:update', (rawData: unknown) => {
      const data = rawData as {
        clinicId: string;
        stats: Record<string, unknown>;
      };
      if (data.clinicId === currentClinic.id) {
        queryClient.setQueryData(['appointment-stats', currentClinic.id], {
          success: true,
          data: data.stats,
        });
      }
    });

    return unsubscribe;
  }, [isConnected, currentClinic, subscribe, queryClient]);

  return {
    ...query,
    isRealTimeEnabled: isConnected,
  };
}

export function useRealTimeQueueStatus(queueName?: string, locationId?: string) {
  const queryClient = useQueryClient();
  const { currentClinic } = useAppStore();
  const { isConnected } = useWebSocketStatus();
  const { subscribe } = useWebSocketContext();

  const query = useQueryData(
    ['queue-status', currentClinic?.id, queueName, locationId],
    async () => {
      if (!currentClinic) throw new Error('No clinic selected');

      const { API_ENDPOINTS } = await import('@/lib/config/config');
      const params = new URLSearchParams({
        locationId: locationId || currentClinic.id,
      });
      if (queueName) params.append('queueName', queueName);

      // ✅ SECURITY: Use centralized API client instead of direct fetch
      const { clinicApiClient } = await import('@/lib/api/client');
      const response = await clinicApiClient.get<Record<string, unknown>>(
        `${API_ENDPOINTS.QUEUE.STATS}?${params}`
      );

      if (!response.success || !response.data) {
        throw new Error('Failed to fetch queue status');
      }

      return { success: true, data: response.data };
    },
    {
      enabled: !!currentClinic && !!locationId,
      staleTime: 30 * 1000, // 30 seconds (optimized for 10M users)
      gcTime: 5 * 60 * 1000, // 5 minutes
      // Keep queue status fresh even when the websocket is connected because
      // the backend socket layer does not emit the same location-level stats
      // shape that this hook reads from the API.
      refetchInterval: 15 * 1000,
      refetchOnWindowFocus: false,
    }
  );

  useEffect(() => {
    if (!isConnected || !currentClinic) return;

    const unsubscribe = subscribe('queue_status_update', (rawData: unknown) => {
      const data = rawData as {
        clinicId: string;
        queueName?: string;
        locationId?: string;
        status: Record<string, unknown>;
      };
      if (data.clinicId === currentClinic.id) {
        const eventLocationId = data.locationId || locationId;

        if (locationId && eventLocationId && eventLocationId !== locationId) {
          return;
        }

        if (queueName && data.queueName && data.queueName !== queueName) {
          return;
        }

        queryClient.setQueryData(['queue-status', currentClinic.id, queueName, locationId], {
          success: true,
          data: data.status,
        });
      }
    });

    return unsubscribe;
  }, [isConnected, currentClinic, queueName, subscribe, queryClient]);

  return {
    ...query,
    isRealTimeEnabled: isConnected,
  };
}

// Enhanced mutation hooks with real-time updates
export function useRealTimeAppointmentMutation() {
  const queryClient = useQueryClient();
  const { currentClinic } = useAppStore();
  const { emit } = useWebSocketIntegration();

  const createAppointment = useOptimisticMutation<Appointment, Partial<Appointment>>({
    queryKey: ['appointments', undefined, currentClinic?.id],
    mutationFn: async (appointmentData: Partial<Appointment>) => {
      if (!currentClinic) throw new Error('No clinic selected');

      const { API_ENDPOINTS } = await import('@/lib/config/config');
      // ✅ SECURITY: Use centralized API client instead of direct fetch
      const { clinicApiClient } = await import('@/lib/api/client');
      const response = await clinicApiClient.post<Appointment>(
        API_ENDPOINTS.APPOINTMENTS.CREATE,
        {
          ...appointmentData,
          clinicId: currentClinic.id,
        }
      );

      if (!response.success || !response.data) {
        throw new Error(response.message || 'Failed to create appointment');
      }

      return response.data;
    },
    optimisticUpdate: (current, variables) => {
      // Create optimistic appointment
      const optimisticAppointment = {
        ...variables,
        id: `temp-${Date.now()}`,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      } as Appointment;
      return [...(current || []), optimisticAppointment];
    },
    mutationOptions: {
      onSuccess: (data) => {
        // Notify other clients via WebSocket
        emit('appointment:created', {
          appointment: data,
          clinicId: currentClinic?.id,
        });
      },
    },
  });

  const updateAppointment = useOptimisticMutation<Appointment, { id: string; updates: Partial<Appointment> }>({
    queryKey: ['appointments', undefined, currentClinic?.id],
    mutationFn: async ({ id, updates }: { id: string; updates: Partial<Appointment> }) => {
      const { API_ENDPOINTS } = await import('@/lib/config/config');
      // ✅ SECURITY: Use centralized API client instead of direct fetch
      const { clinicApiClient } = await import('@/lib/api/client');
      const response = await clinicApiClient.put<Appointment>(
        API_ENDPOINTS.APPOINTMENTS.UPDATE(id),
        updates
      );

      if (!response.success || !response.data) {
        throw new Error(response.message || 'Failed to update appointment');
      }

      return response.data;
    },
    optimisticUpdate: (current, variables) => {
      return (current || []).map((apt: Appointment) =>
        apt.id === variables.id ? { ...apt, ...variables.updates } : apt
      );
    },
    mutationOptions: {
      onSuccess: (data, variables) => {
        // Notify other clients via WebSocket
        emit('appointment:updated', {
          id: variables.id,
          updates: data,
          clinicId: currentClinic?.id,
        });

        // Update Zustand store
        useAppointmentsStore.getState().updateAppointment(variables.id, variables.updates);
      },
    },
  });

  const deleteAppointment = useOptimisticMutation<Appointment, string>({
    queryKey: ['appointments', undefined, currentClinic?.id],
    mutationFn: async (id: string) => {
      const { API_ENDPOINTS } = await import('@/lib/config/config');
      // ✅ SECURITY: Use centralized API client instead of direct fetch
      const { clinicApiClient } = await import('@/lib/api/client');
      const response = await clinicApiClient.delete<{ message: string }>(
        API_ENDPOINTS.APPOINTMENTS.DELETE(id)
      );

      if (!response.success) {
        throw new Error(response.message || 'Failed to delete appointment');
      }

      // Return the deleted appointment for optimistic update
      const appointments = queryClient.getQueryData<{ success: boolean; data: Appointment[] }>(['appointments', {}, currentClinic?.id]);
      const deletedAppointment = appointments?.data?.find(apt => apt.id === id);
      return deletedAppointment || ({ id } as Appointment);
    },
    optimisticUpdate: (current, id) => {
      return (current || []).filter((apt: Appointment) => apt.id !== id);
    },
    mutationOptions: {
      onSuccess: (_, id) => {
        // Notify other clients via WebSocket
        emit('appointment:deleted', {
          id,
          clinicId: currentClinic?.id,
        });
      },
    },
  });

  return {
    createAppointment: createAppointment.mutation,
    updateAppointment: updateAppointment.mutation,
    deleteAppointment: deleteAppointment.mutation,
  };
}

// Utility hook for managing query invalidation based on WebSocket events
export function useWebSocketQuerySync() {
  const queryClient = useQueryClient();
  const { isConnected, subscribe } = useWebSocketIntegration();

  useEffect(() => {
    if (!isConnected) return;

    // Global cache invalidation events
    const unsubscribeGlobalRefresh = subscribe('cache:invalidate', (rawData: unknown) => {
      const data = rawData as {
        queryKeys: string[];
        exact?: boolean;
      };
      data.queryKeys.forEach(queryKey => {
        queryClient.invalidateQueries({ 
          queryKey: [queryKey], 
          exact: data.exact ?? false 
        });
      });
    });

    // Specific query updates
    const unsubscribeQueryUpdate = subscribe('cache:update', (rawData: unknown) => {
      const data = rawData as {
        queryKey: string[];
        data: Record<string, unknown>;
      };
      queryClient.setQueryData(data.queryKey, data.data);
    });

    // Batch invalidation for performance
    const unsubscribeBatchInvalidate = subscribe('cache:batch_invalidate', (rawData: unknown) => {
      const data = rawData as {
        patterns: string[];
      };
      data.patterns.forEach(pattern => {
        queryClient.invalidateQueries({
          predicate: (query) => 
            query.queryKey.some(key => 
              typeof key === 'string' && key.includes(pattern)
            ),
        });
      });
    });

    return () => {
      unsubscribeGlobalRefresh();
      unsubscribeQueryUpdate();
      unsubscribeBatchInvalidate();
    };
  }, [isConnected, subscribe, queryClient]);

  return { isConnected };
}

// ============================================================================
// MASTER REAL-TIME INTEGRATION HOOK
// ============================================================================
// Master hook for complete real-time integration
// Combines WebSocket integration with store synchronization and query invalidation

export function useRealTimeIntegration() {
  const queryClient = useQueryClient();
  const { user, currentClinic } = useAppStore();

  // Initialize WebSocket integration
  const webSocketIntegration = useWebSocketIntegration({
    autoConnect: true,
    subscribeToQueues: true,
    subscribeToAppointments: true,
    tenantId: currentClinic?.id,
    userId: user?.id,
  });

  // Sync Zustand stores with server state
  useEffect(() => {
    if (!webSocketIntegration.isReady) return;

    // Subscribe to real-time store synchronization events
    const unsubscribeFunctions: (() => void)[] = [];

    // Sync appointments store
    const unsubscribeAppointmentSync = webSocketIntegration.subscribe('store:sync:appointments', (data: unknown) => {
      const { setAppointments } = useAppointmentsStore.getState();
      const typedData = data as { appointments: Appointment[] };
      setAppointments(typedData.appointments);
    });

    // Sync user data
    const unsubscribeUserSync = webSocketIntegration.subscribe('store:sync:user', (data: unknown) => {
      const { setUser } = useAppStore.getState();
      const typedData = data as { user: User | null };
      if (typedData.user) {
        // Map auth.types.User to app.store.User
        const authUser = typedData.user as any; // Type assertion for missing properties
        const appUser: import('@/stores/app.store').User = {
          id: authUser.id,
          email: authUser.email || '',
          name: authUser.name || `${authUser.firstName || ''} ${authUser.lastName || ''}`.trim() || 'User',
          role: authUser.role as any,
          clinicId: authUser.clinicId,
          avatarUrl: authUser.avatarUrl || authUser.profilePicture,
          permissions: authUser.permissions || [],
          isActive: authUser.isActive ?? true,
          lastLoginAt: authUser.lastLoginAt,
        };
        setUser(appUser);
      } else {
        setUser(null);
      }
    });

    // Sync clinic data
    const unsubscribeClinicSync = webSocketIntegration.subscribe('store:sync:clinic', (data: unknown) => {
      const { setCurrentClinic } = useAppStore.getState();
      const typedData = data as { clinic: Clinic | null };
      if (typedData.clinic) {
        // Map clinic.types.Clinic to app.store.Clinic
        const clinicData = typedData.clinic as any;
        let settings: import('@/stores/app.store').ClinicSettings;

        if (typeof clinicData.settings === 'object' && clinicData.settings !== null && !Array.isArray(clinicData.settings)) {
          const clinicSettings = clinicData.settings;
          // Ensure all required ClinicSettings properties exist
          settings = {
            appointmentDuration: clinicSettings.appointmentDuration || clinicSettings.appointmentSettings?.appointmentDuration || 30,
            workingHours: clinicSettings.workingHours || {
              start: clinicSettings.appointmentSettings?.minAdvanceBooking ? '09:00' : '09:00',
              end: '17:00',
              days: ['monday', 'tuesday', 'wednesday', 'thursday', 'friday'],
            },
            timeZone: clinicSettings.timeZone || clinicData.timezone || 'UTC',
            features: {
              queue: clinicSettings.features?.queue ?? true,
              notifications: clinicSettings.notifications?.push ?? true,
              telemedicine: clinicSettings.features?.telemedicine ?? true,
              pharmacy: clinicSettings.features?.pharmacy ?? true,
            },
          };
        } else {
          settings = {
            appointmentDuration: 30,
            workingHours: { start: '09:00', end: '17:00', days: ['monday', 'tuesday', 'wednesday', 'thursday', 'friday'] },
            timeZone: clinicData.timezone || 'UTC',
            features: { queue: true, notifications: true, telemedicine: true, pharmacy: true },
          };
        }

        const appClinic: import('@/stores/app.store').Clinic = {
          id: clinicData.id,
          name: clinicData.name,
          address: clinicData.address || '',
          phone: clinicData.phone || '',
          email: clinicData.email || '',
          settings,
        };
        setCurrentClinic(appClinic);
      } else {
        setCurrentClinic(null);
      }
    });

    unsubscribeFunctions.push(
      unsubscribeAppointmentSync,
      unsubscribeUserSync,
      unsubscribeClinicSync
    );

    return () => {
      unsubscribeFunctions.forEach(fn => fn());
    };
  }, [webSocketIntegration.isReady, webSocketIntegration.subscribe]);

  // Invalidate queries on reconnection
  useEffect(() => {
    if (webSocketIntegration.isConnected && webSocketIntegration.connectionStatus === 'connected') {
      // Invalidate all queries to ensure fresh data after reconnection
      queryClient.invalidateQueries();
    }
  }, [webSocketIntegration.isConnected, webSocketIntegration.connectionStatus, queryClient]);

  return {
    ...webSocketIntegration,

    // Additional utilities
    syncStoreWithServer: () => {
      if (webSocketIntegration.isReady) {
        webSocketIntegration.emit('request:store:sync', {
          userId: user?.id,
          clinicId: currentClinic?.id,
        });
      }
    },

    // Force refresh all data
    refreshAllData: () => {
      queryClient.invalidateQueries();
      if (webSocketIntegration.isReady) {
        webSocketIntegration.emit('request:data:refresh', {
          userId: user?.id,
          clinicId: currentClinic?.id,
        });
      }
    },
  };
}

"use client";

import { useEffect, useCallback, useRef } from 'react';
import { useQueryClient } from '@/hooks/core';
import { useWebSocketStore, useAppStore, useAppointmentsStore } from '@/stores';
import { websocketManager } from '@/lib/config/websocket';
import { APP_CONFIG } from '@/lib/config/config';
// ✅ Consolidated: Import types from @/types (single source of truth)
import type { Appointment } from '@/types/appointment.types';
import { useNotificationStore, Notification } from '@/stores/notifications.store';
import { showInfoToast, showWarningToast, TOAST_IDS } from '@/hooks/utils/use-toast';

export interface UseWebSocketIntegrationOptions {
  tenantId?: string | undefined;
  userId?: string | undefined;
  clinicId?: string | undefined;
  autoConnect?: boolean;
  subscribeToQueues?: boolean;
  subscribeToAppointments?: boolean;
}

export function useWebSocketIntegration(options: UseWebSocketIntegrationOptions = {}) {
  const queryClient = useQueryClient();
  const { user, currentClinic } = useAppStore();
  const { addNotification } = useNotificationStore();
  const { 
    updateAppointment, 
    addAppointment, 
    addPendingUpdate, 
    applyPendingUpdates 
  } = useAppointmentsStore();

  const {
    isConnected,
    connectionStatus,
    error,
    connect,
    subscribe,
    emit,
    clearError
  } = useWebSocketStore();

  const subscriptionsRef = useRef<(() => void)[]>([]);

  const {
    autoConnect = true,
    subscribeToQueues = true,
    subscribeToAppointments = true,
    tenantId = currentClinic?.id || 'default',
    userId = user?.id || 'anonymous',
    clinicId = currentClinic?.id
  } = options;

  // Initialize WebSocket connection - Real-time enabled
  useEffect(() => {
    if (!autoConnect || !user) return;

    // Create async function to handle WebSocket initialization
    const initializeWebSocket = async () => {
      try {
        websocketManager.initialize({
          autoConnect: false,
        });

        // ✅ SECURITY: Use secure token access (will be migrated to httpOnly cookies)
        const { getAccessToken } = await import('@/lib/utils/token-manager');
        const token = await getAccessToken() || undefined;

        // ⚠️ SECURITY: Use APP_CONFIG instead of hardcoded URLs
        const websocketUrl = APP_CONFIG.WEBSOCKET.URL;
        if (!websocketUrl) {
          throw new Error('NEXT_PUBLIC_WEBSOCKET_URL or NEXT_PUBLIC_WS_URL must be set in environment variables');
        }

        // Connect to main namespace
        connect(websocketUrl, {
          tenantId,
          userId,
          token,
          autoReconnect: true,
          reconnectionAttempts: 5,
        });

      } catch (error) {
        console.error('Failed to initialize WebSocket:', error);
      }
    };

    // Call the async function
    initializeWebSocket();

    return () => {
      // Cleanup subscriptions
      subscriptionsRef.current.forEach(unsubscribe => unsubscribe());
      subscriptionsRef.current = [];
    };
  }, [autoConnect, user, tenantId, userId, connect]);

  // Subscribe to real-time events once connected
  useEffect(() => {
    if (!isConnected) return;

    const unsubscribeCallbacks: (() => void)[] = [];

    // Subscribe to appointment updates
    if (subscribeToAppointments && clinicId) {
      const unsubscribeAppointmentCreated = subscribe('appointment:created', (rawData: unknown) => {
        const data = rawData as Appointment;
        console.log('🆕 New appointment created:', data);
        addAppointment(data);

        // Invalidate related queries
        queryClient.invalidateQueries({ queryKey: ['appointments'] });
        queryClient.invalidateQueries({ queryKey: ['myAppointments'] });
        queryClient.invalidateQueries({ queryKey: ['appointment-stats'] });
      });

      const unsubscribeAppointmentUpdated = subscribe('appointment:updated', (rawData: unknown) => {
        const data = rawData as { id: string; updates: Partial<Appointment> };
        console.log('📝 Appointment updated:', data);
        addPendingUpdate(data.id, data.updates);

        // Apply updates after a short delay to batch them
        setTimeout(() => {
          applyPendingUpdates();
          queryClient.invalidateQueries({ 
            queryKey: ['appointments'],
            exact: false 
          });
          queryClient.invalidateQueries({
            queryKey: ['myAppointments'],
            exact: false
          });
        }, 100);
      });

      const unsubscribeAppointmentDeleted = subscribe('appointment:deleted', (rawData: unknown) => {
        const data = rawData as { id: string };
        console.log('🗑️ Appointment deleted:', data);
        queryClient.invalidateQueries({ queryKey: ['appointments'] });
        queryClient.invalidateQueries({ queryKey: ['myAppointments'] });
      });

      const unsubscribeAppointmentStatusChanged = subscribe('appointment:status_changed', (rawData: unknown) => {
        const data = rawData as { id: string; status: string; timestamp: string };
        console.log('🔄 Appointment status changed:', data);
        updateAppointment(data.id, { 
          status: data.status as any,
          updatedAt: data.timestamp 
        });

        // Update specific appointment query
        queryClient.setQueryData(['appointment', data.id], (oldData: any) => {
          if (oldData) {
            return { ...oldData, status: data.status, updatedAt: data.timestamp };
          }
          return oldData;
        });
        queryClient.invalidateQueries({
          queryKey: ['myAppointments'],
          exact: false
        });
      });

      unsubscribeCallbacks.push(
        unsubscribeAppointmentCreated,
        unsubscribeAppointmentUpdated,
        unsubscribeAppointmentDeleted,
        unsubscribeAppointmentStatusChanged
      );
    }

    // Subscribe to queue updates
    if (subscribeToQueues && clinicId) {
      const invalidateQueueQueries = () => {
        queryClient.invalidateQueries({ queryKey: ['queue-status'] });
        queryClient.invalidateQueries({ queryKey: ['queue-metrics'] });
        queryClient.invalidateQueries({ queryKey: ['myAppointments'], exact: false });
        queryClient.invalidateQueries({ queryKey: ['appointments'], exact: false });
      };

      const invalidateMedicineDeskQueries = () => {
        queryClient.invalidateQueries({ queryKey: ['prescriptions'], exact: false });
        queryClient.invalidateQueries({ queryKey: ['medicineDeskQueue'], exact: false });
        queryClient.invalidateQueries({ queryKey: ['pharmacyStats'], exact: false });
      };

      const unsubscribeQueueUpdate = subscribe('queue:update', (rawData: unknown) => {
        const data = rawData as Record<string, unknown>;
        console.log('📊 Queue updated:', data);
        invalidateQueueQueries();
      });

      const unsubscribeQueuePatientAdded = subscribe('queue:patient_added', (rawData: unknown) => {
        const data = rawData as Record<string, unknown>;
        console.log('👤 Patient added to queue:', data);
        invalidateQueueQueries();
      });

      const unsubscribeQueuePatientRemoved = subscribe('queue:patient_removed', (rawData: unknown) => {
        const data = rawData as Record<string, unknown>;
        console.log('👤 Patient removed from queue:', data);
        invalidateQueueQueries();
      });

      const unsubscribeEnterpriseQueueUpdated = subscribe('appointment.queue.updated', (rawData: unknown) => {
        const data = rawData as Record<string, unknown>;
        console.log('📊 Enterprise queue updated:', data);
        invalidateQueueQueries();
      });

      const unsubscribeEnterpriseQueuePosition = subscribe(
        'appointment.queue.position.updated',
        (rawData: unknown) => {
          const data = rawData as Record<string, unknown>;
          console.log('📍 Queue position updated:', data);
          invalidateQueueQueries();
        }
      );

      const unsubscribeQueueMetrics = subscribe('queue_metrics_update', (rawData: unknown) => {
        const data = rawData as Record<string, unknown>;
        console.log('📈 Queue metrics updated:', data);
        invalidateQueueQueries();
      });

      const unsubscribeMedicineDeskUpdated = subscribe(
        'pharmacy.medicine_desk.updated',
        (rawData: unknown) => {
          const data = rawData as Record<string, unknown>;
          console.log('💊 Medicine desk queue updated:', data);
          invalidateMedicineDeskQueries();
        }
      );

      unsubscribeCallbacks.push(
        unsubscribeQueueUpdate,
        unsubscribeQueuePatientAdded,
        unsubscribeQueuePatientRemoved,
        unsubscribeEnterpriseQueueUpdated,
        unsubscribeEnterpriseQueuePosition,
        unsubscribeQueueMetrics,
        unsubscribeMedicineDeskUpdated
      );
    }

    // Subscribe to general notifications
    // Backend handles push/email/SMS/WhatsApp delivery
    // Frontend only shows in-app notification and toast for reading
    const unsubscribeNotification = subscribe('notification', (rawData: unknown) => {
      const data = rawData as Record<string, unknown>;

      if (!user?.id) return;

      // Map WebSocket notification to store format
      const notificationType = (data.type || data.category || 'SYSTEM') as Notification['type'];
      const notification: Notification = {
        id: data.id as string || `ws-${Date.now()}-${Math.random()}`,
        userId: user.id,
        type: notificationType,
        title: (data.title as string) || 'New Notification',
        message: (data.message as string) || (data.body as string) || '',
        data: {
          ...((data.data || data.metadata || {}) as Record<string, any>),
          url: (data.url as string) || (data.link as string),
        },
        isRead: false,
        createdAt: (data.createdAt as string) || new Date().toISOString(),
      };

      // Show toast for important notification types
      if (notificationType === 'SYSTEM' || notificationType === 'APPOINTMENT') {
        showInfoToast(notification.title, {
          id: TOAST_IDS.NOTIFICATION.NEW,
          description: notification.message,
          duration: 5000,
        });
      }

      // Add to notification store for reading
      addNotification(notification);
    });

    const unsubscribeSystemUpdate = subscribe('system:update', (rawData: unknown) => {
      const data = rawData as Record<string, unknown>;

      // Handle system-wide updates
      // Backend handles delivery via all channels
      // Frontend only shows in-app notification and toast for reading
      if (data.type !== 'maintenance' || !user?.id) return;

      const notification: Notification = {
        id: `system-${Date.now()}-${Math.random()}`,
        userId: user.id,
        type: 'SYSTEM',
        title: 'System Maintenance',
        message: (data.message as string) || 'System maintenance scheduled',
        data: (data.data as Record<string, any>) || {},
        isRead: false,
        createdAt: new Date().toISOString(),
      };

      // Show toast
      showWarningToast(notification.title, {
        id: TOAST_IDS.NOTIFICATION.NEW,
        description: notification.message,
        duration: 10000,
      });

      // Add to notification store for reading
      addNotification(notification);
    });

    unsubscribeCallbacks.push(unsubscribeNotification, unsubscribeSystemUpdate);

    // Store unsubscribe callbacks
    subscriptionsRef.current = unsubscribeCallbacks;

    return () => {
      unsubscribeCallbacks.forEach(unsubscribe => unsubscribe());
    };
  }, [
    isConnected,
    subscribeToAppointments,
    subscribeToQueues,
    clinicId,
    subscribe,
    addAppointment,
    updateAppointment,
    addPendingUpdate,
    applyPendingUpdates,
    queryClient
  ]);

  // Auto-subscribe to relevant channels once connected
  useEffect(() => {
    if (!isConnected || !clinicId) return;

    // Subscribe to clinic-specific updates
    emit('join_clinic', { clinicId });

    if (subscribeToQueues) {
      emit('subscribe_queue_updates', { clinicId });
    }

    if (subscribeToAppointments) {
      emit('subscribe_appointment_updates', { clinicId, userId });
    }
  }, [isConnected, clinicId, userId, subscribeToQueues, subscribeToAppointments, emit]);

  // Utility functions
  const reconnect = useCallback(() => {
    websocketManager.reconnect();
  }, []);

  const emitEvent = useCallback((event: string, data: Record<string, unknown>) => {
    if (isConnected) {
      emit(event, data);
    } else {
      console.warn('Cannot emit event: WebSocket not connected');
    }
  }, [isConnected, emit]);

  const subscribeToEvent = useCallback((event: string, callback: (data: unknown) => void) => {
    return subscribe(event, callback);
  }, [subscribe]);

  return {
    // Connection state
    isConnected,
    connectionStatus,
    error,

    // Actions
    reconnect,
    clearError,
    emit: emitEvent,
    subscribe: subscribeToEvent,

    // Utilities
    isReady: isConnected && !error,
  };
}

// Hook for queue-specific WebSocket operations
export function useQueueWebSocketIntegration(queueName: string) {
  const { isConnected, emit, subscribe } = useWebSocketStore();
  const queryClient = useQueryClient();

  const subscribeToQueue = useCallback((filters?: Record<string, unknown>) => {
    if (isConnected) {
      emit('subscribe_queue', { queueName, filters });
    }
  }, [isConnected, emit, queueName]);

  const unsubscribeFromQueue = useCallback(() => {
    if (isConnected) {
      emit('unsubscribe_queue', { queueName });
    }
  }, [isConnected, emit, queueName]);

  const getQueueMetrics = useCallback((detailed = false) => {
    if (isConnected) {
      emit('get_queue_metrics', { queueNames: [queueName], detailed });
    }
  }, [isConnected, emit, queueName]);

  useEffect(() => {
    if (!isConnected) return;

    const unsubscribeQueueStatus = subscribe('queue_status', (rawData: unknown) => {
      const data = rawData as Record<string, unknown>;
      if (data.queueName === queueName) {
        queryClient.setQueryData(['queue-status', queueName], data.status);
      }
    });

    const unsubscribeQueueMetrics = subscribe('queue_metrics_update', (rawData: unknown) => {
      const data = rawData as Record<string, unknown>;
      if (data.queueName === queueName) {
        queryClient.setQueryData(['queue-metrics', queueName], data.metrics);
      }
    });

    return () => {
      unsubscribeQueueStatus();
      unsubscribeQueueMetrics();
    };
  }, [isConnected, queueName, subscribe, queryClient]);

  return {
    subscribeToQueue,
    unsubscribeFromQueue,
    getQueueMetrics,
    isConnected,
  };
}

// Hook for appointment-specific WebSocket operations
export function useAppointmentWebSocketIntegration() {
  const { isConnected, emit } = useWebSocketStore();
