      latencyHistory: [],
      error: null,
    },
    database: {
      name: "Database",
      endpoint: "/health",
      icon: Database,
      status: "loading",
      lastChecked: null,
      responseTime: null,
      latencyHistory: [],
      error: null,
    },
    websocket: {
      name: "WebSocket Service",
      endpoint: "/health",
      icon: Wifi,
      status: "loading",
      lastChecked: null,
      responseTime: null,
      latencyHistory: [],
      error: null,
    },
    cache: {
      name: "Cache Service",
      endpoint: "/health",
      icon: HardDrive,
      status: "loading",
      lastChecked: null,
      responseTime: null,
      latencyHistory: [],
      error: null,
    },
    video: {
      name: "Video Service",
      endpoint: "/health",
      icon: Video,
      status: "loading",
      lastChecked: null,
      responseTime: null,
      latencyHistory: [],
      error: null,
    },
    queue: {
      name: "Queue System",
      endpoint: "/health",
      icon: Zap,
      status: "loading",
      lastChecked: null,
      responseTime: null,
      latencyHistory: [],
      error: null,
    },
    logger: {
      name: "Logger Service",
      endpoint: "/health",
      icon: HardDrive,
      status: "loading",
      lastChecked: null,
      responseTime: null,
      latencyHistory: [],
      error: null,
    },
    build: {
      name: "Build & Deploy",
      endpoint: "",
      icon: Zap,
      status: "active",
      lastChecked: null,
      responseTime: null,
      latencyHistory: [],
      error: null,
    },
    cicd: {
      name: "CI/CD",
      endpoint: "",
      icon: Activity,
      status: "active",
      lastChecked: null,
      responseTime: null,
      latencyHistory: [],
      error: null,
    },
    systemUptime: null,
    frontendUptime: null,
    lastGlobalCheck: null,
    isChecking: false,
    healthPercentage: 100,
    globalStatus: 'operational',
  });

  // Fetch Frontend Uptime (Server Action) and keep it ticking
  useEffect(() => {
    // Initial fetch
    getFrontendSystemMetrics().then(metrics => {
        if (metrics.uptime) {
             // Calculate accurate start timestamp
             frontendStartTime.current = Date.now() - (metrics.uptime * 1000);
             setBackendStatus(prev => ({ ...prev, frontendUptime: metrics.uptime }));
        }
    }).catch(err => console.error("Failed to fetch frontend metrics", err));

    // Tick every second
    const interval = setInterval(() => {
        if (frontendStartTime.current) {
            setBackendStatus(prev => ({
                ...prev,
                frontendUptime: Math.floor((Date.now() - frontendStartTime.current!) / 1000)
            }));
        }
    }, 1000);
    
    return () => clearInterval(interval);
  }, []);

  // REST Check Function (Fallback)
  const checkAllServices = useCallback(async (force = false) => {
    // Only fetch if forced or if shouldPoll is true (meaning socket has been disconnected for > 1 min)
    if (!force && !shouldPoll && isHealthSocketConnected) {
       return; 
    }

    const now = Date.now();
    if (!force && now - lastRequestTime.current < REQUEST_COOLDOWN) return;
    lastRequestTime.current = now;

    if (!force && healthDataCache.current && now - healthDataCache.current.timestamp < CACHE_DURATION) {
      return;
    }

    setBackendStatus((prev) => ({ ...prev, isChecking: true }));

    try {
      const healthEndpoint = `${apiBaseUrl}/health`;
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 5000);
      const startTime = Date.now();

      const response = await fetch(healthEndpoint, {
          method: "GET",
          signal: controller.signal,
          headers: { "Content-Type": "application/json", Accept: "application/json" },
          mode: "cors",
      });
      
      clearTimeout(timeoutId);
      const healthCheckResponseTime = Date.now() - startTime;
      let parsedHealthData: any = null;

      if (response.ok) {
           parsedHealthData = await response.json();
           healthDataCache.current = { data: parsedHealthData, timestamp: now };
      }

      const mapStatus = (status?: string): StatusType => {
        if (status === "up" || status === "healthy") return "active";
        if (status === "down" || status === "unhealthy") return "error";
        if (status === "degraded") return "warning";
        return "error";
      };

      setBackendStatus(prev => {
          const newState = { ...prev };
          if (parsedHealthData) {
              const services = parsedHealthData.services || {};
              // API
              newState.api = { ...prev.api, status: mapStatus(services.api?.status), lastChecked: new Date(), responseTime: healthCheckResponseTime, latencyHistory: [...(prev.api.latencyHistory || []).slice(-19), healthCheckResponseTime] };
              // DB
              newState.database = { ...prev.database, status: mapStatus(services.database?.status), lastChecked: new Date() };
              // Cache
              newState.cache = { ...prev.cache, status: mapStatus(services.cache?.status), lastChecked: new Date() };
              // Video
              newState.video = { ...prev.video, status: mapStatus(services.video?.status), lastChecked: new Date() };
              // Websocket - Explicitly fallback status
              newState.websocket = { ...prev.websocket, status: 'warning', error: 'Socket Disconnected (Using REST)' }; 
              
              // Uptime
              if (parsedHealthData.systemMetrics?.uptime || parsedHealthData.uptime) {
                  newState.systemUptime = parsedHealthData.systemMetrics?.uptime || parsedHealthData.uptime;
              }
              newState.globalStatus = 'degraded'; // Fallback implies degraded usually
          } else {
              newState.globalStatus = 'down'; 
          }
          newState.isChecking = false;
          newState.lastGlobalCheck = new Date();
          return newState;
      });

    } catch (err) {
      setBackendStatus(prev => ({ ...prev, isChecking: false, globalStatus: 'down' }));
    }
  }, [apiBaseUrl, isHealthSocketConnected, shouldPoll]);
  
  // Manage Polling State based on Socket Connection
  useEffect(() => {
     let timeoutId: NodeJS.Timeout;

     if (isHealthSocketConnected) {
         setShouldPoll(false); // Stop polling immediately if connected
     } else {
         // Wait 60 seconds before enabling polling fallback
         timeoutId = setTimeout(() => {
             console.warn("⚠️ WebSocket disconnected for 60s - Enabling REST Fallback");
             setShouldPoll(true);
             checkAllServices(true); // Trigger immediate fallback check
         }, FALLBACK_DELAY_MS);
     }

     return () => clearTimeout(timeoutId);
  }, [isHealthSocketConnected, checkAllServices]);

  // Polling Interval (Only active when shouldPoll is true)
  useEffect(() => {
    if (!shouldPoll) return;

    const interval = setInterval(() => {
        checkAllServices();
    }, 10000); 
    
    return () => clearInterval(interval);
  }, [shouldPoll, checkAllServices]);

  // Real-time Update Effect (Primary)
  useEffect(() => {
     if (!realtimeHealthStatus || !isHealthSocketConnected) return;
     
     // Detect change and update local state
     setBackendStatus(prev => {
         const newState = { ...prev };
         const now = new Date();
         
         // Helper function for latency history array maintenance
         const updateHistory = (currentHistory: number[], newMetric: number | null) => {
            if (!newMetric) return currentHistory;
            return [...currentHistory.slice(-19), newMetric];
         };

         // Database
         if (realtimeHealthStatus.database) {
            const lat = realtimeHealthStatus.database.avgResponseTime || null;
            newState.database = {
                ...prev.database,
                status: realtimeHealthStatus.database.isHealthy ? 'active' : 'error',
                lastChecked: now,
                responseTime: lat,
                latencyHistory: updateHistory(prev.database.latencyHistory, lat),
                error: realtimeHealthStatus.database.errors?.[0] || null
            };
         }
         
         // Cache
         if (realtimeHealthStatus.cache) {
             const lat = realtimeHealthStatus.cache.latency || null;
             newState.cache = {
                 ...prev.cache,
                 status: realtimeHealthStatus.cache.healthy ? 'active' : 'error',
                 lastChecked: now,
                 responseTime: lat,
                 latencyHistory: updateHistory(prev.cache.latencyHistory, lat)
             };
         }
         
         // Video
         if (realtimeHealthStatus.video) {
             newState.video = {
                 ...prev.video,
                 status: realtimeHealthStatus.video.isHealthy ? 'active' : 'error',
                 lastChecked: now,
                 error: realtimeHealthStatus.video.error || null
             };
         }
         
         // Websocket
         if (realtimeHealthStatus.communication?.socket || isHealthSocketConnected) {
             const sock = realtimeHealthStatus.communication?.socket;
             // Use 1ms or real data if available (User JSON said 1ms)
             const lat = sock?.latency || 1; 
             newState.websocket = {
                 ...prev.websocket,
                 status: 'active',
                 lastChecked: now,
                 responseTime: lat,
                 latencyHistory: updateHistory(prev.websocket.latencyHistory, lat)
             };
         }
         
         // API (Implicit/System)
         // If we are getting socket updates, API is effectively up/reachable via socket.
         newState.api = {
             ...prev.api,
             status: 'active',
             lastChecked: now,
             responseTime: 1, // Nominal
             latencyHistory: updateHistory(prev.api.latencyHistory, 1)
         }

          // System Uptime from Realtime Data
         if (realtimeHealthStatus.uptime) {
             newState.systemUptime = realtimeHealthStatus.uptime; 
         }
         
         // Global calc
         const total = 9; // fixed count (removed realtime)
         const active = [newState.database, newState.cache, newState.video, newState.websocket].filter(s => s.status === 'active').length + 5; 
         newState.healthPercentage = Math.round((active/total)*100);
         
         newState.globalStatus = newState.healthPercentage > 90 ? 'operational' : newState.healthPercentage > 0 ? 'degraded' : 'down';
         newState.lastGlobalCheck = now;
         newState.isChecking = false; // Realtime updates mean we are not "loading"
         
         return newState;
     });
     
  }, [realtimeHealthStatus, isHealthSocketConnected]);
  
  // Expose checkService placeholder
  const checkService = async (s: BackendService) => s;

  return {
    backendStatus,
    checkAllServices,
    checkService,
    isConnected: isHealthSocketConnected
  };
}

/**
 * React 19 useOptimistic Hook for Queue Operations
 * Provides optimistic UI updates for queue mutations
 */

import { useCallback } from 'react';
import { useOptimisticMutation, useQueryClient } from '@/hooks/core';
import { updateQueueStatus, callNextPatient } from '@/lib/actions/queue.server';

/**
 * Hook for updating queue status with optimistic updates
 */
export function useOptimisticUpdateQueueStatus(clinicId?: string) {
  const queryClient = useQueryClient();

  return useOptimisticMutation<any, { patientId: string; status: string }>({
    queryKey: ['queue', clinicId],
    mutationFn: useCallback(async ({ patientId, status }: { patientId: string; status: string }) => {
      const result = await updateQueueStatus(patientId, status) as { success: boolean; error?: string; data?: unknown };
      if (!result.success) {
        throw new Error(result.error || 'Failed to update queue status');
      }
      return result.data as any;
    }, []),
    optimisticUpdate: (current, variables) => {
      if (!current) return current;
      return current.map((item: any) =>
        item.patientId === variables.patientId
          ? { ...item, status: variables.status, updatedAt: new Date().toISOString() }
          : item
      );
    },
    mutationOptions: {
      onSuccess: () => {
        queryClient.invalidateQueries({ queryKey: ['queue', clinicId] });
      },
    },
  });
}

/**
 * Hook for calling next patient with optimistic updates
 */
export function useOptimisticCallNextPatient(clinicId?: string, doctorId?: string) {
  const queryClient = useQueryClient();

  return useOptimisticMutation<any, void>({
    queryKey: ['queue', clinicId],
    mutationFn: useCallback(async () => {
      if (!doctorId) throw new Error('Doctor ID is required');
      const result = await callNextPatient(doctorId) as { success: boolean; error?: string; data?: unknown };
      if (!result.success) {
        throw new Error(result.error || 'Failed to call next patient');
      }
      return result.data as any;
    }, [doctorId]),
    optimisticUpdate: (current) => {
      if (!current || !Array.isArray(current)) return current;
      return current.slice(1);
    },
    mutationOptions: {
      onSuccess: () => {
        queryClient.invalidateQueries({ queryKey: ['queue', clinicId] });
      },
    },
  });
}

import { useMemo } from 'react';
import { useAuth } from '../auth/useAuth';
import { Role } from '@/types/auth.types';
import { 
  Permission, 
  ROLE_PERMISSIONS, 
  PermissionCheck, 
  PermissionContext, 
  PermissionResult
} from '@/types/rbac.types';
import { ROUTES, getDashboardByRole } from '@/lib/config/routes';

/**
 * Main RBAC hook for permission checking
 */
export const useRBAC = (): PermissionCheck => {
  const { user } = useAuth();

  const userRole = user?.role as Role;
  const userPermissions = useMemo(() => {
    if (!userRole || !ROLE_PERMISSIONS[userRole]) return [];
    return ROLE_PERMISSIONS[userRole];
  }, [userRole]);

  const hasPermission = (permission: Permission): boolean => {
    if (!user || !userRole) return false;
    return userPermissions.includes(permission);
  };

  const hasAnyPermission = (permissions: Permission[]): boolean => {
    if (!user || !userRole) return false;
    return permissions.some(permission => userPermissions.includes(permission));
  };

  const hasAllPermissions = (permissions: Permission[]): boolean => {
    if (!user || !userRole) return false;
    return permissions.every(permission => userPermissions.includes(permission));
  };

  const canAccess = (resource: string, action: string): boolean => {
    if (!user || !userRole) return false;

    // Map resource-action combinations to permissions
    const resourceActionMap: Record<string, Permission> = {
      'appointments:create': Permission.CREATE_APPOINTMENTS,
      'appointments:read': Permission.VIEW_APPOINTMENTS,
      'appointments:update': Permission.UPDATE_APPOINTMENTS,
      'appointments:delete': Permission.DELETE_APPOINTMENTS,
      'appointments:manage': Permission.MANAGE_APPOINTMENT_QUEUE,

      'patients:create': Permission.CREATE_PATIENTS,
      'patients:read': Permission.VIEW_PATIENTS,
      'patients:update': Permission.UPDATE_PATIENTS,
      'patients:delete': Permission.DELETE_PATIENTS,

      'doctors:create': Permission.CREATE_DOCTORS,
      'doctors:read': Permission.VIEW_DOCTORS,
      'doctors:update': Permission.UPDATE_DOCTORS,
      'doctors:delete': Permission.DELETE_DOCTORS,

      'clinics:create': Permission.CREATE_CLINICS,
      'clinics:read': Permission.VIEW_CLINICS,
      'clinics:update': Permission.UPDATE_CLINICS,
      'clinics:delete': Permission.DELETE_CLINICS,
      'clinics:manage': Permission.MANAGE_CLINIC_SETTINGS,

      'users:create': Permission.CREATE_USERS,
      'users:read': Permission.VIEW_USERS,
      'users:update': Permission.UPDATE_USERS,
      'users:delete': Permission.DELETE_USERS,
      'users:manage': Permission.MANAGE_USER_ROLES,

      'analytics:read': Permission.VIEW_ANALYTICS,
      'analytics:export': Permission.EXPORT_ANALYTICS,

      'pharmacy:read': Permission.VIEW_PHARMACY,
      'pharmacy:manage': Permission.MANAGE_MEDICINES,

      'queue:read': Permission.VIEW_QUEUE,
      'queue:manage': Permission.MANAGE_QUEUE,

      'medical-records:create': Permission.CREATE_MEDICAL_RECORDS,
      'medical-records:read': Permission.VIEW_MEDICAL_RECORDS,
      'medical-records:update': Permission.UPDATE_MEDICAL_RECORDS,
      'medical-records:delete': Permission.DELETE_MEDICAL_RECORDS,

      'notifications:read': Permission.VIEW_NOTIFICATIONS,
      'notifications:send': Permission.SEND_NOTIFICATIONS,

      'settings:read': Permission.VIEW_SETTINGS,
      'settings:manage': Permission.MANAGE_SYSTEM_SETTINGS,

      'reports:read': Permission.VIEW_REPORTS,
      'reports:generate': Permission.GENERATE_REPORTS,
      'reports:export': Permission.EXPORT_REPORTS,

      'billing:read': Permission.VIEW_BILLING,
      'billing:manage': Permission.MANAGE_BILLING,

      'video:read': Permission.VIEW_VIDEO_APPOINTMENTS,
      'video:create': Permission.CREATE_VIDEO_APPOINTMENTS,
      'video:update': Permission.UPDATE_VIDEO_APPOINTMENTS,
    };

    const key = `${resource}:${action}`;
    const requiredPermission = resourceActionMap[key];

    if (!requiredPermission) return false;
    return hasPermission(requiredPermission);
  };

  return {
    hasPermission,
    hasAnyPermission,
    hasAllPermissions,
    canAccess,
  };
};

