/**
 * Hook for role-based navigation
 */
export const useRoleBasedNavigation = () => {
  const { user } = useAuth();
  const rbac = useRBAC();

  const getDefaultRoute = (): string => {
    if (!user) return ROUTES.LOGIN;

    const role = user.role as Role;

    // ✅ Use centralized getDashboardByRole function for consistency
    // Falls back to login if role is invalid/unknown
    return getDashboardByRole(role) || ROUTES.LOGIN;
  };

  const getAvailableRoutes = () => {
    const routes = [];

    if (rbac.canAccess('appointments', 'read')) {
      routes.push({ path: '/appointments', label: 'Appointments' });
    }

    if (rbac.canAccess('patients', 'read')) {
      routes.push({ path: '/patients', label: 'Patients' });
    }

    if (rbac.canAccess('doctors', 'read')) {
      routes.push({ path: '/doctors', label: 'Doctors' });
    }

    if (rbac.canAccess('queue', 'read')) {
      routes.push({ path: '/queue', label: 'Queue' });
    }

    if (rbac.canAccess('pharmacy', 'read')) {
      routes.push({ path: '/pharmacy', label: 'Pharmacy' });
    }

    if (rbac.canAccess('analytics', 'read')) {
      routes.push({ path: '/analytics', label: 'Analytics' });
    }

    if (rbac.canAccess('medical-records', 'read')) {
      routes.push({ path: '/ehr', label: 'Medical Records' });
    }

    return routes;
  };

  return {
    getDefaultRoute,
    getAvailableRoutes,
  };
};

/**
 * Context-aware permission checking
 */
export const useContextualPermissions = (context: PermissionContext) => {
  const { user } = useAuth();
  const rbac = useRBAC();

  const canAccessResource = (_resourceId: string, resourceType: string): PermissionResult => {
    if (!user) {
      return { allowed: false, reason: 'User not authenticated' };
    }

    const userRole = user.role as Role;

    // Super admin can access everything
    if (userRole === Role.SUPER_ADMIN) {
      return { allowed: true, context };
    }

    // Check if user owns the resource
    const isOwner = context.resourceOwnerId === user.id;

    // Patients can only access their own resources
    if (userRole === Role.PATIENT) {
      if (isOwner || context.patientId === user.id) {
        return { allowed: true, context };
      }
      return { allowed: false, reason: 'Can only access own resources' };
    }

    // Doctors can access their patients' resources
    if ((userRole === Role.DOCTOR || userRole === Role.ASSISTANT_DOCTOR) && resourceType === 'patient') {
      // Check if patient is assigned to this doctor (would need additional logic)
      return { allowed: true, context };
    }

    // Clinic-level access control
    if (context.clinicId && (user as any).clinicId && context.clinicId !== (user as any).clinicId) {
      return { allowed: false, reason: 'Resource belongs to different clinic' };
    }

    return { allowed: true, context };
  };

  return {
    canAccessResource,
    ...rbac,
  };
};

import { UseMutateFunction } from "@tanstack/react-query";
import { useForm, DefaultValues, UseFormReturn } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";

const useZodForm = <T extends z.ZodType<any, any, any>>(
  schema: T,
  mutation: UseMutateFunction<unknown, unknown, z.infer<T>>,
  defaultValues?: DefaultValues<z.infer<T>>
): UseFormReturn<z.infer<T>> & {
  onFormSubmit: (e?: any) => Promise<void>;
} => {
  const form = useForm<z.infer<T>>({
    resolver: zodResolver(schema) as any,
    ...(defaultValues ? { defaultValues } : {}),
    mode: "onChange" as const,
  });

  const onFormSubmit = form.handleSubmit(async (values) => {
    try {
      await Promise.resolve(mutation(values as z.infer<T>));
    } catch (error) {
      console.error('Form submission error:', error);
      // Re-throw the error so it can be caught by the form's error handler
      throw error;
    }
  });

  return {
    ...form,
    onFormSubmit,
  } as UseFormReturn<z.infer<T>> & {
    onFormSubmit: (e?: any) => Promise<void>;
  };
};

export default useZodForm;

'use server';

import { authenticatedApi } from './auth.server';
import { API_ENDPOINTS } from '../config/config';

// ===== ANALYTICS & REPORTING =====
// 🔒 TENANT ISOLATION: All analytics endpoints use the X-Clinic-ID header
// (auto-injected by authenticatedApi) for tenant scoping. The clinicId query
// parameter is accepted for backward compatibility but the backend ClinicGuard
// uses the header value as the authoritative source.

/**
 * Get dashboard analytics
 */
export async function getDashboardAnalytics(period: 'day' | 'week' | 'month' | 'year' = 'month', _clinicId?: string) {
