  const response = await fetchWithAbort(`${API_URL}${API_ENDPOINTS.COMMUNICATION.SEND}`, {
    method: 'POST',
    headers,
    body: JSON.stringify({
      type: 'email',
      title: 'Consultation Booking Request',
      message: `
        Name: ${data.name}
        Phone: ${data.phone}
        ${data.preferredDate ? `Preferred Date: ${data.preferredDate}` : ''}
