/**
 * ✅ Performance Metrics & Monitoring
 * Tracks API calls, response times, errors
 * Follows SOLID, DRY, KISS principles
 */



import { logger } from './logger';

// ============================================================================
// Metrics Types
// ============================================================================

export interface MetricData {
  name: string;
  value: number;
  timestamp: number;
  tags?: Record<string, string>;
  metadata?: Record<string, any>;
}

export interface ApiMetric {
  endpoint: string;
  method: string;
  statusCode: number;
  responseTime: number;
  timestamp: number;
  error?: string;
  requestSize?: number;
  responseSize?: number;
}

export interface CircuitBreakerState {
  isOpen: boolean;
  failureCount: number;
  lastFailureTime: number | null;
  successCount: number;
  halfOpenAttempts: number;
}

// ============================================================================
// Metrics Collector
// ============================================================================

class MetricsCollector {
  private metrics: MetricData[] = [];
  private apiMetrics: ApiMetric[] = [];
  private readonly maxMetrics = 1000; // Keep last 1000 metrics
  private readonly maxApiMetrics = 500; // Keep last 500 API metrics

  /**
   * Record a metric
   */
  record(metric: MetricData): void {
    this.metrics.push({
      ...metric,
      timestamp: metric.timestamp || Date.now(),
    });

    // Keep only last N metrics
    if (this.metrics.length > this.maxMetrics) {
      this.metrics = this.metrics.slice(-this.maxMetrics);
    }

    // Log in development
    if (process.env.NODE_ENV === 'development') {
      logger.debug('Metric recorded', { name: metric.name, value: metric.value, timestamp: metric.timestamp });
    }
  }

  /**
   * Record API metric
   */
  recordApi(metric: ApiMetric): void {
    this.apiMetrics.push({
      ...metric,
      timestamp: metric.timestamp || Date.now(),
    });

    // Keep only last N API metrics
    if (this.apiMetrics.length > this.maxApiMetrics) {
      this.apiMetrics = this.apiMetrics.slice(-this.maxApiMetrics);
    }

    // Log slow requests
    if (metric.responseTime > 2000) {
      logger.warn('Slow API request', {
        endpoint: metric.endpoint,
        method: metric.method,
        responseTime: metric.responseTime,
      });
    }

    // Log errors
    if (metric.statusCode >= 400) {
      logger.error('API error', {
        endpoint: metric.endpoint,
        method: metric.method,
        statusCode: metric.statusCode,
        error: metric.error,
      });
    }
  }

  /**
   * Get metrics summary
   */
  getSummary(): {
    totalMetrics: number;
    totalApiCalls: number;
    averageResponseTime: number;
    errorRate: number;
    slowRequests: number;
  } {
    const apiCalls = this.apiMetrics;
    const totalApiCalls = apiCalls.length;
    
    if (totalApiCalls === 0) {
      return {
        totalMetrics: this.metrics.length,
        totalApiCalls: 0,
        averageResponseTime: 0,
        errorRate: 0,
        slowRequests: 0,
      };
    }

    const totalResponseTime = apiCalls.reduce((sum, m) => sum + m.responseTime, 0);
    const averageResponseTime = totalResponseTime / totalApiCalls;
    
    const errorCount = apiCalls.filter(m => m.statusCode >= 400).length;
    const errorRate = (errorCount / totalApiCalls) * 100;
    
    const slowRequests = apiCalls.filter(m => m.responseTime > 2000).length;

    return {
      totalMetrics: this.metrics.length,
      totalApiCalls,
      averageResponseTime: Math.round(averageResponseTime),
      errorRate: Math.round(errorRate * 100) / 100,
      slowRequests,
    };
  }

  /**
   * Get recent API metrics
   */
  getRecentApiMetrics(limit: number = 50): ApiMetric[] {
    return this.apiMetrics.slice(-limit);
  }

  /**
   * Clear all metrics
   */
  clear(): void {
    this.metrics = [];
    this.apiMetrics = [];
  }
}

// Global metrics collector
export const metricsCollector = new MetricsCollector();

// ============================================================================
// Circuit Breaker
// ============================================================================

class CircuitBreaker {
  private states: Map<string, CircuitBreakerState> = new Map();
  private readonly failureThreshold: number;
  private readonly successThreshold: number;
  private readonly timeout: number;
  private readonly halfOpenMaxAttempts: number;

  constructor(
    failureThreshold: number = 5,
    successThreshold: number = 2,
    timeout: number = 60000, // 1 minute
    halfOpenMaxAttempts: number = 3
  ) {
    this.failureThreshold = failureThreshold;
    this.successThreshold = successThreshold;
    this.timeout = timeout;
    this.halfOpenMaxAttempts = halfOpenMaxAttempts;
  }

  /**
   * Get state for endpoint
   */
  private getState(endpoint: string): CircuitBreakerState {
    if (!this.states.has(endpoint)) {
      this.states.set(endpoint, {
        isOpen: false,
        failureCount: 0,
        lastFailureTime: null,
        successCount: 0,
        halfOpenAttempts: 0,
      });
    }
    return this.states.get(endpoint)!;
  }

  /**
   * Check if circuit is open
   */
  isOpen(endpoint: string): boolean {
    const state = this.getState(endpoint);
    
    if (!state.isOpen) {
      return false;
    }

    // Check if timeout has passed
    if (state.lastFailureTime && Date.now() - state.lastFailureTime > this.timeout) {
      // Move to half-open state
      state.isOpen = false;
      state.halfOpenAttempts = 0;
      state.successCount = 0;
      return false;
    }

    return true;
  }

  /**
   * Record success
   */
  recordSuccess(endpoint: string): void {
    const state = this.getState(endpoint);
    
    if (state.isOpen) {
      // In half-open state, count successes
      state.successCount++;
      if (state.successCount >= this.successThreshold) {
        // Close circuit
        state.isOpen = false;
        state.failureCount = 0;
        state.successCount = 0;
        state.halfOpenAttempts = 0;
        logger.info('Circuit breaker closed', { endpoint });
      }
    } else {
      // Reset failure count on success
      state.failureCount = 0;
    }
  }

  /**
   * Record failure
   */
  recordFailure(endpoint: string): void {
    const state = this.getState(endpoint);
    
    state.failureCount++;
    state.lastFailureTime = Date.now();

    if (state.isOpen) {
      // In half-open state, increment attempts
      state.halfOpenAttempts++;
      if (state.halfOpenAttempts >= this.halfOpenMaxAttempts) {
        // Re-open circuit
        state.halfOpenAttempts = 0;
        state.successCount = 0;
        logger.warn('Circuit breaker re-opened', { endpoint });
      }
    } else if (state.failureCount >= this.failureThreshold) {
      // Open circuit
      state.isOpen = true;
      state.halfOpenAttempts = 0;
      state.successCount = 0;
      logger.error('Circuit breaker opened', { endpoint, failureCount: state.failureCount });
    }
  }

  /**
   * Reset circuit breaker for endpoint
   */
  reset(endpoint: string): void {
    this.states.delete(endpoint);
  }

  /**
   * Get circuit breaker state
   */
  getCircuitState(endpoint: string): CircuitBreakerState {
    if (!this.states.has(endpoint)) {
      this.states.set(endpoint, {
        isOpen: false,
        failureCount: 0,
        lastFailureTime: null,
        successCount: 0,
        halfOpenAttempts: 0,
      });
    }
    return this.states.get(endpoint)!;
  }
}

// Global circuit breaker
export const circuitBreaker = new CircuitBreaker();

// ============================================================================
// Performance Tracking
// ============================================================================

/**
 * Track API call performance
 */
export function trackApiCall(
  endpoint: string,
  method: string,
  statusCode: number,
  responseTime: number,
  error?: string,
  requestSize?: number,
  responseSize?: number
): void {
  const metric: ApiMetric = {
    endpoint,
    method,
    statusCode,
    responseTime,
    timestamp: Date.now(),
  };
  if (error !== undefined) metric.error = error;
  if (requestSize !== undefined) metric.requestSize = requestSize;
  if (responseSize !== undefined) metric.responseSize = responseSize;
  
  metricsCollector.recordApi(metric);

  // Update circuit breaker
  if (statusCode >= 500 || error) {
    circuitBreaker.recordFailure(endpoint);
  } else {
    circuitBreaker.recordSuccess(endpoint);
  }
}

/**
 * Track custom metric
 */
export function trackMetric(
  name: string,
  value: number,
  tags?: Record<string, string>,
  metadata?: Record<string, any>
): void {
  const metric: MetricData = {
    name,
    value,
    timestamp: Date.now(),
  };
  if (tags !== undefined) metric.tags = tags;
  if (metadata !== undefined) metric.metadata = metadata;
  
  metricsCollector.record(metric);
}

/**
 * Check if endpoint is available (circuit breaker)
 */
export function isEndpointAvailable(endpoint: string): boolean {
  return !circuitBreaker.isOpen(endpoint);
}

/**
 * Get metrics summary
 */
export function getMetricsSummary() {
  return metricsCollector.getSummary();
}

/**
 * Get recent API metrics
 */
export function getRecentApiMetrics(limit: number = 50) {
  return metricsCollector.getRecentApiMetrics(limit);
}

"use client";

// Performance optimization utilities for 100K users
import { useCallback, useRef, useEffect, useMemo, useState } from 'react';

/**
 * Throttle function calls to improve performance under high load
 */
export function throttle<T extends (...args: any[]) => any>(
  func: T,
  limit: number
): (...args: Parameters<T>) => void {
  let inThrottle: boolean;
  return function (this: any, ...args: Parameters<T>) {
    if (!inThrottle) {
      func.apply(this, args);
      inThrottle = true;
      setTimeout(() => (inThrottle = false), limit);
    }
  };
}

/**
 * Debounce function calls to reduce API calls and improve performance
 */
export function debounce<T extends (...args: any[]) => any>(
  func: T,
  delay: number
): (...args: Parameters<T>) => void {
  let timeoutId: NodeJS.Timeout;
  return function (this: any, ...args: Parameters<T>) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => func.apply(this, args), delay);
  };
}

/**
 * React hook for throttled callbacks
 */
export function useThrottledCallback<T extends (...args: any[]) => any>(
  callback: T,
  limit: number
): T {
  const throttledCallback = useMemo(
    () => throttle(callback, limit),
    [callback, limit]
  );

  return throttledCallback as T;
}

/**
 * React hook for debounced callbacks
 */
export function useDebouncedCallback<T extends (...args: any[]) => any>(
  callback: T,
  delay: number
): T {
  const debouncedCallback = useMemo(
    () => debounce(callback, delay),
    [callback, delay]
  );

  return debouncedCallback as T;
}

/**
 * Virtual scrolling utilities for large lists
 */
export interface VirtualScrollOptions {
  itemHeight: number;
  containerHeight: number;
  itemCount: number;
  overscan?: number;
}

export function useVirtualScroll({
  itemHeight,
  containerHeight,
  itemCount,
  overscan = 5,
}: VirtualScrollOptions) {
  const scrollElementRef = useRef<HTMLDivElement>(null);
  const [scrollTop, setScrollTop] = useState(0);

  const startIndex = useMemo(
    () => Math.max(0, Math.floor(scrollTop / itemHeight) - overscan),
    [scrollTop, itemHeight, overscan]
  );

  const endIndex = useMemo(
    () =>
      Math.min(
        itemCount - 1,
        Math.floor((scrollTop + containerHeight) / itemHeight) + overscan
      ),
    [scrollTop, containerHeight, itemHeight, itemCount, overscan]
  );

  const visibleItems = useMemo(
    () => Array.from({ length: endIndex - startIndex + 1 }, (_, i) => startIndex + i),
    [startIndex, endIndex]
  );

  const offsetY = useMemo(() => startIndex * itemHeight, [startIndex, itemHeight]);

  const totalHeight = useMemo(() => itemCount * itemHeight, [itemCount, itemHeight]);

  const handleScroll = useThrottledCallback((e: React.UIEvent<HTMLDivElement>) => {
    setScrollTop(e.currentTarget.scrollTop);
  }, 16); // ~60fps

  return {
    scrollElementRef,
    visibleItems,
    offsetY,
    totalHeight,
    handleScroll,
  };
}

/**
 * Memory-efficient className computation
 */
const classNameCache = new Map<string, string>();

export function memoizeClassName(
  baseClasses: string,
  conditionalClasses?: string | undefined | null
): string {
  const key = `${baseClasses}:${conditionalClasses || ''}`;

  if (classNameCache.has(key)) {
    return classNameCache.get(key)!;
  }

  const result = conditionalClasses 
    ? `${baseClasses} ${conditionalClasses}` 
    : baseClasses;

  // Limit cache size to prevent memory leaks (optimized for 10M users)
  if (classNameCache.size > 5000) {
    // Remove oldest 1000 entries when limit reached
    const keysToDelete = Array.from(classNameCache.keys()).slice(0, 1000);
    keysToDelete.forEach(key => classNameCache.delete(key));
  }

  classNameCache.set(key, result);
  return result;
}

/**
 * Optimized intersection observer for lazy loading
 */
export function useIntersectionObserver(
  options: IntersectionObserverInit = {}
) {
  const elementRef = useRef<HTMLElement>(null);
  const [isIntersecting, setIsIntersecting] = useState(false);

  useEffect(() => {
    const element = elementRef.current;
    if (!element) return;

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry) {
          setIsIntersecting(entry.isIntersecting);
        }
      },
      {
        threshold: 0.1,
        rootMargin: '50px',
        ...options,
      }
    );

    observer.observe(element);

    return () => {
      observer.unobserve(element);
    };
  }, [options]);

  return { elementRef, isIntersecting };
}

/**
 * Performance monitoring utilities
 */
export class PerformanceMonitor {
  private static measurements = new Map<string, number[]>();

  static startMeasurement(name: string) {
    if (typeof performance !== 'undefined') {
      performance.mark(`${name}-start`);
    }
  }

  static endMeasurement(name: string) {
    if (typeof performance !== 'undefined') {
      performance.mark(`${name}-end`);
      performance.measure(name, `${name}-start`, `${name}-end`);

      const measure = performance.getEntriesByName(name, 'measure')[0];
      if (measure) {
        const measurements = this.measurements.get(name) || [];
        measurements.push(measure.duration);

        // Keep only last 100 measurements
        if (measurements.length > 100) {
          measurements.shift();
        }

        this.measurements.set(name, measurements);
      }

      // Clean up marks
      performance.clearMarks(`${name}-start`);
      performance.clearMarks(`${name}-end`);
      performance.clearMeasures(name);
    }
  }

  static getAverageDuration(name: string): number {
    const measurements = this.measurements.get(name);
    if (!measurements || measurements.length === 0) return 0;

    const sum = measurements.reduce((a, b) => a + b, 0);
    return sum / measurements.length;
  }

  static logPerformanceReport() {
    if (process.env.NODE_ENV === 'development') {
      console.group('Performance Report');
      this.measurements.forEach((measurements, name) => {
        const avg = this.getAverageDuration(name);
        console.log(`${name}: ${avg.toFixed(2)}ms average (${measurements.length} samples)`);
      });
      console.groupEnd();
    }
  }
}

/**
 * Hook for performance measurement
 */
export function usePerformanceMeasurement(name: string) {
  useEffect(() => {
    PerformanceMonitor.startMeasurement(name);

    return () => {
      PerformanceMonitor.endMeasurement(name);
    };
  }, [name]);
}

/**
 * Optimized state updates for high-frequency changes
 */
export function useBatchedUpdates<T>(initialValue: T, batchDelay: number = 50) {
  const [value, setValue] = useState(initialValue);
  const pendingUpdate = useRef<T | null>(null);
  const timeoutRef = useRef<NodeJS.Timeout | null>(null);

  const batchedSetValue = useCallback((newValue: T | ((prev: T) => T)) => {
    const resolvedValue = typeof newValue === 'function' 
      ? (newValue as (prev: T) => T)(pendingUpdate.current ?? value)
      : newValue;

    pendingUpdate.current = resolvedValue;

    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current);
    }

    timeoutRef.current = setTimeout(() => {
      if (pendingUpdate.current !== null) {
        setValue(pendingUpdate.current);
        pendingUpdate.current = null;
      }
      timeoutRef.current = null;
    }, batchDelay);
  }, [value, batchDelay]);

  useEffect(() => {
    return () => {
      if (timeoutRef.current) {
        clearTimeout(timeoutRef.current);
      }
    };
  }, []);

  return [value, batchedSetValue] as const;
}

/**
 * ✅ Comprehensive Redirection Utility
 * Single source of truth for all redirection logic
 * Handles all scenarios from A to Z with proper role-based routing
 * 
 * This utility ensures consistent redirection behavior across:
 * - Login/Logout flows
 * - Profile completion flows
 * - Unauthorized access
 * - Session expiry
 * - Role-based access control
 * - Edge cases (unknown roles, invalid tokens, etc.)
 */

import { Role } from '@/types/auth.types';
import { getDashboardByRole, ROUTES, isAuthPath } from '@/lib/config/routes';
import { getProfileCompletionRedirectUrl } from '@/lib/config/profile';

/**
 * Redirection context - all information needed for proper redirection
 */
export interface RedirectContext {
  user?: {
    role?: Role | string;
    profileComplete?: boolean;
  } | null;
  currentPath?: string;
  redirectUrl?: string;
  callbackUrl?: string;
  error?: string;
  isAuthenticated?: boolean;
}

/**
 * Redirection result
 */
export interface RedirectResult {
  path: string;
  reason: string;
  preserveQuery?: boolean;
}

/**
 * Get redirect path after login
 * Handles: profile completion, callback URLs, role-based dashboards
 */
export function getLoginRedirect(context: RedirectContext): RedirectResult {
  const { user, redirectUrl, callbackUrl, currentPath } = context;

  // If no user, redirect to login
  if (!user || !user.role) {
    return {
      path: ROUTES.LOGIN,
      reason: 'no_user',
    };
  }

  const userRole = user.role as Role;

  // Priority 1: Check if profile is incomplete
  if (user.profileComplete === false) {
    const profileUrl = new URL(ROUTES.PROFILE_COMPLETION, window.location.origin);
    if (currentPath && !isAuthPath(currentPath)) {
      profileUrl.searchParams.set('redirect', currentPath);
    }
    return {
      path: profileUrl.pathname + profileUrl.search,
      reason: 'profile_incomplete',
    };
  }

  // Priority 2: Use callback URL if provided and valid
  if (callbackUrl && !isAuthPath(callbackUrl)) {
    return {
      path: callbackUrl,
      reason: 'callback_url',
    };
  }

  // Priority 3: Use redirect URL from response if provided and valid
  if (redirectUrl && !isAuthPath(redirectUrl)) {
    return {
      path: redirectUrl,
      reason: 'response_redirect_url',
    };
  }

  // Priority 4: Use role-based dashboard
  const dashboardPath = getDashboardByRole(userRole);
  if (dashboardPath && dashboardPath !== ROUTES.LOGIN) {
    return {
      path: dashboardPath,
      reason: 'role_based_dashboard',
    };
  }

  // Fallback: Home page
  return {
    path: ROUTES.HOME,
    reason: 'fallback_home',
  };
}

/**
 * Get redirect path after logout
 * Always redirects to login with optional message
 */
export function getLogoutRedirect(message?: string): RedirectResult {
  const loginUrl = new URL(ROUTES.LOGIN, window.location.origin);
  if (message) {
    loginUrl.searchParams.set('message', message);
  }
  return {
    path: loginUrl.pathname + loginUrl.search,
    reason: 'logout',
  };
}

/**
 * Get redirect path for unauthorized access
 * Redirects to role-appropriate dashboard
 */
export function getUnauthorizedRedirect(context: RedirectContext): RedirectResult {
  const { user, currentPath } = context;

  // If no user, redirect to login
  if (!user || !user.role) {
    const loginUrl = new URL(ROUTES.LOGIN, window.location.origin);
    if (currentPath) {
      loginUrl.searchParams.set('callbackUrl', currentPath);
    }
    return {
      path: loginUrl.pathname + loginUrl.search,
      reason: 'unauthorized_no_user',
    };
  }

  const userRole = user.role as Role;
  const dashboardPath = getDashboardByRole(userRole);

  // If invalid role, redirect to login with error
  if (dashboardPath === ROUTES.LOGIN) {
    const loginUrl = new URL(ROUTES.LOGIN, window.location.origin);
    loginUrl.searchParams.set('error', 'invalid_role');
    return {
      path: loginUrl.pathname + loginUrl.search,
      reason: 'invalid_role',
    };
  }

  return {
    path: dashboardPath,
    reason: 'unauthorized_redirect_to_dashboard',
  };
}

/**
 * Get redirect path after profile completion
 * Preserves original destination if provided
 */
export function getProfileCompletionRedirect(
  userRole: Role,
  originalPath?: string
): RedirectResult {
  const profileUrl = new URL(ROUTES.PROFILE_COMPLETION, typeof window !== 'undefined' ? window.location.origin : 'http://localhost:3000');
  if (originalPath && !isAuthPath(originalPath)) {
    profileUrl.searchParams.set('redirect', originalPath);
  }

  return {
    path: profileUrl.pathname + profileUrl.search,
    reason: 'profile_incomplete_redirect',
  };
}

/**
 * Get redirect path for session expiry
 * Redirects to login with session expired message
 */
export function getSessionExpiredRedirect(currentPath?: string): RedirectResult {
  const loginUrl = new URL(ROUTES.LOGIN, window.location.origin);
  loginUrl.searchParams.set('error', 'session_expired');
  if (currentPath && !isAuthPath(currentPath)) {
    loginUrl.searchParams.set('callbackUrl', currentPath);
  }
  return {
    path: loginUrl.pathname + loginUrl.search,
    reason: 'session_expired',
  };
}

/**
 * Get redirect path for invalid token
 * Redirects to login with error
 */
export function getInvalidTokenRedirect(currentPath?: string): RedirectResult {
  const loginUrl = new URL(ROUTES.LOGIN, window.location.origin);
  loginUrl.searchParams.set('error', 'invalid_token');
  if (currentPath && !isAuthPath(currentPath)) {
    loginUrl.searchParams.set('callbackUrl', currentPath);
  }
  return {
    path: loginUrl.pathname + loginUrl.search,
    reason: 'invalid_token',
  };
}

/**
 * Get redirect path for registration
 * Redirects to login with success message
 */
export function getRegistrationRedirect(): RedirectResult {
  const loginUrl = new URL(ROUTES.LOGIN, window.location.origin);
  loginUrl.searchParams.set('registered', 'true');
  return {
    path: loginUrl.pathname + loginUrl.search,
    reason: 'registration_success',
  };
}

/**
 * Get redirect path for password reset
 * Redirects to login with success message
 */
export function getPasswordResetRedirect(): RedirectResult {
  const loginUrl = new URL(ROUTES.LOGIN, window.location.origin);
  loginUrl.searchParams.set('reset', 'true');
  return {
    path: loginUrl.pathname + loginUrl.search,
    reason: 'password_reset_success',
  };
}

/**
 * Get redirect path for OTP verification
 * Similar to login redirect
 */
export function getOTPVerificationRedirect(context: RedirectContext): RedirectResult {
  return getLoginRedirect(context);
}

/**
 * Get redirect path for social login
 * Similar to login redirect
 */
export function getSocialLoginRedirect(context: RedirectContext): RedirectResult {
  return getLoginRedirect(context);
}

/**
 * Comprehensive redirect resolver
 * Determines the correct redirect path based on context
 */
export function resolveRedirect(context: RedirectContext): RedirectResult {
  const { user, error, isAuthenticated, currentPath } = context;

  // Handle errors first
  if (error) {
    if (error === 'session_expired') {
      return getSessionExpiredRedirect(currentPath);
    }
    if (error === 'invalid_token' || error === 'invalid_role') {
      return getInvalidTokenRedirect(currentPath);
    }
  }

  // Handle authentication state
  if (!isAuthenticated || !user) {
    if (currentPath && isAuthPath(currentPath)) {
      // Already on auth page, no redirect needed
      return {
        path: currentPath,
        reason: 'already_on_auth_page',
      };
    }
    return getSessionExpiredRedirect(currentPath);
  }

  // Handle profile completion
  if (user.profileComplete === false) {
    return getProfileCompletionRedirect(user.role as Role, currentPath);
  }

  // Handle login redirect (for post-login scenarios)
  return getLoginRedirect(context);
}

/**
 * Check if a path requires authentication
 */
export function requiresAuth(path: string): boolean {
  return !isAuthPath(path) && path !== ROUTES.HOME;
}

/**
 * Check if a path requires profile completion
 */
export function requiresProfileCompletion(
  path: string,
  profileComplete: boolean
): boolean {
  if (profileComplete) return false;
  if (isAuthPath(path)) return false;
  if (path === ROUTES.PROFILE_COMPLETION) return false;
  return true;
}

/**
 * ✅ Security Utilities
 * Rate limiting, CSRF protection, input validation
 * Follows SOLID, DRY, KISS principles
 * 
 * Note: PHI encryption, TLS 1.3, HIPAA audit logging, GDPR data rights are skipped per requirements
 */

'use client';

import { logger } from './logger';

// ============================================================================
// Rate Limiting
// ============================================================================

interface RateLimitEntry {
  count: number;
  resetTime: number;
}

class RateLimiter {
  private requests: Map<string, RateLimitEntry> = new Map();
  private readonly maxRequests: number;
  private readonly windowMs: number;

  constructor(maxRequests: number = 10, windowMs: number = 60000) {
    this.maxRequests = maxRequests;
    this.windowMs = windowMs;
  }

  /**
   * Check if request should be allowed
   */
  isAllowed(identifier: string): boolean {
    const now = Date.now();
    const entry = this.requests.get(identifier);

    if (!entry || now > entry.resetTime) {
      // Create new entry or reset expired entry
      this.requests.set(identifier, {
        count: 1,
        resetTime: now + this.windowMs,
      });
      return true;
    }

    if (entry.count >= this.maxRequests) {
      return false;
    }

    entry.count++;
    return true;
  }

  /**
   * Get remaining requests
   */
  getRemaining(identifier: string): number {
    const entry = this.requests.get(identifier);
    if (!entry) return this.maxRequests;
    
    const now = Date.now();
    if (now > entry.resetTime) return this.maxRequests;
    
    return Math.max(0, this.maxRequests - entry.count);
  }

  /**
   * Clear expired entries
   */
  cleanup(): void {
    const now = Date.now();
    for (const [key, entry] of this.requests.entries()) {
      if (now > entry.resetTime) {
        this.requests.delete(key);
      }
    }
  }

  /**
   * Reset rate limit for identifier
   */
  reset(identifier: string): void {
    this.requests.delete(identifier);
  }
}

// Global rate limiters
const authRateLimiter = new RateLimiter(5, 60000); // 5 requests per minute
const apiRateLimiter = new RateLimiter(100, 60000); // 100 requests per minute
const generalRateLimiter = new RateLimiter(50, 60000); // 50 requests per minute

// Cleanup expired entries every 5 minutes
if (typeof window !== 'undefined') {
  setInterval(() => {
    authRateLimiter.cleanup();
    apiRateLimiter.cleanup();
    generalRateLimiter.cleanup();
  }, 5 * 60 * 1000);
}

/**
 * Check rate limit for authentication operations
 */
export function checkAuthRateLimit(identifier: string): {
  allowed: boolean;
  remaining: number;
  resetTime?: number;
} {
  const allowed = authRateLimiter.isAllowed(identifier);
  const remaining = authRateLimiter.getRemaining(identifier);
  
  if (!allowed) {
    logger.warn('Auth rate limit exceeded', { identifier });
  }
  
  return {
    allowed,
    remaining,
  };
}

/**
 * Check rate limit for API operations
 */
export function checkApiRateLimit(identifier: string): {
  allowed: boolean;
  remaining: number;
} {
  const allowed = apiRateLimiter.isAllowed(identifier);
  const remaining = apiRateLimiter.getRemaining(identifier);
  
  if (!allowed) {
    logger.warn('API rate limit exceeded', { identifier });
  }
  
  return {
    allowed,
    remaining,
  };
}

/**
 * Check rate limit for general operations
 */
export function checkGeneralRateLimit(identifier: string): {
  allowed: boolean;
  remaining: number;
} {
  const allowed = generalRateLimiter.isAllowed(identifier);
  const remaining = generalRateLimiter.getRemaining(identifier);
  
  return {
    allowed,
    remaining,
  };
}

/**
 * Reset rate limit for identifier
 */
export function resetRateLimit(identifier: string, type: 'auth' | 'api' | 'general' = 'general'): void {
  switch (type) {
    case 'auth':
      authRateLimiter.reset(identifier);
      break;
    case 'api':
      apiRateLimiter.reset(identifier);
      break;
    case 'general':
      generalRateLimiter.reset(identifier);
      break;
  }
}

// ============================================================================
// CSRF Protection
// ============================================================================

/**
 * Generate CSRF token
 */
export function generateCSRFToken(): string {
  const array = new Uint8Array(32);
  if (typeof window !== 'undefined' && window.crypto) {
    window.crypto.getRandomValues(array);
  } else {
    // Fallback for environments without crypto
    for (let i = 0; i < array.length; i++) {
      array[i] = Math.floor(Math.random() * 256);
    }
  }
  return Array.from(array, byte => byte.toString(16).padStart(2, '0')).join('');
}

/**
 * Store CSRF token
 */
export function storeCSRFToken(token: string): void {
  if (typeof window !== 'undefined') {
    sessionStorage.setItem('csrf_token', token);
  }
}

/**
 * Get stored CSRF token
 */
export function getCSRFToken(): string | null {
  if (typeof window === 'undefined') return null;
  return sessionStorage.getItem('csrf_token');
}

/**
 * Validate CSRF token
 */
export function validateCSRFToken(token: string): boolean {
  const storedToken = getCSRFToken();
  if (!storedToken) return false;
  return storedToken === token;
}

// ============================================================================
// Input Validation & Sanitization
// ============================================================================

/**
 * Sanitize string input
 */
export function sanitizeInput(input: string): string {
  if (typeof input !== 'string') return '';
  
  return input
    .trim()
    .replace(/[<>]/g, '') // Remove potential HTML tags
    .replace(/javascript:/gi, '') // Remove javascript: protocol
    .replace(/on\w+=/gi, ''); // Remove event handlers
}

/**
 * Validate email format
 */
export function isValidEmail(email: string): boolean {
  if (!email || typeof email !== 'string') return false;
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email.trim());
}

/**
 * Validate password strength
 */
export function validatePasswordStrength(password: string): {
  valid: boolean;
  errors: string[];
} {
  const errors: string[] = [];
  
  if (!password || password.length < 8) {
    errors.push('Password must be at least 8 characters long');
  }
  
  if (!/[A-Z]/.test(password)) {
    errors.push('Password must contain at least one uppercase letter');
  }
  
  if (!/[a-z]/.test(password)) {
    errors.push('Password must contain at least one lowercase letter');
  }
  
  if (!/[0-9]/.test(password)) {
    errors.push('Password must contain at least one number');
  }
  
  if (!/[!@#$%^&*(),.?":{}|<>]/.test(password)) {
    errors.push('Password must contain at least one special character');
  }
  
  return {
    valid: errors.length === 0,
    errors,
  };
}

/**
 * Validate phone number format
 */
export function isValidPhoneNumber(phone: string): boolean {
  if (!phone || typeof phone !== 'string') return false;
  // Basic phone validation - accepts digits, spaces, dashes, parentheses, plus
  const phoneRegex = /^[\d\s\-+()]+$/;
  return phoneRegex.test(phone.trim()) && phone.replace(/\D/g, '').length >= 10;
}

/**
 * Sanitize object recursively
 */
export function sanitizeObject<T extends Record<string, any>>(obj: T): T {
  const sanitized = { ...obj } as Record<string, any>;
  
  for (const key in sanitized) {
    if (typeof sanitized[key] === 'string') {
      sanitized[key] = sanitizeInput(sanitized[key]);
    } else if (typeof sanitized[key] === 'object' && sanitized[key] !== null && !Array.isArray(sanitized[key])) {
      sanitized[key] = sanitizeObject(sanitized[key]);
    } else if (Array.isArray(sanitized[key])) {
      sanitized[key] = sanitized[key].map((item: any) =>
        typeof item === 'string' ? sanitizeInput(item) : item
      );
    }
  }
  
  return sanitized as T;
}

// ============================================================================
// Request Fingerprinting
// ============================================================================

/**
 * Generate request fingerprint for rate limiting
 */
export function generateRequestFingerprint(
  userId?: string,
  ipAddress?: string,
  userAgent?: string
): string {
  const parts: string[] = [];
  
  if (userId) {
    parts.push(`user:${userId}`);
  }
  
  if (ipAddress) {
    parts.push(`ip:${ipAddress}`);
  }
  
  if (userAgent) {
    // Hash user agent to reduce storage
    const hash = userAgent.split('').reduce((acc, char) => {
      return ((acc << 5) - acc) + char.charCodeAt(0);
    }, 0);
    parts.push(`ua:${Math.abs(hash)}`);
  }
  
  return parts.join('|') || 'anonymous';
}

/**
 * Get client identifier for rate limiting
 */
export function getClientIdentifier(): string {
  if (typeof window === 'undefined') return 'server';
  
  const userId = localStorage.getItem('user_id');
  const userAgent = navigator.userAgent;
  
  return generateRequestFingerprint(userId || undefined, undefined, userAgent);
}

